#define __STDCPP_WANT_MATH_SPEC_FUNCS__ 1



// Feature detection for C++17 special math functions
// macOS libc++ doesn't support these yet, so we need fallbacks
#if defined(__cpp_lib_math_special_functions) || \
    (defined(_MSC_VER) && _MSC_VER >= 1910) || \
    (defined(__GNUC__) && !defined(__clang__) && __GNUC__ >= 7) || \
    (defined(__clang__) && !defined(__APPLE__) && __clang_major__ >= 10)
    #define MML_HAS_STD_SPECIAL_FUNCTIONS 1
#else
    #define MML_HAS_STD_SPECIAL_FUNCTIONS 0
#endif

namespace MML
{
	namespace Functions
	{
		// Basic math functions - templated to support all numeric types (Real, Complex, float, long double, etc.)
		// These delegate to std:: functions which handle type-specific implementations
		template<typename T>
		static inline T Sin(T x) { return std::sin(x); }
		template<typename T>
		static inline T Cos(T x) { return std::cos(x); }
		template<typename T>
		static inline T Sec(T x) { T c = std::cos(x); if (std::abs(c) < std::numeric_limits<T>::epsilon()) throw std::domain_error("Sec: cos(x) is zero"); return T{1} / c; }
		template<typename T>
		static inline T Csc(T x) { T s = std::sin(x); if (std::abs(s) < std::numeric_limits<T>::epsilon()) throw std::domain_error("Csc: sin(x) is zero"); return T{1} / s; }
		template<typename T>
		static inline T Tan(T x) { return std::tan(x); }
		template<typename T>
		static inline T Ctg(T x) { T t = std::tan(x); if (std::abs(t) < std::numeric_limits<T>::epsilon()) throw std::domain_error("Ctg: tan(x) is zero"); return T{1} / t; }

		template<typename T>
		static inline T Exp(T x) { return std::exp(x); }
		template<typename T>
		static inline T Log(T x) { return std::log(x); }
		template<typename T>
		static inline T Log10(T x) { return std::log10(x); }
		template<typename T>
		static inline T Sqrt(T x) { return std::sqrt(x); }
		template<typename T>
		static inline T Pow(T x, T y) { return std::pow(x, y); }

		template<typename T>
		static inline T Sinh(T x) { return std::sinh(x); }
		template<typename T>
		static inline T Cosh(T x) { return std::cosh(x); }
		template<typename T>
		static inline T Sech(T x) { return T{1} / std::cosh(x); }
		template<typename T>
		static inline T Csch(T x) { T s = std::sinh(x); if (std::abs(s) < std::numeric_limits<T>::epsilon()) throw std::domain_error("Csch: sinh(x) is zero"); return T{1} / s; }
		template<typename T>
		static inline T Tanh(T x) { return std::tanh(x); }
		template<typename T>
		static inline T Ctgh(T x) { T t = std::tanh(x); if (std::abs(t) < std::numeric_limits<T>::epsilon()) throw std::domain_error("Ctgh: tanh(x) is zero"); return T{1} / t; }

		template<typename T>
		static inline T Asin(T x) { return std::asin(x); }
		template<typename T>
		static inline T Acos(T x) { return std::acos(x); }
		template<typename T>
		static inline T Atan(T x) { return std::atan(x); }

		template<typename T>
		static inline T Asinh(T x) { return std::asinh(x); }
		template<typename T>
		static inline T Acosh(T x) { return std::acosh(x); }
		template<typename T>
		static inline T Atanh(T x) { return std::atanh(x); }

		// Special functions - Real only (std:: library limitation)
		static inline Real Erf(Real x) { return std::erf(x); }
		static inline Real Erfc(Real x) { return std::erfc(x); }

		static inline Real TGamma(Real x) { return std::tgamma(x); }
		static inline Real LGamma(Real x) { return std::lgamma(x); }

#if MML_HAS_STD_SPECIAL_FUNCTIONS
		// C++17 special math functions (not available on macOS libc++)
		// NOTE: These are ONLY wrappers around std:: functions. They are NOT used by MML internally.
		//       MML uses its own implementations in mml/algorithms/ which work on all platforms.
		static inline Real RiemannZeta(Real x) { return std::riemann_zeta(x); }

		static inline Real Hermite(unsigned int n, Real x) { return std::hermite(n, x); }
		static inline Real Legendre(unsigned int n, Real x) { return std::legendre(n, x); }
		static inline Real Laguerre(unsigned int n, Real x) { return std::laguerre(n, x); }
		static inline Real SphBessel(unsigned int n, Real x) { return std::sph_bessel(n, x); }
		static inline Real SphLegendre(int n1, int n2, Real x) { return std::sph_legendre(n1, n2, x); }

		// Elliptic integrals (incomplete and complete)
		static inline Real Ellint_1(Real k, Real phi) { return std::ellint_1(k, phi); }
		static inline Real Ellint_2(Real k, Real phi) { return std::ellint_2(k, phi); }
		static inline Real Ellint_3(Real k, Real n, Real phi) { return std::ellint_3(k, n, phi); }
		static inline Real Comp_ellint_1(Real x) { return std::comp_ellint_1(x); }
		static inline Real Comp_ellint_2(Real x) { return std::comp_ellint_2(x); }
		static inline Real Comp_ellint_3(Real k, Real n) { return std::comp_ellint_3(k, n); }

		// Bessel functions
		static inline Real CylBesselJ(Real n, Real x) { return std::cyl_bessel_j(n, x); }
		static inline Real CylBesselI(Real n, Real x) { return std::cyl_bessel_i(n, x); }
		static inline Real CylBesselK(Real n, Real x) { return std::cyl_bessel_k(n, x); }
		static inline Real CylNeumann(Real n, Real x) { return std::cyl_neumann(n, x); }

		// Spherical Neumann function
		static inline Real SphNeumann(unsigned int n, Real x) { return std::sph_neumann(n, x); }

		// Associated Legendre and Laguerre polynomials
		static inline Real AssocLegendre(unsigned int l, unsigned int m, Real x) { return std::assoc_legendre(l, m, x); }
		static inline Real AssocLaguerre(unsigned int n, unsigned int m, Real x) { return std::assoc_laguerre(n, m, x); }

		// Beta and exponential integral functions
		static inline Real Beta(Real x, Real y) { return std::beta(x, y); }
		static inline Real Expint(Real x) { return std::expint(x); }

		// Alias for Bessel function of the second kind (same as CylNeumann)
		static inline Real CylBesselY(Real n, Real x) { return std::cyl_neumann(n, x); }
#else
		// =====================================================================================
		// FALLBACK IMPLEMENTATIONS for platforms without C++17 special math (e.g., macOS libc++)
		// These provide the same interface as the std:: functions above.
		// =====================================================================================

		// Legendre polynomial Pₙ(x) using Bonnet's recurrence
		static inline Real Legendre(unsigned int n, Real x) {
			if (n == 0) return 1.0;
			if (n == 1) return x;
			Real P_prev2 = 1.0, P_prev1 = x, P_n = 0.0;
			for (unsigned int k = 2; k <= n; ++k) {
				P_n = ((2.0 * k - 1.0) * x * P_prev1 - (k - 1.0) * P_prev2) / k;
				P_prev2 = P_prev1;
				P_prev1 = P_n;
			}
			return P_n;
		}

		// Hermite polynomial Hₙ(x) (physicist's convention) using recurrence
		static inline Real Hermite(unsigned int n, Real x) {
			if (n == 0) return 1.0;
			if (n == 1) return 2.0 * x;
			Real H_prev2 = 1.0, H_prev1 = 2.0 * x, H_n = 0.0;
			for (unsigned int k = 2; k <= n; ++k) {
				H_n = 2.0 * x * H_prev1 - 2.0 * (k - 1.0) * H_prev2;
				H_prev2 = H_prev1;
				H_prev1 = H_n;
			}
			return H_n;
		}

		// Laguerre polynomial Lₙ(x) using recurrence
		static inline Real Laguerre(unsigned int n, Real x) {
			if (n == 0) return 1.0;
			if (n == 1) return 1.0 - x;
			Real L_prev2 = 1.0, L_prev1 = 1.0 - x, L_n = 0.0;
			for (unsigned int k = 2; k <= n; ++k) {
				L_n = ((2.0 * k - 1.0 - x) * L_prev1 - (k - 1.0) * L_prev2) / k;
				L_prev2 = L_prev1;
				L_prev1 = L_n;
			}
			return L_n;
		}

		// Associated Legendre polynomial Pₗᵐ(x) using recurrence
		static inline Real AssocLegendre(unsigned int l, unsigned int m, Real x) {
			if (m > l) return 0.0;
			// Start with P_m^m
			Real P_mm = 1.0;
			if (m > 0) {
				Real sqrt1mx2 = std::sqrt(1.0 - x * x);
				Real fact = 1.0;
				for (unsigned int i = 1; i <= m; ++i) {
					P_mm *= -fact * sqrt1mx2;
					fact += 2.0;
				}
			}
			if (l == m) return P_mm;
			// P_{m+1}^m
			Real P_mp1_m = x * (2.0 * m + 1.0) * P_mm;
			if (l == m + 1) return P_mp1_m;
			// Recurrence for higher l
			Real P_l_m = 0.0;
			for (unsigned int ll = m + 2; ll <= l; ++ll) {
				P_l_m = (x * (2.0 * ll - 1.0) * P_mp1_m - (ll + m - 1.0) * P_mm) / (ll - m);
				P_mm = P_mp1_m;
				P_mp1_m = P_l_m;
			}
			return P_l_m;
		}

		// Associated Laguerre polynomial Lₙᵐ(x) using recurrence
		static inline Real AssocLaguerre(unsigned int n, unsigned int m, Real x) {
			if (n == 0) return 1.0;
			if (n == 1) return 1.0 + m - x;
			Real L_prev2 = 1.0;
			Real L_prev1 = 1.0 + m - x;
			Real L_n = 0.0;
			for (unsigned int k = 2; k <= n; ++k) {
				L_n = ((2.0 * k - 1.0 + m - x) * L_prev1 - (k - 1.0 + m) * L_prev2) / k;
				L_prev2 = L_prev1;
				L_prev1 = L_n;
			}
			return L_n;
		}

		// Spherical Legendre function Y_l^m(theta) (real, normalized)
		static inline Real SphLegendre(unsigned int l, unsigned int m, Real theta) {
			// Y_l^m(theta) = K_l^m * P_l^m(cos(theta))
			// Normalization: K_l^m = sqrt((2l+1)/(4π) * (l-m)!/(l+m)!)
			Real x = std::cos(theta);
			Real P_lm = AssocLegendre(l, m, x);
			// Compute (l-m)! / (l+m)!
			Real ratio = 1.0;
			for (unsigned int i = l - m + 1; i <= l + m; ++i)
				ratio /= i;
			Real K = std::sqrt((2.0 * l + 1.0) / (4.0 * Constants::PI) * ratio);
			return K * P_lm;
		}

		// Complete elliptic integral of the first kind K(k) using AGM
		static inline Real Comp_ellint_1(Real k) {
			Real a = 1.0, b = std::sqrt(1.0 - k * k);
			while (std::abs(a - b) > 1e-15) {
				Real temp = (a + b) / 2.0;
				b = std::sqrt(a * b);
				a = temp;
			}
			return Constants::PI / (2.0 * a);
		}

		// Complete elliptic integral of the second kind E(k) using AGM
		static inline Real Comp_ellint_2(Real k) {
			Real a = 1.0, b = std::sqrt(1.0 - k * k);
			Real c = k, sum = k * k / 2.0;
			Real power_of_2 = 1.0;
			while (std::abs(c) > 1e-15) {
				Real a_new = (a + b) / 2.0;
				Real b_new = std::sqrt(a * b);
				c = (a - b) / 2.0;
				power_of_2 *= 2.0;
				sum += power_of_2 * c * c;
				a = a_new;
				b = b_new;
			}
			return Constants::PI / (2.0 * a) * (1.0 - sum);
		}

		// Note: More special functions (Bessel, Beta, etc.) can be added here if needed.
		// For now, use MML's own implementations from mml/algorithms/ for those.
#endif

    // Note: Basic math functions (Sin, Cos, Exp, Log, etc.) now templated above.
    // They work with Real, Complex, float, long double, etc. - no separate Complex overloads needed.

		// Factorial functions
		static inline Real Factorial(int n) {
			if (n < 0) throw std::domain_error("Factorial: negative argument");
			Real fact = 1.0;
			for (int i = 2; i <= n; i++)
				fact *= i;
			return fact;
		}
		static inline long long FactorialInt(int n) {
			if (n < 0) throw std::domain_error("FactorialInt: negative argument");
			long long fact = 1;
			for (int i = 2; i <= n; i++)
				fact *= i;
			return fact;
		}
		static inline Real FactorialStirling(int n)
		{
			if (n < 0) throw std::domain_error("FactorialStirling: negative argument");
			if (n == 0 || n == 1) return 1.0;
			return sqrt(2 * Constants::PI * n) * std::pow(n / Constants::E, n);
		}
	}
}


///////////////////////////   mml/base/Vector/Vector.h   ///////////////////////////


// Standard headers - include what we use

namespace MML
{
	/// @brief Generic vector class template for numerical computations
	/// @details Provides a dynamically-sized vector with:
	///          - Standard arithmetic operations (+, -, *, /)
	///          - Vector norms (L1, L2, L∞)
	///          - Element access (checked and unchecked)
	///          - STL-compatible iteration
	///
	///          Wraps std::vector<Type> with mathematical operations.
	///
	/// @threadsafety Thread-safe for const operations. Non-const operations require external
	///               synchronization. See docs/THREADING.md for details.
	///
	/// @tparam Type Element type (typically Real, Complex, or arithmetic types)
	template<class Type>
	class	Vector
	{
	private:
		std::vector<Type> _elems;

	public:
		typedef Type value_type;      ///< Element type alias for STL compatibility

		/////////////////////                  Constructors                ////////////////////
		
		/// @brief Default constructor - creates empty vector
		Vector() {}
		
		/// @brief Construct vector of given size
		/// @param n Number of elements (must be non-negative)
		/// @throws VectorInitializationError if n < 0
		/// @details Elements initialized to zero for arithmetic types, default-constructed otherwise
		explicit Vector(int n) {
			if(n < 0)
				throw VectorInitializationError("Vector::Vector - negative size", n);

			// Initialize to zero for numeric types, default construct for others
			if constexpr (std::is_arithmetic_v<Type>) {
				_elems.resize(n, Type{ 0 });
			} else {
				_elems.resize(n);
			}
		}
		
		/// @brief Construct vector of given size with uniform value
		/// @param n Number of elements (must be non-negative)
		/// @param val Value to fill all elements with
		/// @throws VectorInitializationError if n < 0
		explicit Vector(int n, const Type &val) {
			if (n < 0)
				throw VectorInitializationError("Vector::Vector - negative size", n);

			_elems.resize(n, val);
		}
		
		/// @brief Construct vector from C-style array
		/// @param n Number of elements to copy (must be non-negative)
		/// @param vals Pointer to array of values
		/// @throws VectorInitializationError if n < 0
		explicit Vector(int n, Type* vals) 
		{
			if (n < 0)
				throw VectorInitializationError("Vector::Vector - negative size", n);

			_elems.resize(n);
			for (int i = 0; i < n; ++i)
				_elems[i] = vals[i];
		}
		
		/// @brief Construct from std::vector
		explicit Vector(const std::vector<Type> &values) : _elems(values) {}
		
		/// @brief Construct from initializer list (e.g., Vector<double> v{1.0, 2.0, 3.0})
		explicit Vector(std::initializer_list<Type> list) : _elems(list) {}

		/// @brief Create a unit vector (all zeros except one element = 1)
		/// @param dimVec Dimension of the vector
		/// @param indUnit Index of the unit element (0-based)
		/// @return Unit vector e_i where e_i[indUnit] = 1
		/// @throws VectorDimensionError if indUnit is out of range
		static Vector UnitVector(int dimVec, int indUnit)
		{
			static_assert(std::is_arithmetic_v<Type>, "UnitVector requires arithmetic type");
			
			if (indUnit < 0 || indUnit >= dimVec)
				throw VectorDimensionError("Vector::UnitVector - wrong unit index", dimVec, indUnit);

			Vector ret(dimVec);
			ret[indUnit] = Type{ 1.0 };
			return ret;
		}

		// not really needed, but let's be explicit
		Vector(const Vector& b) = default; 
		Vector(Vector&& b) noexcept = default;
		Vector& operator=(const Vector& b) = default; 
		Vector& operator=(Vector&& b) noexcept = default;

		////////////////            std::vector forwarding                 ////////////////////
		
		/// @brief Get number of elements
		int  size()			const noexcept { return (int)_elems.size(); }
		
		/// @brief Check if vector is empty (STL-compatible)
		bool empty()	const noexcept { return _elems.empty(); }

		// front and back
		Type& front()							noexcept { return _elems.front(); }
		const Type& front() const noexcept { return _elems.front(); }
		Type& back()							noexcept { return _elems.back(); }
		const Type& back() const	noexcept { return _elems.back(); }

    auto begin()	noexcept { return _elems.begin(); }
    auto end()		noexcept { return _elems.end(); }
    auto begin()	const noexcept { return _elems.begin(); }
    auto end()		const noexcept { return _elems.end(); }
    auto cbegin() const noexcept { return _elems.cbegin(); }
    auto cend()		const noexcept { return _elems.cend(); }

		void push_back(const Type& val) { _elems.push_back(val); }
		void push_back(Type&& val)			{ _elems.push_back(std::move(val)); }
		
		void insert(int pos, const Type& val) { _elems.insert(_elems.begin() + pos, val); }
		void insert(int pos, Type&& val) { _elems.insert(_elems.begin() + pos, std::move(val)); }
		
		void erase(int pos)							{ _elems.erase(_elems.begin() + pos); }
		void erase(int start, int end)	{ _elems.erase(_elems.begin() + start, _elems.begin() + end); }
		void erase(const Type& val)			{ _elems.erase(std::remove(_elems.begin(), _elems.end(), val), _elems.end()); }

		/// @brief Remove all elements
		void Clear()	{ _elems.clear(); }
		
		/// @brief Resize the vector
		/// @param newLen New size
		/// @param preserveElements Ignored (std::vector::resize always preserves existing elements)
		void Resize(int newLen, [[maybe_unused]] bool preserveElements = false)	
		{ 
			_elems.resize(newLen); 
		}

		/////////////////////            Accessing elements             ///////////////////////
		
		/// @brief Unchecked element access
		inline Type&       operator[](int n)       noexcept { return _elems[n]; }
		/// @brief Unchecked element access (const)
		inline const Type& operator[](int n) const noexcept { return _elems[n]; }

		/// @brief Checked element access
		/// @param n Index (0-based)
		/// @return Reference to element at index n
		/// @throws VectorDimensionError if index out of bounds
		Type& at(int n)	{
			if(n < 0 || n >= size())
				throw VectorDimensionError("Vector::at - index out of bounds", size(), n);
			else
				return _elems[n];
		}
		/// @brief Checked element access (const)
		/// @throws VectorDimensionError if index out of bounds
		const Type& at(int n) const { 
			if(n < 0 || n >= size())
				throw VectorDimensionError("Vector::at - index out of bounds", size(), n);
			else
				return _elems[n];
		}

		///////////////////////          Arithmetic operators         ////////////////////////
		
		/// @brief Unary negation
		[[nodiscard]] Vector  operator-() const
		{
			Vector ret(size());
			for (int i = 0; i < size(); i++)
				ret._elems[i] = Type{ -1 } * (*this)[i];
			return ret;
		}
		
		/// @brief Vector addition
		/// @throws VectorDimensionError if sizes don't match
		[[nodiscard]] Vector  operator+(const Vector& b) const
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::operator+() - vectors must be equal size", size(), b.size());

			Vector ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret._elems[i] = (*this)[i] + b._elems[i];
			return ret;
		}
		
		/// @brief In-place vector addition
		/// @throws VectorDimensionError if sizes don't match
		Vector& operator+=(const Vector& b)
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::operator+=() - vectors must be equal size", size(), b.size());
			
			for (int i = 0; i < b.size(); i++)
				_elems[i] += b._elems[i];
			return *this;
		}
		
		/// @brief Vector subtraction
		/// @throws VectorDimensionError if sizes don't match
		[[nodiscard]] Vector  operator-(const Vector& b) const
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::operator-() - vectors must be equal size", size(), b.size());

			Vector ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret._elems[i] = (*this)[i] - b._elems[i];
			return ret;
		}
		
		/// @brief In-place vector subtraction
		/// @throws VectorDimensionError if sizes don't match
		Vector& operator-=(const Vector& b)
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::operator-=() - vectors must be equal size", size(), b.size());
			
			for (int i = 0; i < b.size(); i++)
				_elems[i] -= b._elems[i];
			return *this;
		}

		/// @brief Scalar multiplication (vector * scalar)
		[[nodiscard]] Vector  operator*(Type b) const
		{
			Vector ret(size());;
			for (int i = 0; i < size(); i++)
				ret._elems[i] = b * _elems[i];
			return ret;
		}
		
		/// @brief In-place scalar multiplication
		Vector& operator*=(Type b)
		{
			for (int i = 0; i < size(); i++)
				_elems[i] *= b;
			return *this;
		}
		
		/// @brief Scalar division
		[[nodiscard]] Vector  operator/(Type b) const
		{
			Vector ret(size());
			for (int i = 0; i < size(); i++)
				ret._elems[i] = _elems[i] / b;
			return ret;
		}
		
		/// @brief In-place scalar division
		Vector& operator/=(Type b)
		{
			for (int i = 0; i < size(); i++)
				_elems[i] /= b;
			return *this;
		}
		
		/// @brief Scalar multiplication (scalar * vector)
		friend Vector operator*(Type a, const Vector& b)
		{
			Vector ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret._elems[i] = a * b._elems[i];
			return ret;
		}

		///////////////////////             Testing equality             ////////////////////////
		
		/// @brief Exact equality comparison
		/// @throws VectorDimensionError if sizes don't match
		bool operator==(const Vector& b) const
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::operator==() - vectors must be equal size", size(), b.size());

			for (int i = 0; i < size(); i++)
				if ((*this)[i] != b[i])
					return false;

			return true;
		}
		
		/// @brief Exact inequality comparison
		bool operator!=(const Vector& b) const
		{
			return !(*this == b);
		}
		
		/// @brief Approximate equality with tolerance
		/// @param b Vector to compare with
		/// @param eps Maximum allowed difference per element
		/// @return true if |this[i] - b[i]| <= eps for all i
		/// @throws VectorDimensionError if sizes don't match
		bool IsEqualTo(const Vector& b, Real eps = Defaults::VectorIsEqualTolerance) const
		{
			if (size() != b.size())
				throw VectorDimensionError("Vector::IsEqual - vectors must be equal size", size(), b.size());

			for (int i = 0; i < size(); i++)
			{
				if (Abs((*this)[i] - b[i]) > eps)
					return false;
			}
			return true;
		}	
		
		/// @brief Check if all elements are zero
		bool isZero() const noexcept
		{
			for (int i = 0; i < size(); i++)
				if (Abs((*this)[i]) != 0.0 )
					return false;
			return true;
		}

		//////////////////////                 Operations                 ///////////////////////
		
		/// @brief L1 norm (sum of absolute values): ||v||_1 = Σ|v_i|
		Real NormL1() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < size(); i++)
				norm += Abs((*this)[i]);
			return norm;
		}
		
		/// @brief L2 norm (Euclidean length): ||v||_2 = √(Σ|v_i|²)
		/// @details For complex vectors, uses std::norm(z) = |z|² = real² + imag²
		Real NormL2() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < size(); i++) {
				if constexpr (std::is_same_v<Type, Complex> || 
				              std::is_same_v<Type, std::complex<float>> ||
				              std::is_same_v<Type, std::complex<long double>>) {
					norm += std::norm((*this)[i]);  // |z|² for complex
				} else {
					norm += (*this)[i] * (*this)[i];  // x² for real
				}
			}
			return std::sqrt(norm);
		}
		
		/// @brief L∞ norm (maximum absolute value): ||v||_∞ = max|v_i|
		Real NormLInf() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < size(); i++)
				norm = std::max(norm, Abs((*this)[i]));
			return norm;
		}

		///////////////////////////               I/O                 ///////////////////////////
		
		/// @brief Print vector to stream with formatting
		/// @param stream Output stream
		/// @param width Field width for each element
		/// @param precision Decimal precision
		/// @param zeroThreshold Values with |x| <= threshold printed as 0
		std::ostream& Print(std::ostream& stream, int width, int precision, Real zeroThreshold) const
		{
			stream << "[";
			bool first = true;
			for (const Type& x : _elems)
			{
				if (!first)
					stream << ", ";
				else
					first = false;

        if( Abs(x) > zeroThreshold )
				  stream << std::setw(width) << std::setprecision(precision) << x;
        else
          stream << std::setw(width) << std::setprecision(precision) << 0.0;
			}
			stream << "]";

			return stream;
		}
		
		/// @brief Print vector to stream with formatting
		std::ostream& Print(std::ostream& stream, int width, int precision) const
		{
			return Print(stream, width, precision, 0.0);
		}
		
		/// @brief Print vector with message prefix and newline
    std::ostream& PrintLine(std::ostream& stream, const std::string &msg, int width, int precision) const
		{
			stream << msg;
			Print(stream, width, precision);
			stream << std::endl;

			return stream;
		}
		
		/// @brief Print vector as column (one element per line)
		std::ostream& PrintCol(std::ostream& stream, int width, int precision) const
		{
			for (const Type& x : _elems)
				stream << std::setw(width) << std::setprecision(precision) << x << std::endl;
			return stream;
		}		

		/// @brief Convert to string representation
		std::string to_string(int width, int precision) const
		{
			std::stringstream str;

			Print(str, width, precision);

			return str.str();
		}
		
		/// @brief Convert to string with default formatting
		std::string to_string() const
		{
			return to_string(Defaults::VectorPrintWidth, Defaults::VectorPrintPrecision);
		}

		/// @brief Stream output operator
		friend std::ostream& operator<<(std::ostream &stream, const Vector &a)
		{
			a.Print(stream, Defaults::VectorPrintWidth, Defaults::VectorPrintPrecision);

			return stream;
		}
		
		///////////////////////         Binary File I/O                //////////////////////
		
		/// @brief Save vector to binary file
		/// 
		/// Binary format:
		/// - 4 bytes: magic number 0x4D4D4C56 ("MMLV" for MML Vector)
		/// - 4 bytes: version (currently 1)
		/// - 4 bytes: size (int32)
		/// - 4 bytes: element size in bytes (sizeof(Type))
		/// - size*sizeof(Type) bytes: data
		/// 
		/// @param vec Vector to save
		/// @param filename Path to output file
		/// @return true if successful
		static bool SaveToBinary(const Vector& vec, const std::string& filename)
		{
			std::ofstream file(filename, std::ios::binary);
			if (!file.is_open()) {
				std::cerr << "Error: could not create binary file " << filename << std::endl;
				return false;
			}
			
			// Write header
			const uint32_t magic = BinaryFormat::MAGIC_VECTOR;
			const uint32_t version = BinaryFormat::VERSION_VECTOR;
			const uint32_t size = static_cast<uint32_t>(vec._elems.size());
			const uint32_t elemSize = static_cast<uint32_t>(sizeof(Type));
			
			file.write(reinterpret_cast<const char*>(&magic), sizeof(magic));
			file.write(reinterpret_cast<const char*>(&version), sizeof(version));
			file.write(reinterpret_cast<const char*>(&size), sizeof(size));
			file.write(reinterpret_cast<const char*>(&elemSize), sizeof(elemSize));
			
			// Write data
			if (size > 0) {
				file.write(reinterpret_cast<const char*>(vec._elems.data()), 
				           size * sizeof(Type));
			}
			
			file.close();
			return true;
		}
		
		/// @brief Load vector from binary file
		/// @param filename Path to input file
		/// @param outVec Vector to populate
		/// @return true if successful
		static bool LoadFromBinary(const std::string& filename, Vector& outVec)
		{
			std::ifstream file(filename, std::ios::binary);
			if (!file.is_open()) {
				std::cerr << "Error: could not open binary file " << filename << std::endl;
				return false;
			}
			
			// Read and verify header
			uint32_t magic, version, size, elemSize;
			
			file.read(reinterpret_cast<char*>(&magic), sizeof(magic));
			if (magic != BinaryFormat::MAGIC_VECTOR) {
				std::cerr << "Error: invalid magic number in " << filename << std::endl;
				return false;
			}
			
			file.read(reinterpret_cast<char*>(&version), sizeof(version));
			if (version != BinaryFormat::VERSION_VECTOR) {
				std::cerr << "Error: unsupported version " << version << " in " << filename << std::endl;
				return false;
			}
			
			file.read(reinterpret_cast<char*>(&size), sizeof(size));
			file.read(reinterpret_cast<char*>(&elemSize), sizeof(elemSize));
			
			if (elemSize != sizeof(Type)) {
				std::cerr << "Error: element size mismatch in " << filename 
				          << " (file: " << elemSize << ", expected: " << sizeof(Type) << ")" << std::endl;
				return false;
			}
			
			// Read data
			outVec._elems.resize(size);
			if (size > 0) {
				file.read(reinterpret_cast<char*>(outVec._elems.data()), 
				          size * sizeof(Type));
			}
			
			file.close();
			return true;
		}
		
		/// @brief Save vector to text file (one value per line)
		/// @param vec Vector to save
		/// @param filename Path to output file
		/// @return true if successful
		static bool SaveToFile(const Vector& vec, const std::string& filename)
		{
			std::ofstream file(filename);
			if (!file.is_open()) return false;
			
			file << vec._elems.size() << std::endl;
			for (const auto& val : vec._elems)
				file << val << std::endl;
			
			file.close();
			return true;
		}
		
		/// @brief Load vector from text file
		/// @param filename Path to input file
		/// @param outVec Vector to populate
		/// @return true if successful
		static bool LoadFromFile(const std::string& filename, Vector& outVec)
		{
			std::ifstream file(filename);
			if (!file.is_open()) return false;
			
			size_t size;
			file >> size;
			outVec._elems.resize(size);
			
			for (size_t i = 0; i < size; ++i)
				file >> outVec._elems[i];
			
			file.close();
			return true;
		}
	};

	// Common type aliases
	typedef Vector<int>     VectorInt;      ///< Integer vector
	typedef Vector<float>   VectorFlt;      ///< Single-precision vector
	typedef Vector<double>  VectorDbl;      ///< Double-precision vector
	typedef Vector<Complex> VectorComplex;  ///< Complex vector

	// Short aliases
	typedef Vector<int>     VecI;   ///< Short alias for VectorInt
	typedef Vector<float>   VecF;   ///< Short alias for VectorFlt
	typedef Vector<double>  VecD;   ///< Short alias for VectorDbl
	typedef Vector<Complex> VecC;   ///< Short alias for VectorComplex

	// Verify noexcept move operations enable STL optimizations
	static_assert(std::is_nothrow_move_constructible_v<Vector<double>>,
	              "Vector<double> should be nothrow move constructible");
	static_assert(std::is_nothrow_move_assignable_v<Vector<double>>,
	              "Vector<double> should be nothrow move assignable");
}


///////////////////////////   mml/base/Vector/VectorN.h   ///////////////////////////


// Standard headers - include what we use

namespace MML
{
	/// @brief Fixed-size vector with compile-time dimension (stack-allocated).
	/// @tparam Type Element type
	/// @tparam N Vector dimension (fixed at compile time)
	template<class Type, int N>
	class VectorN
	{
	protected:
		Type  _val[N] = { 0 };

	public:
		typedef Type value_type;      // make T available externally

		///////////////////////          Constructors and destructor       //////////////////////
		/// @brief Default constructor (zero vector).
		VectorN() {}
		/// @brief Constructs vector with all elements set to init_val.
		/// @param init_val Initialization value for all elements
		explicit VectorN(const Type& init_val) {
			for (int i = 0; i < N; ++i)
				_val[i] = init_val;
		}
		/// @brief Constructs vector from initializer list.
		/// @param list Initializer list (must have <= N elements)
		/// @throws VectorDimensionError if list.size() > N
		VectorN(std::initializer_list<Type> list)
		{
			if (static_cast<int>(list.size()) > N)
				throw VectorDimensionError("VectorN initializer list has more elements than vector dimension", N, static_cast<int>(list.size()));
			int count = 0;
			for (auto element : list)
			{
				_val[count] = element;
				++count;
			}
		}
		/// @brief Constructs vector from std::vector.
		/// @param list Vector of values (must have <= N elements)
		/// @throws VectorDimensionError if list.size() > N
		VectorN(std::vector<Type> list)
		{
			if (static_cast<int>(list.size()) > N)
				throw VectorDimensionError("VectorN std::vector has more elements than vector dimension", N, static_cast<int>(list.size()));
			int count{ 0 };
			for (auto element : list)
			{
				_val[count] = element;
				++count;
			}
		}
		/// @brief Constructs vector from raw array.
		/// @param vals Array of N elements
		explicit VectorN(Type* vals)
		{
			for (int i = 0; i < N; ++i)
				_val[i] = vals[i];
		}
		
		/// @brief Returns unit vector (1 at indUnit, 0 elsewhere).
		/// @param indUnit Index for the unit component
		static VectorN UnitVector(int indUnit)
		{
			VectorN ret;
			ret[indUnit] = 1.0;
			return ret;
		}
		/// @brief Returns normalized vector (unit length).
		VectorN Normalized() const
		{
			VectorN ret;
			Real norm = NormL2();
			if (norm == 0.0)
				throw VectorDimensionError("VectorN::Normalized - cannot normalize zero vector", N, 0);
			for (int i = 0; i < N; ++i)
				ret._val[i] = _val[i] / norm;
			return ret;
		}
		////////////////////////            Standard stuff             ////////////////////////
		/// @brief Returns vector dimension.
		int  size() const noexcept { return N; }
		/// @brief Sets all elements to zero.
		void clear() noexcept {
			for (int i = 0; i < N; ++i)
				_val[i] = Type{ 0 };
		}

		///////////////////////            Accessing elements             ///////////////////////
		/// @brief Element access (non-const).
		/// @param n Index
		inline Type& operator[](int n) noexcept { return _val[n]; }
		/// @brief Element access (const).
		/// @param n Index
		inline const Type& operator[](int n) const noexcept { return _val[n]; }

		/// @brief Checked element access (non-const).
		/// @param n Index (throws if out of bounds)
		Type& at(int n) {
			if (n < 0 || n >= N)
				throw VectorDimensionError("VectorN::at - index out of bounds", N, n);
			else
				return _val[n];
		}
		/// @brief Checked element access (const).
		/// @param n Index (throws if out of bounds)
		const Type& at(int n) const {
			if (n < 0 || n >= N)
				throw VectorDimensionError("VectorN::at - index out of bounds", N, n);
			else
				return _val[n];
		}

		///////////////////////            Iterator support                ///////////////////////
		Type*       begin()        noexcept { return _val; }
		Type*       end()          noexcept { return _val + N; }
		const Type* begin()  const noexcept { return _val; }
		const Type* end()    const noexcept { return _val + N; }
		const Type* cbegin() const noexcept { return _val; }
		const Type* cend()   const noexcept { return _val + N; }
		Type*       data()         noexcept { return _val; }
		const Type* data()   const noexcept { return _val; }

		///////////////////////            Testing equality                ///////////////////////
		/// @brief Exact equality comparison.
		/// @param b Vector to compare
		bool operator==(const VectorN& b) const
		{
			for (int i = 0; i < size(); i++)
				if ((*this)[i] != b[i])
					return false;

			return true;
		}
		/// @brief Checks equality within tolerance (static version).
		/// @param a First vector
		/// @param b Second vector
		/// @param eps Tolerance
		static bool AreEqual(const VectorN& a, const VectorN& b, Type eps = Defaults::VectorIsEqualTolerance)
		{
			return a.IsEqualTo(b, eps);
		}
		/// @brief Checks equality within tolerance.
		/// @param b Vector to compare
		/// @param eps Tolerance
		bool IsEqualTo(const VectorN& b, Type eps = Defaults::VectorIsEqualTolerance) const
		{
			for (int i = 0; i < N; i++)
			{
				if (Abs((*this)[i] - b[i]) > eps)
					return false;
			}
			return true;
		}
		/// @brief Inequality operator.
		/// @param b Vector to compare
		bool operator!=(const VectorN& b) const
		{
			return !(*this == b);
		}

		/// @brief Checks if vector is zero (all elements = 0).
		bool isZero() const noexcept
		{
			for (int i = 0; i < N; i++)
				if (_val[i] != 0.0)
					return false;

			return true;
		}

		/////////////////////             Arithmetic operators             ///////////////////////
		/// @brief Unary minus (negation).
		[[nodiscard]] VectorN  operator-() const
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = Type{ -1 } *_val[i];
			return ret;
		}
		
		/// @brief Vector addition.
		/// @param b Vector to add
		[[nodiscard]] VectorN  operator+(const VectorN& b) const
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = _val[i] + b._val[i];
			return ret;
		}
		/// @brief In-place addition.
		/// @param b Vector to add
		VectorN& operator+=(const VectorN& b)
		{
			for (int i = 0; i < N; i++)
				_val[i] += b._val[i];
			return *this;
		}
		/// @brief Vector subtraction.
		/// @param b Vector to subtract
		[[nodiscard]] VectorN  operator-(const VectorN& b) const
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = _val[i] - b._val[i];
			return ret;
		}
		/// @brief In-place subtraction.
		/// @param b Vector to subtract
		VectorN& operator-=(const VectorN& b)
		{
			for (int i = 0; i < N; i++)
				_val[i] -= b._val[i];
			return *this;
		}

		/// @brief Scalar multiplication (vector * scalar).
		/// @param b Scalar multiplier
		[[nodiscard]] VectorN  operator*(const Type &b) const
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = _val[i] * b;
			return ret;
		}
		/// @brief In-place scalar multiplication.
		/// @param b Scalar multiplier
		VectorN& operator*=(const Type& b)
		{
			for (int i = 0; i < N; i++)
				_val[i] *= b;
			return *this;
		}
		/// @brief Scalar division (vector / scalar).
		/// @param b Scalar divisor
		[[nodiscard]] VectorN  operator/(const Type &b) const
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = _val[i] / b;
			return ret;
		}		
		/// @brief In-place scalar division.
		/// @param b Scalar divisor
		VectorN& operator/=(const Type& b)
		{
			for (int i = 0; i < N; i++)
				_val[i] /= b;
			return *this;
		}
		
		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend VectorN operator*(Type a, const VectorN<Type, N>& b)
		{
			VectorN ret;
			for (int i = 0; i < N; i++)
				ret._val[i] = a * b[i];
			return ret;
		}

		//////////////////////                 Operations                 ///////////////////////
		/// @brief Computes L1 norm (Manhattan norm).
		Real NormL1() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < N; i++)
				norm += Abs((*this)[i]);
			return norm;
		}
		/// @brief Computes L2 norm (Euclidean norm): ||v||_2 = √(Σ|v_i|²)
		/// @details For complex vectors, uses std::norm(z) = |z|² = real² + imag²
		Real NormL2() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < N; i++) {
				if constexpr (std::is_same_v<Type, Complex> || 
				              std::is_same_v<Type, std::complex<float>> ||
				              std::is_same_v<Type, std::complex<long double>>) {
					norm += std::norm((*this)[i]);  // |z|² for complex
				} else {
					norm += (*this)[i] * (*this)[i];  // x² for real
				}
			}
			return std::sqrt(norm);
		}
		/// @brief Computes L-infinity norm (maximum absolute value).
		Real NormLInf() const
		{
			Real norm{ 0.0 };
			for (int i = 0; i < N; i++)
				norm = std::max(norm, Abs((*this)[i]));
			return norm;
		}

		///////////////////////////               I/O                 ///////////////////////////
		/// @brief Prints vector to stream.
		/// @param stream Output stream
		/// @param width Field width
		/// @param precision Decimal precision
		std::ostream& Print(std::ostream& stream, int width, int precision) const
		{
			stream << "[";
			bool first = true;
			for (const Type& x : _val)
			{
				if (!first)
					stream << ", ";
				else
					first = false;

				stream << std::setw(width) << std::setprecision(precision) << x;
			}
			stream << "]";

			return stream;
		}
		/// @brief Prints vector with values below threshold shown as zero.
		/// @param stream Output stream
		/// @param width Field width
		/// @param precision Decimal precision
		/// @param zeroThreshold Threshold for displaying as zero
		std::ostream& Print(std::ostream& stream, int width, int precision, Real zeroThreshold) const
		{
			stream << "[";
			bool first = true;
			for (const Type& x : _val)
			{
				if (!first)
					stream << ", ";
				else
					first = false;

				if (Abs(x) > zeroThreshold)
					stream << std::setw(width) << std::setprecision(precision) << x;
				else
					stream << std::setw(width) << std::setprecision(precision) << 0.0;
			}
			stream << "]";

			return stream;
		}
		/// @brief Prints vector with message prefix on single line.
		/// @param stream Output stream
		/// @param msg Message prefix
		/// @param width Field width
		/// @param precision Decimal precision
		std::ostream& PrintLine(std::ostream& stream, std::string msg, int width, int precision) const
		{
			stream << msg;
			Print(stream, width, precision);
			stream << std::endl;

			return stream;
		}

		/// @brief Converts vector to string.
		/// @param width Field width
		/// @param precision Decimal precision
		std::string to_string(int width, int precision) const
		{
			std::stringstream str;

			Print(str, width, precision);

			return str.str();
		}
		/// @brief Stream output operator.
		friend std::ostream& operator<<(std::ostream& stream, const VectorN<Type, N>& a)
		{
			a.Print(stream, Defaults::VectorNPrintWidth, Defaults::VectorNPrintPrecision);

			return stream;
		}
	};

	typedef VectorN<Real, 2> Vec2;
	typedef VectorN<Real, 3> Vec3;
	typedef VectorN<Real, 4> Vec4;

	typedef VectorN<float, 2> Vec2Flt;
	typedef VectorN<float, 3> Vec3Flt;
	typedef VectorN<float, 4> Vec4Flt;

	typedef VectorN<double, 2> Vec2Dbl;
	typedef VectorN<double, 3> Vec3Dbl;
	typedef VectorN<double, 4> Vec4Dbl;

	typedef VectorN<Complex, 2> Vec2Complex;
	typedef VectorN<Complex, 3> Vec3Complex;
	typedef VectorN<Complex, 4> Vec4Complex;

	typedef VectorN<float, 2> Vec2F;
	typedef VectorN<float, 3> Vec3F;
	typedef VectorN<float, 4> Vec4F;

	typedef VectorN<double, 2> Vec2D;
	typedef VectorN<double, 3> Vec3D;
	typedef VectorN<double, 4> Vec4D;

	typedef VectorN<Complex, 2> Vec2C;
	typedef VectorN<Complex, 3> Vec3C;
	typedef VectorN<Complex, 4> Vec4C;
}


///////////////////////////   mml/interfaces/IParametrized.h   ///////////////////////////

/**
 * @file IParametrized.h
 * @brief Shared base interface for parametrized mathematical objects.
 *
 * Defines the common parameter access API used across:
 * - Parametrized functions (IRealFunctionParametrized, IScalarFunctionParametrized, etc.)
 * - Parametrized ODE systems (IODESystemParametrized, IODESystemDAEParametrized)
 * - Dynamical systems (IDynamicalSystem via IODESystemParametrized)
 *
 * Provides three pure virtual methods that derived classes must implement:
 * - getNumParam() — number of parameters
 * - getParam(i) — read a single parameter
 * - setParam(i, val) — write a single parameter
 *
 * And two virtual methods with default implementations:
 * - getParams() — bulk read (calls getParam in a loop)
 * - setParams(v) — bulk write (calls setParam in a loop)
 *
 * @see IRealFunctionParametrized, IODESystemParametrized, IDynamicalSystem
 */




namespace MML
{
	/**
	 * @brief Interface for objects with adjustable real-valued parameters.
	 *
	 * This is the shared base for all parametrized mathematical objects in MML.
	 * Concrete classes only need to implement getNumParam(), getParam(), and
	 * setParam(); bulk accessors getParams()/setParams() have sensible defaults.
	 *
	 * @par Design Notes
	 * - Pure interface (no data members, no constructor).
	 * - Default getParams()/setParams() are virtual so they can be overridden
	 *   for efficiency (e.g., a single memcpy when parameters are contiguous).
	 * - Works with any class hierarchy via regular (non-virtual) inheritance;
	 *   virtual inheritance is not required because no diamond occurs in MML.
	 */
	class IParametrized
	{
	public:
		virtual ~IParametrized() = default;

		/** @brief Get the number of adjustable parameters. */
		virtual int  getNumParam() const = 0;

		/** @brief Get the i-th parameter value. */
		virtual Real getParam(int i) const = 0;

		/** @brief Set the i-th parameter to val. */
		virtual void setParam(int i, Real val) = 0;

		/** @brief Get all parameters as a vector.
		 *  Default implementation loops over getParam().
		 */
		virtual Vector<Real> getParams() const
		{
			Vector<Real> p(getNumParam());
			for (int i = 0; i < getNumParam(); ++i)
				p[i] = getParam(i);
			return p;
		}

		/** @brief Set all parameters from a vector.
		 *  Default implementation loops over setParam().
		 */
		virtual void setParams(const Vector<Real>& params)
		{
			for (int i = 0; i < std::min(getNumParam(), static_cast<int>(params.size())); ++i)
				setParam(i, params[i]);
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/GeometryCore/GeometryPoints.h   ///////////////////////////




namespace MML {
	/// @brief 2D point in Cartesian coordinates (x, y)
	/// @details Represents a point in 2D Euclidean space using Cartesian coordinates.
	///          Supports basic arithmetic operations (addition, subtraction, scalar multiplication/division),
	///          distance calculations, and equality comparisons with configurable tolerance.
	class Point2Cartesian {
	private:
		Real _x, _y;

	public:
		/// @brief Gets the x-coordinate (const version)
		Real X() const { return _x; }
		/// @brief Gets the x-coordinate (mutable reference)
		Real& X() { return _x; }
		/// @brief Gets the y-coordinate (const version)
		Real Y() const { return _y; }
		/// @brief Gets the y-coordinate (mutable reference)
		Real& Y() { return _y; }

		/// @brief Default constructor - initializes to origin (0, 0)
		Point2Cartesian()
			: _x(0)
			, _y(0) {}
		/// @brief Constructs a point from Cartesian coordinates
		/// @param x The x-coordinate
		/// @param y The y-coordinate
		Point2Cartesian(Real x, Real y)
			: _x(x)
			, _y(y) {}

		/// @brief Computes Euclidean distance to another point
		/// @param b The other point
		/// @return Distance between this point and b
		Real Dist(const Point2Cartesian& b) const { return sqrt(POW2(b.X() - X()) + POW2(b.Y() - Y())); }

		/// @brief Exact equality comparison
		bool operator==(const Point2Cartesian& b) const { return (X() == b.X()) && (Y() == b.Y()); }
		/// @brief Exact inequality comparison
		bool operator!=(const Point2Cartesian& b) const { return (X() != b.X()) || (Y() != b.Y()); }
		/// @brief Approximate equality comparison with tolerance
		/// @param b The other point
		/// @param eps Tolerance for comparison (default: Defaults::Pnt2CartIsEqualTolerance)
		/// @return True if distance between points is less than eps
		bool IsEqualTo(const Point2Cartesian& b, Real eps = Defaults::Pnt2CartIsEqualTolerance) const { return Dist(b) < eps; }

		/// @brief Vector addition of two points
		Point2Cartesian operator+(const Point2Cartesian& b) const { return Point2Cartesian(X() + b.X(), Y() + b.Y()); }
		/// @brief In-place vector addition
		Point2Cartesian& operator+=(const Point2Cartesian& b) {
			_x += b.X();
			_y += b.Y();
			return *this;
		}

		/// @brief Vector subtraction of two points
		Point2Cartesian operator-(const Point2Cartesian& b) const { return Point2Cartesian(X() - b.X(), Y() - b.Y()); }
		/// @brief In-place vector subtraction
		Point2Cartesian& operator-=(const Point2Cartesian& b) {
			_x -= b.X();
			_y -= b.Y();
			return *this;
		}

		/// @brief Scalar multiplication (point * scalar)
		Point2Cartesian operator*(Real b) const { return Point2Cartesian(X() * b, Y() * b); }
		/// @brief In-place scalar multiplication
		Point2Cartesian& operator*=(Real b) {
			_x *= b;
			_y *= b;
			return *this;
		}

		/// @brief Scalar division
		Point2Cartesian operator/(Real b) const { return Point2Cartesian(X() / b, Y() / b); }
		/// @brief In-place scalar division
		Point2Cartesian& operator/=(Real b) {
			_x /= b;
			_y /= b;
			return *this;
		}

		/// @brief Scalar multiplication (scalar * point)
		friend Point2Cartesian operator*(Real a, const Point2Cartesian& b) { return Point2Cartesian(a * b.X(), a * b.Y()); }
	};

	/// @brief 2D point in polar coordinates (r, φ)
	/// @details Represents a point in 2D space using polar coordinates where r is the radial
	///          distance from origin and φ (phi) is the angle from the positive x-axis in radians.
	///          Supports conversion to/from Cartesian coordinates and distance calculations.
	class Point2Polar {
	private:
		Real _r, _phi;

	public:
		/// @brief Gets the radial coordinate (const version)
		Real R() const { return _r; }
		/// @brief Gets the radial coordinate (mutable reference)
		Real& R() { return _r; }
		/// @brief Gets the angular coordinate φ in radians (const version)
		Real Phi() const { return _phi; }
		/// @brief Gets the angular coordinate φ in radians (mutable reference)
		Real& Phi() { return _phi; }

		/// @brief Default constructor - initializes to origin (0, 0)
		Point2Polar()
			: _r(0)
			, _phi(0) {}
		/// @brief Constructs a point from polar coordinates
		/// @param r Radial distance from origin
		/// @param phi Angle from positive x-axis (in radians)
		Point2Polar(Real r, Real phi)
			: _r(r)
			, _phi(phi) {}
		/// @brief Constructs a polar point from a Cartesian point
		/// @param pnt The Cartesian point to convert
		Point2Polar(const Point2Cartesian& pnt) {
			_r = sqrt(POW2(pnt.X()) + POW2(pnt.Y()));
			_phi = atan2(pnt.Y(), pnt.X());
		}

		/// @brief Exact equality comparison
		bool operator==(const Point2Polar& b) const { return (R() == b.R()) && (Phi() == b.Phi()); }
		/// @brief Exact inequality comparison
		bool operator!=(const Point2Polar& b) const { return (R() != b.R()) || (Phi() != b.Phi()); }
		/// @brief Approximate equality comparison with tolerance
		/// @param b The other point
		/// @param eps Tolerance for comparison (default: Defaults::Pnt2PolarIsEqualTolerance)
		/// @return True if distance between points is less than eps
		bool IsEqualTo(const Point2Polar& b, Real eps = Defaults::Pnt2PolarIsEqualTolerance) const { return Dist(b) < eps; }

		/// @brief Converts this polar point to Cartesian coordinates
		/// @return Equivalent Point2Cartesian (x = r*cos(φ), y = r*sin(φ))
		Point2Cartesian TransfToCart() const { return Point2Cartesian(R() * cos(Phi()), R() * sin(Phi())); }

		/// @brief Computes distance to another polar point using law of cosines
		/// @param b The other point
		/// @return Euclidean distance between the two points
		Real Dist(const Point2Polar& b) const { return sqrt(R() * R() + b.R() * b.R() - 2 * R() * b.R() * cos(b.Phi() - Phi())); }
	};

	/// @brief 3D point in Cartesian coordinates (x, y, z)
	/// @details Represents a point in 3D Euclidean space using Cartesian coordinates.
	///          Supports basic arithmetic operations (addition, subtraction, scalar multiplication/division),
	///          distance calculations, and equality comparisons with configurable tolerance.
	class Point3Cartesian {
	private:
		Real _x, _y, _z;

	public:
		/// @brief Gets the x-coordinate (const version)
		Real X() const { return _x; }
		/// @brief Gets the x-coordinate (mutable reference)
		Real& X() { return _x; }
		/// @brief Gets the y-coordinate (const version)
		Real Y() const { return _y; }
		/// @brief Gets the y-coordinate (mutable reference)
		Real& Y() { return _y; }
		/// @brief Gets the z-coordinate (const version)
		Real Z() const { return _z; }
		/// @brief Gets the z-coordinate (mutable reference)
		Real& Z() { return _z; }

		/// @brief Default constructor - initializes to origin (0, 0, 0)
		Point3Cartesian()
			: _x(0)
			, _y(0)
			, _z(0) {}
		/// @brief Constructs a point from Cartesian coordinates
		/// @param x The x-coordinate
		/// @param y The y-coordinate
		/// @param z The z-coordinate
		Point3Cartesian(Real x, Real y, Real z)
			: _x(x)
			, _y(y)
			, _z(z) {}

		/// @brief Computes Euclidean distance to another point
		/// @param b The other point
		/// @return Distance between this point and b
		Real Dist(const Point3Cartesian& b) const { return sqrt(POW2(b.X() - X()) + POW2(b.Y() - Y()) + POW2(b.Z() - Z())); }

		/// @brief Exact equality comparison
		bool operator==(const Point3Cartesian& b) const { return (X() == b.X()) && (Y() == b.Y()) && (Z() == b.Z()); }
		/// @brief Exact inequality comparison
		bool operator!=(const Point3Cartesian& b) const { return (X() != b.X()) || (Y() != b.Y()) || (Z() != b.Z()); }
		/// @brief Approximate equality comparison with tolerance
		/// @param b The other point
		/// @param eps Tolerance for comparison (default: Defaults::Pnt3CartIsEqualTolerance)
		/// @return True if distance between points is less than eps
		bool IsEqualTo(const Point3Cartesian& b, Real eps = Defaults::Pnt3CartIsEqualTolerance) const { return Dist(b) < eps; }

		/// @brief Vector addition of two points
		Point3Cartesian operator+(const Point3Cartesian& b) const { return Point3Cartesian(X() + b.X(), Y() + b.Y(), Z() + b.Z()); }
		/// @brief In-place vector addition
		Point3Cartesian& operator+=(const Point3Cartesian& b) {
			_x += b.X();
			_y += b.Y();
			_z += b.Z();
			return *this;
		}

		/// @brief Vector subtraction of two points
		Point3Cartesian operator-(const Point3Cartesian& b) const { return Point3Cartesian(X() - b.X(), Y() - b.Y(), Z() - b.Z()); }
		/// @brief In-place vector subtraction
		Point3Cartesian& operator-=(const Point3Cartesian& b) {
			_x -= b.X();
			_y -= b.Y();
			_z -= b.Z();
			return *this;
		}

		/// @brief Scalar multiplication (point * scalar)
		Point3Cartesian operator*(Real b) const { return Point3Cartesian(X() * b, Y() * b, Z() * b); }
		/// @brief In-place scalar multiplication
		Point3Cartesian& operator*=(Real b) {
			_x *= b;
			_y *= b;
			_z *= b;
			return *this;
		}

		/// @brief Scalar division
		Point3Cartesian operator/(Real b) const { return Point3Cartesian(X() / b, Y() / b, Z() / b); }
		/// @brief In-place scalar division
		Point3Cartesian& operator/=(Real b) {
			_x /= b;
			_y /= b;
			_z /= b;
			return *this;
		}

		/// @brief Scalar multiplication (scalar * point)
		friend Point3Cartesian operator*(Real a, const Point3Cartesian& b) { return Point3Cartesian(a * b.X(), a * b.Y(), a * b.Z()); }
	};

	/// @brief 3D point in spherical coordinates (r, θ, φ)
	/// @details Represents a point in 3D space using spherical coordinates where:
	///          - r: radial distance from origin
	///          - θ (theta): polar angle from positive z-axis (0 to π)
	///          - φ (phi): azimuthal angle from positive x-axis in xy-plane (0 to 2π)
	///          Uses physics convention (ISO 31-11). Supports conversion to Cartesian coordinates.
	class Point3Spherical {
	private:
		Real _r, _theta, _phi;

	public:
		/// @brief Gets the radial coordinate (const version)
		Real R() const { return _r; }
		/// @brief Gets the radial coordinate (mutable reference)
		Real& R() { return _r; }
		/// @brief Gets the polar angle θ in radians (const version)
		Real Theta() const { return _theta; }
		/// @brief Gets the polar angle θ in radians (mutable reference)
		Real& Theta() { return _theta; }
		/// @brief Gets the azimuthal angle φ in radians (const version)
		Real Phi() const { return _phi; }
		/// @brief Gets the azimuthal angle φ in radians (mutable reference)
		Real& Phi() { return _phi; }

		/// @brief Default constructor - initializes to origin
		Point3Spherical()
			: _r(0)
			, _theta(0)
			, _phi(0) {}
		/// @brief Constructs a point from spherical coordinates
		/// @param r Radial distance from origin
		/// @param theta Polar angle from z-axis (in radians, 0 to π)
		/// @param phi Azimuthal angle in xy-plane (in radians, 0 to 2π)
		Point3Spherical(Real r, Real theta, Real phi)
			: _r(r)
			, _theta(theta)
			, _phi(phi) {}
		/// @brief Constructs a spherical point from a Cartesian point
		/// @param pnt The Cartesian point to convert
		Point3Spherical(const Point3Cartesian& pnt) {
			_r = sqrt(POW2(pnt.X()) + POW2(pnt.Y()) + POW2(pnt.Z()));
			_theta = atan2(sqrt(POW2(pnt.X()) + POW2(pnt.Y())), pnt.Z());
			_phi = atan2(pnt.Y(), pnt.X());
		}

		/// @brief Exact equality comparison
		bool operator==(const Point3Spherical& b) const { return (R() == b.R()) && (Theta() == b.Theta()) && (Phi() == b.Phi()); }
		/// @brief Exact inequality comparison
		bool operator!=(const Point3Spherical& b) const { return (R() != b.R()) || (Theta() != b.Theta()) || (Phi() != b.Phi()); }
		/// @brief Approximate equality comparison with tolerance
		/// @param b The other point
		/// @param eps Tolerance for comparison (default: Defaults::Pnt3SphIsEqualTolerance)
		/// @return True if distance between points is less than eps
		bool IsEqualTo(const Point3Spherical& b, Real eps = Defaults::Pnt3SphIsEqualTolerance) const { return Dist(b) < eps; }

		/// @brief Converts this spherical point to Cartesian coordinates
		/// @return Equivalent Point3Cartesian using spherical-to-Cartesian transformation
		Point3Cartesian TransfToCart() const {
			return Point3Cartesian(R() * sin(Theta()) * cos(Phi()), R() * sin(Theta()) * sin(Phi()), R() * cos(Theta()));
		}

		/// @brief Computes distance to another spherical point
		/// @param b The other point
		/// @return Euclidean distance between the two points (using spherical law of cosines)
		Real Dist(const Point3Spherical& b) const {
			Real cosGamma = cos(Theta()) * cos(b.Theta()) + sin(Theta()) * sin(b.Theta()) * cos(b.Phi() - Phi());
			cosGamma = std::clamp(cosGamma, (Real)-1.0, (Real)1.0);
			return sqrt(R() * R() + b.R() * b.R() - 2 * R() * b.R() * cosGamma);
		}
	};

	/// @brief 3D point in cylindrical coordinates (r, φ, z)
	/// @details Represents a point in 3D space using cylindrical coordinates where:
	///          - r: radial distance from z-axis
	///          - φ (phi): azimuthal angle from positive x-axis in xy-plane (in radians)
	///          - z: height along z-axis
	///          Supports conversion to Cartesian coordinates and distance calculations.
	class Point3Cylindrical {
	private:
		Real _r, _phi, _z;

	public:
		/// @brief Gets the radial coordinate (const version)
		Real R() const { return _r; }
		/// @brief Gets the radial coordinate (mutable reference)
		Real& R() { return _r; }
		/// @brief Gets the azimuthal angle φ in radians (const version)
		Real Phi() const { return _phi; }
		/// @brief Gets the azimuthal angle φ in radians (mutable reference)
		Real& Phi() { return _phi; }
		/// @brief Gets the z-coordinate (const version)
		Real Z() const { return _z; }
		/// @brief Gets the z-coordinate (mutable reference)
		Real& Z() { return _z; }

		/// @brief Default constructor - initializes to origin
		Point3Cylindrical()
			: _r(0)
			, _phi(0)
			, _z(0) {}
		/// @brief Constructs a point from cylindrical coordinates
		/// @param r Radial distance from z-axis
		/// @param phi Azimuthal angle from x-axis (in radians)
		/// @param z Height along z-axis
		Point3Cylindrical(Real r, Real phi, Real z)
			: _r(r)
			, _phi(phi)
			, _z(z) {}
		/// @brief Constructs a cylindrical point from a Cartesian point
		/// @param pnt The Cartesian point to convert
		Point3Cylindrical(const Point3Cartesian& pnt) {
			_r = sqrt(POW2(pnt.X()) + POW2(pnt.Y()));
			_phi = atan2(pnt.Y(), pnt.X());
			_z = pnt.Z();
		}

		/// @brief Exact equality comparison
		bool operator==(const Point3Cylindrical& b) const { return (R() == b.R()) && (Phi() == b.Phi()) && (Z() == b.Z()); }
		/// @brief Exact inequality comparison
		bool operator!=(const Point3Cylindrical& b) const { return (R() != b.R()) || (Phi() != b.Phi()) || (Z() != b.Z()); }
		/// @brief Approximate equality comparison with tolerance
		/// @param b The other point
		/// @param eps Tolerance for comparison (default: Defaults::Pnt3CylIsEqualTolerance)
		/// @return True if distance between points is less than eps
		bool IsEqualTo(const Point3Cylindrical& b, Real eps = Defaults::Pnt3CylIsEqualTolerance) const { return Dist(b) < eps; }

		/// @brief Converts this cylindrical point to Cartesian coordinates
		/// @return Equivalent Point3Cartesian using cylindrical-to-Cartesian transformation
		Point3Cartesian TransfToCart() const { return Point3Cartesian(R() * cos(Phi()), R() * sin(Phi()), Z()); }

		/// @brief Computes distance to another cylindrical point
		/// @param b The other point
		/// @return Euclidean distance between the two points
		Real Dist(const Point3Cylindrical& b) const {
			return sqrt(R() * R() + b.R() * b.R() - 2 * R() * b.R() * cos(b.Phi() - Phi()) + POW2(b.Z() - Z()));
		}
	};

	//=============================================================================
	// TYPE ALIASES FOR POINTS
	//=============================================================================

	/// @brief Alias for Point2Cartesian
	typedef Point2Cartesian Pnt2Cart;
	/// @brief Alias for Point2Polar
	typedef Point2Polar Pnt2Pol;
	/// @brief Alias for Point3Cartesian
	typedef Point3Cartesian Pnt3Cart;
	/// @brief Alias for Point3Spherical
	typedef Point3Spherical Pnt3Sph;
	/// @brief Alias for Point3Cylindrical
	typedef Point3Cylindrical Pnt3Cyl;

} // namespace MML

