namespace MML {

	//=============================================================================
	// PURE 2D GEOMETRIC SHAPES - Coordinate-free intrinsic geometry
	//=============================================================================

	/// @brief Triangle defined by three side lengths (coordinate-free)
	/// Represents a triangle purely by its side lengths a, b, c.
	/// All properties are intrinsic - independent of position or orientation.

	class Triangle {
	private:
		Real _a, _b, _c;

	public:
		// Accessors
		Real A() const { return _a; }
		Real& A() { return _a; }
		Real B() const { return _b; }
		Real& B() { return _b; }
		Real C() const { return _c; }
		Real& C() { return _c; }

		// Constructors
		Triangle()
			: _a(0.0)
			, _b(0.0)
			, _c(0.0) {}
		Triangle(Real a, Real b, Real c)
			: _a(a)
			, _b(b)
			, _c(c) {}

		// Validity
		bool IsValid() const { return _a > 0 && _b > 0 && _c > 0 && _a + _b > _c && _a + _c > _b && _b + _c > _a; }

		// Basic properties
		Real Perimeter() const { return _a + _b + _c; }
		Real Semiperimeter() const { return (_a + _b + _c) / 2.0; }

		Real Area() const {
			Real s = Semiperimeter();
			return sqrt(s * (s - _a) * (s - _b) * (s - _c)); // Heron's formula
		}

		// Angles (in radians) - using law of cosines
		Real AngleA() const { return acos(std::clamp((_b * _b + _c * _c - _a * _a) / (2 * _b * _c), (Real)-1.0, (Real)1.0)); } // opposite to side a
		Real AngleB() const { return acos(std::clamp((_a * _a + _c * _c - _b * _b) / (2 * _a * _c), (Real)-1.0, (Real)1.0)); } // opposite to side b
		Real AngleC() const { return acos(std::clamp((_a * _a + _b * _b - _c * _c) / (2 * _a * _b), (Real)-1.0, (Real)1.0)); } // opposite to side c

		// Altitudes (heights)
		Real AltitudeToA() const { return 2.0 * Area() / _a; }
		Real AltitudeToB() const { return 2.0 * Area() / _b; }
		Real AltitudeToC() const { return 2.0 * Area() / _c; }

		// Medians
		Real MedianToA() const { return 0.5 * sqrt(2 * _b * _b + 2 * _c * _c - _a * _a); }
		Real MedianToB() const { return 0.5 * sqrt(2 * _a * _a + 2 * _c * _c - _b * _b); }
		Real MedianToC() const { return 0.5 * sqrt(2 * _a * _a + 2 * _b * _b - _c * _c); }

		// Inscribed and circumscribed circles
		Real Inradius() const { return Area() / Semiperimeter(); }
		Real Circumradius() const { return (_a * _b * _c) / (4.0 * Area()); }

		// Classification
		bool IsRight(Real eps = Defaults::ShapePropertyTolerance) const {
			Real a2 = _a * _a, b2 = _b * _b, c2 = _c * _c;
			return std::abs(a2 + b2 - c2) < eps || std::abs(a2 + c2 - b2) < eps || std::abs(b2 + c2 - a2) < eps;
		}
		bool IsIsosceles(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) < eps || std::abs(_a - _c) < eps || std::abs(_b - _c) < eps; }
		bool IsEquilateral(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) < eps && std::abs(_a - _c) < eps; }
		bool IsAcute() const {
			Real a2 = _a * _a, b2 = _b * _b, c2 = _c * _c;
			return (a2 + b2 > c2) && (a2 + c2 > b2) && (b2 + c2 > a2);
		}
		bool IsObtuse() const {
			Real a2 = _a * _a, b2 = _b * _b, c2 = _c * _c;
			return (a2 + b2 < c2) || (a2 + c2 < b2) || (b2 + c2 < a2);
		}
		bool IsScalene(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) > eps && std::abs(_a - _c) > eps && std::abs(_b - _c) > eps; }
	};

	/// @brief Circle defined by radius (coordinate-free)

	class Circle {
	private:
		Real _radius;

	public:
		Real Radius() const { return _radius; }
		Real& Radius() { return _radius; }
		Real Diameter() const { return 2.0 * _radius; }

		Circle()
			: _radius(0.0) {}
		explicit Circle(Real radius)
			: _radius(radius) {}

		bool IsValid() const { return _radius > 0; }

		Real Area() const { return Constants::PI * _radius * _radius; }
		Real Circumference() const { return 2.0 * Constants::PI * _radius; }
		Real Perimeter() const { return Circumference(); }

		// Arc and sector for given central angle (radians)
		Real ArcLength(Real angle) const { return _radius * angle; }
		Real SectorArea(Real angle) const { return 0.5 * _radius * _radius * angle; }

		// Chord length for given central angle
		Real ChordLength(Real angle) const { return 2.0 * _radius * sin(angle / 2.0); }

		// Segment area (region between chord and arc)
		Real SegmentArea(Real angle) const { return 0.5 * _radius * _radius * (angle - sin(angle)); }

		// Relationships
		static Circle FromArea(Real area) { return Circle(sqrt(area / Constants::PI)); }
		static Circle FromCircumference(Real circ) { return Circle(circ / (2.0 * Constants::PI)); }
		static Circle Inscribed(const Triangle& t) { return Circle(t.Inradius()); }
		static Circle Circumscribed(const Triangle& t) { return Circle(t.Circumradius()); }
	};

	/// @brief Ellipse defined by semi-major and semi-minor axes (coordinate-free)

	class Ellipse {
	private:
		Real _a; // semi-major axis
		Real _b; // semi-minor axis

	public:
		Real SemiMajor() const { return _a; }
		Real& SemiMajor() { return _a; }
		Real SemiMinor() const { return _b; }
		Real& SemiMinor() { return _b; }
		Real MajorAxis() const { return 2.0 * _a; }
		Real MinorAxis() const { return 2.0 * _b; }

		Ellipse()
			: _a(0.0)
			, _b(0.0) {}
		Ellipse(Real semiMajor, Real semiMinor)
			: _a(semiMajor)
			, _b(semiMinor) {}

		bool IsValid() const { return _a > 0 && _b > 0; }
		bool IsCircle(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) < eps; }

		Real Area() const { return Constants::PI * _a * _b; }

		// Circumference approximation (Ramanujan's formula)
		Real Circumference() const {
			Real h = POW2(_a - _b) / POW2(_a + _b);
			return Constants::PI * (_a + _b) * (1.0 + 3.0 * h / (10.0 + sqrt(4.0 - 3.0 * h)));
		}
		Real Perimeter() const { return Circumference(); }

		// Eccentricity e = sqrt(1 - b²/a²), ranges from 0 (circle) to 1 (parabola limit)
		Real Eccentricity() const {
			if (_a == 0)
				return 0;
			return sqrt(1.0 - (_b * _b) / (_a * _a));
		}

		// Linear eccentricity (distance from center to focus)
		Real LinearEccentricity() const { return sqrt(_a * _a - _b * _b); }

		// Focal distance (distance between foci)
		Real FocalDistance() const { return 2.0 * LinearEccentricity(); }

		// Semi-latus rectum (half the chord through focus perpendicular to major axis)
		Real SemiLatusRectum() const { return (_b * _b) / _a; }

		// Directrix distance from center
		Real DirectrixDistance() const { return _a / Eccentricity(); }

		static Ellipse FromFoci(Real focalDist, Real majorAxis) {
			Real a = majorAxis / 2.0;
			Real c = focalDist / 2.0;
			Real b = sqrt(a * a - c * c);
			return Ellipse(a, b);
		}
	};

	/// @brief Circular sector (pie slice) defined by radius and central angle
	/// @details A circular sector is the portion of a disk enclosed by two radii
	/// and an arc. Sometimes called a "pie slice" or "wedge".

	class CircularSector {
	private:
		Real _radius;
		Real _angle; // central angle in radians

	public:
		/// @brief Gets the radius (const version)
		Real Radius() const { return _radius; }
		/// @brief Gets the radius (mutable reference)
		Real& Radius() { return _radius; }
		/// @brief Gets the central angle in radians (const version)
		Real Angle() const { return _angle; }
		/// @brief Gets the central angle in radians (mutable reference)
		Real& Angle() { return _angle; }
		/// @brief Gets the central angle in degrees
		Real AngleDegrees() const { return _angle * 180.0 / Constants::PI; }

		/// @brief Default constructor - creates invalid sector
		CircularSector()
			: _radius(0.0)
			, _angle(0.0) {}
		/// @brief Constructs a sector from radius and central angle
		/// @param radius The radius of the sector
		/// @param angle The central angle in radians
		CircularSector(Real radius, Real angle)
			: _radius(radius)
			, _angle(angle) {}

		/// @brief Checks if the sector parameters are valid
		/// @return True if radius > 0 and 0 < angle ≤ 2π
		bool IsValid() const { return _radius > 0 && _angle > 0 && _angle <= 2.0 * Constants::PI; }

		/// @brief Calculates the area of the sector
		/// @return Area = ½r²θ
		Real Area() const { return 0.5 * _radius * _radius * _angle; }
		/// @brief Calculates the arc length
		/// @return Arc length = rθ
		Real ArcLength() const { return _radius * _angle; }
		/// @brief Calculates the perimeter (two radii plus arc)
		/// @return Perimeter = 2r + arc length
		Real Perimeter() const { return 2.0 * _radius + ArcLength(); }
		/// @brief Calculates the chord length (straight line between arc endpoints)
		/// @return Chord length = 2r·sin(θ/2)
		Real ChordLength() const { return 2.0 * _radius * sin(_angle / 2.0); }
	};

	/// @brief Circular segment (region between chord and arc)

	class CircularSegment {
	private:
		Real _radius;
		Real _angle; // central angle in radians

	public:
		Real Radius() const { return _radius; }
		Real& Radius() { return _radius; }
		Real Angle() const { return _angle; }
		Real& Angle() { return _angle; }

		CircularSegment()
			: _radius(0.0)
			, _angle(0.0) {}
		CircularSegment(Real radius, Real angle)
			: _radius(radius)
			, _angle(angle) {}

		// Construct from radius and chord height (sagitta)
		static CircularSegment FromSagitta(Real radius, Real sagitta) {
			Real angle = 2.0 * acos(1.0 - sagitta / radius);
			return CircularSegment(radius, angle);
		}

		bool IsValid() const { return _radius > 0 && _angle > 0 && _angle <= 2.0 * Constants::PI; }

		Real Area() const { return 0.5 * _radius * _radius * (_angle - sin(_angle)); }
		Real ArcLength() const { return _radius * _angle; }
		Real ChordLength() const { return 2.0 * _radius * sin(_angle / 2.0); }
		Real Sagitta() const { return _radius * (1.0 - cos(_angle / 2.0)); } // height of segment
		Real Perimeter() const { return ArcLength() + ChordLength(); }
	};

	/// @brief Annulus (ring) defined by inner and outer radii

	class Annulus {
	private:
		Real _innerRadius;
		Real _outerRadius;

	public:
		Real InnerRadius() const { return _innerRadius; }
		Real& InnerRadius() { return _innerRadius; }
		Real OuterRadius() const { return _outerRadius; }
		Real& OuterRadius() { return _outerRadius; }
		Real Width() const { return _outerRadius - _innerRadius; }

		Annulus()
			: _innerRadius(0.0)
			, _outerRadius(0.0) {}
		Annulus(Real inner, Real outer)
			: _innerRadius(inner)
			, _outerRadius(outer) {}

		bool IsValid() const { return _innerRadius >= 0 && _outerRadius > _innerRadius; }

		Real Area() const { return Constants::PI * (_outerRadius * _outerRadius - _innerRadius * _innerRadius); }

		Real InnerCircumference() const { return 2.0 * Constants::PI * _innerRadius; }
		Real OuterCircumference() const { return 2.0 * Constants::PI * _outerRadius; }
		Real MeanCircumference() const { return Constants::PI * (_innerRadius + _outerRadius); }

		Circle InnerCircle() const { return Circle(_innerRadius); }
		Circle OuterCircle() const { return Circle(_outerRadius); }
	};

	/// @brief Regular polygon defined by number of sides and side length

	class RegularPolygon {
	private:
		int _n; // number of sides
		Real _sideLength;

	public:
		int NumSides() const { return _n; }
		int& NumSides() { return _n; }
		Real SideLength() const { return _sideLength; }
		Real& SideLength() { return _sideLength; }

		RegularPolygon()
			: _n(3)
			, _sideLength(0.0) {}
		RegularPolygon(int n, Real sideLength)
			: _n(n)
			, _sideLength(sideLength) {}

		bool IsValid() const { return _n >= 3 && _sideLength > 0; }

		Real InteriorAngle() const { return (_n - 2) * Constants::PI / _n; }
		Real ExteriorAngle() const { return 2.0 * Constants::PI / _n; }
		Real CentralAngle() const { return 2.0 * Constants::PI / _n; }

		Real Perimeter() const { return _n * _sideLength; }

		Real Area() const { return 0.25 * _n * _sideLength * _sideLength / tan(Constants::PI / _n); }

		// Apothem (distance from center to midpoint of side)
		Real Apothem() const { return _sideLength / (2.0 * tan(Constants::PI / _n)); }

		// Circumradius (distance from center to vertex)
		Real Circumradius() const { return _sideLength / (2.0 * sin(Constants::PI / _n)); }

		// Inradius = apothem
		Real Inradius() const { return Apothem(); }

		Circle InscribedCircle() const { return Circle(Inradius()); }
		Circle CircumscribedCircle() const { return Circle(Circumradius()); }

		// Factory methods
		static RegularPolygon FromCircumradius(int n, Real R) {
			Real side = 2.0 * R * sin(Constants::PI / n);
			return RegularPolygon(n, side);
		}

		static RegularPolygon FromInradius(int n, Real r) {
			Real side = 2.0 * r * tan(Constants::PI / n);
			return RegularPolygon(n, side);
		}

		static RegularPolygon FromArea(int n, Real area) {
			Real side = sqrt(4.0 * area * tan(Constants::PI / n) / n);
			return RegularPolygon(n, side);
		}

		// Named polygons
		static RegularPolygon EquilateralTriangle(Real side) { return RegularPolygon(3, side); }
		static RegularPolygon Square(Real side) { return RegularPolygon(4, side); }
		static RegularPolygon Pentagon(Real side) { return RegularPolygon(5, side); }
		static RegularPolygon Hexagon(Real side) { return RegularPolygon(6, side); }
		static RegularPolygon Heptagon(Real side) { return RegularPolygon(7, side); }
		static RegularPolygon Octagon(Real side) { return RegularPolygon(8, side); }
		static RegularPolygon Nonagon(Real side) { return RegularPolygon(9, side); }
		static RegularPolygon Decagon(Real side) { return RegularPolygon(10, side); }
		static RegularPolygon Dodecagon(Real side) { return RegularPolygon(12, side); }
	};

	/// @brief Rectangle defined by width and height (coordinate-free)

	class Rectangle {
	private:
		Real _width;
		Real _height;

	public:
		Real Width() const { return _width; }
		Real& Width() { return _width; }
		Real Height() const { return _height; }
		Real& Height() { return _height; }

		Rectangle()
			: _width(0.0)
			, _height(0.0) {}
		Rectangle(Real width, Real height)
			: _width(width)
			, _height(height) {}

		bool IsValid() const { return _width > 0 && _height > 0; }
		bool IsSquare(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_width - _height) < eps; }

		Real Area() const { return _width * _height; }
		Real Perimeter() const { return 2.0 * (_width + _height); }
		Real Diagonal() const { return sqrt(_width * _width + _height * _height); }

		// Aspect ratio (width/height)
		Real AspectRatio() const { return _width / _height; }

		// Inscribed/circumscribed circles
		Real InscribedCircleRadius() const { return std::min(_width, _height) / 2.0; }
		Real CircumscribedCircleRadius() const { return Diagonal() / 2.0; }

		static Rectangle Square(Real side) { return Rectangle(side, side); }
		static Rectangle GoldenRectangle(Real width) { return Rectangle(width, width / Constants::GoldenRatio); }
		static Rectangle FromDiagonalAndRatio(Real diagonal, Real ratio) {
			Real h = diagonal / sqrt(1.0 + ratio * ratio);
			Real w = h * ratio;
			return Rectangle(w, h);
		}
	};

	/// @brief Parallelogram defined by two sides and included angle

	class Parallelogram {
	private:
		Real _a;	 // one pair of parallel sides
		Real _b;	 // other pair of parallel sides
		Real _angle; // included angle in radians

	public:
		Real SideA() const { return _a; }
		Real& SideA() { return _a; }
		Real SideB() const { return _b; }
		Real& SideB() { return _b; }
		Real Angle() const { return _angle; }
		Real& Angle() { return _angle; }
		Real AngleDegrees() const { return _angle * 180.0 / Constants::PI; }

		Parallelogram()
			: _a(0.0)
			, _b(0.0)
			, _angle(0.0) {}
		Parallelogram(Real a, Real b, Real angle)
			: _a(a)
			, _b(b)
			, _angle(angle) {}

		bool IsValid() const { return _a > 0 && _b > 0 && _angle > 0 && _angle < Constants::PI; }
		bool IsRectangle(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_angle - Constants::PI / 2) < eps; }
		bool IsRhombus(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) < eps; }
		bool IsSquare(Real eps = Defaults::ShapePropertyTolerance) const { return IsRectangle(eps) && IsRhombus(eps); }

		Real Area() const { return _a * _b * sin(_angle); }
		Real Perimeter() const { return 2.0 * (_a + _b); }

		// Heights
		Real HeightToA() const { return _b * sin(_angle); }
		Real HeightToB() const { return _a * sin(_angle); }

		// Diagonals (using law of cosines)
		Real DiagonalP() const { return sqrt(_a * _a + _b * _b - 2 * _a * _b * cos(_angle)); }
		Real DiagonalQ() const { return sqrt(_a * _a + _b * _b + 2 * _a * _b * cos(_angle)); }

		// The two angles
		Real AcuteAngle() const { return std::min<Real>(_angle, Constants::PI - _angle); }
		Real ObtuseAngle() const { return std::max<Real>(_angle, Constants::PI - _angle); }

		static Parallelogram FromDiagonals(Real p, Real q, Real angleBetween) {
			// Diagonals bisect each other; use parallelogram law
			Real a = 0.5 * sqrt(p * p + q * q + 2 * p * q * cos(angleBetween));
			Real b = 0.5 * sqrt(p * p + q * q - 2 * p * q * cos(angleBetween));
			Real angle = acos((a * a + b * b - 0.25 * p * p) / (2 * a * b));
			return Parallelogram(a, b, angle);
		}
	};

	/// @brief Rhombus defined by side length and one diagonal (or both diagonals)

	class Rhombus {
	private:
		Real _side;
		Real _d1; // first diagonal
		Real _d2; // second diagonal

	public:
		Real Side() const { return _side; }
		Real& Side() { return _side; }
		Real Diagonal1() const { return _d1; }
		Real& Diagonal1() { return _d1; }
		Real Diagonal2() const { return _d2; }
		Real& Diagonal2() { return _d2; }

		Rhombus()
			: _side(0.0)
			, _d1(0.0)
			, _d2(0.0) {}

		// From diagonals (diagonals of rhombus are perpendicular bisectors)
		Rhombus(Real d1, Real d2)
			: _d1(d1)
			, _d2(d2) {
			_side = sqrt(d1 * d1 + d2 * d2) / 2.0;
		}

		static Rhombus FromSideAndDiagonal(Real side, Real diagonal) {
			Real halfD1 = diagonal / 2.0;
			Real halfD2 = sqrt(side * side - halfD1 * halfD1);
			return Rhombus(diagonal, 2.0 * halfD2);
		}

		static Rhombus FromSideAndAngle(Real side, Real angle) {
			Real d1 = 2.0 * side * sin(angle / 2.0);
			Real d2 = 2.0 * side * cos(angle / 2.0);
			return Rhombus(d1, d2);
		}

		bool IsValid() const { return _side > 0 && _d1 > 0 && _d2 > 0; }
		bool IsSquare(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_d1 - _d2) < eps; }

		Real Area() const { return 0.5 * _d1 * _d2; }
		Real Perimeter() const { return 4.0 * _side; }

		// Angles (acute and obtuse)
		Real AcuteAngle() const { return 2.0 * atan(std::min(_d1, _d2) / std::max(_d1, _d2)); }
		Real ObtuseAngle() const { return Constants::PI - AcuteAngle(); }

		// Height (perpendicular distance between parallel sides)
		Real Height() const { return Area() / _side; }

		// Inscribed circle (rhombus has incircle tangent to all sides)
		Real Inradius() const { return (_d1 * _d2) / (2.0 * sqrt(_d1 * _d1 + _d2 * _d2)); }
		Circle InscribedCircle() const { return Circle(Inradius()); }
	};

	/// @brief Trapezoid defined by parallel sides and height

	class Trapezoid {
	private:
		Real _a;	  // one parallel side
		Real _b;	  // other parallel side
		Real _height; // perpendicular distance between parallel sides

	public:
		Real ParallelSideA() const { return _a; }
		Real& ParallelSideA() { return _a; }
		Real ParallelSideB() const { return _b; }
		Real& ParallelSideB() { return _b; }
		Real Height() const { return _height; }
		Real& Height() { return _height; }

		Trapezoid()
			: _a(0.0)
			, _b(0.0)
			, _height(0.0) {}
		Trapezoid(Real a, Real b, Real height)
			: _a(a)
			, _b(b)
			, _height(height) {}

		bool IsValid() const { return _a > 0 && _b > 0 && _height > 0; }
		bool IsParallelogram(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_a - _b) < eps; }

		Real Area() const { return 0.5 * (_a + _b) * _height; }

		// Median (midsegment) - line connecting midpoints of non-parallel sides
		Real Median() const { return 0.5 * (_a + _b); }

		// For isosceles trapezoid with known leg length
		static Trapezoid Isosceles(Real base, Real top, Real leg) {
			Real height = sqrt(leg * leg - 0.25 * POW2(base - top));
			return Trapezoid(base, top, height);
		}
	};

} // namespace MML

///////////////////////////   mml/base/Geometry/GeometryCore/Geometry3DShapes.h   ///////////////////////////




namespace MML {

	//=============================================================================
	// 3D PURE GEOMETRIC SHAPES - Coordinate-free intrinsic geometry
	//=============================================================================

	/// @brief Sphere defined by radius (coordinate-free pure geometry)
	/// Note: Named SphereGeom to avoid conflict with Surfaces::Sphere parametric surface.

	class SphereGeom {
	private:
		Real _radius;

	public:
		Real Radius() const { return _radius; }
		Real& Radius() { return _radius; }
		Real Diameter() const { return 2.0 * _radius; }

		SphereGeom()
			: _radius(0.0) {}
		explicit SphereGeom(Real radius)
			: _radius(radius) {}

		bool IsValid() const { return _radius > 0; }

		Real Volume() const { return (4.0 / 3.0) * Constants::PI * _radius * _radius * _radius; }
		Real SurfaceArea() const { return 4.0 * Constants::PI * _radius * _radius; }

		// Great circle (equator)
		Circle GreatCircle() const { return Circle(_radius); }

		// Spherical cap for given height h
		Real CapArea(Real h) const { return 2.0 * Constants::PI * _radius * h; }
		Real CapVolume(Real h) const { return Constants::PI * h * h * (3.0 * _radius - h) / 3.0; }

		// Spherical zone (between two parallel planes)
		Real ZoneArea(Real h) const { return 2.0 * Constants::PI * _radius * h; }

		static SphereGeom FromVolume(Real vol) { return SphereGeom(cbrt(3.0 * vol / (4.0 * Constants::PI))); }
		static SphereGeom FromSurfaceArea(Real area) { return SphereGeom(sqrt(area / (4.0 * Constants::PI))); }
		static SphereGeom Circumscribed(const Rectangle& rect, Real depth) {
			Real d = sqrt(rect.Width() * rect.Width() + rect.Height() * rect.Height() + depth * depth);
			return SphereGeom(d / 2.0);
		}
	};

	/// @brief CylinderSurface defined by radius and height (coordinate-free pure geometry)
	/// Note: Named CylinderGeom to avoid conflict with Surfaces::CylinderSurface parametric surface.

	class CylinderGeom {
	private:
		Real _radius;
		Real _height;

	public:
		Real Radius() const { return _radius; }
		Real& Radius() { return _radius; }
		Real Height() const { return _height; }
		Real& Height() { return _height; }
		Real Diameter() const { return 2.0 * _radius; }

		CylinderGeom()
			: _radius(0.0)
			, _height(0.0) {}
		CylinderGeom(Real radius, Real height)
			: _radius(radius)
			, _height(height) {}

		bool IsValid() const { return _radius > 0 && _height > 0; }

		Real Volume() const { return Constants::PI * _radius * _radius * _height; }

		Real LateralArea() const { return 2.0 * Constants::PI * _radius * _height; }
		Real BaseArea() const { return Constants::PI * _radius * _radius; }
		Real SurfaceArea() const { return LateralArea() + 2.0 * BaseArea(); }

		Circle Base() const { return Circle(_radius); }

		static CylinderGeom FromVolume(Real volume, Real radius) {
			Real h = volume / (Constants::PI * radius * radius);
			return CylinderGeom(radius, h);
		}
	};

	/// @brief Cone defined by base radius and height (coordinate-free pure geometry)
	/// Note: Named ConeGeom to avoid conflict with Surfaces::Cone parametric surface.

	class ConeGeom {
	private:
		Real _radius;
		Real _height;

	public:
		Real Radius() const { return _radius; }
		Real& Radius() { return _radius; }
		Real Height() const { return _height; }
		Real& Height() { return _height; }

		ConeGeom()
			: _radius(0.0)
			, _height(0.0) {}
		ConeGeom(Real radius, Real height)
			: _radius(radius)
			, _height(height) {}

		bool IsValid() const { return _radius > 0 && _height > 0; }

		Real SlantHeight() const { return sqrt(_radius * _radius + _height * _height); }
		Real Volume() const { return Constants::PI * _radius * _radius * _height / 3.0; }

		Real LateralArea() const { return Constants::PI * _radius * SlantHeight(); }
		Real BaseArea() const { return Constants::PI * _radius * _radius; }
		Real SurfaceArea() const { return LateralArea() + BaseArea(); }

		// Half-angle at apex
		Real ApexAngle() const { return atan(_radius / _height); }

		Circle Base() const { return Circle(_radius); }

		static ConeGeom FromSlantHeight(Real radius, Real slant) {
			Real h = sqrt(slant * slant - radius * radius);
			return ConeGeom(radius, h);
		}
	};

	/// @brief Frustum (truncated cone) defined by two radii and height

	class Frustum {
	private:
		Real _r1; // bottom radius
		Real _r2; // top radius
		Real _height;

	public:
		Real BottomRadius() const { return _r1; }
		Real& BottomRadius() { return _r1; }
		Real TopRadius() const { return _r2; }
		Real& TopRadius() { return _r2; }
		Real Height() const { return _height; }
		Real& Height() { return _height; }

		Frustum()
			: _r1(0.0)
			, _r2(0.0)
			, _height(0.0) {}
		Frustum(Real r1, Real r2, Real height)
			: _r1(r1)
			, _r2(r2)
			, _height(height) {}

		bool IsValid() const { return _r1 > 0 && _r2 > 0 && _height > 0; }

		Real SlantHeight() const {
			Real dr = _r1 - _r2;
			return sqrt(dr * dr + _height * _height);
		}

		Real Volume() const { return Constants::PI * _height * (_r1 * _r1 + _r1 * _r2 + _r2 * _r2) / 3.0; }

		Real LateralArea() const { return Constants::PI * (_r1 + _r2) * SlantHeight(); }

		Real SurfaceArea() const { return LateralArea() + Constants::PI * (_r1 * _r1 + _r2 * _r2); }

		Circle BottomBase() const { return Circle(_r1); }
		Circle TopBase() const { return Circle(_r2); }
	};

	/// @brief Tetrahedron defined by six edge lengths (coordinate-free)
	/// Vertices: A, B, C, D
	/// Edges: AB=a, AC=b, AD=c, BC=d, BD=e, CD=f

	class Tetrahedron {
	private:
		Real _ab, _ac, _ad; // edges from vertex A
		Real _bc, _bd, _cd; // edges opposite to edges from A

	public:
		Real AB() const { return _ab; }
		Real& AB() { return _ab; }
		Real AC() const { return _ac; }
		Real& AC() { return _ac; }
		Real AD() const { return _ad; }
		Real& AD() { return _ad; }
		Real BC() const { return _bc; }
		Real& BC() { return _bc; }
		Real BD() const { return _bd; }
		Real& BD() { return _bd; }
		Real CD() const { return _cd; }
		Real& CD() { return _cd; }

		Tetrahedron()
			: _ab(0)
			, _ac(0)
			, _ad(0)
			, _bc(0)
			, _bd(0)
			, _cd(0) {}
		Tetrahedron(Real ab, Real ac, Real ad, Real bc, Real bd, Real cd)
			: _ab(ab)
			, _ac(ac)
			, _ad(ad)
			, _bc(bc)
			, _bd(bd)
			, _cd(cd) {}

		// Regular tetrahedron (all edges equal)
		static Tetrahedron Regular(Real edge) { return Tetrahedron(edge, edge, edge, edge, edge, edge); }

		bool IsRegular(Real eps = Defaults::ShapePropertyTolerance) const {
			return std::abs(_ab - _ac) < eps && std::abs(_ab - _ad) < eps && std::abs(_ab - _bc) < eps && std::abs(_ab - _bd) < eps &&
				   std::abs(_ab - _cd) < eps;
		}

		// Volume using Cayley-Menger determinant
		Real Volume() const {
			Real a2 = _ab * _ab, b2 = _ac * _ac, c2 = _ad * _ad;
			Real d2 = _bc * _bc, e2 = _bd * _bd, f2 = _cd * _cd;

			// Cayley-Menger determinant / 288
			Real term1 = a2 * f2 * (b2 + c2 + d2 + e2 - a2 - f2);
			Real term2 = b2 * e2 * (a2 + c2 + d2 + f2 - b2 - e2);
			Real term3 = c2 * d2 * (a2 + b2 + e2 + f2 - c2 - d2);
			Real term4 = -a2 * b2 * f2 - a2 * c2 * e2 - b2 * c2 * d2;
			Real term5 = -d2 * e2 * f2;

			Real det = term1 + term2 + term3 + term4 + term5;
			return sqrt(std::abs(det)) / 12.0;
		}

		// Surface area (sum of four triangular faces)
		Real SurfaceArea() const {
			Triangle abc(_ab, _ac, _bc); // face ABC
			Triangle abd(_ab, _ad, _bd); // face ABD
			Triangle acd(_ac, _ad, _cd); // face ACD
			Triangle bcd(_bc, _bd, _cd); // face BCD
			return abc.Area() + abd.Area() + acd.Area() + bcd.Area();
		}

		// The four faces as triangles
		Triangle FaceABC() const { return Triangle(_ab, _ac, _bc); }
		Triangle FaceABD() const { return Triangle(_ab, _ad, _bd); }
		Triangle FaceACD() const { return Triangle(_ac, _ad, _cd); }
		Triangle FaceBCD() const { return Triangle(_bc, _bd, _cd); }

		// For regular tetrahedron
		Real Inradius() const { return 3.0 * Volume() / SurfaceArea(); }

		Real Circumradius() const {
			if (!IsRegular())
				return 0; // Only valid for regular
			return _ab * sqrt(6.0) / 4.0;
		}
	};

	/// @brief Spheroid (ellipsoid of revolution) - oblate or prolate

	class Spheroid {
	private:
		Real _equatorial; // equatorial radius (a)
		Real _polar;	  // polar radius (c)

	public:
		Real EquatorialRadius() const { return _equatorial; }
		Real& EquatorialRadius() { return _equatorial; }
		Real PolarRadius() const { return _polar; }
		Real& PolarRadius() { return _polar; }

		Spheroid()
			: _equatorial(0.0)
			, _polar(0.0) {}
		Spheroid(Real equatorial, Real polar)
			: _equatorial(equatorial)
			, _polar(polar) {}

		bool IsValid() const { return _equatorial > 0 && _polar > 0; }
		bool IsSphere(Real eps = Defaults::ShapePropertyTolerance) const { return std::abs(_equatorial - _polar) < eps; }
		bool IsOblate() const { return _equatorial > _polar; }	// flattened at poles (like Earth)
		bool IsProlate() const { return _polar > _equatorial; } // elongated at poles

		Real Volume() const { return (4.0 / 3.0) * Constants::PI * _equatorial * _equatorial * _polar; }

		// Flattening f = (a - c) / a
		Real Flattening() const { return (_equatorial - _polar) / _equatorial; }

		// Eccentricity
		Real Eccentricity() const {
			if (IsOblate())
				return sqrt(1.0 - (_polar * _polar) / (_equatorial * _equatorial));
			else
				return sqrt(1.0 - (_equatorial * _equatorial) / (_polar * _polar));
		}

		// Surface area (exact formula involves elliptic integrals, using approximation)
		Real SurfaceArea() const {
			if (IsSphere())
				return 4.0 * Constants::PI * _equatorial * _equatorial;

			Real a = _equatorial, c = _polar;
			if (IsOblate()) {
				Real e = Eccentricity();
				return 2.0 * Constants::PI * a * a * (1.0 + (1.0 - e * e) / e * atanh(e));
			} else // Prolate
			{
				Real e = Eccentricity();
				return 2.0 * Constants::PI * a * a * (1.0 + c / (a * e) * asin(e));
			}
		}

		static Spheroid Earth() {
			// WGS84 ellipsoid
			return Spheroid(6378137.0, 6356752.3142);
		}
	};

	/// @brief Torus defined by major and minor radii (coordinate-free pure geometry)
	/// Note: Named TorusGeom to avoid conflict with Surfaces::Torus parametric surface.

	class TorusGeom {
	private:
		Real _R; // major radius (center of tube to center of torus)
		Real _r; // minor radius (radius of tube)

	public:
		Real MajorRadius() const { return _R; }
		Real& MajorRadius() { return _R; }
		Real MinorRadius() const { return _r; }
		Real& MinorRadius() { return _r; }

		TorusGeom()
			: _R(0.0)
			, _r(0.0) {}
		TorusGeom(Real major, Real minor)
			: _R(major)
			, _r(minor) {}

		bool IsValid() const { return _R > 0 && _r > 0; }
		bool IsRingTorus() const { return _R > _r; }	// donut shape, hole in middle
		bool IsHornTorus() const { return _R == _r; }	// tangent to axis
		bool IsSpindleTorus() const { return _R < _r; } // self-intersecting

		Real Volume() const { return 2.0 * Constants::PI * Constants::PI * _R * _r * _r; }
		Real SurfaceArea() const { return 4.0 * Constants::PI * Constants::PI * _R * _r; }

		// Inner and outer radii (for ring torus)
		Real InnerRadius() const { return _R - _r; }
		Real OuterRadius() const { return _R + _r; }

		// Cross-section
		Circle TubeCrossSection() const { return Circle(_r); }
	};

} // namespace MML

///////////////////////////   mml/base/Matrix/Matrix.h   ///////////////////////////



namespace MML
{
	// Forward declarations
	template<class Type> class Matrix;
	template<class Type> class MatrixViewNew;

	///////////////////////////////////////////////////////////////////////////////////////////
	///                               MatrixViewNew - Lightweight view                       ///
	///////////////////////////////////////////////////////////////////////////////////////////
	
	/// @brief Lightweight non-owning view into a Matrix block
	/// @details Provides strided access to a rectangular subregion of a Matrix without copying.
	///          Used for efficient submatrix operations.
	/// @warning This view stores a raw pointer into the parent Matrix's internal storage.
	///          The view becomes invalid (dangling) if the parent Matrix is destroyed,
	///          resized, or otherwise reallocated. Do not store views beyond the
	///          parent's lifetime or across Resize() calls.
	/// @tparam Type Element type
	template<class Type>
	class MatrixViewNew {
		Type* _data;
		int _rows, _cols, _stride;
	public:
		/// @brief Construct view into matrix data
		/// @param data Pointer to first element of the view
		/// @param rows Number of rows in view
		/// @param cols Number of columns in view
		/// @param stride Row stride (number of columns in parent matrix)
		MatrixViewNew(Type* data, int rows, int cols, int stride)
			: _data(data), _rows(rows), _cols(cols), _stride(stride) {}

		/// @brief Element access (row-major with stride)
		Type& operator()(int i, int j) noexcept { return _data[i * _stride + j]; }
		/// @brief Element access (const)
		const Type& operator()(int i, int j) const noexcept { return _data[i * _stride + j]; }

		/// @brief Get number of rows (preferred API)
		int rows() const noexcept { return _rows; }
		/// @brief Get number of columns (preferred API)
		int cols() const noexcept { return _cols; }
	};

	///////////////////////////////////////////////////////////////////////////////////////////
	///                                      Matrix                                          ///
	///////////////////////////////////////////////////////////////////////////////////////////
	
	/// @brief Generic matrix class template for numerical computations
	/// @details Modern implementation using contiguous std::vector storage (row-major).
	///
	///          Key features:
	///          - std::vector for automatic memory management (RAII)
	///          - Exception-safe (no manual new/delete)
	///          - Better cache locality (flat storage vs Type**)
	///          - Move semantics automatic and efficient
	///          - Full arithmetic operations (+, -, *, /)
	///          - Matrix properties (trace, transpose, inverse)
	///          - Row/column extraction and manipulation
	///          - Iterator support for STL algorithms
	///
	/// @threadsafety Thread-safe for const operations. Non-const operations (including Resize)
	///               require external synchronization. See docs/THREADING.md for details.
	///
	/// @tparam Type Element type (typically Real, Complex, or arithmetic types)
	template<class Type>
	class Matrix
	{
	private:
		// Allocation safety limits
		static constexpr int MAX_DIMENSION = 100000;
		static constexpr size_t MAX_ELEMENTS = 100000000;  ///< ~800MB for doubles

		int _rows;
		int _cols;
		std::vector<Type> _data;  // Flat row-major storage

		// Index calculation (row-major)
		inline size_t idx(int i, int j) const { return static_cast<size_t>(i) * _cols + j; }

		// Validate dimensions for allocation
		void ValidateDimensions(int rows, int cols) const
		{
			if (rows < 0 || cols < 0)
				throw MatrixDimensionError("Matrix - dimensions cannot be negative", rows, cols, -1, -1);
			
			if (rows > MAX_DIMENSION || cols > MAX_DIMENSION)
				throw MatrixDimensionError("Matrix - dimensions exceed maximum limit", rows, cols, MAX_DIMENSION, MAX_DIMENSION);
			
			// Integer overflow protection
			size_t numElements = static_cast<size_t>(rows) * static_cast<size_t>(cols);
			if (cols > 0 && numElements / static_cast<size_t>(cols) != static_cast<size_t>(rows))
				throw std::overflow_error("Matrix - size calculation overflow");
			
			if (numElements > MAX_ELEMENTS)
				throw std::bad_alloc();
		}

		bool IsMatrixTypeComplex() const
		{
			return std::is_same_v<Type, std::complex<double>> ||
			       std::is_same_v<Type, std::complex<float>> ||
			       std::is_same_v<Type, std::complex<long double>>;
		}

	public:
		typedef Type value_type;  ///< Element type alias for STL compatibility

		///////////////////////          Constructors and destructor       //////////////////////
		
		/// @brief Default constructor - creates empty matrix
		Matrix() : _rows(0), _cols(0), _data() {}
		
		/// @brief Construct matrix of given dimensions
		/// @param rows Number of rows (must be non-negative)
		/// @param cols Number of columns (must be non-negative)
		/// @throws MatrixDimensionError if dimensions are negative or exceed limits
		/// @details Elements initialized to zero for numeric types
		explicit Matrix(int rows, int cols) : _rows(rows), _cols(cols)
		{
			if (rows < 0 || cols < 0) {
				throw MatrixDimensionError("Matrix: negative dimensions not allowed");
			}
			if (rows == 0 || cols == 0) {
				_rows = 0;
				_cols = 0;
				return;
			}
			ValidateDimensions(rows, cols);
			
			if constexpr (is_MML_simple_numeric<Type>) {
				_data.resize(static_cast<size_t>(rows) * cols, Type{0});
			} else {
				_data.resize(static_cast<size_t>(rows) * cols);
			}
		}
		
		/// @brief Construct matrix with uniform fill value
		/// @param rows Number of rows
		/// @param cols Number of columns
		/// @param val Value to fill all elements with
		/// @throws MatrixDimensionError if dimensions are invalid
		explicit Matrix(int rows, int cols, const Type& val) : _rows(rows), _cols(cols)
		{
			if (rows < 0 || cols < 0) {
				throw MatrixDimensionError("Matrix: negative dimensions not allowed");
			}
			if (rows == 0 || cols == 0) {
				_rows = 0;
				_cols = 0;
				return;
			}
			ValidateDimensions(rows, cols);
			_data.resize(static_cast<size_t>(rows) * cols, val);
		}
		
		/// @brief Construct from nested std::vector (2D array)
		/// @param values 2D vector where values[i][j] is element at row i, column j
		/// @throws MatrixDimensionError if rows have inconsistent sizes
		explicit Matrix(const std::vector<std::vector<Type>>& values)
		{
			if (values.empty() || values[0].empty()) {
				_rows = 0;
				_cols = 0;
				return;
			}
			_rows = static_cast<int>(values.size());
			_cols = static_cast<int>(values[0].size());
			ValidateDimensions(_rows, _cols);
			
			_data.reserve(static_cast<size_t>(_rows) * _cols);
			for (int i = 0; i < _rows; ++i) {
				if (static_cast<int>(values[i].size()) != _cols)
					throw MatrixDimensionError("Matrix - inconsistent row sizes", _rows, _cols, i, static_cast<int>(values[i].size()));
				for (int j = 0; j < _cols; ++j)
					_data.push_back(values[i][j]);
			}
		}
		
		/// @brief Construct from std::array (compile-time sized)
		/// @tparam Rows Number of rows (compile-time)
		/// @tparam Cols Number of columns (compile-time)
		template <std::size_t Rows, std::size_t Cols>
		explicit Matrix(const std::array<std::array<Type, Cols>, Rows>& arr)
			: _rows(static_cast<int>(Rows)), _cols(static_cast<int>(Cols))
		{
			ValidateDimensions(_rows, _cols);
			_data.reserve(static_cast<size_t>(_rows) * _cols);
			for (size_t i = 0; i < Rows; ++i)
				for (size_t j = 0; j < Cols; ++j)
					_data.push_back(arr[i][j]);
		}
		
		/// @brief Construct from raw pointer to contiguous data
		/// @param rows Number of rows
		/// @param cols Number of columns
		/// @param val Pointer to data array
		/// @param isRowWise If true, data is row-major; if false, column-major
		explicit Matrix(int rows, int cols, Type* val, bool isRowWise = true)
			: _rows(rows), _cols(cols)
		{
			if (rows < 0 || cols < 0) {
				throw MatrixDimensionError("Matrix: negative dimensions not allowed");
			}
			if (rows == 0 || cols == 0) {
				_rows = 0;
				_cols = 0;
				return;
			}
			ValidateDimensions(rows, cols);
			_data.resize(static_cast<size_t>(rows) * cols);
			
			if (isRowWise) {
				std::copy(val, val + static_cast<size_t>(rows) * cols, _data.begin());
			} else {
				// Column-wise: need to transpose during copy
				for (int j = 0; j < cols; ++j)
					for (int i = 0; i < rows; ++i)
						_data[idx(i, j)] = *val++;
			}
		}
		
		/// @brief Construct from initializer list (row-major order)
		/// @param rows Number of rows
		/// @param cols Number of columns
		/// @param values Initializer list with rows*cols elements
		/// @param strictMode If true, throws if list size doesn't match dimensions
		/// @throws MatrixDimensionError if strictMode and size mismatch
		explicit Matrix(int rows, int cols, std::initializer_list<Type> values, bool strictMode = true)
			: _rows(rows), _cols(cols)
		{
			if (rows < 0 || cols < 0) {
				throw MatrixDimensionError("Matrix: negative dimensions not allowed");
			}
			if (rows == 0 || cols == 0) {
				_rows = 0;
				_cols = 0;
				return;
			}
			ValidateDimensions(rows, cols);
			
			size_t totalSize = static_cast<size_t>(rows) * cols;
			if (strictMode && values.size() != totalSize)
				throw MatrixDimensionError("Matrix - initializer list size mismatch", rows, cols, -1, -1);
			
			if constexpr (is_MML_simple_numeric<Type>) {
				_data.resize(totalSize, Type{0});
			} else {
				_data.resize(totalSize);
			}
			
			auto it = values.begin();
			for (size_t i = 0; i < totalSize && it != values.end(); ++i, ++it)
				_data[i] = *it;
		}
		
		/// @brief Copy constructor
		Matrix(const Matrix& m) = default;
		
		/// @brief Move constructor
		/// @details Source matrix is left in valid empty state
		Matrix(Matrix&& m) noexcept 
			: _data(std::move(m._data)), _rows(m._rows), _cols(m._cols)
		{
			m._rows = 0;
			m._cols = 0;
		}
		
		/// @brief Submatrix constructor - extract rectangular region
		/// @param m Source matrix
		/// @param ind_row Starting row index
		/// @param ind_col Starting column index
		/// @param row_num Number of rows to extract
		/// @param col_num Number of columns to extract
		/// @throws MatrixDimensionError if region is out of bounds
		Matrix(const Matrix& m, int ind_row, int ind_col, int row_num, int col_num)
		{
			if (ind_row < 0 || ind_row >= m._rows || ind_col < 0 || ind_col >= m._cols)
				throw MatrixDimensionError("Matrix submatrix - invalid start indices", m._rows, m._cols, ind_row, ind_col);
			if (row_num <= 0 || col_num <= 0)
				throw MatrixDimensionError("Matrix submatrix - dimensions must be positive", row_num, col_num, -1, -1);
			if (ind_row + row_num > m._rows || ind_col + col_num > m._cols)
				throw MatrixDimensionError("Matrix submatrix - out of bounds", m._rows, m._cols, ind_row + row_num, ind_col + col_num);
			
			_rows = row_num;
			_cols = col_num;
			_data.reserve(static_cast<size_t>(row_num) * col_num);
			
			for (int i = 0; i < row_num; ++i)
				for (int j = 0; j < col_num; ++j)
					_data.push_back(m(ind_row + i, ind_col + j));
		}
		
		/// @brief Destructor (default - std::vector handles cleanup)
		~Matrix() = default;

		///////////////////////          Assignment operators              //////////////////////
		
		/// @brief Copy assignment
		Matrix& operator=(const Matrix& m) = default;
		
		/// @brief Move assignment
		Matrix& operator=(Matrix&& m) noexcept
		{
			if (this != &m) {
				_data = std::move(m._data);
				_rows = m._rows;
				_cols = m._cols;
				m._rows = 0;
				m._cols = 0;
			}
			return *this;
		}

		///////////////////////              Resize operations             //////////////////////
		
		/// @brief Resize the matrix
		/// @param rows New number of rows
		/// @param cols New number of columns
		/// @param preserveElements If true, existing elements are preserved (up to new dimensions)
		/// @throws MatrixDimensionError if dimensions are invalid
		void Resize(int rows, int cols, bool preserveElements = false)
		{
			if (rows == _rows && cols == _cols)
				return;
			
			if (rows <= 0 || cols <= 0)
				throw MatrixDimensionError("Matrix::Resize - dimensions must be positive", rows, cols, -1, -1);
			
			ValidateDimensions(rows, cols);
			
			if (preserveElements) {
				std::vector<Type> newData(static_cast<size_t>(rows) * cols, Type{0});
				int minRows = std::min(_rows, rows);
				int minCols = std::min(_cols, cols);
				for (int i = 0; i < minRows; ++i)
					for (int j = 0; j < minCols; ++j)
						newData[static_cast<size_t>(i) * cols + j] = _data[idx(i, j)];
				_data = std::move(newData);
			} else {
				if constexpr (is_MML_simple_numeric<Type>) {
					_data.assign(static_cast<size_t>(rows) * cols, Type{0});
				} else {
					_data.resize(static_cast<size_t>(rows) * cols);
				}
			}
			_rows = rows;
			_cols = cols;
		}
		
		/// @brief Convert to identity matrix (in-place)
		/// @throws MatrixDimensionError if matrix is not square
		void MakeUnitMatrix()
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::MakeUnitMatrix - must be square", _rows, _cols, -1, -1);
			
			std::fill(_data.begin(), _data.end(), Type{0});
			for (int i = 0; i < _rows; ++i)
				_data[idx(i, i)] = Type{1};
		}

		///////////////////////          Static factory methods            //////////////////////
		
		/// @brief Create identity matrix
		/// @param dim Matrix dimension (creates dim × dim identity)
		/// @return Identity matrix I where I(i,i) = 1, I(i,j) = 0 for i≠j
		static Matrix Identity(int dim)
		{
			if (dim <= 0)
				throw MatrixDimensionError("Matrix::Identity - dimension must be positive", dim, dim, -1, -1);
			
			Matrix mat(dim, dim);
			mat.MakeUnitMatrix();
			return mat;
		}
		
		/// @brief Create diagonal matrix from vector
		/// @param diagValues Vector of diagonal elements
		/// @return Diagonal matrix D where D(i,i) = diagValues[i]
		static Matrix Diagonal(const Vector<Type>& diagValues)
		{
			int n = diagValues.size();
			if (n <= 0)
				throw MatrixDimensionError("Matrix::Diagonal - vector size must be positive", n, n, -1, -1);
			
			Matrix mat(n, n);
			for (int i = 0; i < n; ++i)
				mat(i, i) = diagValues[i];
			return mat;
		}

		///////////////////////              Standard stuff                //////////////////////
		
		/// @brief Get number of rows (preferred API)
		inline int rows() const noexcept { return _rows; }
		/// @brief Get number of columns (preferred API)
		inline int cols() const noexcept { return _cols; }
		/// @brief Check if matrix is empty (zero dimensions)
		inline bool isEmpty() const noexcept { return _rows == 0 || _cols == 0; }
		
		/// @brief Direct access to underlying data (for algorithms that need it)
		Type* data() noexcept { return _data.data(); }
		/// @brief Direct access to underlying data (const)
		const Type* data() const noexcept { return _data.data(); }

		//////////////////         Accessors         /////////////////
		
		/// @brief Check if matrix is square.
		inline bool isSquare() const noexcept { return _rows == _cols; }
		
		/// @brief Returns string representation of matrix (compact format).
		std::string to_string() const
		{
			std::ostringstream oss;
			oss << "[";
			for (int i = 0; i < _rows; ++i) {
				if (i > 0) oss << "; ";
				oss << "[";
				for (int j = 0; j < _cols; ++j) {
					if (j > 0) oss << ", ";
					oss << (*this)(i, j);
				}
				oss << "]";
			}
			oss << "]";
			return oss.str();
		}

		///////////////////////          Vector extraction                 //////////////////////
		
		/// @brief Extract a row as vector
		/// @param rowInd Row index (0-based)
		/// @return Vector containing row elements
		/// @throws MatrixAccessBoundsError if index out of bounds
		Vector<Type> VectorFromRow(int rowInd) const
		{
			if (rowInd < 0 || rowInd >= _rows)
				throw MatrixAccessBoundsError("VectorFromRow - invalid row index", rowInd, 0, _rows, _cols);
			
			Vector<Type> ret(_cols);
			for (int j = 0; j < _cols; ++j)
				ret[j] = (*this)(rowInd, j);
			return ret;
		}
		
		/// @brief Extract a column as vector
		/// @param colInd Column index (0-based)
		/// @return Vector containing column elements
		/// @throws MatrixAccessBoundsError if index out of bounds
		Vector<Type> VectorFromColumn(int colInd) const
		{
			if (colInd < 0 || colInd >= _cols)
				throw MatrixAccessBoundsError("VectorFromColumn - invalid column index", 0, colInd, _rows, _cols);
			
			Vector<Type> ret(_rows);
			for (int i = 0; i < _rows; ++i)
				ret[i] = (*this)(i, colInd);
			return ret;
		}
		
		/// @brief Extract diagonal as vector (for square matrices)
		/// @return Vector containing diagonal elements
		/// @throws MatrixDimensionError if matrix is not square
		/// @brief Extract diagonal elements as vector (preferred API)
		/// @return Vector containing diagonal elements
		/// @throws MatrixDimensionError if matrix is not square
		Vector<Type> diagonal() const
		{
			if (_rows != _cols)
				throw MatrixDimensionError("diagonal - must be square", _rows, _cols, -1, -1);
			
			Vector<Type> ret(_rows);
			for (int i = 0; i < _rows; ++i)
				ret[i] = (*this)(i, i);
			return ret;
		}

		///////////////////////          Matrix extraction                 //////////////////////
		
		/// @brief Extract lower triangular part
		/// @param includeDiagonal If true, includes diagonal; if false, strictly lower
		/// @return Lower triangular matrix
		/// @throws MatrixDimensionError if matrix is not square
		[[nodiscard]] Matrix GetLower(bool includeDiagonal = true) const
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::GetLower - must be square", _rows, _cols, -1, -1);
			
			Matrix ret(_rows, _cols);
			for (int i = 0; i < _rows; ++i) {
				int jEnd = includeDiagonal ? i + 1 : i;
				for (int j = 0; j < jEnd; ++j)
					ret(i, j) = (*this)(i, j);
			}
			return ret;
		}
		
		/// @brief Extract upper triangular part
		/// @param includeDiagonal If true, includes diagonal; if false, strictly upper
		/// @return Upper triangular matrix
		/// @throws MatrixDimensionError if matrix is not square
		[[nodiscard]] Matrix GetUpper(bool includeDiagonal = true) const
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::GetUpper - must be square", _rows, _cols, -1, -1);
			
			Matrix ret(_rows, _cols);
			for (int i = 0; i < _rows; ++i) {
				int jStart = includeDiagonal ? i : i + 1;
				for (int j = jStart; j < _cols; ++j)
					ret(i, j) = (*this)(i, j);
			}
			return ret;
		}
		
		/// @brief Extract rectangular submatrix
		/// @param start_row Starting row index
		/// @param start_col Starting column index
		/// @param row_num Number of rows
		/// @param col_num Number of columns
		/// @return Submatrix copy
		Matrix GetSubmatrix(int start_row, int start_col, int row_num, int col_num) const
		{
			return Matrix(*this, start_row, start_col, row_num, col_num);
		}

		///////////////////////          Row/column operations             //////////////////////
		
		/// @brief Initialize a row from a vector
		/// @param rowInd Target row index
		/// @param vec Source vector (must have size == ColNum())
		/// @throws MatrixAccessBoundsError if row index invalid
		/// @throws MatrixDimensionError if vector size doesn't match columns
		void InitRowWithVector(int rowInd, const Vector<Type>& vec)
		{
			if (rowInd < 0 || rowInd >= _rows)
				throw MatrixAccessBoundsError("InitRowWithVector - invalid row index", rowInd, 0, _rows, _cols);
			if (vec.size() != _cols)
				throw MatrixDimensionError("InitRowWithVector - vector size must match columns", _rows, _cols, vec.size(), -1);
			
			for (int j = 0; j < _cols; ++j)
				_data[idx(rowInd, j)] = vec[j];
		}
		
		/// @brief Initialize a column from a vector
		/// @param colInd Target column index
		/// @param vec Source vector (must have size == RowNum())
		/// @throws MatrixAccessBoundsError if column index invalid
		/// @throws MatrixDimensionError if vector size doesn't match rows
		void InitColWithVector(int colInd, const Vector<Type>& vec)
		{
			if (colInd < 0 || colInd >= _cols)
				throw MatrixAccessBoundsError("InitColWithVector - invalid column index", 0, colInd, _rows, _cols);
			if (vec.size() != _rows)
				throw MatrixDimensionError("InitColWithVector - vector size must match rows", _rows, _cols, vec.size(), -1);
			
			for (int i = 0; i < _rows; ++i)
				_data[idx(i, colInd)] = vec[i];
		}
		
		/// @brief Swap two rows
		/// @param k First row index
		/// @param l Second row index
		void SwapRows(int k, int l)
		{
			if (k < 0 || k >= _rows || l < 0 || l >= _rows)
				throw MatrixDimensionError("Matrix::SwapRows - invalid row index", _rows, _cols, k, l);
			if (k == l) return;
			
			for (int j = 0; j < _cols; ++j)
				std::swap(_data[idx(k, j)], _data[idx(l, j)]);
		}
		
		/// @brief Swap two columns
		/// @param k First column index
		/// @param l Second column index
		void SwapCols(int k, int l)
		{
			if (k < 0 || k >= _cols || l < 0 || l >= _cols)
				throw MatrixDimensionError("Matrix::SwapCols - invalid column index", _rows, _cols, k, l);
			if (k == l) return;
			
			for (int i = 0; i < _rows; ++i)
				std::swap(_data[idx(i, k)], _data[idx(i, l)]);
		}

		///////////////////////              Creating views                //////////////////////
		
		/// @brief Create mutable view of a rectangular block
		/// @warning The returned view is invalidated by Resize() or destruction of this matrix.
		/// @param startRow Starting row index
		/// @param startCol Starting column index
		/// @param numRows Number of rows in block
		/// @param numCols Number of columns in block
		/// @return MatrixViewNew providing strided access to block
		MatrixViewNew<Type> block(int startRow, int startCol, int numRows, int numCols)
		{
			if (startRow < 0 || startCol < 0 || numRows <= 0 || numCols <= 0 ||
			    startRow + numRows > _rows || startCol + numCols > _cols)
				throw MatrixDimensionError("Matrix::block - invalid parameters", _rows, _cols, startRow, startCol);
			return MatrixViewNew<Type>(&_data[idx(startRow, startCol)], numRows, numCols, _cols);
		}
		
		/// @brief Create const view of a rectangular block
		/// @warning The returned view is invalidated by Resize() or destruction of this matrix.
		const MatrixViewNew<Type> block(int startRow, int startCol, int numRows, int numCols) const
		{
			if (startRow < 0 || startCol < 0 || numRows <= 0 || numCols <= 0 ||
			    startRow + numRows > _rows || startCol + numCols > _cols)
				throw MatrixDimensionError("Matrix::block - invalid parameters", _rows, _cols, startRow, startCol);
			return MatrixViewNew<Type>(const_cast<Type*>(&_data[idx(startRow, startCol)]), numRows, numCols, _cols);
		}

		///////////////////////               Matrix properties            //////////////////////
		
		/// @brief Check if matrix is identity matrix
		/// @param eps Tolerance for floating-point comparison
		/// @return true if |M(i,i)-1| < eps and |M(i,j)| < eps for i≠j
		bool isIdentity(double eps = Defaults::IsMatrixUnitTolerance) const
		{
			if (_rows != _cols) return false;
			
			for (int i = 0; i < _rows; ++i) {
				for (int j = 0; j < _cols; ++j) {
					if (i == j) {
						if (Abs((*this)(i, j) - Type{1}) > eps) return false;
					} else {
						if (Abs((*this)(i, j)) > eps) return false;
					}
				}
			}
			return true;
		}

		/// @brief Check if matrix is diagonal
		/// @param eps Tolerance for off-diagonal elements
		/// @return true if |M(i,j)| < eps for all i≠j
		bool isDiagonal(double eps = Defaults::IsMatrixDiagonalTolerance) const
		{
			for (int i = 0; i < _rows; ++i)
				for (int j = 0; j < _cols; ++j)
					if (i != j && Abs((*this)(i, j)) > eps)
						return false;
			return true;
		}

		/// @brief Check if matrix is diagonally dominant
		/// @return true if |M(i,i)| ≥ Σ_{j≠i} |M(i,j)| for all rows
		bool isDiagonallyDominant() const
		{
			for (int i = 0; i < _rows; ++i) {
				Real sum{0};  // Use Real for magnitude accumulation
				for (int j = 0; j < _cols; ++j)
					if (i != j)
						sum += Abs((*this)(i, j));
				if (Abs((*this)(i, i)) < sum)
					return false;
			}
			return true;
		}

		/// @brief Check if matrix is symmetric (M = Mᵀ) within tolerance
		/// @param eps Maximum allowed difference |M(i,j) - M(j,i)|
		/// @return true if M(i,j) ≈ M(j,i) for all i,j
		bool isSymmetric(double eps = Defaults::IsMatrixSymmetricTolerance) const
		{
			if (_rows != _cols) return false;
			
			for (int i = 0; i < _rows; ++i)
				for (int j = i + 1; j < _cols; ++j)
					if (Abs((*this)(i, j) - (*this)(j, i)) > eps)
						return false;
			return true;
		}

		/// @brief Check if matrix is anti-symmetric (skew-symmetric) within tolerance
		/// @param eps Maximum allowed difference |M(i,j) + M(j,i)|
		/// @return true if M(i,j) ≈ -M(j,i) for all i,j
		bool isAntiSymmetric(double eps = Defaults::IsMatrixSymmetricTolerance) const
		{
			if (_rows != _cols) return false;
			
			for (int i = 0; i < _rows; ++i) {
				for (int j = i + 1; j < _cols; ++j) {
					if (IsMatrixTypeComplex()) {
						if (Abs((*this)(i, j) + std::conj((*this)(j, i))) > eps)
							return false;
					} else {
						if (Abs((*this)(i, j) + (*this)(j, i)) > eps)
							return false;
					}
				}
			}
			return true;
		}

		/// @brief Check if matrix is a zero matrix (all elements are zero within tolerance)
		/// @param eps Maximum allowed absolute value for an element to be considered zero
		/// @return true if all elements have absolute value <= eps
		bool isZero(double eps = Defaults::IsMatrixZeroTolerance) const
		{
			for (const auto& elem : _data)
				if (Abs(elem) > eps)
					return false;
			return true;
		}

		///////////////////////             Matrix norm calculations       //////////////////////
		
		/// @brief L1 norm (sum of absolute values of all elements)
		Real NormL1() const
		{
			Real norm{0};
			for (const auto& elem : _data)
				norm += Abs(elem);
			return norm;
		}
		
		/// @brief Frobenius norm: ||M||_F = √(Σ |M(i,j)|²)
		/// @details For complex matrices, uses std::norm(z) = |z|² = real² + imag²
		Real NormL2() const
		{
			Real norm{0};
			for (const auto& elem : _data) {
				if constexpr (std::is_same_v<Type, Complex> || 
				              std::is_same_v<Type, std::complex<float>> ||
				              std::is_same_v<Type, std::complex<long double>>) {
					norm += std::norm(elem);  // |z|² for complex
				} else {
					norm += elem * elem;  // x² for real
				}
			}
			return std::sqrt(norm);
		}
		
		/// @brief L∞ norm (maximum absolute value of any element)
		Real NormLInf() const
		{
			Real norm{0};
			for (const auto& elem : _data)
				norm = std::max(norm, static_cast<Real>(Abs(elem)));
			return norm;
		}

		///////////////////////               Access operators             //////////////////////
		
		/// @brief Primary element access - M(i,j)
		inline Type  operator()(int i, int j) const noexcept { return _data[idx(i, j)]; }
		/// @brief Primary element access (mutable)
		inline Type& operator()(int i, int j)       noexcept { return _data[idx(i, j)]; }
		
		/// @brief Legacy row access - M[i][j] syntax
		/// @details Returns pointer to row start for compatibility with mat[i][j] code
		inline Type* operator[](int i)             noexcept { return &_data[idx(i, 0)]; }
		/// @brief Legacy row access (const)
		inline const Type* operator[](int i) const noexcept { return &_data[idx(i, 0)]; }
		
		/// @brief Bounds-checked element access
		/// @throws MatrixAccessBoundsError if indices out of bounds
		const Type& at(int i, int j) const
		{
			if (i < 0 || i >= _rows || j < 0 || j >= _cols)
				throw MatrixAccessBoundsError("Matrix::at", i, j, _rows, _cols);
			return _data[idx(i, j)];
		}
		
		/// @brief Bounds-checked element access (mutable)
		/// @throws MatrixAccessBoundsError if indices out of bounds
		Type& at(int i, int j)
		{
			if (i < 0 || i >= _rows || j < 0 || j >= _cols)
				throw MatrixAccessBoundsError("Matrix::at", i, j, _rows, _cols);
			return _data[idx(i, j)];
		}

		///////////////////////             Iterator support               //////////////////////
		
		/// @brief Flat iterators - traverse all elements in row-major order
		auto begin()        { return _data.begin(); }
		auto end()          { return _data.end(); }
		auto begin() const  { return _data.begin(); }
		auto end() const    { return _data.end(); }
		auto cbegin() const { return _data.cbegin(); }
		auto cend() const   { return _data.cend(); }

		/// @brief Row iterator proxy for range-based for loops
		class row_range {
			Type* _ptr;
			int _cols;
		public:
			row_range(Type* ptr, int cols) : _ptr(ptr), _cols(cols) {}
			Type* begin() { return _ptr; }
			Type* end()   { return _ptr + _cols; }
		};
		
		class const_row_range {
			const Type* _ptr;
			int _cols;
		public:
			const_row_range(const Type* ptr, int cols) : _ptr(ptr), _cols(cols) {}
			const Type* begin() const { return _ptr; }
			const Type* end() const   { return _ptr + _cols; }
		};
		
		/// @brief Get iterable row range for range-based for
		/// @param i Row index
		/// @return row_range object for iteration
		row_range row(int i)
		{
			if (i < 0 || i >= _rows)
				throw MatrixAccessBoundsError("Matrix::row", i, 0, _rows, _cols);
			return row_range(&_data[idx(i, 0)], _cols);
		}
		
		/// @brief Get iterable row range (const)
		const_row_range row(int i) const
		{
			if (i < 0 || i >= _rows)
				throw MatrixAccessBoundsError("Matrix::row", i, 0, _rows, _cols);
			return const_row_range(&_data[idx(i, 0)], _cols);
		}

		/// @brief Column iterator (strided, forward-only)
		class col_iterator {
			Type* _ptr;
			int _stride;
		public:
			using iterator_category = std::forward_iterator_tag;
			using value_type = Type;
			using difference_type = std::ptrdiff_t;
			using pointer = Type*;
			using reference = Type&;

			col_iterator(Type* ptr, int stride) : _ptr(ptr), _stride(stride) {}
			col_iterator& operator++() { _ptr += _stride; return *this; }
			col_iterator operator++(int) { auto tmp = *this; _ptr += _stride; return tmp; }
			bool operator==(const col_iterator& other) const { return _ptr == other._ptr; }
			bool operator!=(const col_iterator& other) const { return _ptr != other._ptr; }
			Type& operator*() { return *_ptr; }
		};
		
		class col_range {
			Type* _ptr;
			int _rows, _stride;
		public:
			col_range(Type* ptr, int rows, int stride) : _ptr(ptr), _rows(rows), _stride(stride) {}
			col_iterator begin() { return col_iterator(_ptr, _stride); }
			col_iterator end()   { return col_iterator(_ptr + _rows * _stride, _stride); }
		};
		
		/// @brief Get iterable column range
		/// @param j Column index
		/// @return col_range object for strided iteration
		col_range col(int j)
		{
			if (j < 0 || j >= _cols)
				throw MatrixAccessBoundsError("Matrix::col", 0, j, _rows, _cols);
			return col_range(&_data[j], _rows, _cols);
		}

		///////////////////////              Equality operations           //////////////////////
		
		/// @brief Exact equality comparison
		bool operator==(const Matrix& b) const
		{
			if (_rows != b._rows || _cols != b._cols)
				return false;
			return _data == b._data;
		}
		
		/// @brief Exact inequality
		bool operator!=(const Matrix& b) const { return !(*this == b); }
		
		/// @brief Approximate equality with tolerance
		/// @param b Matrix to compare with
		/// @param eps Maximum allowed difference per element
		bool IsEqualTo(const Matrix& b, Real eps = Defaults::MatrixIsEqualTolerance) const
		{
			if (_rows != b._rows || _cols != b._cols)
				return false;
			
			for (size_t i = 0; i < _data.size(); ++i)
				if (Abs(_data[i] - b._data[i]) > eps)
					return false;
			return true;
		}
		
		/// @brief Static version of IsEqualTo
		static bool AreEqual(const Matrix& a, const Matrix& b, Real eps = Defaults::MatrixIsEqualTolerance)
		{
			return a.IsEqualTo(b, eps);
		}

		///////////////////////              Arithmetic operators          //////////////////////
		
		/// @brief Unary negation
		[[nodiscard]] Matrix operator-() const
		{
			Matrix ret(_rows, _cols);
			for (size_t i = 0; i < _data.size(); ++i)
				ret._data[i] = -_data[i];
			return ret;
		}
		
		/// @brief Matrix addition
		/// @throws MatrixDimensionError if dimensions don't match
		[[nodiscard]] Matrix operator+(const Matrix& b) const
		{
			if (_rows != b._rows || _cols != b._cols)
				throw MatrixDimensionError("Matrix::operator+ - dimensions must match", _rows, _cols, b._rows, b._cols);
			
			Matrix ret(_rows, _cols);
			for (size_t i = 0; i < _data.size(); ++i)
				ret._data[i] = _data[i] + b._data[i];
			return ret;
		}
		
		/// @brief In-place matrix addition
		Matrix& operator+=(const Matrix& b)
		{
			if (_rows != b._rows || _cols != b._cols)
				throw MatrixDimensionError("Matrix::operator+= - dimensions must match", _rows, _cols, b._rows, b._cols);
			
			for (size_t i = 0; i < _data.size(); ++i)
				_data[i] += b._data[i];
			return *this;
		}
		
		/// @brief Matrix subtraction
		/// @throws MatrixDimensionError if dimensions don't match
		[[nodiscard]] Matrix operator-(const Matrix& b) const
		{
			if (_rows != b._rows || _cols != b._cols)
				throw MatrixDimensionError("Matrix::operator- - dimensions must match", _rows, _cols, b._rows, b._cols);
			
			Matrix ret(_rows, _cols);
			for (size_t i = 0; i < _data.size(); ++i)
				ret._data[i] = _data[i] - b._data[i];
			return ret;
		}
		
		/// @brief In-place matrix subtraction
		Matrix& operator-=(const Matrix& b)
		{
			if (_rows != b._rows || _cols != b._cols)
				throw MatrixDimensionError("Matrix::operator-= - dimensions must match", _rows, _cols, b._rows, b._cols);
			
			for (size_t i = 0; i < _data.size(); ++i)
				_data[i] -= b._data[i];
			return *this;
		}
		
		/// @brief Matrix multiplication: C = A * B
		/// @throws MatrixDimensionError if A.cols != B.rows
		[[nodiscard]] Matrix operator*(const Matrix& b) const
		{
			if (_cols != b._rows)
				throw MatrixDimensionError("Matrix::operator* - a.cols must equal b.rows", _rows, _cols, b._rows, b._cols);
			
			Matrix ret(_rows, b._cols);
			for (int i = 0; i < _rows; ++i) {
				for (int j = 0; j < b._cols; ++j) {
					Type sum{0};
					for (int k = 0; k < _cols; ++k)
						sum += (*this)(i, k) * b(k, j);
					ret(i, j) = sum;
				}
			}
			return ret;
		}
		
		/// @brief Scalar multiplication: M * s
		[[nodiscard]] Matrix operator*(const Type& scalar) const
		{
			Matrix ret(_rows, _cols);
			for (size_t i = 0; i < _data.size(); ++i)
				ret._data[i] = _data[i] * scalar;
			return ret;
		}
		
		/// @brief In-place scalar multiplication
		Matrix& operator*=(const Type& scalar)
		{
			for (auto& elem : _data)
				elem *= scalar;
			return *this;
		}
		
		/// @brief Scalar division: M / s
		[[nodiscard]] Matrix operator/(const Type& scalar) const
		{
			Matrix ret(_rows, _cols);
			for (size_t i = 0; i < _data.size(); ++i)
				ret._data[i] = _data[i] / scalar;
			return ret;
		}
		
		/// @brief In-place scalar division
		Matrix& operator/=(const Type& scalar)
		{
			for (auto& elem : _data)
				elem /= scalar;
			return *this;
		}
		
		/// @brief Matrix-vector multiplication: M * v
		/// @throws MatrixDimensionError if cols != vector size
		Vector<Type> operator*(const Vector<Type>& v) const
		{
			if (_cols != v.size())
				throw MatrixDimensionError("Matrix * Vector - cols must equal vector size", _rows, _cols, v.size(), -1);
			
			Vector<Type> ret(_rows);
			for (int i = 0; i < _rows; ++i) {
				Type sum{0};
				for (int j = 0; j < _cols; ++j)
					sum += (*this)(i, j) * v[j];
				ret[i] = sum;
			}
			return ret;
		}
		
		/// @brief Scalar * Matrix (commutative)
		friend Matrix operator*(const Type& scalar, const Matrix& m)
		{
			return m * scalar;
		}
		
		/// @brief Vector * Matrix multiplication: vᵀ * M
		friend Vector<Type> operator*(const Vector<Type>& v, const Matrix& m)
		{
			if (v.size() != m._rows)
				throw MatrixDimensionError("Vector * Matrix - vector size must equal rows", v.size(), -1, m._rows, m._cols);
			
			Vector<Type> ret(m._cols);
			for (int j = 0; j < m._cols; ++j) {
				Type sum{0};
				for (int i = 0; i < m._rows; ++i)
					sum += v[i] * m(i, j);
				ret[j] = sum;
			}
			return ret;
		}

		///////////////////////            Trace, Inverse & Transpose      //////////////////////
		
		/// @brief Calculate matrix trace (sum of diagonal elements) - preferred API
		/// @return tr(M) = Σ M(i,i)
		/// @throws MatrixDimensionError if matrix is not square
		Type trace() const
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::trace - must be square", _rows, _cols, -1, -1);
			
			Type sum{0};
			for (int i = 0; i < _rows; ++i)
				sum += (*this)(i, i);
			return sum;
		}

		/// @brief Invert matrix in-place using Gauss-Jordan elimination
		/// @throws MatrixDimensionError if matrix is not square
		/// @throws SingularMatrixError if matrix is singular
		void Invert()
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::Invert - must be square", _rows, _cols, -1, -1);
			
			// Gauss-Jordan elimination with pivoting
			int n = _rows;
			Matrix& a = *this;
			std::vector<int> indxc(n), indxr(n), ipiv(n, 0);

			// Compute infinity norm for norm-scaled singularity threshold
			Real norm_a = 0.0;
			for (int ii = 0; ii < n; ii++)
				for (int jj = 0; jj < n; jj++) {
					Real abs_val = Abs(a(ii, jj));
					if (abs_val > norm_a) norm_a = abs_val;
				}
			Real singularity_threshold = std::numeric_limits<Real>::epsilon() * norm_a * n;

			for (int i = 0; i < n; ++i) {
				Real big{0};
				int irow = 0, icol = 0;
				
				// Find pivot
				for (int j = 0; j < n; ++j) {
					if (ipiv[j] != 1) {
						for (int k = 0; k < n; ++k) {
							if (ipiv[k] == 0) {
								if (Abs(a(j, k)) >= big) {
									big = Abs(a(j, k));
									irow = j;
									icol = k;
								}
							}
						}
					}
				}
				++ipiv[icol];
				
				// Swap rows if needed
				if (irow != icol) {
					for (int l = 0; l < n; ++l)
						std::swap(a(irow, l), a(icol, l));
				}
				
				indxr[i] = irow;
				indxc[i] = icol;
				
				if (Abs(a(icol, icol)) < singularity_threshold)
					throw SingularMatrixError("Matrix::Invert - Singular Matrix", Abs(a(icol, icol)));
				
				Type pivinv = Type{1} / a(icol, icol);
				a(icol, icol) = Type{1};
				for (int l = 0; l < n; ++l)
					a(icol, l) *= pivinv;
				
				for (int ll = 0; ll < n; ++ll) {
					if (ll != icol) {
						Type dum = a(ll, icol);
						a(ll, icol) = Type{0};
						for (int l = 0; l < n; ++l)
							a(ll, l) -= a(icol, l) * dum;
					}
				}
			}
			
			// Unscramble columns
			for (int l = n - 1; l >= 0; --l) {
				if (indxr[l] != indxc[l]) {
					for (int k = 0; k < n; ++k)
						std::swap(a(k, indxr[l]), a(k, indxc[l]));
				}
			}
		}
		
		/// @brief Get inverse matrix (returns copy) - preferred API
		/// @throws SingularMatrixError if matrix is singular
		[[nodiscard]] Matrix inverse() const
		{
			Matrix ret(*this);
			ret.Invert();
			return ret;
		}

		/// @brief Transpose matrix in-place (only for square matrices)
		/// @throws MatrixDimensionError if matrix is not square
		void Transpose()
		{
			if (_rows != _cols)
				throw MatrixDimensionError("Matrix::Transpose - in-place requires square matrix", _rows, _cols, -1, -1);
			
			for (int i = 0; i < _rows; ++i)
				for (int j = i + 1; j < _cols; ++j)
					std::swap(_data[idx(i, j)], _data[idx(j, i)]);
		}
		
		/// @brief Get transpose matrix (returns copy, works for any dimensions) - preferred API
		/// @return Mᵀ where Mᵀ(i,j) = M(j,i)
		[[nodiscard]] Matrix transpose() const
		{
			Matrix ret(_cols, _rows);
			for (int i = 0; i < _rows; ++i)
				for (int j = 0; j < _cols; ++j)
					ret(j, i) = (*this)(i, j);
			return ret;
		}

		///////////////////////                    I/O                    //////////////////////
		
		/// @brief Print matrix to stream with formatting options
		/// @param stream Output stream
		/// @param fmt Format options (width, precision, brackets, etc.)
		void Print(std::ostream& stream, const MatrixPrintFormat& fmt = MatrixPrintFormat::Default()) const
		{
			if (isEmpty()) {
				if (fmt.showHeader)
					stream << "Rows: " << _rows << " Cols: " << _cols << " - Empty matrix" << std::endl;
				return;
			}

			if (fmt.showHeader)
				stream << "Rows: " << _rows << " Cols: " << _cols << std::endl;

			std::ios_base::fmtflags oldFlags = stream.flags();
			if (fmt.scientific)
				stream << std::scientific;
			else if (fmt.fixed)
				stream << std::fixed;

			for (int i = 0; i < _rows; ++i) {
				if (fmt.showBrackets) stream << "[ ";
				for (int j = 0; j < _cols; ++j) {
					stream << std::setw(fmt.width) << std::setprecision(fmt.precision) << (*this)(i, j);
					if (j < _cols - 1) stream << fmt.delimiter;
				}
				if (fmt.showBrackets) stream << " ]";
				if (i < _rows - 1) stream << std::endl;
			}
			
			stream.flags(oldFlags);
		}
		
		/// @brief Print with specified width and precision
		void Print(std::ostream& stream, int width, int precision) const
		{
			MatrixPrintFormat fmt = MatrixPrintFormat::Default();
			fmt.width = width;
			fmt.precision = precision;
			fmt.fixed = false;
			Print(stream, fmt);
		}
		
		/// @brief Print with zero threshold (values below threshold printed as 0)
		void Print(std::ostream& stream, int width, int precision, Real threshold) const
		{
			// Create a temporary copy with thresholded values
			Matrix<Type> temp(*this);
			if constexpr (is_MML_simple_numeric<Type>) {
				for (int i = 0; i < _rows; ++i) {
					for (int j = 0; j < _cols; ++j) {
						if (std::abs(static_cast<Real>(temp(i, j))) < threshold) {
							temp(i, j) = Type{0};
						}
					}
				}
			}
			// Use the standard Print function for consistent formatting
			temp.Print(stream, width, precision);
		}
		
		/// @brief Stream output operator
		friend std::ostream& operator<<(std::ostream& stream, const Matrix& a)
		{
			a.Print(stream, 10, 3);
			return stream;
		}
		
		/// @brief Convert to string representation
		std::string to_string(int width, int precision) const
		{
			std::stringstream str;
			Print(str, width, precision);
			return str.str();
		}
	};

	//////////////////////               Default Matrix typedefs       //////////////////////
	
	// Common type aliases
	typedef Matrix<int>     MatrixInt;      ///< Integer matrix
	typedef Matrix<float>   MatrixFlt;      ///< Single-precision matrix
	typedef Matrix<double>  MatrixDbl;      ///< Double-precision matrix
	typedef Matrix<Complex> MatrixComplex;  ///< Complex matrix

	// Short aliases
	typedef Matrix<int>     MatI;   ///< Short alias for MatrixInt
	typedef Matrix<float>   MatF;   ///< Short alias for MatrixFlt
	typedef Matrix<double>  MatD;   ///< Short alias for MatrixDbl
	typedef Matrix<Complex> MatC;   ///< Short alias for MatrixComplex

	// Verify noexcept move operations
	static_assert(std::is_nothrow_move_constructible_v<Matrix<double>>,
	              "Matrix<double> should be nothrow move constructible");
	static_assert(std::is_nothrow_move_assignable_v<Matrix<double>>,
	              "Matrix<double> should be nothrow move assignable");
}



///////////////////////////   mml/tools/serializer/MatrixIO.h   ///////////////////////////




namespace MML
{
namespace Serializer
{
	///////////////////////////////////////////////////////////////////////////////////////////
	///                               Text File I/O                                         ///
	///////////////////////////////////////////////////////////////////////////////////////////

	/**
	 * @brief Load matrix from text file (space-separated values)
	 * @tparam Type Matrix element type
	 * @param filename Path to input file
	 * @param outMat Matrix to populate
	 * @return true if successful
	 * 
	 * File format:
	 * - First line: rows cols
	 * - Following lines: space-separated matrix elements (row by row)
	 */
	template<class Type>
	bool LoadMatrixFromFile(const std::string& filename, Matrix<Type>& outMat)
	{
		std::ifstream file(filename);
		if (!file.is_open()) {
			std::cerr << "Error: could not open file " << filename << " for reading." << std::endl;
			return false;
		}
		
		int rows, cols;
		file >> rows >> cols;
		outMat.Resize(rows, cols);
		
		for (int i = 0; i < rows; ++i)
			for (int j = 0; j < cols; ++j)
				file >> outMat(i, j);
		
		file.close();
		return true;
	}

	/**
	 * @brief Save matrix to text file
	 * @tparam Type Matrix element type
	 * @param mat Matrix to save
	 * @param filename Path to output file
	 * @return true if successful
	 */
	template<class Type>
	bool SaveMatrixToFile(const Matrix<Type>& mat, const std::string& filename)
	{
		std::ofstream file(filename);
		if (!file.is_open()) {
			std::cerr << "Error: could not create file " << filename << " for writing." << std::endl;
			return false;
		}
		
		file << mat.rows() << " " << mat.cols() << std::endl;
		for (int i = 0; i < mat.rows(); ++i) {
			for (int j = 0; j < mat.cols(); ++j)
				file << mat(i, j) << " ";
			file << std::endl;
		}
		
		file.close();
		return true;
	}

	///////////////////////////////////////////////////////////////////////////////////////////
	///                               CSV File I/O                                          ///
	///////////////////////////////////////////////////////////////////////////////////////////

	/**
	 * @brief Load matrix from CSV file
	 * @tparam Type Matrix element type
	 * @param filename Path to CSV file
	 * @param outMat Matrix to populate
	 * @return true if successful
	 */
	template<class Type>
	bool LoadMatrixFromCSV(const std::string& filename, Matrix<Type>& outMat)
	{
		std::ifstream file(filename);
		if (!file.is_open()) return false;
		
		std::vector<std::vector<Type>> data;
		std::string line;
		
		while (std::getline(file, line)) {
			std::vector<Type> row;
			std::stringstream ss(line);
			std::string cell;
			while (std::getline(ss, cell, ',')) {
				std::stringstream cellStream(cell);
				Type value;
				cellStream >> value;
				row.push_back(value);
			}
			if (!row.empty())
				data.push_back(row);
		}
		
		file.close();
		if (data.empty()) return false;
		
		outMat = Matrix<Type>(data);
		return true;
	}

	/**
	 * @brief Save matrix to CSV file
	 * @tparam Type Matrix element type
	 * @param mat Matrix to save
	 * @param filename Path to CSV file
	 * @return true if successful
	 */
	template<class Type>
	bool SaveMatrixToCSV(const Matrix<Type>& mat, const std::string& filename)
	{
		std::ofstream file(filename);
		if (!file.is_open()) return false;
		
		for (int i = 0; i < mat.rows(); ++i) {
			for (int j = 0; j < mat.cols(); ++j) {
				file << mat(i, j);
				if (j < mat.cols() - 1) file << ",";
			}
			file << "\n";
		}
		
		file.close();
		return true;
	}

	///////////////////////////////////////////////////////////////////////////////////////////
	///                               Binary File I/O                                       ///
	///////////////////////////////////////////////////////////////////////////////////////////

	/**
	 * @brief Save matrix to binary file (compact, exact precision)
	 * @tparam Type Matrix element type
	 * @param mat Matrix to save
	 * @param filename Path to output file
	 * @return true if successful
	 * 
	 * Binary format:
	 * - 4 bytes: magic number 0x4D4D4C4D ("MMLM" for MML Matrix)
	 * - 4 bytes: version (currently 1)
	 * - 4 bytes: rows (int32)
	 * - 4 bytes: cols (int32)
	 * - 4 bytes: element size in bytes (sizeof(Type))
	 * - 4 bytes: reserved (0)
	 * - rows*cols*sizeof(Type) bytes: data in row-major order
	 */
	template<class Type>
	bool SaveMatrixToBinary(const Matrix<Type>& mat, const std::string& filename)
	{
		std::ofstream file(filename, std::ios::binary);
		if (!file.is_open()) {
			std::cerr << "Error: could not create binary file " << filename << std::endl;
			return false;
		}
		
		// Write header
		const uint32_t magic = BinaryFormat::MAGIC_MATRIX;
		const uint32_t version = BinaryFormat::VERSION_MATRIX;
		const uint32_t rows = static_cast<uint32_t>(mat.rows());
		const uint32_t cols = static_cast<uint32_t>(mat.cols());
		const uint32_t elemSize = static_cast<uint32_t>(sizeof(Type));
		const uint32_t reserved = 0;
		
		file.write(reinterpret_cast<const char*>(&magic), sizeof(magic));
		file.write(reinterpret_cast<const char*>(&version), sizeof(version));
		file.write(reinterpret_cast<const char*>(&rows), sizeof(rows));
		file.write(reinterpret_cast<const char*>(&cols), sizeof(cols));
		file.write(reinterpret_cast<const char*>(&elemSize), sizeof(elemSize));
		file.write(reinterpret_cast<const char*>(&reserved), sizeof(reserved));
		
		// Write data - use data() for contiguous access
		file.write(reinterpret_cast<const char*>(mat.data()), 
		           static_cast<std::streamsize>(rows) * cols * sizeof(Type));
		
		file.close();
		return true;
	}

	/**
	 * @brief Load matrix from binary file
	 * @tparam Type Matrix element type
	 * @param filename Path to input file
	 * @param outMat Matrix to populate
	 * @return true if successful
	 */
	template<class Type>
	bool LoadMatrixFromBinary(const std::string& filename, Matrix<Type>& outMat)
	{
		std::ifstream file(filename, std::ios::binary);
		if (!file.is_open()) {
			std::cerr << "Error: could not open binary file " << filename << std::endl;
			return false;
		}
		
		// Read and verify header
		uint32_t magic, version, rows, cols, elemSize, reserved;
		
		file.read(reinterpret_cast<char*>(&magic), sizeof(magic));
		if (magic != BinaryFormat::MAGIC_MATRIX) {
			std::cerr << "Error: invalid magic number in " << filename << std::endl;
			return false;
		}
		
		file.read(reinterpret_cast<char*>(&version), sizeof(version));
		if (version != BinaryFormat::VERSION_MATRIX) {
			std::cerr << "Error: unsupported version " << version << " in " << filename << std::endl;
			return false;
		}
		
		file.read(reinterpret_cast<char*>(&rows), sizeof(rows));
		file.read(reinterpret_cast<char*>(&cols), sizeof(cols));
		file.read(reinterpret_cast<char*>(&elemSize), sizeof(elemSize));
		file.read(reinterpret_cast<char*>(&reserved), sizeof(reserved));
		
		if (elemSize != sizeof(Type)) {
			std::cerr << "Error: element size mismatch in " << filename 
			          << " (file: " << elemSize << ", expected: " << sizeof(Type) << ")" << std::endl;
			return false;
		}
		
		// Read data
		outMat.Resize(static_cast<int>(rows), static_cast<int>(cols));
		file.read(reinterpret_cast<char*>(outMat.data()), 
		          static_cast<std::streamsize>(rows) * cols * sizeof(Type));
		
		file.close();
		return true;
	}

	/**
	 * @brief Get estimated binary file size in bytes
	 * @tparam Type Matrix element type
	 * @param rows Number of rows
	 * @param cols Number of columns
	 * @return Estimated file size in bytes
	 */
	template<class Type>
	size_t EstimateMatrixBinaryFileSize(int rows, int cols)
	{
		return 24 + static_cast<size_t>(rows) * static_cast<size_t>(cols) * sizeof(Type);
	}

} // namespace Serializer
} // namespace MML


///////////////////////////   mml/base/Matrix/Matrix3D.h   ///////////////////////////




namespace MML {
	/// @brief Three-dimensional matrix (tensor) with contiguous memory layout.
	/// @ingroup Base
	/// @tparam Type Element type (typically double, float, int, or Complex).
	/// Memory is allocated as a single contiguous std::vector for cache efficiency
	/// and automatic memory management (no manual new/delete).
	/// Supports both [i][j][k] and (i,j,k) access patterns.
	/// @par Thread Safety
	/// Read operations are thread-safe. Write operations to different elements
	/// are safe from different threads. Structural changes (Resize, assignment)
	/// require external synchronization.

	template<class Type>
	class Matrix3D {
	private:
		int _dim1 = 0, _dim2 = 0, _dim3 = 0; ///< Dimensions (depth, rows, columns)
		std::vector<Type>    _data;   ///< Contiguous data block
		std::vector<Type*>   _rows;   ///< Row pointers for [i][j][k] access
		std::vector<Type**>  _slices; ///< Slice pointers (one per slice)

		/// @brief Builds pointer structure for [i][j][k] access from _data.
		void BuildPointers() {
			_rows.resize(_dim1 * _dim2);
			_slices.resize(_dim1);

			for (int i = 0; i < _dim1; ++i) {
				_slices[i] = _rows.data() + i * _dim2;
				for (int j = 0; j < _dim2; ++j)
					_rows[i * _dim2 + j] = _data.data() + (i * _dim2 + j) * _dim3;
			}
		}

		/// @brief Validates dimensions and returns total element count.
		/// @throws ArgumentError If any dimension ≤ 0.
		static int ValidateDims(int d1, int d2, int d3) {
			if (d1 <= 0 || d2 <= 0 || d3 <= 0)
				throw ArgumentError("Matrix3D dimensions must be positive");
			return d1 * d2 * d3;
		}

	public:
		/// /** @name Constructors and Destructor
		/// @{ */

		/// @brief Constructs an empty (0×0×0) tensor.
		Matrix3D() = default;

		/// @brief Constructs a tensor with given dimensions.
		/// @param d1 First dimension (depth/slices).
		/// @param d2 Second dimension (rows per slice).
		/// @param d3 Third dimension (columns per row).
		/// @throws ArgumentError If any dimension ≤ 0.
		/// @note Elements are value-initialized (zero for numeric types).
		Matrix3D(int d1, int d2, int d3)
			: _dim1(d1), _dim2(d2), _dim3(d3)
			, _data(ValidateDims(d1, d2, d3)) {
			BuildPointers();
		}

		/// @brief Constructs a tensor with given dimensions and initial value.
		/// @param d1 First dimension.
		/// @param d2 Second dimension.
		/// @param d3 Third dimension.
		/// @param initVal Value to initialize all elements.
		Matrix3D(int d1, int d2, int d3, const Type& initVal)
			: _dim1(d1), _dim2(d2), _dim3(d3)
			, _data(ValidateDims(d1, d2, d3), initVal) {
			BuildPointers();
		}

		/// @brief Copy constructor (deep copy).
		/// @note Data is deep-copied via std::vector. Pointers are rebuilt.
		Matrix3D(const Matrix3D& other)
			: _dim1(other._dim1), _dim2(other._dim2), _dim3(other._dim3)
			, _data(other._data) {
			if (!_data.empty())
				BuildPointers();
		}

		/// @brief Move constructor (transfers ownership).
		Matrix3D(Matrix3D&& other) noexcept
			: _dim1(other._dim1), _dim2(other._dim2), _dim3(other._dim3)
			, _data(std::move(other._data))
			, _rows(std::move(other._rows))
			, _slices(std::move(other._slices)) {
			other._dim1 = other._dim2 = other._dim3 = 0;
		}

		/// @brief Destructor (default — std::vector handles memory).
		~Matrix3D() = default;
		/// /** @} */


		/// /** @name Assignment Operators
		/// @{ */

		/// @brief Copy assignment (deep copy).
		Matrix3D& operator=(const Matrix3D& other) {
			if (this != &other) {
				_dim1 = other._dim1;
				_dim2 = other._dim2;
				_dim3 = other._dim3;
				_data = other._data;
				if (!_data.empty())
					BuildPointers();
				else {
					_rows.clear();
					_slices.clear();
				}
			}
			return *this;
		}

		/// @brief Move assignment (transfers ownership).
		Matrix3D& operator=(Matrix3D&& other) noexcept {
			if (this != &other) {
				_dim1 = other._dim1;
				_dim2 = other._dim2;
				_dim3 = other._dim3;
				_data = std::move(other._data);
				_rows = std::move(other._rows);
				_slices = std::move(other._slices);
				other._dim1 = other._dim2 = other._dim3 = 0;
			}
			return *this;
		}
		/// /** @} */


		/// /** @name Dimension Accessors
		/// @{ */

		/// @brief Gets the first dimension (depth/number of slices).
		int dim1() const { return _dim1; }

		/// @brief Gets the second dimension (rows per slice).
		int dim2() const { return _dim2; }

		/// @brief Gets the third dimension (columns per row).
		int dim3() const { return _dim3; }

		/// @brief Gets the total number of elements.
		int size() const { return _dim1 * _dim2 * _dim3; }

		/// @brief Returns true if the tensor has no elements.
		bool isEmpty() const { return _data.empty(); }

		/// @brief Gets pointer to raw data (for algorithms needing contiguous memory).
		Type* data() { return _data.data(); }

		/// @brief Gets const pointer to raw data.
		const Type* data() const { return _data.data(); }
		/// /** @} */


		/// /** @name Element Access
		/// @{ */

		/// @brief Bracket notation access: m[i][j][k].
		/// @param i Slice index (first dimension).
		/// @return Pointer to slice i (allows chained [j][k] access).
		/// @note No bounds checking (use At() for checked access).
		Type** operator[](int i) { return _slices[i]; }

		/// @brief Const bracket access.
		const Type* const* operator[](int i) const { return _slices[i]; }

		/// @brief Parenthesis notation access: m(i, j, k).
		/// @param i Slice index.
		/// @param j Row index.
		/// @param k Column index.
		/// @return Reference to element at (i,j,k).
		/// @note Bounds-checked only if MML_DEBUG is defined.
		Type& operator()(int i, int j, int k) {
#ifdef MML_DEBUG
			if (i < 0 || i >= _dim1 || j < 0 || j >= _dim2 || k < 0 || k >= _dim3)
				throw IndexError("Matrix3D index out of bounds");
#endif
			return _data[(i * _dim2 + j) * _dim3 + k];
		}

		/// @brief Const parenthesis access.
		const Type& operator()(int i, int j, int k) const {
#ifdef MML_DEBUG
			if (i < 0 || i >= _dim1 || j < 0 || j >= _dim2 || k < 0 || k >= _dim3)
				throw IndexError("Matrix3D index out of bounds");
#endif
			return _data[(i * _dim2 + j) * _dim3 + k];
		}

		/// @brief Always bounds-checked element access.
		/// @param i Slice index.
		/// @param j Row index.
		/// @param k Column index.
		/// @return Reference to element at (i,j,k).
		/// @throws IndexError If any index is out of bounds.
		Type& At(int i, int j, int k) {
			if (i < 0 || i >= _dim1 || j < 0 || j >= _dim2 || k < 0 || k >= _dim3)
				throw IndexError("Matrix3D::At index out of bounds");
			return _data[(i * _dim2 + j) * _dim3 + k];
		}

		/// @brief Const bounds-checked access.
		const Type& At(int i, int j, int k) const {
			if (i < 0 || i >= _dim1 || j < 0 || j >= _dim2 || k < 0 || k >= _dim3)
				throw IndexError("Matrix3D::At index out of bounds");
			return _data[(i * _dim2 + j) * _dim3 + k];
		}
		/// /** @} */


		/// /** @name Utility Operations
		/// @{ */

		/// @brief Fills all elements with a value.
		/// @param value The value to fill.
		void Fill(const Type& value) { std::fill(_data.begin(), _data.end(), value); }

		/// @brief Applies a function to all elements in-place.
		/// @param func Unary function Type → Type.
		void Apply(std::function<Type(Type)> func) {
			for (auto& elem : _data)
				elem = func(elem);
		}

		/// @brief Resizes the tensor (discards existing data).
		/// @param d1 New first dimension.
		/// @param d2 New second dimension.
		/// @param d3 New third dimension.
		/// @note If dimensions match current, does nothing.
		void Resize(int d1, int d2, int d3) {
			if (d1 == _dim1 && d2 == _dim2 && d3 == _dim3)
				return;
			if (d1 > 0 && d2 > 0 && d3 > 0) {
				_dim1 = d1; _dim2 = d2; _dim3 = d3;
				_data.assign(d1 * d2 * d3, Type{});
				BuildPointers();
			} else {
				_dim1 = _dim2 = _dim3 = 0;
				_data.clear();
				_rows.clear();
				_slices.clear();
			}
		}

		/// @brief Resizes the tensor and initializes to a value.
		/// @param d1 New first dimension.
		/// @param d2 New second dimension.
		/// @param d3 New third dimension.
		/// @param initVal Value to initialize all elements.
		void Resize(int d1, int d2, int d3, const Type& initVal) {
			if (d1 > 0 && d2 > 0 && d3 > 0) {
				_dim1 = d1; _dim2 = d2; _dim3 = d3;
				_data.assign(d1 * d2 * d3, initVal);
				BuildPointers();
			} else {
				_dim1 = _dim2 = _dim3 = 0;
				_data.clear();
				_rows.clear();
				_slices.clear();
			}
		}
		/// /** @} */


		/// /** @name Comparison Operators
		/// @{ */

		/// @brief Checks equality (dimensions and all elements).
		bool operator==(const Matrix3D& other) const {
			if (_dim1 != other._dim1 || _dim2 != other._dim2 || _dim3 != other._dim3)
				return false;
			return _data == other._data;
		}

		/// @brief Checks inequality.
		bool operator!=(const Matrix3D& other) const { return !(*this == other); }
		/// /** @} */


		/// /** @name Scalar Operations
		/// @{ */

		/// @brief In-place scalar multiplication.
		Matrix3D& operator*=(const Type& scalar) {
			for (auto& elem : _data) elem *= scalar;
			return *this;
		}

		/// @brief In-place scalar division.
		Matrix3D& operator/=(const Type& scalar) {
			for (auto& elem : _data) elem /= scalar;
			return *this;
		}

		/// @brief In-place scalar addition.
		Matrix3D& operator+=(const Type& scalar) {
			for (auto& elem : _data) elem += scalar;
			return *this;
		}

		/// @brief Scalar multiplication returning new tensor.
		Matrix3D operator*(const Type& scalar) const {
			Matrix3D r(*this);
			r *= scalar;
			return r;
		}

		/// @brief Scalar division returning new tensor.
		Matrix3D operator/(const Type& scalar) const {
			Matrix3D r(*this);
			r /= scalar;
			return r;
		}

		/// @brief Scalar addition returning new tensor.
		Matrix3D operator+(const Type& scalar) const {
			Matrix3D r(*this);
			r += scalar;
			return r;
		}
		/// /** @} */


		/// /** @name Element-wise Operations
		/// @{ */

		/// @brief In-place element-wise addition.
		/// @param other Tensor with matching dimensions.
		/// @throws MatrixDimensionError If dimensions don't match.
		Matrix3D& operator+=(const Matrix3D& other) {
			if (_dim1 != other._dim1 || _dim2 != other._dim2 || _dim3 != other._dim3)
				throw MatrixDimensionError("Matrix3D dimensions must match for addition");
			for (int i = 0, n = size(); i < n; ++i)
				_data[i] += other._data[i];
			return *this;
		}

		/// @brief In-place element-wise subtraction.
		/// @param other Tensor with matching dimensions.
		/// @throws MatrixDimensionError If dimensions don't match.
		Matrix3D& operator-=(const Matrix3D& other) {
			if (_dim1 != other._dim1 || _dim2 != other._dim2 || _dim3 != other._dim3)
				throw MatrixDimensionError("Matrix3D dimensions must match for subtraction");
			for (int i = 0, n = size(); i < n; ++i)
				_data[i] -= other._data[i];
			return *this;
		}

		/// @brief Element-wise addition returning new tensor.
		Matrix3D operator+(const Matrix3D& other) const {
			Matrix3D r(*this);
			r += other;
			return r;
		}

		/// @brief Element-wise subtraction returning new tensor.
		Matrix3D operator-(const Matrix3D& other) const {
			Matrix3D r(*this);
			r -= other;
			return r;
		}
		/// /** @} */


		/// /** @name String Output
		/// @{ */

		/// @brief Returns brief string representation "Matrix3D[d1×d2×d3]".
		std::string ToString() const {
			std::ostringstream oss;
			oss << "Matrix3D[" << _dim1 << "×" << _dim2 << "×" << _dim3 << "]";
			return oss.str();
		}

		/// @brief Returns detailed string representation with all elements.
		/// @param precision Decimal places for floating-point output.
		std::string ToStringFull(int precision = 4) const {
			std::ostringstream oss;
			oss << std::fixed << std::setprecision(precision);
			oss << "Matrix3D[" << _dim1 << "×" << _dim2 << "×" << _dim3 << "]:\n";
			for (int i = 0; i < _dim1; ++i) {
				oss << "Slice " << i << ":\n";
				for (int j = 0; j < _dim2; ++j) {
					oss << "  [";
					for (int k = 0; k < _dim3; ++k) {
						if (k > 0)
							oss << ", ";
						oss << _data[(i * _dim2 + j) * _dim3 + k];
					}
					oss << "]\n";
				}
			}
			return oss.str();
		}

		/// @brief Stream output operator.
		friend std::ostream& operator<<(std::ostream& os, const Matrix3D& m) { return os << m.ToString(); }
		/// /** @} */
	};

	/// /** @name Type Aliases
	/// @{ */

	using Matrix3Dd = Matrix3D<double>; ///< Double-precision 3D tensor
	using Matrix3Df = Matrix3D<float>;	///< Single-precision 3D tensor
	using Matrix3Di = Matrix3D<int>;	///< Integer 3D tensor
										/// /** @} */

} // namespace MML


