// Standard headers - include what we use

namespace MML 
{
	/// @brief Allocation limits for symmetric matrices.
	/// @details Prevents accidental allocation of excessively large matrices.

	struct MatrixSymLimits {
		static constexpr int MAX_DIMENSION = 10000;				 ///< Maximum matrix dimension
		static constexpr size_t MAX_ELEMENTS = 50'000'000; ///< Maximum storage elements
	};

	/// @brief Symmetric matrix with optimized compact storage.
	/// @details MatrixSym stores only the lower triangular elements of a symmetric
	/// matrix, automatically providing symmetric access through operator(). This
	/// reduces storage to n(n+1)/2 elements for an n×n matrix.
	/// **Indexing:** For elements (i,j), the class automatically handles the
	/// symmetry: accessing (i,j) or (j,i) returns the same stored value.
	/// @tparam Type Element type (typically Real, float, or Complex)

	template<class Type>
	class MatrixSym 
	{
	private:
		int _dim;								 ///< Matrix dimension (rows = cols = _dim)
		std::vector<Type> _data; ///< Contiguous storage for lower triangular elements

		/// @brief Computes number of stored elements for given dimension.
		/// @param dim Matrix dimension.
		/// @return n(n+1)/2 elements for n×n matrix.

		static constexpr size_t numElements(int dim) noexcept { return static_cast<size_t>(dim) * (dim + 1) / 2; }

		/// @brief Computes linear index into storage array.
		/// @param i Row index.
		/// @param j Column index.
		/// @return Index into _data array (automatically handles i < j by swapping).
		/// @details Storage layout: row-wise lower triangular
		/// [a₀₀, a₁₀, a₁₁, a₂₀, a₂₁, a₂₂, ...]

		static constexpr size_t linearIndex(int i, int j) noexcept {
			// Ensure i >= j for lower triangular access
			if (i < j)
				std::swap(i, j);
			return static_cast<size_t>(i) * (i + 1) / 2 + j;
		}

		/// @brief Validates dimension against limits.
		void validateDimension(int dim) const {
			if (dim < 0)
				throw MatrixDimensionError("MatrixSym: dimension cannot be negative", dim, -1, -1, -1);
			if (dim > MatrixSymLimits::MAX_DIMENSION)
				throw MatrixDimensionError("MatrixSym: dimension exceeds maximum allowed", dim, MatrixSymLimits::MAX_DIMENSION, -1, -1);

			size_t requiredElements = numElements(dim);
			if (requiredElements > MatrixSymLimits::MAX_ELEMENTS)
				throw MatrixAllocationError("MatrixSym: allocation would exceed maximum elements", dim, -1);
		}

	public:
		typedef Type value_type; ///< Element type alias for STL compatibility

		/// @brief Default constructor - creates empty (0×0) matrix.
		MatrixSym() noexcept
				: _dim(0)
				, _data() {}

		/// @brief Dimension constructor - creates dim×dim matrix initialized to zero.
		/// @param dim Matrix dimension.
		/// @throws MatrixDimensionError If dim < 0 or exceeds limits.
		explicit MatrixSym(int dim)
				: _dim(0)
				, _data() {
			if (dim == 0)
				return;

			validateDimension(dim);
			_dim = dim;
			_data.resize(numElements(dim), Type{0});
		}

		/// @brief Dimension + value constructor - creates matrix initialized to val.
		/// @param dim Matrix dimension.
		/// @param val Initial value for all stored elements.
		MatrixSym(int dim, Type val)
				: _dim(0)
				, _data() {
			if (dim == 0)
				return;

			validateDimension(dim);
			_dim = dim;
			_data.resize(numElements(dim), val);
		}

		/// @brief Initializer list constructor - takes lower triangular elements row-wise.
		/// @param dim Matrix dimension.
		/// @param values Lower triangular elements: {a₀₀, a₁₀, a₁₁, a₂₀, a₂₁, a₂₂, ...}
		/// @throws MatrixDimensionError If values.size() != dim(dim+1)/2.
		/// @code
		/// MatrixSym<double> S(3, {1, 2, 3, 4, 5, 6});
		/// // Creates symmetric matrix:
		/// // [1, 2, 4]
		/// // [2, 3, 5]
		/// // [4, 5, 6]
		/// @endcode

		MatrixSym(int dim, std::initializer_list<Type> values)
				: _dim(0)
				, _data() {
			if (dim == 0) {
				if (values.size() != 0)
					throw MatrixDimensionError("MatrixSym: non-empty initializer for zero dimension", 0, -1, -1, -1);
				return;
			}

			validateDimension(dim);

			size_t expected = numElements(dim);
			if (values.size() != expected)
				throw MatrixDimensionError("MatrixSym: initializer list size mismatch - expected " + std::to_string(expected) + " but got " +
																		 std::to_string(values.size()),
																	 dim, -1, static_cast<int>(values.size()), -1);

			_dim = dim;
			_data.assign(values.begin(), values.end());
		}

		/// @brief Copy constructor.
		MatrixSym(const MatrixSym& other)
				: _dim(other._dim)
				, _data(other._data) {}

		/// @brief Move constructor.
		MatrixSym(MatrixSym&& other) noexcept
				: _dim(other._dim)
				, _data(std::move(other._data)) {
			other._dim = 0;
		}

		/// @brief Destructor - default is fine with std::vector.
		~MatrixSym() = default;
		/// /** @} */


		/// /** @name Dimension Accessors
		/// @{ */


		/// @brief Returns matrix dimension (rows = cols = Dim()).
		int Dim() const noexcept { return _dim; }

		/// @brief Returns number of rows (preferred API).
		int rows() const noexcept { return _dim; }

		/// @brief Returns number of columns (preferred API).
		int cols() const noexcept { return _dim; }

		/// @brief Returns number of stored elements: n(n+1)/2.
		size_t size() const noexcept { return _data.size(); }

		/// @brief Checks if matrix is empty (0×0).
		bool empty() const noexcept { return _dim == 0; }

		/// @brief Raw data pointer for interoperability with libraries.
		Type* data() noexcept { return _data.data(); }

		/// @brief Raw data pointer (const) for interoperability.
		const Type* data() const noexcept { return _data.data(); }


		/// @brief Resizes the matrix, destroying existing data.
		/// @param newDim New matrix dimension.
		void Resize(int newDim) {
			if (newDim == _dim)
				return;

			if (newDim == 0) {
				_dim = 0;
				_data.clear();
				return;
			}

			validateDimension(newDim);
			_dim = newDim;
			_data.assign(numElements(newDim), Type{0});
		}

		/// @brief Resizes the matrix with optional data preservation.
		/// @param newDim New matrix dimension.
		/// @param preserveData If true, preserves overlapping elements.
		void Resize(int newDim, bool preserveData) {
			if (!preserveData || _dim == 0) {
				Resize(newDim);
				return;
			}

			if (newDim == _dim)
				return;

			if (newDim == 0) {
				_dim = 0;
				_data.clear();
				return;
			}

			validateDimension(newDim);

			// Create new storage
			std::vector<Type> newData(numElements(newDim), Type{0});

			// Copy existing elements where dimensions overlap
			int minDim = std::min(_dim, newDim);
			for (int i = 0; i < minDim; ++i) {
				for (int j = 0; j <= i; ++j) {
					size_t oldIdx = linearIndex(i, j);
					size_t newIdx = static_cast<size_t>(i) * (i + 1) / 2 + j;
					newData[newIdx] = _data[oldIdx];
				}
			}

			_dim = newDim;
			_data = std::move(newData);
		}

		/// @brief Sets all elements to zero.
		void SetToZero() noexcept { std::fill(_data.begin(), _data.end(), Type{0}); }

		/// @brief Sets all elements to a specified value.
		void SetToValue(Type val) noexcept { std::fill(_data.begin(), _data.end(), val); }

		/// @brief Tolerance-based equality comparison.
		/// @param b Matrix to compare with.
		/// @param eps Maximum allowed element difference.
		/// @return True if dimensions match and all elements are within tolerance.
		bool IsEqualTo(const MatrixSym& b, Real eps = Defaults::MatrixIsEqualTolerance) const {
			if (_dim != b._dim)
				return false;

			for (size_t i = 0; i < _data.size(); ++i) {
				if (Abs(_data[i] - b._data[i]) > eps)
					return false;
			}
			return true;
		}

		/// @brief Static helper for tolerance-based comparison.
		static bool AreEqual(const MatrixSym& a, const MatrixSym& b, Real eps = Defaults::MatrixIsEqualTolerance) {
			return a.IsEqualTo(b, eps);
		}

		/// @brief Converts to full Matrix representation.
		/// @return n×n Matrix with symmetric values filled in.
		Matrix<Type> GetAsMatrix() const {
			if (_dim == 0)
				return Matrix<Type>();

			Matrix<Type> ret(_dim, _dim);
			for (int i = 0; i < _dim; ++i) {
				for (int j = 0; j < _dim; ++j) {
					ret(i, j) = (*this)(i, j);
				}
			}
			return ret;
		}

		/// @brief Creates symmetric matrix from lower triangular part of a matrix.
		/// @param m Source matrix (must be square).
		/// @return MatrixSym containing m's lower triangular elements.
		/// @throws MatrixDimensionError If m is not square.
		static MatrixSym FromLower(const Matrix<Type>& m) {
			if (m.rows() != m.cols())
				throw MatrixDimensionError("MatrixSym::FromLower - must be square matrix", m.rows(), m.cols(), -1, -1);

			int dim = m.rows();
			if (dim == 0)
				return MatrixSym();

			MatrixSym ret(dim);
			for (int i = 0; i < dim; ++i) {
				for (int j = 0; j <= i; ++j) {
					ret(i, j) = m(i, j);
				}
			}
			return ret;
		}

		/// @brief Creates symmetric matrix from upper triangular part of a matrix.
		/// @param m Source matrix (must be square).
		/// @return MatrixSym containing m's upper triangular elements (transposed).
		/// @throws MatrixDimensionError If m is not square.
		static MatrixSym FromUpper(const Matrix<Type>& m) {
			if (m.rows() != m.cols())
				throw MatrixDimensionError("MatrixSym::FromUpper - must be square matrix", m.rows(), m.cols(), -1, -1);

			int dim = m.rows();
			if (dim == 0)
				return MatrixSym();

			MatrixSym ret(dim);
			for (int i = 0; i < dim; ++i) {
				for (int j = i; j < dim; ++j) {
					// a(i,j) from upper = a(j,i) in storage = a(i,j) symmetric
					ret(j, i) = m(i, j); // Transpose to lower
				}
			}
			return ret;
		}

		/// @brief Creates symmetric matrix as (M + Mᵀ) / 2.
		/// @param m Source matrix (must be square).
		/// @return MatrixSym containing symmetrized version of m.
		/// @throws MatrixDimensionError If m is not square.
		/// @note This is the standard way to symmetrize an arbitrary matrix.
		static MatrixSym FromFullMatrix(const Matrix<Type>& m) {
			if (m.rows() != m.cols())
				throw MatrixDimensionError("MatrixSym::FromFullMatrix - must be square matrix", m.rows(), m.cols(), -1, -1);

			int dim = m.rows();
			if (dim == 0)
				return MatrixSym();

			MatrixSym ret(dim);
			for (int i = 0; i < dim; ++i) {
				for (int j = 0; j <= i; ++j) {
					ret(i, j) = (m(i, j) + m(j, i)) / Type{2};
				}
			}
			return ret;
		}

		/// @brief Creates identity matrix of given dimension.
		/// @param dim Matrix dimension.
		/// @return dim×dim identity matrix (1s on diagonal).
		static MatrixSym Identity(int dim) {
			MatrixSym ret(dim); // Initializes to zero
			for (int i = 0; i < dim; ++i) {
				ret(i, i) = Type{1};
			}
			return ret;
		}

		/// @brief Creates diagonal matrix from vector.
		/// @param diag Vector of diagonal elements.
		/// @return dim×dim diagonal matrix where dim = diag.size().
		static MatrixSym GetDiagonalMatrix(const Vector<Type>& diag) {
			int dim = static_cast<int>(diag.size());
			MatrixSym ret(dim); // Initializes to zero
			for (int i = 0; i < dim; ++i) {
				ret(i, i) = diag[i];
			}
			return ret;
		}

		/// @brief Extracts a row as a vector.
		/// @param rowInd Row index (0-based).
		/// @return Vector of _dim elements.
		/// @throws MatrixAccessBoundsError If rowInd out of range.
		Vector<Type> VectorFromRow(int rowInd) const {
			if (rowInd < 0 || rowInd >= _dim)
				throw MatrixAccessBoundsError("VectorFromRow - row index out of bounds", rowInd, 0, _dim, _dim);

			Vector<Type> ret(_dim);
			for (int j = 0; j < _dim; ++j) {
				ret[j] = (*this)(rowInd, j);
			}
			return ret;
		}

		/// @brief Extracts a column as a vector.
		/// @param colInd Column index (0-based).
		/// @return Vector of _dim elements.
		/// @throws MatrixAccessBoundsError If colInd out of range.
		/// @note For symmetric matrices, VectorFromColumn(i) == VectorFromRow(i).
		Vector<Type> VectorFromColumn(int colInd) const {
			if (colInd < 0 || colInd >= _dim)
				throw MatrixAccessBoundsError("VectorFromColumn - column index out of bounds", 0, colInd, _dim, _dim);

			Vector<Type> ret(_dim);
			for (int i = 0; i < _dim; ++i) {
				ret[i] = (*this)(i, colInd);
			}
			return ret;
		}

		/// @brief Extracts the main diagonal as a vector.
		Vector<Type> VectorFromDiagonal() const {
			Vector<Type> ret(_dim);
			for (int i = 0; i < _dim; ++i) {
				ret[i] = (*this)(i, i);
			}
			return ret;
		}

		/// @brief Computes trace (sum of diagonal elements).
		/// @return @f$ \text{tr}(A) = \sum_{i=0}^{n-1} a_{ii} @f$
		Type Trace() const noexcept {
			Type sum{0};
			for (int i = 0; i < _dim; ++i) {
				sum += (*this)(i, i);
			}
			return sum;
		}

		/// @brief Computes Frobenius norm.
		/// @return @f$ \|A\|_F = \sqrt{\sum_{i,j} |a_{ij}|^2} @f$
		/// @note Off-diagonal elements are counted twice (once from each triangle).
		Real NormFrobenius() const {
			Real sum{0}; // Norm is always real, even for complex matrices
			for (int i = 0; i < _dim; ++i) {
				// Diagonal element: use |a|^2
				if constexpr (std::is_same_v<Type, Complex> || std::is_same_v<Type, std::complex<float>> ||
											std::is_same_v<Type, std::complex<long double>>) {
					sum += std::norm((*this)(i, i));
					// Off-diagonal elements (counted twice in full matrix)
					for (int j = 0; j < i; ++j) {
						sum += Real{2} * std::norm((*this)(i, j));
					}
				} else {
					sum += (*this)(i, i) * (*this)(i, i);
					// Off-diagonal elements (counted twice in full matrix)
					for (int j = 0; j < i; ++j) {
						sum += Real{2} * (*this)(i, j) * (*this)(i, j);
					}
				}
			}
			return std::sqrt(sum);
		}

		/// @brief Computes infinity norm (maximum absolute row sum).
		/// @return @f$ \|A\|_\infty = \max_i \sum_j |a_{ij}| @f$
		Real NormInf() const {
			Real maxSum{0}; // Norm is always real
			for (int i = 0; i < _dim; ++i) {
				Real rowSum{0};
				for (int j = 0; j < _dim; ++j) {
					rowSum += Abs((*this)(i, j));
				}
				if (rowSum > maxSum)
					maxSum = rowSum;
			}
			return maxSum;
		}

		/// @brief Computes 1-norm (maximum absolute column sum).
		/// @return @f$ \|A\|_1 = \max_j \sum_i |a_{ij}| @f$
		/// @note For symmetric matrices, Norm1() == NormInf().

		Real Norm1() const {
			return NormInf(); // Symmetric property: row sum = column sum
		}

		/// @brief Copy assignment.
		MatrixSym& operator=(const MatrixSym& other) {
			if (this != &other) {
				_dim = other._dim;
				_data = other._data;
			}
			return *this;
		}

		/// @brief Move assignment.
		MatrixSym& operator=(MatrixSym&& other) noexcept {
			if (this != &other) {
				_dim = other._dim;
				_data = std::move(other._data);
				other._dim = 0;
			}
			return *this;
		}

		/// @brief Element access (const) without bounds checking.
		/// @param i Row index.
		/// @param j Column index.
		/// @return Element at (i, j), automatically handling symmetry.
		Type operator()(int i, int j) const noexcept { return _data[linearIndex(i, j)]; }

		/// @brief Element access (non-const) without bounds checking.
		/// @param i Row index.
		/// @param j Column index.
		/// @return Reference to stored element (setting (i,j) also sets (j,i)).
		Type& operator()(int i, int j) noexcept { return _data[linearIndex(i, j)]; }

		/// @brief Bounds-checked element access (const).
		/// @param i Row index.
		/// @param j Column index.
		/// @return Element at (i, j).
		/// @throws MatrixAccessBoundsError If indices out of range.

		const Type& at(int i, int j) const {
			if (i < 0 || i >= _dim || j < 0 || j >= _dim)
				throw MatrixAccessBoundsError("MatrixSym::at", i, j, _dim, _dim);
			return _data[linearIndex(i, j)];
		}

		/// @brief Bounds-checked element access (non-const).
		/// @param i Row index.
		/// @param j Column index.
		/// @return Reference to stored element.
		/// @throws MatrixAccessBoundsError If indices out of range.

		Type& at(int i, int j) {
			if (i < 0 || i >= _dim || j < 0 || j >= _dim)
				throw MatrixAccessBoundsError("MatrixSym::at", i, j, _dim, _dim);
			return _data[linearIndex(i, j)];
		}


		/// /** @name Arithmetic Operators

		/// @brief Matrix addition (returns symmetric result).
		MatrixSym operator+(const MatrixSym& b) const {
			if (_dim != b._dim)
				throw MatrixDimensionError("MatrixSym::operator+ - dimensions must match", _dim, -1, b._dim, -1);

			MatrixSym ret(_dim);
			for (size_t i = 0; i < _data.size(); ++i) {
				ret._data[i] = _data[i] + b._data[i];
			}
			return ret;
		}

		/// @brief In-place matrix addition.
		MatrixSym& operator+=(const MatrixSym& b) {
			if (_dim != b._dim)
				throw MatrixDimensionError("MatrixSym::operator+= - dimensions must match", _dim, -1, b._dim, -1);

			for (size_t i = 0; i < _data.size(); ++i) {
				_data[i] += b._data[i];
			}
			return *this;
		}

		/// @brief Unary negation.
		MatrixSym operator-() const {
			MatrixSym ret(_dim);
			for (size_t i = 0; i < _data.size(); ++i) {
				ret._data[i] = -_data[i];
			}
			return ret;
		}

		/// @brief Matrix subtraction (returns symmetric result).
		MatrixSym operator-(const MatrixSym& b) const {
			if (_dim != b._dim)
				throw MatrixDimensionError("MatrixSym::operator- - dimensions must match", _dim, -1, b._dim, -1);

			MatrixSym ret(_dim);
			for (size_t i = 0; i < _data.size(); ++i) {
				ret._data[i] = _data[i] - b._data[i];
			}
			return ret;
		}

		/// @brief In-place matrix subtraction.
		MatrixSym& operator-=(const MatrixSym& b) {
			if (_dim != b._dim)
				throw MatrixDimensionError("MatrixSym::operator-= - dimensions must match", _dim, -1, b._dim, -1);

			for (size_t i = 0; i < _data.size(); ++i) {
				_data[i] -= b._data[i];
			}
			return *this;
		}

		/// @brief Symmetric-symmetric matrix multiplication.
		/// @param b Right-hand symmetric matrix.
		/// @return Regular Matrix (product is NOT symmetric in general).
		/// @throws MatrixDimensionError If dimensions don't match.
		/// @note Returns Matrix, not MatrixSym, because A*B is not symmetric even if A and B are.
		Matrix<Type> operator*(const MatrixSym& b) const {
			if (_dim != b._dim)
				throw MatrixDimensionError("MatrixSym::operator*(MatrixSym) - dimensions must match", _dim, _dim, b._dim, b._dim);

			Matrix<Type> ret(_dim, _dim);
			for (int i = 0; i < _dim; ++i) {
				for (int j = 0; j < _dim; ++j) {
					Type sum{0};
					for (int k = 0; k < _dim; ++k) {
						sum += (*this)(i, k) * b(k, j);
					}
					ret(i, j) = sum;
				}
			}
			return ret;
		}

		/// @brief Symmetric-matrix multiplication.
		/// @param b Right-hand general matrix.
		/// @return Regular Matrix of size (dim × b.cols()).
		/// @throws MatrixDimensionError If dimensions don't match.
		Matrix<Type> operator*(const Matrix<Type>& b) const {
			if (_dim != b.rows())
				throw MatrixDimensionError("MatrixSym::operator*(Matrix) - dimension mismatch", _dim, _dim, b.rows(), b.cols());

			Matrix<Type> ret(_dim, b.cols());
			for (int i = 0; i < _dim; ++i) {
				for (int j = 0; j < b.cols(); ++j) {
					Type sum{0};
					for (int k = 0; k < _dim; ++k) {
						sum += (*this)(i, k) * b(k, j);
					}
					ret(i, j) = sum;
				}
			}
			return ret;
		}

		/// @brief Scalar multiplication (A * scalar).
		friend MatrixSym operator*(const MatrixSym& a, Type scalar) {
			MatrixSym ret(a._dim);
			for (size_t i = 0; i < a._data.size(); ++i) {
				ret._data[i] = a._data[i] * scalar;
			}
			return ret;
		}

		/// @brief Scalar multiplication (scalar * A, commutative).
		friend MatrixSym operator*(Type scalar, const MatrixSym& a) { return a * scalar; }

		/// @brief In-place scalar multiplication.
		MatrixSym& operator*=(Type scalar) {
			for (auto& elem : _data) {
				elem *= scalar;
			}
			return *this;
		}

		/// @brief Scalar division (A / scalar).
		friend MatrixSym operator/(const MatrixSym& a, Type scalar) {
			MatrixSym ret(a._dim);
			for (size_t i = 0; i < a._data.size(); ++i) {
				ret._data[i] = a._data[i] / scalar;
			}
			return ret;
		}

		/// @brief In-place scalar division.
		MatrixSym& operator/=(Type scalar) {
			for (auto& elem : _data) {
				elem /= scalar;
			}
			return *this;
		}

		/// @brief Matrix-vector multiplication (A * v).
		/// @param a Symmetric matrix.
		/// @param v Column vector.
		/// @return Result vector A·v.
		/// @throws MatrixDimensionError If dimensions don't match.
		friend Vector<Type> operator*(const MatrixSym& a, const Vector<Type>& v) {
			if (a._dim != static_cast<int>(v.size()))
				throw MatrixDimensionError("operator*(MatrixSym, Vector) - dimension mismatch", a._dim, a._dim, static_cast<int>(v.size()), -1);

			Vector<Type> ret(a._dim);
			for (int i = 0; i < a._dim; ++i) {
				Type sum{0};
				for (int j = 0; j < a._dim; ++j) {
					sum += a(i, j) * v[j];
				}
				ret[i] = sum;
			}
			return ret;
		}

		/// @brief Row vector times matrix (vᵀ * A).
		/// @param v Row vector.
		/// @param a Symmetric matrix.
		/// @return Result vector vᵀ·A.
		/// @throws MatrixDimensionError If dimensions don't match.
		/// @note For symmetric A: v*A == A*v.
		friend Vector<Type> operator*(const Vector<Type>& v, const MatrixSym& a) {
			if (static_cast<int>(v.size()) != a._dim)
				throw MatrixDimensionError("operator*(Vector, MatrixSym) - dimension mismatch", static_cast<int>(v.size()), -1, a._dim, a._dim);

			Vector<Type> ret(a._dim);
			for (int j = 0; j < a._dim; ++j) {
				Type sum{0};
				for (int i = 0; i < a._dim; ++i) {
					sum += v[i] * a(i, j);
				}
				ret[j] = sum;
			}
			return ret;
		}

		/// @brief Computes the inverse of the matrix.
		/// @return Inverse as a general Matrix (inverse of symmetric is symmetric, but returned as Matrix).
		/// @throws MatrixDimensionError If matrix is empty.
		/// @throws SingularMatrixError If matrix is singular.
		/// @note Converts to Matrix, inverts, and returns result.
		Matrix<Type> GetInverse() const {
			if (_dim == 0)
				throw MatrixDimensionError("MatrixSym::GetInverse - cannot invert empty matrix", 0, 0, -1, -1);

			Matrix<Type> a = GetAsMatrix();
			a.Invert();
			return a;
		}

		/// @brief Converts matrix to formatted string.
		/// @param width Field width for each element (default 10).
		/// @param precision Decimal precision (default 3).
		/// @return Formatted string representation.
		std::string to_string(int width = 10, int precision = 3) const {
			std::stringstream str;
			Print(str, width, precision);
			return str.str();
		}

		/// @brief Prints matrix with configurable formatting.
		/// @param stream Output stream.
		/// @param fmt MatrixPrintFormat specifying width, precision, brackets, etc.
		/// @see MatrixPrintFormat For format options.
		void Print(std::ostream& stream, const MatrixPrintFormat& fmt = MatrixPrintFormat::Default()) const {
			if (fmt.showHeader) {
				stream << "Rows: " << _dim << " Cols: " << _dim << " (Symmetric)" << std::endl;
			}

			std::ios_base::fmtflags oldFlags = stream.flags();
			if (fmt.scientific)
				stream << std::scientific;
			else if (fmt.fixed)
				stream << std::fixed;

			// Compact mode for small matrices
			if (fmt.compactMode && _dim <= 3) {
				if (fmt.showBrackets)
					stream << "[";
				for (int i = 0; i < _dim; ++i) {
					if (i > 0)
						stream << "; ";
					for (int j = 0; j < _dim; ++j) {
						if (j > 0)
							stream << fmt.delimiter;
						stream << std::setw(fmt.width) << std::setprecision(fmt.precision) << (*this)(i, j);
					}
				}
				if (fmt.showBrackets)
					stream << "]";
				stream << std::endl;
			} else {
				// Normal multi-line mode
				for (int i = 0; i < _dim; ++i) {
					if (fmt.showBrackets)
						stream << "[ ";
					for (int j = 0; j < _dim; ++j) {
						stream << std::setw(fmt.width) << std::setprecision(fmt.precision) << (*this)(i, j);
						if (j < _dim - 1)
							stream << fmt.delimiter;
					}
					if (fmt.showBrackets)
						stream << " ]";
					if (i < _dim - 1)
						stream << std::endl;
				}
			}

			stream.flags(oldFlags);
		}

		/// @brief Print with explicit width and precision.
		/// @param stream Output stream.
		/// @param width Field width.
		/// @param precision Decimal precision.

		void Print(std::ostream& stream, int width, int precision) const {
			MatrixPrintFormat fmt = MatrixPrintFormat::Default();
			fmt.width = width;
			fmt.precision = precision;
			Print(stream, fmt);
		}

		/// @brief Stream output operator (default formatting).
		friend std::ostream& operator<<(std::ostream& stream, const MatrixSym& a) {
			a.Print(stream, 10, 3);
			return stream;
		}
	};
} // namespace MML

///////////////////////////   mml/base/Matrix/MatrixTriDiag.h   ///////////////////////////




// Standard headers - include what we use

namespace MML
{
	template<class Type>
	class TridiagonalMatrix
	{
	private:
		int _dim;
		Vector<Type> _belowDiag;
		Vector<Type> _diag;
		Vector<Type> _aboveDiag;

	public:
		TridiagonalMatrix(int dim, const Vector<Type>& a, const Vector<Type>& diag, const Vector<Type>& c) : _belowDiag(a), _diag(diag), _aboveDiag(c), _dim(dim)
		{
			if( dim < 3)
				throw MatrixDimensionError("TridiagonalMatrix constructor: dimension must be >= 3");

			if (a.size() != dim || diag.size() != dim || c.size() != dim)
				throw MatrixDimensionError("TridiagonalMatrix constructor: vector dimensions must match matrix dimension");
		}

		TridiagonalMatrix(int dim, std::initializer_list<Type> values) : _dim(dim), _belowDiag(dim), _diag(dim), _aboveDiag(dim)
		{
			if (values.size() != dim * 3 - 2)
				throw MatrixDimensionError("TridiagonalMatrix constructor: initializer list size must be 3*dim-2");

			auto val = values.begin();
			_belowDiag[0] = 0.0;
			_diag[0] = *val++;
			_aboveDiag[0] = *val++;
			for (int i = 1; i < dim - 1; ++i)
			{
				_belowDiag[i] = *val++;
				_diag[i] = *val++;
				_aboveDiag[i] = *val++;
			}
			_belowDiag[dim - 1] = *val++;
			_diag[dim - 1] = *val++;
			_aboveDiag[dim - 1] = 0.0;
		}

		int rows() const noexcept { return _dim; }
		int cols() const noexcept { return _dim; }

		Type  operator()(int i, int j) const {
			if (i == j)
				return _diag[i];
			else if (i == j - 1)
				return _aboveDiag[i];
			else if (i == j + 1 && j < _dim - 1)
				return _belowDiag[i];
			else
				return 0.0;
		}
		Type& operator()(int i, int j) {
			if (i == j)
				return _diag[i];
			else if (i == j - 1)
				return _aboveDiag[i];
			else if (i == j + 1 && j < _dim - 1)
				return _belowDiag[i];
			else
				throw MatrixAccessBoundsError("TridiagonalMatrix::operator()", i, j, _dim, _dim);
		}

		bool IsEqualTo(const TridiagonalMatrix& b, Type eps = Defaults::MatrixIsEqualTolerance) const
		{
			if (_dim != b._dim)
				return false;

			for (int i = 0; i < _dim; i++) {
				if (std::abs(_diag[i] - b._diag[i]) > eps)
					return false;
				if (std::abs(_belowDiag[i] - b._belowDiag[i]) > eps)
					return false;
				if (std::abs(_aboveDiag[i] - b._aboveDiag[i]) > eps)
					return false;
			}
			return true;
		}

		TridiagonalMatrix operator+(const TridiagonalMatrix& b) const
		{
			if (_dim != b._dim)
				throw MatrixDimensionError("TridiagonalMatrix::operator+() - must be same dim", _dim, _dim, b._dim, b._dim);

			TridiagonalMatrix temp(*this);
			for (int i = 0; i < _belowDiag.size(); i++)
				temp._belowDiag[i] += b._belowDiag[i];
			for (int i = 0; i < _diag.size(); i++)
				temp._diag[i] += b._diag[i];
			for (int i = 0; i < _aboveDiag.size(); i++)
				temp._aboveDiag[i] += b._aboveDiag[i];

			return temp;
		}
		TridiagonalMatrix operator-(const TridiagonalMatrix& b) const
		{
			if (_dim != b._dim)
				throw MatrixDimensionError("TridiagonalMatrix::operator+() - must be same dim", _dim, _dim, b._dim, b._dim);

			TridiagonalMatrix temp(*this);
			for (int i = 0; i < _belowDiag.size(); i++)
				temp._belowDiag[i] -= b._belowDiag[i];
			for (int i = 0; i < _diag.size(); i++)
				temp._diag[i] -= b._diag[i];
			for (int i = 0; i < _aboveDiag.size(); i++)
				temp._aboveDiag[i] -= b._aboveDiag[i];

			return temp;
		}

		friend TridiagonalMatrix operator*(const TridiagonalMatrix& a, Type b)
		{
			int	i, j;
			TridiagonalMatrix	ret(a);

			for (int i = 0; i < ret._belowDiag.size(); i++)
				ret._belowDiag[i] *= b;
			for (int i = 0; i < ret._diag.size(); i++)
				ret._diag[i] *= b;
			for (int i = 0; i < ret._aboveDiag.size(); i++)
				ret._aboveDiag[i] *= b;

			return ret;
		}
		friend TridiagonalMatrix operator*(Type a, const TridiagonalMatrix& b)
		{
			int	i, j;
			TridiagonalMatrix	ret(b);

			for (int i = 0; i < ret._belowDiag.size(); i++)
				ret._belowDiag[i] *= a;
			for (int i = 0; i < ret._diag.size(); i++)
				ret._diag[i] *= a;
			for (int i = 0; i < ret._aboveDiag.size(); i++)
				ret._aboveDiag[i] *= a;

			return ret;
		}
		friend TridiagonalMatrix operator/(const TridiagonalMatrix& a, Type b)
		{
			int	i, j;
			TridiagonalMatrix	ret(a);

			for (int i = 0; i < ret._belowDiag.size(); i++)
				ret._belowDiag[i] /= b;
			for (int i = 0; i < ret._diag.size(); i++)
				ret._diag[i] /= b;
			for (int i = 0; i < ret._aboveDiag.size(); i++)
				ret._aboveDiag[i] /= b;

			return ret;
		}

		TridiagonalMatrix GetTranspose() const
		{
			// For a tridiagonal matrix, transpose swaps and shifts the above and below diagonals
			// belowDiag_new[i] = aboveDiag_old[i-1] (with belowDiag_new[0] = 0)
			// aboveDiag_new[i] = belowDiag_old[i+1] (with aboveDiag_new[dim-1] = 0)
			Vector<Type> newBelowDiag(_dim);
			Vector<Type> newAboveDiag(_dim);

			newBelowDiag[0] = 0.0;
			for (int i = 1; i < _dim; i++)
				newBelowDiag[i] = _aboveDiag[i - 1];

			for (int i = 0; i < _dim - 1; i++)
				newAboveDiag[i] = _belowDiag[i + 1];
			newAboveDiag[_dim - 1] = 0.0;

			return TridiagonalMatrix(_dim, newBelowDiag, _diag, newAboveDiag);
		}

		TridiagonalMatrix GetInverse() const
		{
			// For tridiagonal matrices, computing the exact inverse is complex
			// and often results in a full matrix (not tridiagonal)
			// This would require returning a full Matrix<Type> instead
			throw NotImplementedError("TridiagonalMatrix::GetInverse() - "
				"inverse of tridiagonal matrix is generally not tridiagonal. "
				"Use Matrix<Type> conversion or solve linear systems directly with Solve()");
		}

		void Solve(const Vector<Type>& rhs, Vector<Type>& sol)
		{
			int j, n = _belowDiag.size();
			Type bet;  // Must be Type to work with complex matrices
			Vector<Type> gam(n);

			// Compute scale-relative tolerance based on max diagonal magnitude
			Real maxDiag = Real{0};
			for (int i = 0; i < n; i++) {
				Real mag = std::abs(_diag[i]);
				if (mag > maxDiag) maxDiag = mag;
			}
			Real tol = maxDiag * std::numeric_limits<Real>::epsilon();
			if (tol < std::numeric_limits<Real>::epsilon())
				tol = std::numeric_limits<Real>::epsilon();

			if (std::abs(_diag[0]) < tol)
				throw SingularMatrixError("TridiagonalMatrix::Solve - zero pivot at element 0", 0, 0);

			sol[0] = rhs[0] / (bet = _diag[0]);

			for (j = 1; j < n; j++) {
				gam[j] = _aboveDiag[j - 1] / bet;
				bet = _diag[j] - _belowDiag[j] * gam[j];

				if (std::abs(bet) < tol)
					throw SingularMatrixError("TridiagonalMatrix::Solve - zero pivot during elimination", j, j);

				sol[j] = (rhs[j] - _belowDiag[j] * sol[j - 1]) / bet;
			}
			for (j = (n - 2); j >= 0; j--)
				sol[j] -= gam[j + 1] * sol[j + 1];
		}
		Vector<Type> Solve(const Vector<Type>& rhs)
		{
			Vector<Type> sol(rhs.size());
			Solve(rhs, sol);
			return sol;
		}

		// New formatted print with MatrixPrintFormat
		void Print(std::ostream& stream, const MatrixPrintFormat& fmt = MatrixPrintFormat::Default()) const
		{
			// Show header if requested
			if (fmt.showHeader) {
				stream << "Rows: " << _dim << " Cols: " << _dim << " (Tridiagonal)" << std::endl;
			}

			// Set formatting flags
			std::ios_base::fmtflags oldFlags = stream.flags();
			if (fmt.scientific)
				stream << std::scientific;
			else if (fmt.fixed)
				stream << std::fixed;

			// Compact mode - print on one line for small matrices
			if (fmt.compactMode && _dim <= 3) {
				if (fmt.showBrackets)
					stream << "[";
				for (int i = 0; i < _dim; i++) {
					if (i > 0) stream << "; ";
					for (int j = 0; j < _dim; j++) {
						if (j > 0) stream << fmt.delimiter;
						stream << std::setw(fmt.width) << std::setprecision(fmt.precision) << (*this)(i, j);
					}
				}
				if (fmt.showBrackets)
					stream << "]";
				stream << std::endl;
			}
			else {
				// Normal multi-line mode
				for (int i = 0; i < _dim; i++)
				{
					if (fmt.showBrackets)
						stream << "[ ";
					for (int j = 0; j < _dim; j++)
					{
						stream << std::setw(fmt.width) << std::setprecision(fmt.precision) << (*this)(i, j);
						if (j < _dim - 1)
							stream << fmt.delimiter;
					}
					if (fmt.showBrackets)
						stream << " ]";
					if (i < _dim - 1)
						stream << std::endl;
				}
			}

			// Restore original flags
			stream.flags(oldFlags);
		}

		/// @brief Print with explicit width and precision.
		void   Print(std::ostream& stream, int width, int precision) const
		{
			MatrixPrintFormat fmt = MatrixPrintFormat::Default();
			fmt.width = width;
			fmt.precision = precision;
			Print(stream, fmt);
		}
	};
}


///////////////////////////   mml/base/Matrix/MatrixBandDiag.h   ///////////////////////////




// Standard headers - include what we use

namespace MML {
	/// @brief Band diagonal matrix with compact storage.
	/// @ingroup Base
	/// Stores only the non-zero diagonal band, reducing memory from O(n²) to O(n·(m₁+m₂+1)).
	/// Supports efficient O(n) matrix-vector multiplication.
	/// @par Storage Convention
	/// Data is stored in a Matrix<Real> of size n × (m₁ + m₂ + 1):
	/// - Diagonal at column m₁
	/// - Subdiagonals at columns 0 to m₁-1
	/// - Superdiagonals at columns m₁+1 to m₁+m₂

	class BandDiagonalMatrix {
		// The array a[0..n-1][0..m1+m2] stores A as follows: The diagonal elements are in a[0..n-1][m1].
		// Subdiagonal elements are in a[j..n-1][0..m1-1] with j > 0 appropriate to the number of
		// elements on each subdiagonal. Superdiagonal elements are in a[0..j][m1+1..m1+m2] with
		// j < n-1 appropriate to the number of elements on each superdiagonal.
		int _dim;			///< Matrix dimension (n×n)
		int _m1, _m2;		///< Lower and upper bandwidth
		Matrix<Real> _data; ///< Compact storage of band elements

	public:
		/// /** @name Dimension Accessors
		/// @{ */


		/// @brief Returns the number of rows.
		int rows() const { return _dim; }

		/// @brief Returns the number of columns.
		int cols() const { return _dim; }
		/// /** @} */


		/// @brief Constructs a band diagonal matrix.
		/// @param dim Matrix dimension n (creates n×n matrix).
		/// @param m1 Lower bandwidth (number of subdiagonals).
		/// @param m2 Upper bandwidth (number of superdiagonals).
		/// @param data Compact storage matrix of size dim × (m1+m2+1).
		/// @throws Runtime error if data dimensions don't match.

		BandDiagonalMatrix(int dim, int m1, int m2, const Matrix<Real>& data)
			: _dim(dim)
			, _m1(m1)
			, _m2(m2)
			, _data(data) {
			if (data.rows() != dim || data.cols() != m1 + m2 + 1)
				throw MatrixDimensionError("BandDiagonalMatrix constructor: data dimensions must be dim x (m1+m2+1)");
		}

		/// /** @name Element Access
		/// @{ */


		/// @brief Const element access - returns 0 for elements outside the band.
		/// @param i Row index.
		/// @param j Column index.
		/// @return Element value (0 if outside band).

		Real operator()(int i, int j) const {
			if (i > j + _m1 || j > i + _m2)
				return 0.0;
			else
				return _data[i][j - i + _m1];
		}

		/// @brief Mutable element access - throws for elements outside the band.
		/// @param i Row index.
		/// @param j Column index.
		/// @return Reference to element.
		/// @throws MatrixAccessBoundsError If (i,j) is outside the band.

		Real& operator()(int i, int j) {
			if (i > j + _m1 || j > i + _m2)
				throw MatrixAccessBoundsError("BandDiagonalMatrix::operator()", i, j, _dim, _dim);
			else
				return _data[i][j - i + _m1];
		}
		/// /** @} */


		/// /** @name Matrix-Vector Operations
		/// @{ */


		/// @brief Matrix-vector multiplication optimized for band structure.
		/// Complexity: O(n · (m₁ + m₂ + 1)) instead of O(n²).
		/// @param x Input vector of size n.
		/// @return Result vector y = A·x.
		/// @throws ArgumentError If vector size doesn't match.

		Vector<Real> operator*(const Vector<Real>& x) const {
			if (x.size() != _dim)
				throw ArgumentError("BandDiagonalMatrix::operator* - Vector size mismatch");

			Vector<Real> result(_dim);
			for (int i = 0; i < _dim; i++) {
				Real sum = 0.0;
				// Only iterate over the band (non-zero elements)
				int j_start = std::max(0, i - _m1);
				int j_end = std::min(_dim - 1, i + _m2);

				for (int j = j_start; j <= j_end; j++) {
					sum += (*this)(i, j) * x[j];
				}
				result[i] = sum;
			}
			return result;
		}
		/// /** @} */


		/// /** @name Conversion and Query
		/// @{ */


		/// @brief Converts to full matrix representation.
		/// @return Dense n×n matrix with all elements (including zeros).
		/// @note Useful for debugging or interfacing with dense algorithms.

		Matrix<Real> ToFullMatrix() const {
			Matrix<Real> full(_dim, _dim);
			for (int i = 0; i < _dim; i++) {
				for (int j = 0; j < _dim; j++) {
					full[i][j] = (*this)(i, j);
				}
			}
			return full;
		}

		/// @brief Returns the lower bandwidth (number of subdiagonals).
		int GetLowerBandwidth() const { return _m1; }

		/// @brief Returns the upper bandwidth (number of superdiagonals).
		int GetUpperBandwidth() const { return _m2; }

		/// @brief Returns the matrix dimension.
		int GetDimension() const { return _dim; }

		/// @brief Checks if an element position is within the band.
		/// @param i Row index.
		/// @param j Column index.
		/// @return True if element can be non-zero.

		bool IsInBand(int i, int j) const { return !(i > j + _m1 || j > i + _m2); }
		/// /** @} */


		/// /** @name Arithmetic Operations
		/// @{ */


		/// @brief Scalar multiplication.
		BandDiagonalMatrix operator*(Real scalar) const {
			Matrix<Real> new_data = _data * scalar;
			return BandDiagonalMatrix(_dim, _m1, _m2, new_data);
		}

		/// @brief Scalar division.
		/// @throws DivisionByZeroError If scalar is near zero.

		BandDiagonalMatrix operator/(Real scalar) const {
			if (std::abs(scalar) < PrecisionValues<Real>::MatrixElementZeroThreshold)
				throw DivisionByZeroError("BandDiagonalMatrix::operator/ - Division by zero");
			Matrix<Real> new_data = _data / scalar;
			return BandDiagonalMatrix(_dim, _m1, _m2, new_data);
		}

		/// @brief Unary negation.
		BandDiagonalMatrix operator-() const {
			Matrix<Real> new_data = -_data;
			return BandDiagonalMatrix(_dim, _m1, _m2, new_data);
		}

		/// @brief Matrix addition (requires identical structure).
		/// @throws MatrixDimensionError If dimensions or bandwidth don't match.

		BandDiagonalMatrix operator+(const BandDiagonalMatrix& other) const {
			if (_dim != other._dim || _m1 != other._m1 || _m2 != other._m2)
				throw MatrixDimensionError("BandDiagonalMatrix::operator+ - Incompatible dimensions or bandwidth");

			Matrix<Real> new_data = _data + other._data;
			return BandDiagonalMatrix(_dim, _m1, _m2, new_data);
		}

		/// @brief Matrix subtraction (requires identical structure).
		/// @throws MatrixDimensionError If dimensions or bandwidth don't match.

		BandDiagonalMatrix operator-(const BandDiagonalMatrix& other) const {
			if (_dim != other._dim || _m1 != other._m1 || _m2 != other._m2)
				throw MatrixDimensionError("BandDiagonalMatrix::operator- - Incompatible dimensions or bandwidth");

			Matrix<Real> new_data = _data - other._data;
			return BandDiagonalMatrix(_dim, _m1, _m2, new_data);
		}

		/// @brief In-place scalar multiplication.
		BandDiagonalMatrix& operator*=(Real scalar) {
			_data *= scalar;
			return *this;
		}

		/// @brief In-place scalar division.
		/// @throws DivisionByZeroError If scalar is near zero.

		BandDiagonalMatrix& operator/=(Real scalar) {
			if (std::abs(scalar) < PrecisionValues<Real>::MatrixElementZeroThreshold)
				throw DivisionByZeroError("BandDiagonalMatrix::operator/= - Division by zero");
			_data /= scalar;
			return *this;
		}

		/// @brief In-place addition.
		/// @throws MatrixDimensionError If dimensions or bandwidth don't match.

		BandDiagonalMatrix& operator+=(const BandDiagonalMatrix& other) {
			if (_dim != other._dim || _m1 != other._m1 || _m2 != other._m2)
				throw MatrixDimensionError("BandDiagonalMatrix::operator+= - Incompatible dimensions or bandwidth");

			_data += other._data;
			return *this;
		}

		/// @brief In-place subtraction.
		/// @throws MatrixDimensionError If dimensions or bandwidth don't match.

		BandDiagonalMatrix& operator-=(const BandDiagonalMatrix& other) {
			if (_dim != other._dim || _m1 != other._m1 || _m2 != other._m2)
				throw MatrixDimensionError("BandDiagonalMatrix::operator-= - Incompatible dimensions or bandwidth");

			_data -= other._data;
			return *this;
		}
		/// /** @} */


		/// /** @name Matrix Properties
		/// @{ */


		/// @brief Returns the trace (sum of diagonal elements).
		Real Trace() const {
			Real trace = 0.0;
			for (int i = 0; i < _dim; i++)
				trace += (*this)(i, i);
			return trace;
		}

		/// @brief Computes the Frobenius norm.
		/// @return √(Σ|aᵢⱼ|²) over all band elements.

		Real NormFrobenius() const {
			Real sum = 0.0;
			for (int i = 0; i < _dim; i++) {
				int j_start = std::max(0, i - _m1);
				int j_end = std::min(_dim - 1, i + _m2);
				for (int j = j_start; j <= j_end; j++) {
					Real val = (*this)(i, j);
					sum += val * val;
				}
			}
			return std::sqrt(sum);
		}

		/// @brief Computes the infinity norm (max row sum).
		/// @return max_i Σⱼ|aᵢⱼ|

		Real NormInf() const {
			Real max_val = 0.0;
			for (int i = 0; i < _dim; i++) {
				Real row_sum = 0.0;
				int j_start = std::max(0, i - _m1);
				int j_end = std::min(_dim - 1, i + _m2);
				for (int j = j_start; j <= j_end; j++)
					row_sum += std::abs((*this)(i, j));
				max_val = std::max(max_val, row_sum);
			}
			return max_val;
		}

		/// @brief Computes the transpose matrix.
		/// @return Transposed matrix (swaps m₁ and m₂).

		BandDiagonalMatrix Transpose() const {
			// For transpose, m1 and m2 are swapped
			Matrix<Real> trans_data(_dim, _m1 + _m2 + 1);

			for (int i = 0; i < _dim; i++) {
				int j_start = std::max(0, i - _m1);
				int j_end = std::min(_dim - 1, i + _m2);
				for (int j = j_start; j <= j_end; j++) {
					// A^T[j][i] = A[i][j]
					// In band storage: trans_data[j][i - j + m2] = data[i][j - i + m1]
					trans_data[j][i - j + _m2] = _data[i][j - i + _m1];
				}
			}

			return BandDiagonalMatrix(_dim, _m2, _m1, trans_data);
		}

		/// @brief Checks if the matrix is symmetric within tolerance.
		/// @param tolerance Maximum allowed difference between A[i][j] and A[j][i].
		/// @return True if m₁ == m₂ and |A[i][j] - A[j][i]| ≤ tolerance for all i,j.

		bool IsSymmetric(Real tolerance = 1e-10) const {
			if (_m1 != _m2)
				return false; // Symmetric requires equal bandwidths

			for (int i = 0; i < _dim; i++) {
				int j_start = std::max(0, i - _m1);
				int j_end = std::min(_dim - 1, i + _m2);
				for (int j = j_start; j <= j_end; j++) {
					if (std::abs((*this)(i, j) - (*this)(j, i)) > tolerance)
						return false;
				}
			}
			return true;
		}

		/// @brief Checks equality with another band matrix.
		/// @param other Matrix to compare with.
		/// @param tolerance Maximum allowed element difference.
		/// @return True if dimensions, bandwidth, and elements match.

		bool IsEqualTo(const BandDiagonalMatrix& other, Real tolerance = Defaults::MatrixIsEqualTolerance) const {
			if (_dim != other._dim || _m1 != other._m1 || _m2 != other._m2)
				return false;

			return _data.IsEqualTo(other._data, tolerance);
		}
		/// /** @} */


		/// /** @name Diagonal Extraction
		/// @{ */


		/// @brief Extracts the main diagonal as a vector.
		Vector<Real> GetDiagonal() const {
			Vector<Real> diag(_dim);
			for (int i = 0; i < _dim; i++)
				diag[i] = (*this)(i, i);
			return diag;
		}

		/// @brief Extracts a specific diagonal.
		/// @param k Diagonal index: 0 = main, k > 0 = below main, k < 0 = above main.
		/// @return Vector of diagonal elements.
		/// @throws IndexError If diagonal is outside the band.

		Vector<Real> GetDiagonal(int k) const {
			if (k > _m1 || k < -_m2)
				throw IndexError("BandDiagonalMatrix::GetDiagonal - Diagonal outside band");

			int diag_length;
			int start_row, start_col;

			if (k >= 0) {
				// Below or on main diagonal
				diag_length = _dim - k;
				start_row = k;
				start_col = 0;
			} else {
				// Above main diagonal
				diag_length = _dim + k;
				start_row = 0;
				start_col = -k;
			}

			Vector<Real> diag(diag_length);
			for (int i = 0; i < diag_length; i++)
				diag[i] = (*this)(start_row + i, start_col + i);

			return diag;
		}
		/// /** @} */


		/// /** @name Output
		/// @{ */


		/// @brief Prints the full matrix representation to a stream.
		/// @param stream Output stream.
		/// @param width Field width for each element.
		/// @param precision Decimal precision for floating-point output.

		void Print(std::ostream& stream, int width, int precision) const {
			stream << "Dim: " << _dim << std::endl;
			for (int i = 0; i < _dim; i++) {
				stream << "[ ";
				for (int j = 0; j < _dim; j++) {
					stream << std::setw(width) << std::setprecision(precision) << (*this)(i, j) << ", ";
				}
				stream << " ]" << std::endl;
			}
		}
		/// /** @} */
	};

	/// @brief Scalar-matrix multiplication (commutative).
	inline BandDiagonalMatrix operator*(Real scalar, const BandDiagonalMatrix& mat) { return mat * scalar; }
} // namespace MML


///////////////////////////   mml/interfaces/ITensor.h   ///////////////////////////

/**
 * @file ITensor.h
 * @brief Interfaces for tensor objects with index variance tracking.
 * 
 * Defines abstract interfaces for tensors of rank 2 through 5 in N-dimensional
 * space. Each tensor interface tracks the number of contravariant (upper) and
 * covariant (lower) indices, enabling proper transformation behavior under
 * coordinate changes.
 * 
 * **Tensor Notation:**
 * - Contravariant indices (superscripts): Transform like coordinate differentials dx^i
 * - Covariant indices (subscripts): Transform like gradient components ∂f/∂x_i
 * - Mixed tensors: Have both types, e.g., T^i_j (1 contravariant, 1 covariant)
 * 
 * **Rank Hierarchy:**
 * - ITensor2<N>: Rank-2 tensors (matrices), e.g., metric tensor g_ij
 * - ITensor3<N>: Rank-3 tensors, e.g., Christoffel symbols Γ^i_jk
 * - ITensor4<N>: Rank-4 tensors, e.g., Riemann curvature R^i_jkl
 * - ITensor5<N>: Rank-5 tensors for specialized applications
 * 
 * @see ITensorField.h for position-dependent tensor fields
 */



namespace MML
{
	// Forward declarations for contraction return types
	template<int N> class Tensor2;
	template<int N> class Tensor3;

	/**
	 * @brief Enumeration for tensor index variance type.
	 */
	enum TensorIndexType { 
		CONTRAVARIANT,  ///< Upper index, transforms with inverse Jacobian
		COVARIANT       ///< Lower index, transforms with Jacobian
	};
    
	/**
	 * @brief Interface for rank-2 tensors in N-dimensional space.
	 * 
	 * Represents tensors with 2 indices, such as:
	 * - Metric tensor g_ij (0 contravariant, 2 covariant)
	 * - Inverse metric g^ij (2 contravariant, 0 covariant)
	 * - Mixed tensor T^i_j (1 contravariant, 1 covariant)
	 * 
	 * @tparam N Dimension of the underlying space
	 */
	template<int N>
	class ITensor2
	{
	public:
		virtual ~ITensor2() = default;

		/** @brief Get the number of contravariant (upper) indices. */
		virtual int   NumContravar() const = 0;
		
		/** @brief Get the number of covariant (lower) indices. */
		virtual int   NumCovar() const = 0;

		/** @brief Check if the index at position `index` is contravariant (upper). */
		virtual bool  IsContravar(int index) const = 0;

		/** @brief Check if the index at position `index` is covariant (lower). */
		bool IsCovar(int index) const { return !IsContravar(index); }

		/**
		 * @brief Access tensor component (const).
		 * @param i First index (0 to N-1)
		 * @param j Second index (0 to N-1)
		 * @return The tensor component T_ij or T^ij
		 */
		virtual Real  operator()(int i, int j) const = 0;
		
		/**
		 * @brief Access tensor component (mutable).
		 * @param i First index (0 to N-1)
		 * @param j Second index (0 to N-1)
		 * @return Reference to the tensor component
		 */
		virtual Real& operator()(int i, int j) = 0;

		/**
		 * @brief Contract the tensor (trace operation for mixed tensors).
		 * 
		 * For a mixed tensor T^i_j, returns the trace: sum of T^i_i over i.
		 * This is the fundamental contraction operation that produces a scalar.
		 * 
		 * @return Scalar result of contraction (trace)
		 * @throws TensorCovarContravarNumError if tensor is not mixed type (1 up, 1 down)
		 */
		virtual Real Contract() const = 0;

		/**
		 * @brief Apply tensor as a multilinear form to two vectors.
		 * 
		 * Computes the contraction T(v1, v2) = sum_{i,j} T_ij * v1_i * v2_j.
		 * This evaluates the tensor as a bilinear form on the given vectors.
		 * 
		 * @param v1 First vector argument
		 * @param v2 Second vector argument
		 * @return Scalar result of the bilinear form evaluation
		 */
		virtual Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2) const = 0;
	};

	/**
	 * @brief Interface for rank-3 tensors in N-dimensional space.
	 * 
	 * Represents tensors with 3 indices, commonly used for:
	 * - Christoffel symbols Γ^i_jk (connection coefficients)
	 * - Torsion tensors T^i_jk
	 * - Structure constants of Lie algebras
	 * 
	 * @tparam N Dimension of the underlying space
	 */
	template<int N>
	class ITensor3
	{
	public:
		virtual ~ITensor3() = default;

		virtual int   NumContravar() const = 0;
		virtual int   NumCovar() const = 0;

		/** @brief Check if the index at position `index` is contravariant (upper). */
		virtual bool  IsContravar(int index) const = 0;

		/** @brief Check if the index at position `index` is covariant (lower). */
		bool IsCovar(int index) const { return !IsContravar(index); }

		/**
		 * @brief Access tensor component.
		 * @param i First index
		 * @param j Second index
		 * @param k Third index
		 */
		virtual Real  operator()(int i, int j, int k) const = 0;
		virtual Real& operator()(int i, int j, int k) = 0;

		/**
		 * @brief Contract two indices, producing a rank-1 tensor (vector).
		 * 
		 * Sums over the contracted index: result_a = sum_s T_{...s...s...}
		 * where the two 's' positions are determined by ind1 and ind2.
		 * 
		 * @param ind1 First index to contract (0, 1, or 2)
		 * @param ind2 Second index to contract (0, 1, or 2), must differ from ind1
		 * @return VectorN<Real, N> - the contracted rank-1 result
		 * @throws TensorIndexError if indices out of range or equal
		 */
		virtual VectorN<Real, N> Contract(int ind1, int ind2) const = 0;

		/**
		 * @brief Apply tensor as a multilinear form to three vectors.
		 * 
		 * Computes T(v1, v2, v3) = sum_{i,j,k} T_ijk * v1_i * v2_j * v3_k.
		 * This evaluates the tensor as a trilinear form on the given vectors.
		 * 
		 * @param v1 First vector argument
		 * @param v2 Second vector argument
		 * @param v3 Third vector argument
		 * @return Scalar result of the trilinear form evaluation
		 */
		virtual Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2,
		                         const VectorN<Real, N>& v3) const = 0;
	};

	/**
	 * @brief Interface for rank-4 tensors in N-dimensional space.
	 * 
	 * Represents tensors with 4 indices, most notably:
	 * - Riemann curvature tensor R^i_jkl
	 * - Elasticity tensor C_ijkl (in continuum mechanics)
	 * - Weyl conformal tensor
	 * 
	 * @tparam N Dimension of the underlying space
	 */
	template<int N>
	class ITensor4
	{
	public:
		virtual ~ITensor4() = default;

		virtual int   NumContravar() const = 0;
		virtual int   NumCovar() const = 0;

		/** @brief Check if the index at position `index` is contravariant (upper). */
		virtual bool  IsContravar(int index) const = 0;

		/** @brief Check if the index at position `index` is covariant (lower). */
		bool IsCovar(int index) const { return !IsContravar(index); }

		/**
		 * @brief Access tensor component.
		 * @param i First index
		 * @param j Second index
		 * @param k Third index
		 * @param l Fourth index
		 */
		virtual Real  operator()(int i, int j, int k, int l) const = 0;
		virtual Real& operator()(int i, int j, int k, int l) = 0;

		/**
		 * @brief Contract two indices, producing a rank-2 tensor.
		 * 
		 * Sums over the contracted index: result_{ab} = sum_s T_{...s...s...}
		 * For example, contracting indices 0 and 2 of Riemann R^i_jkl gives Ricci R_jl.
		 * 
		 * @param ind1 First index to contract (0, 1, 2, or 3)
		 * @param ind2 Second index to contract (0, 1, 2, or 3), must differ from ind1
		 * @return Tensor2<N> - the contracted rank-2 result
		 * @throws TensorIndexError if indices out of range or equal
		 */
		virtual Tensor2<N> Contract(int ind1, int ind2) const = 0;

		/**
		 * @brief Apply tensor as a multilinear form to four vectors.
		 * 
		 * Computes T(v1, v2, v3, v4) = sum_{i,j,k,l} T_ijkl * v1_i * v2_j * v3_k * v4_l.
		 * This evaluates the tensor as a quadrilinear form on the given vectors.
		 * 
		 * @param v1 First vector argument
		 * @param v2 Second vector argument
		 * @param v3 Third vector argument
		 * @param v4 Fourth vector argument
		 * @return Scalar result of the quadrilinear form evaluation
		 */
		virtual Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2,
		                         const VectorN<Real, N>& v3, const VectorN<Real, N>& v4) const = 0;
	};

	/**
	 * @brief Interface for rank-5 tensors in N-dimensional space.
	 * 
	 * Represents tensors with 5 indices for specialized applications
	 * such as higher-order derivatives or multi-field theories.
	 * 
	 * @tparam N Dimension of the underlying space
	 */
	template<int N>
	class ITensor5
	{
	public:
		virtual ~ITensor5() = default;

		virtual int   NumContravar() const = 0;
		virtual int   NumCovar() const = 0;

		/** @brief Check if the index at position `index` is contravariant (upper). */
		virtual bool  IsContravar(int index) const = 0;

		/** @brief Check if the index at position `index` is covariant (lower). */
		bool IsCovar(int index) const { return !IsContravar(index); }

		/**
		 * @brief Access tensor component.
		 * @param i First index
		 * @param j Second index
		 * @param k Third index
		 * @param l Fourth index
		 * @param m Fifth index
		 */
		virtual Real  operator()(int i, int j, int k, int l, int m) const = 0;
		virtual Real& operator()(int i, int j, int k, int l, int m) = 0;

		/**
		 * @brief Contract two indices, producing a rank-3 tensor.
		 * 
		 * Sums over the contracted index: result_{abc} = sum_s T_{...s...s...}
		 * Contraction reduces rank by 2, so rank-5 becomes rank-3.
		 * 
		 * @param ind1 First index to contract (0-4)
		 * @param ind2 Second index to contract (0-4), must differ from ind1
		 * @return Tensor3<N> - the contracted rank-3 result
		 * @throws TensorIndexError if indices out of range or equal
		 */
		virtual Tensor3<N> Contract(int ind1, int ind2) const = 0;

		/**
		 * @brief Apply tensor as a multilinear form to five vectors.
		 * 
		 * Computes T(v1, v2, v3, v4, v5) = sum_{i,j,k,l,m} T_ijklm * v1_i * v2_j * v3_k * v4_l * v5_m.
		 * This evaluates the tensor as a 5-linear form on the given vectors.
		 * 
		 * @param v1 First vector argument
		 * @param v2 Second vector argument
		 * @param v3 Third vector argument
		 * @param v4 Fourth vector argument
		 * @param v5 Fifth vector argument
		 * @return Scalar result of the 5-linear form evaluation
		 */
		virtual Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2,
		                         const VectorN<Real, N>& v3, const VectorN<Real, N>& v4,
		                         const VectorN<Real, N>& v5) const = 0;
	};
}



///////////////////////////   mml/base/Tensor.h   ///////////////////////////

/**
 * @file Tensor.h
 * @brief Concrete tensor classes implementing ITensor interfaces.
 * 
 * Provides tensor classes of rank 2 through 5 in N-dimensional space, with full
 * support for covariant/contravariant index tracking and tensor operations.
 * 
 * **Index Variance Convention:**
 * - Constructor takes (nCovar, nContravar) - number of each index type
 * - By default, indices are ordered: covariant first, then contravariant
 * - The _isContravar[i] array tracks the variance of each index position
 * - Example: Tensor2<3>(1, 1) creates a mixed tensor T_i^j (1 down, 1 up)
 * 
 * **Tensor Notation Reference:**
 * - Contravariant (upper) indices: T^i transform with inverse Jacobian
 * - Covariant (lower) indices: T_i transform with Jacobian
 * - Contraction: Summing over one upper and one lower index (Einstein notation)
 * 
 * **Class Hierarchy:**
 * - Tensor2<N>: Rank-2 tensors (metric, stress, etc.)
 * - Tensor3<N>: Rank-3 tensors (Christoffel symbols, etc.)
 * - Tensor4<N>: Rank-4 tensors (Riemann curvature, elasticity, etc.)
 * - Tensor5<N>: Rank-5 tensors (specialized applications)
 * 
 * @see ITensor.h for abstract interfaces
 * @see ITensorField.h for position-dependent tensor fields
 */






// Standard headers - include what we use

namespace MML
{
	///////////////////////////////////////////////////////////////////////////
	///                            Tensor2                                  ///
	///////////////////////////////////////////////////////////////////////////

	/// @brief Rank-2 tensor in N-dimensional space with covariant/contravariant tracking.
	/// @details Represents tensors with 2 indices, such as:
	///          - Metric tensor g_ij (2 covariant, 0 contravariant)
	///          - Inverse metric g^ij (0 covariant, 2 contravariant)
	///          - Mixed tensor T^i_j (1 covariant, 1 contravariant)
	///          - Stress tensor, electromagnetic field tensor, etc.
	///
	///          Components are stored in an N×N matrix. Index variance is tracked
	///          per-position via the _isContravar array, enabling proper tensor
	///          algebra including contraction (trace) operations.
	///
	/// @tparam N Dimension of the underlying vector space (e.g., 3 for 3D, 4 for spacetime)
	///
	/// @par Example Usage:
	/// @code
	///     // Create a metric tensor g_ij (fully covariant)
	///     Tensor2<3> metric(2, 0);  // 2 covariant, 0 contravariant
	///     metric(0,0) = 1.0; metric(1,1) = 1.0; metric(2,2) = 1.0;
	///
	///     // Create a mixed tensor T^i_j for contraction
	///     Tensor2<3> mixed(1, 1);  // 1 covariant, 1 contravariant
	///     Real trace = mixed.Contract();  // Sum of diagonal elements
	///
	///     // Evaluate as bilinear form
	///     VectorN<Real, 3> v1{1, 0, 0}, v2{0, 1, 0};
	///     Real result = metric(v1, v2);  // = g_ij * v1^i * v2^j
	/// @endcode
	template <int N>
	class Tensor2 : public ITensor2<N>
	{
		MatrixNM<Real, N, N> _coeff;   ///< Storage for tensor components
		int _numContravar = 0;         ///< Number of contravariant (upper) indices
		int _numCovar = 0;             ///< Number of covariant (lower) indices
		bool _isContravar[2];          ///< Per-index variance: true = contravariant, false = covariant
	public:

		///////////////////////////////////////////////////////////////////////
		///                        Constructors                             ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Constructs a zero-initialized rank-2 tensor with specified index variance.
		/// @param nCovar Number of covariant (lower) indices, must be non-negative
		/// @param nContraVar Number of contravariant (upper) indices, must be non-negative
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 2 or either is negative
		/// @note The first nCovar indices are covariant, the remaining are contravariant.
		///       For example, (1, 1) creates T_i^j where index 0 is covariant and index 1 is contravariant.
		Tensor2(int nCovar, int nContraVar) : _numContravar(nContraVar), _numCovar(nCovar)
		{
			if ( _numContravar < 0 || _numCovar  < 0 || _numContravar + _numCovar != 2 )
				throw TensorCovarContravarNumError("Tensor2 ctor, wrong number of contravariant and covariant indices", nCovar, nContraVar);

			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;

			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;
		}

		/// @brief Constructs a rank-2 tensor with specified values and index variance.
		/// @param nCovar Number of covariant (lower) indices
		/// @param nContraVar Number of contravariant (upper) indices
		/// @param values Initializer list of N×N values in row-major order
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 2
		/// @note Values are filled row-by-row. Missing values are zero-initialized.
		Tensor2(int nCovar, int nContraVar, std::initializer_list<Real> values) : _numContravar(nContraVar), _numCovar(nCovar)
		{
			if ( _numContravar < 0 || _numCovar  < 0 || _numContravar + _numCovar != 2 )
				throw TensorCovarContravarNumError("Tensor2 ctor, wrong number of covariant and contravariant indices", nCovar, nContraVar);

			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;

			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;

			if (values.size() > N * N)
				throw TensorCovarContravarNumError("Tensor2 ctor, initializer_list has more than N*N elements", static_cast<int>(values.size()), N * N);

			auto val = values.begin();
			for (size_t i = 0; i < N; ++i)
				for (size_t j = 0; j < N; ++j)
					if (val != values.end())
						_coeff[i][j] = *val++;
					else
						_coeff[i][j] = 0.0;
		}

		///////////////////////////////////////////////////////////////////////
		///                     Index Variance Query                        ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Returns the number of contravariant (upper) indices.
		int  NumContravar() const override { return _numContravar; }

		/// @brief Returns the number of covariant (lower) indices.
		int  NumCovar()     const override { return _numCovar; }

		/// @brief Returns the underlying coefficient matrix.
		MatrixNM<Real, N, N> GetMatrix() const {	return _coeff; }

		/// @brief Checks if index i is contravariant (upper index).
		/// @param i Index position (0 or 1)
		bool IsContravar(int i) const override { return _isContravar[i]; }

		/// @brief Checks if index i is covariant (lower index).
		/// @param i Index position (0 or 1)
		bool IsCovar(int i) const			{ return !_isContravar[i]; }

		/// @brief Sets the variance of index i.
		void setContravar(int i, bool val) { _isContravar[i] = val; }

		///////////////////////////////////////////////////////////////////////
		///                        Element Access                           ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Access tensor element (const) with assertion bounds checking.
		/// @param i First index (0 to N-1)
		/// @param j Second index (0 to N-1)
		/// @return The tensor component T(i,j)
		Real  operator()(int i, int j) const override { 
			assert(i >= 0 && i < N && "Tensor2: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor2: index j out of bounds");
			return _coeff[i][j]; 
		}

		/// @brief Access tensor element (mutable) with assertion bounds checking.
		/// @param i First index (0 to N-1)
		/// @param j Second index (0 to N-1)
		/// @return Reference to the tensor component T(i,j)
		Real& operator()(int i, int j) override { 
			assert(i >= 0 && i < N && "Tensor2: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor2: index j out of bounds");
			return _coeff[i][j]; 
		}
		
		/// @brief Checked element access (const) with exception on out-of-bounds.
		/// @param i First index (0 to N-1)
		/// @param j Second index (0 to N-1)
		/// @return The tensor component T(i,j)
		/// @throws TensorIndexError if any index is out of bounds
		Real at(int i, int j) const {
			if (i < 0 || i >= N || j < 0 || j >= N)
				throw TensorIndexError("Tensor2::at - index out of bounds");
			return _coeff[i][j];
		}

		/// @brief Checked element access (mutable) with exception on out-of-bounds.
		/// @param i First index (0 to N-1)
		/// @param j Second index (0 to N-1)
		/// @return Reference to the tensor component T(i,j)
		/// @throws TensorIndexError if any index is out of bounds
		Real& at(int i, int j) {
			if (i < 0 || i >= N || j < 0 || j >= N)
				throw TensorIndexError("Tensor2::at - index out of bounds");
			return _coeff[i][j];
		}

		///////////////////////////////////////////////////////////////////////
		///                      Arithmetic Operations                      ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Add two tensors of the same variance type.
		/// @throws TensorCovarContravarArithmeticError if index variance doesn't match
		Tensor2 operator+(const Tensor2& other) const
		{
			if (_numContravar != other._numContravar || _numCovar != other._numCovar)
				throw TensorCovarContravarArithmeticError("Tensor2 operator+, wrong number of contravariant and covariant indices", _numContravar, _numCovar, other._numContravar, other._numCovar);

			Tensor2 result(_numCovar, _numContravar);

			result._coeff = _coeff + other._coeff;

			return result;
		}

		/// @brief Subtract two tensors of the same variance type.
		/// @throws TensorCovarContravarArithmeticError if index variance doesn't match
		Tensor2 operator-(const Tensor2& other) const
		{
			if (_numContravar != other._numContravar || _numCovar != other._numCovar)
				throw TensorCovarContravarArithmeticError("Tensor2 operator-, wrong number of contravariant and covariant indices", _numContravar, _numCovar, other._numContravar, other._numCovar);

			Tensor2 result(_numCovar, _numContravar);

			result._coeff = _coeff - other._coeff;

			return result;
		}

		/// @brief Multiply tensor by a scalar.
		Tensor2 operator*(Real scalar) const
		{
			Tensor2 result(_numCovar, _numContravar);

			result._coeff = _coeff * scalar;

			return result;
		}

		/// @brief Divide tensor by a scalar.
		Tensor2 operator/(Real scalar) const
		{
			Tensor2 result(_numCovar, _numContravar);

			result._coeff = _coeff / scalar;

			return result;
		}

		/// @brief Scalar multiplication from the left (scalar * tensor).
		friend Tensor2 operator*(Real scalar, const Tensor2& b)
		{
			Tensor2 result(b.NumCovar(), b.NumContravar());

			result._coeff = b._coeff * scalar;

			return result;
		}

		///////////////////////////////////////////////////////////////////////
		///                       Tensor Operations                         ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Contract (trace) the tensor over its two indices.
		/// @details Computes the trace: sum_i T^i_i for a mixed tensor.
		///          This operation requires exactly one covariant and one contravariant index.
		/// @return The scalar trace value
		/// @throws TensorCovarContravarNumError if tensor is not mixed (1,1)
		/// @note Contraction is only meaningful for mixed tensors. For a (2,0) or (0,2) tensor,
		///       you would first need to raise/lower an index using a metric tensor.
		Real Contract() const override
		{
			if (_numContravar != 1 || _numCovar != 1)
				throw TensorCovarContravarNumError("Tensor2 Contract, wrong number of contravariant and covariant indices", _numContravar, _numCovar);

			Real result = 0.0;
			for (int i = 0; i < N; i++)
				result += _coeff[i][i];

			return result;
		}

		/// @brief Evaluate tensor as a bilinear form on two vectors.
		/// @details Computes T_ij * v1^i * v2^j (or appropriate variant based on variance).
		/// @param v1 First vector argument
		/// @param v2 Second vector argument
		/// @return The scalar result of the bilinear form evaluation
		Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2) const override
		{
			Real sum = 0.0;
			for (int i = 0; i < N; i++)
				for (int j = 0; j < N; j++)
					sum += _coeff[i][j] * v1[i] * v2[j];

			return sum;
		}

		///////////////////////////////////////////////////////////////////////
		///                            Output                               ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Print tensor components to a stream.
		void   Print(std::ostream& stream, int width, int precision) const
		{
			stream << std::fixed << "(N = " << N << ")" << std::endl;

			for (size_t i = 0; i < N; i++)
			{
				stream << "[ ";
				for (size_t j = 0; j < N; j++)
					stream << std::setw(width) << std::setprecision(precision) << _coeff[i][j] << ", ";
				stream << " ]" << std::endl;
			}
		}
		friend std::ostream& operator<<(std::ostream& stream, const Tensor2& a)
		{
			a.Print(stream, 15, 10);

			return stream;
		}
	};

	///////////////////////////////////////////////////////////////////////////
	///                            Tensor3                                  ///
	///////////////////////////////////////////////////////////////////////////

	/// @brief Rank-3 tensor in N-dimensional space with covariant/contravariant tracking.
	/// @details Represents tensors with 3 indices, commonly used for:
	///          - Christoffel symbols Γ^k_ij (connection coefficients)
	///          - Structure constants of Lie algebras
	///          - Completely antisymmetric tensors (Levi-Civita symbol)
	///          - Third-order material tensors
	///
	///          Index variance is tracked per-position. Contraction reduces rank by 2,
	///          returning a VectorN (rank-1 tensor).
	///
	/// @tparam N Dimension of the underlying vector space
	///
	/// @par Example Usage:
	/// @code
	///     // Create Christoffel-like tensor Γ^k_ij (1 up, 2 down)
	///     Tensor3<3> christoffel(2, 1);  // 2 covariant, 1 contravariant
	///     
	///     // Contract indices 1 and 2 (trace over the covariant indices)
	///     VectorN<Real, 3> contracted = christoffel.Contract(1, 2);
	/// @endcode
	template <int N>
	class Tensor3 : public ITensor3<N>
	{
		Real _coeff[N][N][N] = { 0 };  ///< Storage for N³ tensor components
		int _numContravar;             ///< Number of contravariant (upper) indices
		int _numCovar;                 ///< Number of covariant (lower) indices
		bool _isContravar[3];          ///< Per-index variance: true = contravariant, false = covariant
	public:

		///////////////////////////////////////////////////////////////////////
		///                        Constructors                             ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Constructs a zero-initialized rank-3 tensor with specified index variance.
		/// @param nCovar Number of covariant (lower) indices
		/// @param nContraVar Number of contravariant (upper) indices
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 3
		Tensor3(int nCovar, int nContraVar) : _numContravar(nContraVar), _numCovar(nCovar)
		{
			if (_numContravar + _numCovar != 3)
				throw TensorCovarContravarNumError("Tensor3 ctor, wrong number of contravariant and covariant indices", nCovar, nContraVar);

			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;

			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;
		}

		/// @brief Constructs a rank-3 tensor with specified values and index variance.
		/// @param nCovar Number of covariant (lower) indices
		/// @param nContraVar Number of contravariant (upper) indices  
		/// @param values Initializer list of N³ values in lexicographic order
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 3
		Tensor3(int nCovar, int nContraVar, std::initializer_list<Real> values) : _numContravar(nContraVar), _numCovar(nCovar)
		{
			if (_numContravar + _numCovar != 3)
				throw TensorCovarContravarNumError("Tensor3 ctor, wrong number of contravariant and covariant indices", nCovar, nContraVar);
			
			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;
			
			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;
			
			if (values.size() > N * N * N)
				throw TensorCovarContravarNumError("Tensor3 ctor, initializer_list has more than N*N*N elements", static_cast<int>(values.size()), N * N * N);

			auto val = values.begin();
			for (size_t i = 0; i < N; ++i)
				for (size_t j = 0; j < N; ++j)
					for (size_t k = 0; k < N; ++k)
						if (val != values.end())
							_coeff[i][j][k] = *val++;
						else
							_coeff[i][j][k] = 0.0;
		}

		///////////////////////////////////////////////////////////////////////
		///                     Index Variance Query                        ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Returns the number of contravariant (upper) indices.
		int   NumContravar() const override { return _numContravar; }

		/// @brief Returns the number of covariant (lower) indices.
		int   NumCovar()     const override { return _numCovar; }

		/// @brief Checks if index i is contravariant (upper index).
		bool IsContravar(int i) const override { return _isContravar[i]; }

		/// @brief Checks if index i is covariant (lower index).
		bool IsCovar(int i) const { return !_isContravar[i]; }

		/// @brief Sets the variance of index i.
		void setContravar(int i, bool val) { _isContravar[i] = val; }

		///////////////////////////////////////////////////////////////////////
		///                        Element Access                           ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Access tensor element (const) with assertion bounds checking.
		Real  operator()(int i, int j, int k) const override { 
			assert(i >= 0 && i < N && "Tensor3: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor3: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor3: index k out of bounds");
			return _coeff[i][j][k]; 
		}

		/// @brief Access tensor element (mutable) with assertion bounds checking.
		Real& operator()(int i, int j, int k) override { 
			assert(i >= 0 && i < N && "Tensor3: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor3: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor3: index k out of bounds");
			return _coeff[i][j][k]; 
		}
		
		/// @brief Checked element access (const) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real at(int i, int j, int k) const {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N)
				throw TensorIndexError("Tensor3::at - index out of bounds");
			return _coeff[i][j][k];
		}

		/// @brief Checked element access (mutable) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real& at(int i, int j, int k) {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N)
				throw TensorIndexError("Tensor3::at - index out of bounds");
			return _coeff[i][j][k];
		}

		///////////////////////////////////////////////////////////////////////
		///                       Tensor Operations                         ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Evaluate tensor as a trilinear form on three vectors.
		/// @details Computes T_ijk * v1^i * v2^j * v3^k (or appropriate variant).
		/// @return The scalar result of the trilinear form evaluation
		Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2, const VectorN<Real, N>& v3) const override
		{
			Real sum = 0.0;
			for (int i = 0; i < N; i++)
				for (int j = 0; j < N; j++)
					for (int k = 0; k < N; k++)
						sum += _coeff[i][j][k] * v1[i] * v2[j] * v3[k];

			return sum;
		}

		/// @brief Contract two indices, reducing rank from 3 to 1.
		/// @details Returns a VectorN by summing over the diagonal of the specified indices.
		///          For example, contracting indices 0 and 1 computes sum_s T(s,s,k) for each k.
		/// @param ind1 First index to contract (0-2)
		/// @param ind2 Second index to contract (0-2), must differ from ind1
		/// @return VectorN containing the contracted result (rank-1 tensor)
		/// @throws TensorIndexError if indices are out of range or equal
		/// @note The result inherits the variance of the remaining (non-contracted) index.
		VectorN<Real, N> Contract(int ind1, int ind2) const override
		{
			if (ind1 < 0 || ind1 > 2 || ind2 < 0 || ind2 > 2)
				throw TensorIndexError("Tensor3 Contract, index out of range [0,2]");
			if (ind1 == ind2)
				throw TensorIndexError("Tensor3 Contract, indices must be different");
			if (ind1 > ind2) std::swap(ind1, ind2);  // Normalize: ind1 < ind2

			VectorN<Real, N> result;

			// Find the remaining index (the one not being contracted)
			int remaining = -1;
			for (int i = 0; i < 3; i++)
				if (i != ind1 && i != ind2)
					remaining = i;

			// Contract: sum over the contracted index
			for (int a = 0; a < N; a++)  // result index
			{
				Real sum = 0.0;
				for (int s = 0; s < N; s++)  // contracted index
				{
					int idx[3];
					idx[ind1] = s;
					idx[ind2] = s;
					idx[remaining] = a;
					sum += _coeff[idx[0]][idx[1]][idx[2]];
				}
				result[a] = sum;
			}

			return result;
		}
	};

	///////////////////////////////////////////////////////////////////////////
	///                            Tensor4                                  ///
	///////////////////////////////////////////////////////////////////////////

	/// @brief Rank-4 tensor in N-dimensional space with covariant/contravariant tracking.
	/// @details Represents tensors with 4 indices, commonly used for:
	///          - Riemann curvature tensor R^a_bcd
	///          - Elasticity tensor C_ijkl
	///          - Electromagnetic constitutive tensors
	///          - Fourth-order material property tensors
	///
	///          Index variance is tracked per-position. Contraction reduces rank by 2,
	///          returning a Tensor2 with properly propagated index variance.
	///
	/// @tparam N Dimension of the underlying vector space
	///
	/// @par Example Usage:
	/// @code
	///     // Create Riemann tensor R^a_bcd (1 up, 3 down)
	///     Tensor4<4> riemann(3, 1);  // 3 covariant, 1 contravariant
	///     
	///     // Contract indices to get Ricci tensor R_bd = R^a_bad
	///     Tensor2<4> ricci = riemann.Contract(0, 2);  // Contract indices 0 and 2
	/// @endcode
	template <int N>
	class Tensor4 : public ITensor4<N>
	{
		Real _coeff[N][N][N][N] = { 0 };  ///< Storage for N⁴ tensor components
		int _numContravar;                 ///< Number of contravariant (upper) indices
		int _numCovar;                     ///< Number of covariant (lower) indices
		bool _isContravar[4];              ///< Per-index variance: true = contravariant, false = covariant
	public:

		///////////////////////////////////////////////////////////////////////
		///                        Constructors                             ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Constructs a zero-initialized rank-4 tensor with specified index variance.
		/// @param nCovar Number of covariant (lower) indices
		/// @param nContraVar Number of contravariant (upper) indices
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 4
		Tensor4(int nCovar, int nContraVar) : _numContravar(nContraVar), _numCovar(nCovar) 
		{
			if (_numContravar + _numCovar != 4)
				throw TensorCovarContravarNumError("Tensor4 ctor, wrong number of contravariant and covariant indices", nCovar, nContraVar);

			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;

			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;
		}

		///////////////////////////////////////////////////////////////////////
		///                     Index Variance Query                        ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Returns the number of contravariant (upper) indices.
		int   NumContravar() const override { return _numContravar; }

		/// @brief Returns the number of covariant (lower) indices.
		int   NumCovar()     const override { return _numCovar; }

		/// @brief Checks if index i is contravariant (upper index).
		bool IsContravar(int i) const override { return _isContravar[i]; }

		/// @brief Checks if index i is covariant (lower index).
		bool IsCovar(int i) const { return !_isContravar[i]; }

		/// @brief Sets the variance of index i.
		void setContravar(int i, bool val) { _isContravar[i] = val; }

		///////////////////////////////////////////////////////////////////////
		///                        Element Access                           ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Access tensor element (const) with assertion bounds checking.
		Real  operator()(int i, int j, int k, int l) const override { 
			assert(i >= 0 && i < N && "Tensor4: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor4: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor4: index k out of bounds");
			assert(l >= 0 && l < N && "Tensor4: index l out of bounds");
			return _coeff[i][j][k][l]; 
		}

		/// @brief Access tensor element (mutable) with assertion bounds checking.
		Real& operator()(int i, int j, int k, int l) override { 
			assert(i >= 0 && i < N && "Tensor4: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor4: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor4: index k out of bounds");
			assert(l >= 0 && l < N && "Tensor4: index l out of bounds");
			return _coeff[i][j][k][l]; 
		}
		
		/// @brief Checked element access (const) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real at(int i, int j, int k, int l) const {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N || l < 0 || l >= N)
				throw TensorIndexError("Tensor4::at - index out of bounds");
			return _coeff[i][j][k][l];
		}

		/// @brief Checked element access (mutable) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real& at(int i, int j, int k, int l) {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N || l < 0 || l >= N)
				throw TensorIndexError("Tensor4::at - index out of bounds");
			return _coeff[i][j][k][l];
		}

		///////////////////////////////////////////////////////////////////////
		///                       Tensor Operations                         ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Evaluate tensor as a quadrilinear form on four vectors.
		/// @details Computes T_ijkl * v1^i * v2^j * v3^k * v4^l (or appropriate variant).
		/// @return The scalar result of the quadrilinear form evaluation
		Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2, const VectorN<Real, N>& v3, const VectorN<Real, N>& v4) const override
		{
			Real sum = 0.0;
			for (int i = 0; i < N; i++)
				for (int j = 0; j < N; j++)
					for (int k = 0; k < N; k++)
						for (int l = 0; l < N; l++)
							sum += _coeff[i][j][k][l] * v1[i] * v2[j] * v3[k] * v4[l];

			return sum;
		}

		/// @brief Contract two indices, reducing rank from 4 to 2.
		/// @details Returns a Tensor2 by summing over the diagonal of the specified indices.
		///          The result tensor correctly inherits the variance of non-contracted indices.
		///
		///          For example, given tensor T^i_j^k_l and contracting indices 0 and 1:
		///          - Result has indices from positions 2 and 3 (originally k and l)
		///          - Result's _isContravar is copied from original positions [2] and [3]
		///          - So result would have variance pattern matching ^k_l
		///
		/// @param ind1 First index to contract (0-3)
		/// @param ind2 Second index to contract (0-3), must differ from ind1
		/// @return Tensor2 containing the contracted result with proper index variance
		/// @throws TensorIndexError if indices are out of range or equal
		/// @note Index variance is explicitly propagated from the original tensor,
		///       not reconstructed from covariant/contravariant counts.
		Tensor2<N> Contract(int ind1, int ind2) const override
		{
			if (ind1 < 0 || ind1 > 3 || ind2 < 0 || ind2 > 3)
				throw TensorIndexError("Tensor4 Contract, index out of range [0,3]");
			if (ind1 == ind2)
				throw TensorIndexError("Tensor4 Contract, indices must be different");
			if (ind1 > ind2) std::swap(ind1, ind2);  // Normalize: ind1 < ind2

			// Determine covariant/contravariant counts for result
			int newCovar = _numCovar;
			int newContravar = _numContravar;
			if (_isContravar[ind1]) newContravar--; else newCovar--;
			if (_isContravar[ind2]) newContravar--; else newCovar--;

			Tensor2<N> result(newCovar, newContravar);

			// Build mapping: which original indices become result indices
			int map[2];  // map[result_idx] = original_idx
			int m_idx = 0;
			for (int i = 0; i < 4; i++)
				if (i != ind1 && i != ind2)
					map[m_idx++] = i;

			// Properly propagate index variance from original tensor
			for (int i = 0; i < 2; i++)
				result.setContravar(i, _isContravar[map[i]]);

			// Contract: sum over the contracted index
			for (int a = 0; a < N; a++)        // result index 0
				for (int b = 0; b < N; b++)    // result index 1
				{
					Real sum = 0.0;
					for (int s = 0; s < N; s++)  // contracted index
					{
						int idx[4];
						idx[ind1] = s;
						idx[ind2] = s;
						idx[map[0]] = a;
						idx[map[1]] = b;
						sum += _coeff[idx[0]][idx[1]][idx[2]][idx[3]];
					}
					result(a, b) = sum;
				}

			return result;
		}
	};

	///////////////////////////////////////////////////////////////////////////
	///                            Tensor5                                  ///
	///////////////////////////////////////////////////////////////////////////

	/// @brief Rank-5 tensor in N-dimensional space with covariant/contravariant tracking.
	/// @details Represents tensors with 5 indices, used in specialized applications:
	///          - Higher-order material property tensors
	///          - Derivatives of fourth-order tensors
	///          - Theoretical physics applications
	///
	///          Index variance is tracked per-position. Contraction reduces rank by 2,
	///          returning a Tensor3 with properly propagated index variance.
	///
	/// @tparam N Dimension of the underlying vector space
	///
	/// @par Example Usage:
	/// @code
	///     // Create a rank-5 tensor with 3 covariant, 2 contravariant indices
	///     Tensor5<3> t(3, 2);  // T_ijk^lm
	///     
	///     // Contract to get a Tensor3
	///     Tensor3<3> contracted = t.Contract(0, 3);  // Contract first covariant with first contravariant
	/// @endcode
	template <int N>
	class Tensor5 : public ITensor5<N>
	{
		Real _coeff[N][N][N][N][N] = { 0 };  ///< Storage for N⁵ tensor components
		int _numContravar;                    ///< Number of contravariant (upper) indices
		int _numCovar;                        ///< Number of covariant (lower) indices
		bool _isContravar[5];                 ///< Per-index variance: true = contravariant, false = covariant
	public:

		///////////////////////////////////////////////////////////////////////
		///                        Constructors                             ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Constructs a zero-initialized rank-5 tensor with specified index variance.
		/// @param nCovar Number of covariant (lower) indices
		/// @param nContraVar Number of contravariant (upper) indices
		/// @throws TensorCovarContravarNumError if nCovar + nContraVar != 5
		Tensor5(int nCovar, int nContraVar) : _numContravar(nContraVar), _numCovar(nCovar) 
		{
			if (_numContravar + _numCovar != 5)
				throw TensorCovarContravarNumError("Tensor5 ctor, wrong number of contravariant and covariant indices", nCovar, nContraVar);

			for (int i = 0; i < _numCovar; i++)
				_isContravar[i] = false;

			for (int i = _numCovar; i < _numCovar + _numContravar; i++)
				_isContravar[i] = true;

		}

		///////////////////////////////////////////////////////////////////////
		///                     Index Variance Query                        ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Returns the number of contravariant (upper) indices.
		int   NumContravar() const override { return _numContravar; }

		/// @brief Returns the number of covariant (lower) indices.
		int   NumCovar()     const override { return _numCovar; }

		/// @brief Checks if index i is contravariant (upper index).
		bool IsContravar(int i) const { return _isContravar[i]; }

		/// @brief Checks if index i is covariant (lower index).
		bool IsCovar(int i) const { return !_isContravar[i]; }

		/// @brief Sets the variance of index i.
		void setContravar(int i, bool val) { _isContravar[i] = val; }

		///////////////////////////////////////////////////////////////////////
		///                        Element Access                           ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Access tensor element (const) with assertion bounds checking.
		Real  operator()(int i, int j, int k, int l, int m) const override { 
			assert(i >= 0 && i < N && "Tensor5: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor5: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor5: index k out of bounds");
			assert(l >= 0 && l < N && "Tensor5: index l out of bounds");
			assert(m >= 0 && m < N && "Tensor5: index m out of bounds");
			return _coeff[i][j][k][l][m]; 
		}

		/// @brief Access tensor element (mutable) with assertion bounds checking.
		Real& operator()(int i, int j, int k, int l, int m) override { 
			assert(i >= 0 && i < N && "Tensor5: index i out of bounds");
			assert(j >= 0 && j < N && "Tensor5: index j out of bounds");
			assert(k >= 0 && k < N && "Tensor5: index k out of bounds");
			assert(l >= 0 && l < N && "Tensor5: index l out of bounds");
			assert(m >= 0 && m < N && "Tensor5: index m out of bounds");
			return _coeff[i][j][k][l][m]; 
		}
		
		/// @brief Checked element access (const) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real at(int i, int j, int k, int l, int m) const {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N || l < 0 || l >= N || m < 0 || m >= N)
				throw TensorIndexError("Tensor5::at - index out of bounds");
			return _coeff[i][j][k][l][m];
		}

		/// @brief Checked element access (mutable) with exception on out-of-bounds.
		/// @throws TensorIndexError if any index is out of bounds
		Real& at(int i, int j, int k, int l, int m) {
			if (i < 0 || i >= N || j < 0 || j >= N || k < 0 || k >= N || l < 0 || l >= N || m < 0 || m >= N)
				throw TensorIndexError("Tensor5::at - index out of bounds");
			return _coeff[i][j][k][l][m];
		}

		///////////////////////////////////////////////////////////////////////
		///                       Tensor Operations                         ///
		///////////////////////////////////////////////////////////////////////

		/// @brief Evaluate tensor as a quintilinear form on five vectors.
		/// @details Computes T_ijklm * v1^i * v2^j * v3^k * v4^l * v5^m (or appropriate variant).
		/// @return The scalar result of the quintilinear form evaluation
		Real operator()(const VectorN<Real, N>& v1, const VectorN<Real, N>& v2, 
		                const VectorN<Real, N>& v3, const VectorN<Real, N>& v4, 
		                const VectorN<Real, N>& v5) const override
		{
			Real sum = 0.0;
			for (int i = 0; i < N; i++)
				for (int j = 0; j < N; j++)
					for (int k = 0; k < N; k++)
						for (int l = 0; l < N; l++)
							for (int m = 0; m < N; m++)
								sum += _coeff[i][j][k][l][m] * v1[i] * v2[j] * v3[k] * v4[l] * v5[m];
			return sum;
		}

		/// @brief Contract two indices, reducing rank from 5 to 3.
		/// @details Returns a Tensor3 by summing over the diagonal of the specified indices.
		///          The result tensor correctly inherits the variance of non-contracted indices.
		///
		///          For example, given tensor T_ij^k_l^m and contracting indices 1 and 2:
		///          - Result has indices from positions 0, 3, 4 (originally i, l, m)
		///          - Result's _isContravar is copied from original positions [0], [3], [4]
		///          - So result would have variance pattern matching _i_l^m
		///
		/// @param ind1 First index to contract (0-4)
		/// @param ind2 Second index to contract (0-4), must differ from ind1
		/// @return Tensor3 containing the contracted result with proper index variance
		/// @throws TensorIndexError if indices are out of range or equal
		/// @note Index variance is explicitly propagated from the original tensor,
		///       not reconstructed from covariant/contravariant counts.
		Tensor3<N> Contract(int ind1, int ind2) const override
		{
			if (ind1 < 0 || ind1 > 4 || ind2 < 0 || ind2 > 4)
				throw TensorIndexError("Tensor5 Contract, index out of range [0,4]");
			if (ind1 == ind2)
				throw TensorIndexError("Tensor5 Contract, indices must be different");
			if (ind1 > ind2) std::swap(ind1, ind2);  // Normalize: ind1 < ind2

			// Determine covariant/contravariant counts for result
			int newCovar = _numCovar;
			int newContravar = _numContravar;
			if (_isContravar[ind1]) newContravar--; else newCovar--;
			if (_isContravar[ind2]) newContravar--; else newCovar--;

			Tensor3<N> result(newCovar, newContravar);

			// Build mapping: which original indices become result indices
			int map[3];  // map[result_idx] = original_idx
			int m_idx = 0;
			for (int i = 0; i < 5; i++)
				if (i != ind1 && i != ind2)
					map[m_idx++] = i;

			// Properly propagate index variance from original tensor
			for (int i = 0; i < 3; i++)
				result.setContravar(i, _isContravar[map[i]]);

			// Contract: sum over the contracted index
			for (int a = 0; a < N; a++)        // result index 0
				for (int b = 0; b < N; b++)    // result index 1
					for (int c = 0; c < N; c++)// result index 2
					{
						Real sum = 0.0;
						for (int s = 0; s < N; s++)  // contracted index
						{
							// Build the 5 indices for _coeff access
							int idx[5];
							idx[ind1] = s;
							idx[ind2] = s;
							idx[map[0]] = a;
							idx[map[1]] = b;
							idx[map[2]] = c;
							sum += _coeff[idx[0]][idx[1]][idx[2]][idx[3]][idx[4]];
						}
						result(a, b, c) = sum;
					}

			return result;
		}
	};
}

///////////////////////////   mml/interfaces/IFunction.h   ///////////////////////////

/**
 * @file IFunction.h
 * @brief Core function interface hierarchy for mathematical functions.
 * 
 * This file defines the complete hierarchy of function interfaces used throughout MML:
 * 
 * **Base Template:**
 * - IFunction<RetType, ArgType> - Generic function interface
 * 
 * **Real Functions (R → R):**
 * - IRealFunction - Basic real-to-real function
 * - IRealFunctionParametrized - Real function with adjustable parameters
 * 
 * **Scalar Functions (R^N → R):**
 * - IScalarFunction<N> - Multi-variable scalar function
 * - IScalarFunctionParametrized<N> - Parametrized scalar function
 * 
 * **Vector Functions:**
 * - IRealToVectorFunction<N> - R → R^N mapping
 * - IVectorFunction<N> - R^N → R^N mapping
 * - IVectorFunctionParametrized<N> - Parametrized vector function
 * - IVectorFunctionNM<N,M> - R^N → R^M mapping
 * 
 * **Parametric Geometry:**
 * - IParametricCurve<N> - Curve in N-dimensional space
 * - IParametricCurveParametrized<N> - Parametrized curve
 * - IParametricSurface<N> - Surface with variable domain
 * - IParametricSurfaceRect<N> - Surface on rectangular domain
 */





namespace MML
{
	/**
	 * @brief Generic function interface template.
	 * 
	 * Base template for all function types in MML. Defines a callable
	 * interface mapping from _ArgType to _RetType.
	 * 
	 * @tparam _RetType Return type of the function
	 * @tparam _ArgType Argument type of the function
	 */
	template<typename _RetType, typename _ArgType>
	class IFunction
	{
	public:
		/**
		 * @brief Evaluate the function at the given argument.
		 * @param arg The input argument
		 * @return The function value at the argument
		 */
		virtual _RetType operator()(_ArgType) const = 0;

		virtual ~IFunction() {}
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for real-valued functions of a single real variable.
	 * 
	 * Represents functions f: R → R. This is the most fundamental function
	 * type, used extensively in root finding, integration, and differentiation.
	 * 
	 * @note Implementations should ensure operator() is const and thread-safe
	 *       for parallel evaluation.
	 */
	class IRealFunction : public IFunction<Real, Real>
	{
	public:
		/**
		 * @brief Evaluate the function at point x.
		 * @param x The input value
		 * @return f(x)
		 */
		virtual Real operator()(Real) const = 0;
		
		/**
		 * @brief Sample the function over a range of values.
		 * 
		 * Generates numPnt equally-spaced sample points and their function values,
		 * useful for plotting or numerical analysis.
		 * 
		 * @param x1 Start of sampling range
		 * @param x2 End of sampling range
		 * @param numPnt Number of sample points
		 * @param[out] outX Vector of x coordinates
		 * @param[out] outY Vector of corresponding y = f(x) values
		 */
		void GetValues(Real x1, Real x2, int numPnt, Vector<Real>& outX, Vector<Real>& outY) const
		{
			outX.Resize(numPnt);
			outY.Resize(numPnt);

			for (int i = 0; i < numPnt; i++) {
				outX[i] = x1 + i * (x2 - x1) / (numPnt - 1);
				outY[i] = (*this)(outX[i]);
			}
		}

		virtual ~IRealFunction() {}
	};

	/**
	 * @brief Real function with adjustable parameters.
	 * 
	 * Extends IRealFunction to support functions with internal parameters
	 * that can be get/set at runtime. Useful for curve fitting, optimization,
	 * and parametric studies.
	 * 
	 * Example: f(x; a, b) = a*sin(b*x) where a, b are parameters.
	 */
	class IRealFunctionParametrized : public IRealFunction, public IParametrized
	{
	public:
		virtual ~IRealFunctionParametrized() = default;
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for scalar functions of N real variables.
	 * 
	 * Represents functions f: R^N → R. Used in optimization, gradient
	 * computation, and multi-variable calculus.
	 * 
	 * @tparam N Dimension of the input space
	 */
	template<int N>
	class IScalarFunction : public IFunction<Real, const VectorN<Real, N>&>
	{
	public:
		/**
		 * @brief Evaluate the function at point x.
		 * @param x N-dimensional input vector
		 * @return f(x)
		 */
		virtual Real operator()(const VectorN<Real, N>& x) const = 0;

		virtual ~IScalarFunction() {}
	};

	/**
	 * @brief Scalar function with adjustable parameters.
	 * 
	 * @tparam N Dimension of the input space
	 */
	template<int N>
	class IScalarFunctionParametrized : public IScalarFunction<N>, public IParametrized
	{
	public:
		virtual ~IScalarFunctionParametrized() = default;
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for vector-valued functions of a single real variable.
	 * 
	 * Represents functions f: R → R^N. Commonly used for parametric curves
	 * and time-dependent vector quantities.
	 * 
	 * @tparam N Dimension of the output vector
	 */
	template<int N>
	class IRealToVectorFunction : public IFunction<VectorN<Real, N>, Real>
	{
	public:
		/**
		 * @brief Evaluate the function at parameter x.
		 * @param x The input parameter
		 * @return N-dimensional output vector
		 */
		virtual VectorN<Real, N> operator()(Real x) const = 0;

		virtual ~IRealToVectorFunction() {}
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for vector-valued functions of N real variables.
	 * 
	 * Represents functions f: R^N → R^N (same input/output dimension).
	 * Used for vector fields, coordinate transformations, and systems
	 * of equations.
	 * 
	 * @tparam N Dimension of both input and output spaces
	 */
	template<int N>
	class IVectorFunction : public IFunction<VectorN<Real, N>, const VectorN<Real, N>&>
	{
	public:
		/**
		 * @brief Evaluate the function at point x.
		 * @param x N-dimensional input vector
		 * @return N-dimensional output vector
		 */
		virtual VectorN<Real, N> operator()(const VectorN<Real, N>& x) const = 0;

		/**
		 * @brief Evaluate a single component of the output.
		 * @param x N-dimensional input vector
		 * @param component Index of the output component (0 to N-1)
		 * @return The specified component of f(x)
		 * 
		 * @note This method delegates to evaluateComponent() which can be
		 *       overridden for efficient per-component evaluation. The default
		 *       implementation computes the full vector, which may be O(N).
		 */
		Real operator()(const VectorN<Real, N>& x, int component) const
		{
			return evaluateComponent(x, component);
		}

		virtual ~IVectorFunction() {}

	protected:
		/**
		 * @brief Override point for efficient single-component evaluation.
		 * 
		 * Derived classes can override this method to provide O(1) per-component
		 * evaluation instead of the default O(N) full-vector computation.
		 * This is particularly beneficial when:
		 * - Computing Jacobians (avoids O(N²) becoming O(N))
		 * - Optimization algorithms need individual gradient components
		 * - Large dimensions (N >> 1)
		 * 
		 * @param x N-dimensional input vector
		 * @param component Index of the output component (0 to N-1)
		 * @return The specified component of f(x)
		 */
		virtual Real evaluateComponent(const VectorN<Real, N>& x, int component) const
		{
			VectorN<Real, N> val = (*this)(x);
			return val[component];
		}
	};

	/**
	 * @brief Vector function with adjustable parameters.
	 * 
	 * @tparam N Dimension of input and output spaces
	 */
	template<int N>
	class IVectorFunctionParametrized : public IVectorFunction<N>, public IParametrized
	{
	public:
		virtual ~IVectorFunctionParametrized() = default;
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for vector-valued functions with different input/output dimensions.
	 * 
	 * Represents functions f: R^N → R^M where N ≠ M in general.
	 * Useful for projections, embeddings, and general mappings.
	 * 
	 * @tparam N Dimension of the input space
	 * @tparam M Dimension of the output space
	 */
	template<int N, int M>
	class IVectorFunctionNM : public IFunction<VectorN<Real, M>, const VectorN<Real, N>&>
	{
	public:
		/**
		 * @brief Evaluate the function at point x.
		 * @param x N-dimensional input vector
		 * @return M-dimensional output vector
		 */
		virtual VectorN<Real, M> operator()(const VectorN<Real, N>& x) const = 0;
		
		/**
		 * @brief Evaluate a single component of the output.
		 * @param x N-dimensional input vector
		 * @param component Index of the output component (0 to M-1)
		 * @return The specified component of f(x)
		 * 
		 * @note This method delegates to evaluateComponent() which can be
		 *       overridden for efficient per-component evaluation. The default
		 *       implementation computes the full vector, which may be O(M).
		 */
		Real operator()(const VectorN<Real, N>& x, int component) const
		{
			return evaluateComponent(x, component);
		}
		
		virtual ~IVectorFunctionNM() {}

	protected:
		/**
		 * @brief Override point for efficient single-component evaluation.
		 * 
		 * Derived classes can override this method to provide O(1) per-component
		 * evaluation instead of the default O(M) full-vector computation.
		 * This is particularly beneficial when:
		 * - Computing Jacobians (avoids O(M²) becoming O(M))
		 * - Optimization algorithms need individual gradient components
		 * - Large output dimensions (M >> 1)
		 * 
		 * @param x N-dimensional input vector
		 * @param component Index of the output component (0 to M-1)
		 * @return The specified component of f(x)
		 */
		virtual Real evaluateComponent(const VectorN<Real, N>& x, int component) const
		{
			VectorN<Real, M> val = (*this)(x);
			return val[component];
		}
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for parametric curves in N-dimensional space.
	 * 
	 * Represents a curve γ: [tMin, tMax] → R^N. The parameter t typically
	 * represents arc length or time. Used for path integrals, trajectory
	 * analysis, and geometric modeling.
	 * 
	 * @tparam N Dimension of the ambient space
	 */
	template<int N>
	class IParametricCurve : public IRealToVectorFunction<N>
	{
	public:
		/** @brief Get the minimum parameter value. */
		virtual Real getMinT() const = 0;
		
		/** @brief Get the maximum parameter value. */
		virtual Real getMaxT() const = 0;

		/**
		 * @brief Generate points along the curve for visualization.
		 * @param t1 Start parameter
		 * @param t2 End parameter
		 * @param numPoints Number of sample points
		 * @return Vector of points on the curve
		 */
		std::vector<VectorN<Real, N>> GetTrace(double t1, double t2, int numPoints) const
		{
			std::vector<VectorN<Real, N>> ret;
			if (numPoints <= 0)
				return ret;
			ret.reserve(static_cast<size_t>(numPoints));

			const Real tStart = static_cast<Real>(t1);
			if (numPoints == 1)
			{
				ret.push_back((*this)(tStart));
				return ret;
			}

			const Real tEnd = static_cast<Real>(t2);
			const Real deltaT = (tEnd - tStart) / (numPoints - 1);
			for (int i = 0; i < numPoints; i++)
			{
				const Real t = tStart + static_cast<Real>(i) * deltaT;
				ret.push_back((*this)(t));
			}
			return ret;
		}

		virtual ~IParametricCurve() {}
	};

	/**
	 * @brief Parametric curve with adjustable parameters.
	 * 
	 * @tparam N Dimension of the ambient space
	 */
	template<int N>
	class IParametricCurveParametrized : public IParametricCurve<N>, public IParametrized
	{
	public:
			/**
			 * @brief Evaluate the curve with explicit parameters.
			 * @param t Curve parameter
			 * @param params External parameter vector
			 * @return Point on the curve
			 */
			virtual VectorN<Real, N> operator()(Real t, const Vector<Real> &params) const = 0;
	};

	//////////////////////////////////////////////////////////////////////
	/**
	 * @brief Interface for parametric surfaces with variable domain.
	 * 
	 * Represents a surface S: D → R^N where D is a domain in R^2 with
	 * u ∈ [uMin, uMax] and w ∈ [wMin(u), wMax(u)]. The w-limits can
	 * depend on u, allowing non-rectangular domains (e.g., triangular,
	 * circular patches).
	 * 
	 * @tparam N Dimension of the ambient space (typically 3)
	 */
	template<int N>
	class IParametricSurface : public IVectorFunctionNM<2, N>
	{
	public:
		/**
		 * @brief Evaluate the surface at parameter (u, w).
		 * @param u First surface parameter
		 * @param w Second surface parameter
		 * @return Point on the surface
		 */
		virtual VectorN<Real, N> operator()(Real u, Real w) const = 0;

		/** @brief Get minimum u parameter. */
		virtual Real getMinU() const = 0;
		
		/** @brief Get maximum u parameter. */
		virtual Real getMaxU() const = 0;
		
		/**
		 * @brief Get minimum w parameter at given u.
		 * @param u The u-coordinate
		 * @return Minimum w value at this u
		 */
		virtual Real getMinW(Real u) const = 0;
		
		/**
		 * @brief Get maximum w parameter at given u.
		 * @param u The u-coordinate
		 * @return Maximum w value at this u
		 */
		virtual Real getMaxW(Real u) const = 0;

		/**
		 * @brief Evaluate using a 2D coordinate vector.
		 * @param coord Vector containing (u, w)
		 * @return Point on the surface
		 */
		virtual VectorN<Real, N> operator()(const VectorN<Real, 2>& coord) const
		{
			return operator()(coord[0], coord[1]);
		}

		virtual ~IParametricSurface() {}
	};

	/**
	 * @brief Interface for parametric surfaces on rectangular domains.
	 * 
	 * Simplified surface interface where the domain is a rectangle:
	 * u ∈ [uMin, uMax], w ∈ [wMin, wMax] with constant bounds.
	 * 
	 * @tparam N Dimension of the ambient space (typically 3)
	 */
	template<int N>
	class IParametricSurfaceRect : public IVectorFunctionNM<2, N>
	{
	public:
		/**
		 * @brief Evaluate the surface at parameter (u, w).
		 * @param u First surface parameter
		 * @param w Second surface parameter
		 * @return Point on the surface
		 */
		virtual VectorN<Real, N> operator()(Real u, Real w) const = 0;

		/** @brief Get minimum u parameter. */
		virtual Real getMinU() const = 0;
		
		/** @brief Get maximum u parameter. */
		virtual Real getMaxU() const = 0;
		
		/** @brief Get minimum w parameter (constant). */
		virtual Real getMinW() const = 0;
		
		/** @brief Get maximum w parameter (constant). */
		virtual Real getMaxW() const = 0;

		/**
		 * @brief Evaluate using a 2D coordinate vector.
		 * @param coord Vector containing (u, w)
		 * @return Point on the surface
		 */
		virtual VectorN<Real, N> operator()(const VectorN<Real, 2>& coord) const
		{
			return operator()(coord[0], coord[1]);
		}

		virtual ~IParametricSurfaceRect() {}
	};
}

///////////////////////////   mml/interfaces/IODESystem.h   ///////////////////////////

/**
 * @file IODESystem.h
 * @brief Interfaces for ordinary differential equation (ODE) systems.
 * 
 * Defines the contract for ODE systems that can be solved by MML's ODE solvers.
 * The hierarchy supports:
 * 
 * - **IODESystem** - Basic first-order ODE system: dx/dt = f(t, x)
 * - **IODESystemWithJacobian** - System with analytic Jacobian for implicit methods
 * - **IODESystemParametrized** - System with adjustable parameters
 * 
 * All ODE systems are expressed in first-order form. Higher-order ODEs must be
 * converted to equivalent first-order systems (e.g., y'' = f becomes y1' = y2, y2' = f).
 * 
 * @see ODESolver, ODESystemSolution, RungeKutta methods
 */




namespace MML
{
	/**
	 * @brief Interface for first-order ODE systems.
	 * 
	 * Represents a system of first-order ordinary differential equations:
	 * @f[
	 *   \frac{d\mathbf{x}}{dt} = \mathbf{f}(t, \mathbf{x})
	 * @f]
	 * 
	 * where x is an N-dimensional state vector and f is the derivative function.
	 * 
	 * **Implementation Requirements:**
	 * - derivs() must be thread-safe for parallel integration
	 * - getDim() returns the system dimension (number of equations)
	 * - getVarName() provides human-readable variable names for output
	 * 
	 * @note This is the base interface used by all MML ODE solvers including
	 *       Euler, Runge-Kutta, and adaptive step-size methods.
	 */
	class IODESystem
	{
	public:
		virtual ~IODESystem() = default;
		
		/**
		 * @brief Get the dimension (number of equations) of the system.
		 * @return Number of first-order equations in the system
		 */
		virtual int   getDim() const = 0;
		
		/**
		 * @brief Compute the derivatives at a given state.
		 * 
		 * Evaluates the right-hand side f(t, x) of the ODE system.
		 * 
		 * @param t Current time/independent variable
		 * @param x Current state vector (size = getDim())
		 * @param[out] dxdt Output derivative vector dx/dt (size = getDim())
		 */
		virtual void  derivs(const Real t, const Vector<Real> &x, Vector<Real> &dxdt) const = 0;

		/**
		 * @brief Get a human-readable name for a state variable.
		 * 
		 * Override this method to provide meaningful names for output
		 * and debugging (e.g., "position", "velocity", "theta").
		 * 
		 * @param ind Index of the variable (0 to getDim()-1)
		 * @return Name string for the variable
		 */
		virtual std::string getVarName(int ind) const
		{
			if (ind < 0 || ind >= getDim())
				return "var" + std::to_string(ind);

			return "var" + std::to_string(ind + 1); // 1-based index 
		}
	};

	/**
	 * @brief ODE system with analytic Jacobian matrix.
	 * 
	 * Extends IODESystem to provide the Jacobian matrix ∂f/∂x, which is
	 * required by implicit integration methods (e.g., backward Euler,
	 * implicit Runge-Kutta) and stiff ODE solvers.
	 * 
	 * The Jacobian matrix J has elements:
	 * @f[
	 *   J_{ij} = \frac{\partial f_i}{\partial x_j}
	 * @f]
	 * 
	 * @note Providing an analytic Jacobian improves both accuracy and
	 *       performance compared to numerical differentiation.
	 */
	class IODESystemWithJacobian : public IODESystem
	{
	public:
		/**
		 * @brief Compute derivatives and Jacobian matrix simultaneously.
		 * 
		 * @param t Current time
		 * @param x Current state vector
		 * @param[out] dxdt Output derivative vector
		 * @param[out] dydx Output Jacobian matrix (getDim() × getDim())
		 */
		virtual void jacobian(const Real t, const Vector<Real>& x, Vector<Real>& dxdt, Matrix<Real>& dydx) const = 0;
	};

	/**
	 * @brief ODE system with adjustable parameters.
	 * 
	 * Extends IODESystem to support systems where coefficients or parameters
	 * can be modified at runtime. Useful for parameter sweeps, sensitivity
	 * analysis, and fitting ODE models to data.
	 * 
	 * Example: A damped oscillator with adjustable damping and stiffness:
	 * @f[
	 *   \ddot{x} + c\dot{x} + kx = 0
	 * @f]
	 * where c and k are parameters.
	 */
	class IODESystemParametrized : public IODESystem, public IParametrized
	{
	public:
		virtual ~IODESystemParametrized() = default;
	};

}

///////////////////////////   mml/interfaces/IDynamicalSystem.h   ///////////////////////////

/**
 * @file IDynamicalSystem.h
 * @brief Interface for dynamical systems with advanced analysis capabilities.
 * 
 * Defines the contract for dynamical systems that support:
 * - Parameter and state variable metadata (names, ranges)
 * - Analytical or numerical Jacobian computation
 * - System property flags (autonomous, Hamiltonian, dissipative)
 * - Conserved quantities (invariants)
 * 
 * This interface extends IODESystemParametrized to enable advanced analysis
 * features like fixed point finding, Lyapunov exponent computation, and
 * bifurcation analysis.
 * 
 * @see IODESystemParametrized, DynamicalSystemBase, LorenzSystem
 */




namespace MML
{
	//=============================================================================
	// IDYNAMICALSYSTEM INTERFACE
	//=============================================================================

	/// @brief Extended interface for dynamical systems analysis
	///
	/// Extends IODESystemParametrized with:
	/// - Parameter metadata (names, ranges)
	/// - State variable metadata
	/// - Optional analytical Jacobian
	/// - System property flags
	class IDynamicalSystem : public IODESystemParametrized {
	public:
		virtual ~IDynamicalSystem() = default;

		//=========================================================================
		// METADATA
		//=========================================================================

		/** @brief Get name of state variable */
		virtual std::string getStateName(int i) const { return "x" + std::to_string(i); }

		/** @brief Get name of parameter */
		virtual std::string getParamName(int i) const { return "p" + std::to_string(i); }

		/** @brief Get valid range for parameter */
		virtual std::pair<Real, Real> getParamRange(int i) const {
			return {-1e10, 1e10}; // Default: no restriction
		}

		/** @brief Get default initial condition */
		virtual Vector<Real> getDefaultInitialCondition() const { return Vector<Real>(getDim(), 0.0); }

		//=========================================================================
		// JACOBIAN
		//=========================================================================

		/** @brief Does system provide analytical Jacobian? */
		virtual bool hasAnalyticalJacobian() const { return false; }

		/** @brief Compute Jacobian matrix at point (x, t) */
		virtual void jacobian(Real t, const Vector<Real>& x, Matrix<Real>& J) const {
			// Default: numerical Jacobian via finite differences
			int n = getDim();
			J.Resize(n, n);
			Vector<Real> f1(n), f2(n), xp(x);

			Real eps = std::sqrt(std::numeric_limits<Real>::epsilon());

			for (int j = 0; j < n; ++j) {
				Real h = eps * std::max<Real>(std::abs(x[j]), Real(1.0));
				xp[j] = x[j] + h;
				derivs(t, xp, f1);
				xp[j] = x[j] - h;
				derivs(t, xp, f2);
				xp[j] = x[j];

				for (int i = 0; i < n; ++i)
					J(i, j) = (f1[i] - f2[i]) / (2.0 * h);
			}
		}

		//=========================================================================
		// SYSTEM PROPERTIES
		//=========================================================================

		/** @brief Is the system autonomous (no explicit time dependence)? */
		virtual bool isAutonomous() const { return true; }

		/** @brief Is the system Hamiltonian (energy conserving)? */
		virtual bool isHamiltonian() const { return false; }

		/** @brief Is the system dissipative (contracting phase space)? */
		virtual bool isDissipative() const { return false; }

		//=========================================================================
		// INVARIANTS
		//=========================================================================

		/** @brief Number of conserved quantities */
		virtual int getNumInvariants() const { return 0; }

		/** @brief Name of invariant */
		virtual std::string getInvariantName(int i) const { return ""; }

		/** @brief Compute invariant value at state x */
		virtual Real computeInvariant(int i, const Vector<Real>& x) const { return 0.0; }
	};

} // namespace MML


///////////////////////////   mml/interfaces/IODESystemDAE.h   ///////////////////////////

/**
 * @file IODESystemDAE.h
 * @brief Interfaces for differential-algebraic equation (DAE) systems.
 * 
 * Defines the contract for DAE systems that can be solved by MML's DAE solvers.
 * DAEs combine differential equations with algebraic constraints:
 * 
 * **Semi-Explicit Index-1 Form (supported):**
 * @f[
 *   \frac{d\mathbf{x}}{dt} = \mathbf{f}(t, \mathbf{x}, \mathbf{y})
 * @f]
 * @f[
 *   \mathbf{0} = \mathbf{g}(t, \mathbf{x}, \mathbf{y})
 * @f]
 * 
 * Where:
 * - **x** (n-dimensional): Differential variables (have time derivatives)
 * - **y** (m-dimensional): Algebraic variables (satisfy constraints)
 * - **f**: Differential equations computing dx/dt
 * - **g**: Algebraic constraint equations (must equal zero)
 * 
 * **Index-1 Requirement:**
 * The Jacobian ∂g/∂y must be nonsingular for the DAE to be index-1.
 * This ensures the algebraic variables y can be uniquely determined
 * from the constraints given x and t.
 * 
 * **Common Use Cases:**
 * - Constrained mechanical systems (pendulum, rigid bodies)
 * - Electrical circuits (Kirchhoff's laws as constraints)
 * - Chemical reaction networks (mass balance constraints)
 * - Power systems (load flow equations)
 * 
 * @see DAESolver, DAESolution, IODESystem
 */




namespace MML
{
	/**
	 * @brief Interface for semi-explicit index-1 DAE systems.
	 * 
	 * Represents a differential-algebraic system in semi-explicit form:
	 * @f[
	 *   \frac{d\mathbf{x}}{dt} = \mathbf{f}(t, \mathbf{x}, \mathbf{y})
	 * @f]
	 * @f[
	 *   \mathbf{0} = \mathbf{g}(t, \mathbf{x}, \mathbf{y})
	 * @f]
	 * 
	 * **Implementation Requirements:**
	 * - getDiffDim() returns the dimension of differential variables x
	 * - getAlgDim() returns the dimension of algebraic variables y
	 * - diffEqs() computes the differential equations f(t, x, y)
	 * - algConstraints() computes the constraint residuals g(t, x, y)
	 * 
	 * **Consistent Initial Conditions:**
	 * Initial values (x₀, y₀) must satisfy g(t₀, x₀, y₀) = 0.
	 * Use ComputeConsistentIC() utility to find consistent y₀ given x₀.
	 * 
	 * @note This interface supports index-1 DAEs only. Higher-index DAEs
	 *       require index reduction techniques before using these solvers.
	 * 
	 * @example
	 * @code
	 * // Simple pendulum in Cartesian coordinates
	 * // Differential: dx/dt = vx, dy/dt = vy, dvx/dt = λx, dvy/dt = λy - g
	 * // Constraint: x² + y² = L²
	 * class PendulumDAE : public IODESystemDAE {
	 *     Real L = 1.0, g = 9.81;
	 * public:
	 *     int getDiffDim() const override { return 4; }  // x, y, vx, vy
	 *     int getAlgDim() const override { return 1; }   // λ (tension/L)
	 *     
	 *     void diffEqs(Real t, const Vector<Real>& diff, const Vector<Real>& alg,
	 *                  Vector<Real>& dxdt) const override {
	 *         Real x = diff[0], y = diff[1], vx = diff[2], vy = diff[3];
	 *         Real lambda = alg[0];
	 *         dxdt[0] = vx;
	 *         dxdt[1] = vy;
	 *         dxdt[2] = lambda * x;
	 *         dxdt[3] = lambda * y - g;
	 *     }
	 *     
	 *     void algConstraints(Real t, const Vector<Real>& diff, const Vector<Real>& alg,
	 *                         Vector<Real>& constraints) const override {
	 *         Real x = diff[0], y = diff[1];
	 *         constraints[0] = x*x + y*y - L*L;
	 *     }
	 * };
	 * @endcode
	 */
	class IODESystemDAE
	{
	public:
		virtual ~IODESystemDAE() = default;
		
		//=========================================================================
		//                           Dimensions
		//=========================================================================
		
		/**
		 * @brief Get the dimension of differential variables.
		 * @return Number of differential variables (x) in the system
		 */
		virtual int getDiffDim() const = 0;
		
		/**
		 * @brief Get the dimension of algebraic variables.
		 * @return Number of algebraic variables (y) in the system
		 */
		virtual int getAlgDim() const = 0;
		
		/**
		 * @brief Get the total dimension (differential + algebraic).
		 * @return Total number of variables in the system
		 */
		int getTotalDim() const { return getDiffDim() + getAlgDim(); }

		//=========================================================================
		//                           Equations
		//=========================================================================
		
		/**
		 * @brief Compute the differential equations dx/dt = f(t, x, y).
		 * 
		 * Evaluates the right-hand side of the differential equations.
		 * 
		 * @param t Current time/independent variable
		 * @param x Current differential state vector (size = getDiffDim())
		 * @param y Current algebraic state vector (size = getAlgDim())
		 * @param[out] dxdt Output derivative vector dx/dt (size = getDiffDim())
		 */
		virtual void diffEqs(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                     Vector<Real>& dxdt) const = 0;

		/**
		 * @brief Compute the algebraic constraint residuals g(t, x, y).
		 * 
		 * Evaluates the constraint equations. For a valid solution,
		 * the output should be zero (or within numerical tolerance).
		 * 
		 * @param t Current time/independent variable
		 * @param x Current differential state vector (size = getDiffDim())
		 * @param y Current algebraic state vector (size = getAlgDim())
		 * @param[out] g Output constraint residual vector (size = getAlgDim())
		 */
		virtual void algConstraints(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                            Vector<Real>& g) const = 0;

		//=========================================================================
		//                           Variable Names
		//=========================================================================
		
		/**
		 * @brief Get a human-readable name for a differential variable.
		 * 
		 * Override to provide meaningful names for output and debugging
		 * (e.g., "position_x", "velocity", "angle").
		 * 
		 * @param i Index of the differential variable (0 to getDiffDim()-1)
		 * @return Name string for the variable
		 */
		virtual std::string getDiffVarName(int i) const
		{
			if (i < 0 || i >= getDiffDim())
				return "x?";
			return "x" + std::to_string(i + 1);
		}
		
		/**
		 * @brief Get a human-readable name for an algebraic variable.
		 * 
		 * Override to provide meaningful names for output and debugging
		 * (e.g., "tension", "current", "lagrange_mult").
		 * 
		 * @param i Index of the algebraic variable (0 to getAlgDim()-1)
		 * @return Name string for the variable
		 */
		virtual std::string getAlgVarName(int i) const
		{
			if (i < 0 || i >= getAlgDim())
				return "y?";
			return "y" + std::to_string(i + 1);
		}
	};

	/**
	 * @brief DAE system with analytic Jacobian matrices.
	 * 
	 * Extends IODESystemDAE to provide the four Jacobian matrices needed
	 * for efficient implicit integration:
	 * 
	 * - **∂f/∂x**: How differential equations depend on differential variables
	 * - **∂f/∂y**: How differential equations depend on algebraic variables
	 * - **∂g/∂x**: How constraints depend on differential variables
	 * - **∂g/∂y**: How constraints depend on algebraic variables (MUST be nonsingular)
	 * 
	 * The combined system Jacobian for Newton iteration is:
	 * @f[
	 *   \begin{bmatrix}
	 *     I - h\frac{\partial f}{\partial x} & -h\frac{\partial f}{\partial y} \\
	 *     \frac{\partial g}{\partial x} & \frac{\partial g}{\partial y}
	 *   \end{bmatrix}
	 * @f]
	 * 
	 * **Index-1 Requirement:**
	 * For the DAE to be index-1, the Jacobian ∂g/∂y (returned by jacobian_gy)
	 * must be nonsingular. If this matrix is singular, the DAE has index > 1
	 * and requires index reduction before solving.
	 * 
	 * @note Providing analytic Jacobians significantly improves both accuracy
	 *       and performance compared to numerical differentiation.
	 */
	class IODESystemDAEWithJacobian : public IODESystemDAE
	{
	public:
		/**
		 * @brief Compute Jacobian ∂f/∂x (differential eqs w.r.t. differential vars).
		 * 
		 * @param t Current time
		 * @param x Differential state vector
		 * @param y Algebraic state vector
		 * @param[out] df_dx Output Jacobian matrix (getDiffDim() × getDiffDim())
		 */
		virtual void jacobian_fx(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                         Matrix<Real>& df_dx) const = 0;
		
		/**
		 * @brief Compute Jacobian ∂f/∂y (differential eqs w.r.t. algebraic vars).
		 * 
		 * @param t Current time
		 * @param x Differential state vector
		 * @param y Algebraic state vector
		 * @param[out] df_dy Output Jacobian matrix (getDiffDim() × getAlgDim())
		 */
		virtual void jacobian_fy(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                         Matrix<Real>& df_dy) const = 0;
		
		/**
		 * @brief Compute Jacobian ∂g/∂x (constraints w.r.t. differential vars).
		 * 
		 * @param t Current time
		 * @param x Differential state vector
		 * @param y Algebraic state vector
		 * @param[out] dg_dx Output Jacobian matrix (getAlgDim() × getDiffDim())
		 */
		virtual void jacobian_gx(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                         Matrix<Real>& dg_dx) const = 0;
		
		/**
		 * @brief Compute Jacobian ∂g/∂y (constraints w.r.t. algebraic vars).
		 * 
		 * **CRITICAL:** This matrix MUST be nonsingular for index-1 DAEs.
		 * If singular, the DAE has index > 1 and cannot be solved directly.
		 * 
		 * @param t Current time
		 * @param x Differential state vector
		 * @param y Algebraic state vector
		 * @param[out] dg_dy Output Jacobian matrix (getAlgDim() × getAlgDim())
		 */
		virtual void jacobian_gy(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                         Matrix<Real>& dg_dy) const = 0;
		
		/**
		 * @brief Compute all Jacobians simultaneously (optional optimization).
		 * 
		 * Override this if computing multiple Jacobians shares significant
		 * computation. Default implementation calls individual jacobian_* methods.
		 * 
		 * @param t Current time
		 * @param x Differential state vector
		 * @param y Algebraic state vector
		 * @param[out] df_dx Jacobian ∂f/∂x
		 * @param[out] df_dy Jacobian ∂f/∂y
		 * @param[out] dg_dx Jacobian ∂g/∂x
		 * @param[out] dg_dy Jacobian ∂g/∂y
		 */
		virtual void allJacobians(Real t, const Vector<Real>& x, const Vector<Real>& y,
		                          Matrix<Real>& df_dx, Matrix<Real>& df_dy,
		                          Matrix<Real>& dg_dx, Matrix<Real>& dg_dy) const
		{
			jacobian_fx(t, x, y, df_dx);
			jacobian_fy(t, x, y, df_dy);
			jacobian_gx(t, x, y, dg_dx);
			jacobian_gy(t, x, y, dg_dy);
		}
	};

	/**
	 * @brief DAE system with adjustable parameters.
	 * 
	 * Extends IODESystemDAE to support systems where coefficients or parameters
	 * can be modified at runtime. Useful for parameter sweeps, sensitivity
	 * analysis, and fitting DAE models to data.
	 * 
	 * @example
	 * @code
	 * // Pendulum with adjustable length and gravity
	 * class ParametrizedPendulum : public IODESystemDAEParametrized {
	 *     Real L = 1.0, g = 9.81;  // Default values
	 * public:
	 *     int getNumParam() const override { return 2; }
	 *     Real getParam(int i) const override { return i == 0 ? L : g; }
	 *     void setParam(int i, Real val) override { 
	 *         if (i == 0) L = val; else g = val; 
	 *     }
	 *     // ... rest of DAE implementation
	 * };
	 * @endcode
	 */
	class IODESystemDAEParametrized : public IODESystemDAE, public IParametrized
	{
	public:
		virtual ~IODESystemDAEParametrized() = default;
	};

} // namespace MML


///////////////////////////   mml/interfaces/ICoordTransf.h   ///////////////////////////

/**
 * @file ICoordTransf.h
 * @brief Coordinate transformation interfaces for N-dimensional spaces.
 * 
 * This file defines abstract interfaces for coordinate system transformations.
 * These interfaces provide a consistent protocol for converting between
 * different coordinate representations (e.g., Cartesian to spherical).
 * 
 * @note All coordinate transformations are implemented as vector functions
 *       where each output component can be accessed individually.
 */





namespace MML
{
	/**
	 * @brief Interface for coordinate transformations between vector spaces.
	 * 
	 * This template class defines the protocol for transforming coordinates
	 * from one representation to another. Implementations must provide both
	 * the transformation and access to individual component functions.
	 * 
	 * @tparam VectorFrom Type of the source coordinate vector
	 * @tparam VectorTo   Type of the destination coordinate vector
	 * @tparam N          Dimension of the coordinate space
	 * 
	 * Example implementations:
	 * - Cartesian to spherical coordinates
	 * - Cartesian to cylindrical coordinates
	 * - General curvilinear coordinate systems
	 */
	template<typename VectorFrom, typename VectorTo, int N>
	class ICoordTransf : public IVectorFunction<N>
	{
	public:
		/**
		 * @brief Transform coordinates from source to destination representation.
		 * @param in Input coordinates in source representation
		 * @return Transformed coordinates in destination representation
		 */
		virtual       VectorTo            transf(const VectorFrom& in) const = 0;
		
		/**
		 * @brief Get the scalar function for a specific coordinate component.
		 * @param i Component index (0 to N-1)
		 * @return Reference to the scalar function computing the i-th output component
		 * 
		 * @note **Lifetime contract**: The returned reference remains valid for the lifetime of
		 *       this ICoordTransf object. Callers must not cache the reference beyond the
		 *       parent object's lifetime. The transform object owns the underlying functions.
		 */
		virtual const IScalarFunction<N>& coordTransfFunc(int i) const = 0;

		virtual ~ICoordTransf() {}
	};

	/**
	 * @brief Interface for invertible coordinate transformations.
	 * 
	 * Extends ICoordTransf with inverse transformation capabilities.
	 * Use this interface when the coordinate transformation is bijective
	 * and both forward and inverse mappings are needed.
	 * 
	 * @tparam VectorFrom Type of the source coordinate vector
	 * @tparam VectorTo   Type of the destination coordinate vector
	 * @tparam N          Dimension of the coordinate space
	 */
	template<typename VectorFrom, typename VectorTo, int N>
	class ICoordTransfWithInverse : public virtual ICoordTransf<VectorFrom, VectorTo, N>
	{
	public:
		/**
		 * @brief Inverse transformation from destination back to source coordinates.
		 * @param in Input coordinates in destination representation
		 * @return Transformed coordinates in source representation
		 */
		virtual       VectorFrom          transfInverse(const VectorTo& in) const = 0;
		
		/**
		 * @brief Get the scalar function for a specific inverse coordinate component.
		 * @param i Component index (0 to N-1)
		 * @return Reference to the scalar function computing the i-th inverse component
		 * 
		 * @note **Lifetime contract**: The returned reference remains valid for the lifetime of
		 *       this ICoordTransfWithInverse object. Callers must not cache the reference beyond
		 *       the parent object's lifetime. The transform object owns the underlying functions.
		 */
		virtual const IScalarFunction<N>& inverseCoordTransfFunc(int i) const = 0;

		virtual ~ICoordTransfWithInverse() {}
	};
}

///////////////////////////   mml/interfaces/ITensorField.h   ///////////////////////////

/**
 * @file ITensorField.h
 * @brief Interfaces for position-dependent tensor fields.
 * 
 * Defines abstract interfaces for tensor fields - functions that assign a tensor
 * to each point in N-dimensional space. These are essential for differential
 * geometry and physics applications.
 * 
 * **Field Types:**
 * - ITensorField2<N>: Rank-2 tensor field, e.g., metric field g_ij(x)
 * - ITensorField3<N>: Rank-3 tensor field, e.g., Christoffel symbols Γ^i_jk(x)
 * - ITensorField4<N>: Rank-4 tensor field, e.g., Riemann curvature R^i_jkl(x)
 * - ITensorField5<N>: Rank-5 tensor field for specialized applications
 * 
 * Each field tracks its index variance (number of contravariant/covariant indices)
 * and provides both full tensor evaluation via operator() and component-wise
 * access via Component().
 * 
 * **Usage Examples:**
 * - Metric tensor fields for curved spacetime
 * - Electromagnetic field tensor
 * - Stress-energy tensor in general relativity
 * - Connection coefficients for parallel transport
 * 
 * @see ITensor.h for constant (position-independent) tensors
 * @see RiemannianManifold for applications
 */





namespace MML
{
	/**
	 * @brief Interface for rank-2 tensor fields in N-dimensional space.
	 * 
	 * Maps each position x ∈ R^N to a rank-2 tensor T_ij(x) or T^ij(x).
	 * The most common example is the metric tensor field g_ij(x).
	 * 
	 * Implementations must provide the Component() method for individual
	 * component evaluation, which is often more efficient than computing
	 * the full tensor.
	 * 
	 * @tparam N Dimension of the base space
	 */
	template<int N>
	class ITensorField2 : public IFunction<Tensor2<N>, const VectorN<Real, N>& >
	{
		int _numContravar;  ///< Number of contravariant (upper) indices
		int _numCovar;      ///< Number of covariant (lower) indices
	public:
		/**
		 * @brief Construct a tensor field with specified index structure.
		 * @param numContra Number of contravariant indices (0, 1, or 2)
		 * @param numCo Number of covariant indices (2-numContra)
		 */
		ITensorField2(int numContra, int numCo) : _numContravar(numContra), _numCovar(numCo) {}

		/** @brief Get the number of contravariant indices. */
		int getNumContravar() const { return _numContravar; }
		
		/** @brief Get the number of covariant indices. */
		int getNumCovar()			const { return _numCovar; }

		/**
		 * @brief Evaluate a single tensor component at a position.
		 * 
		 * More efficient than operator() when only specific components are needed.
		 * 
		 * @param i First tensor index
		 * @param j Second tensor index
		 * @param pos Position in N-dimensional space
		 * @return The component T_ij(pos) or T^ij(pos)
		 */
		virtual Real Component(int i, int j, const VectorN<Real, N>& pos) const = 0;

		virtual ~ITensorField2() {}
	};

	/**
	 * @brief Interface for rank-3 tensor fields in N-dimensional space.
	 * 
	 * Maps each position to a rank-3 tensor. Primary application is the
	 * Christoffel symbol field Γ^i_jk(x) representing connection coefficients
	 * on a manifold with metric.
	 * 
	 * @tparam N Dimension of the base space
	 */
	template<int N>
	class ITensorField3 : public IFunction<Tensor3<N>, const VectorN<Real, N>& >
	{
	protected:
		int _numContravar;
		int _numCovar;
	public:
		ITensorField3(int numContra, int numCo) : _numContravar(numContra), _numCovar(numCo) {}
		ITensorField3() : _numContravar(0), _numCovar(3) {}

		int getNumContravar() const { return _numContravar; }
		int getNumCovar() const { return _numCovar; }

		/**
		 * @brief Evaluate a single tensor component at a position.
		 * @param i First tensor index
		 * @param j Second tensor index
		 * @param k Third tensor index
		 * @param pos Position in N-dimensional space
		 * @return The component value at pos
		 */
		virtual Real    Component(int i, int j, int k, const VectorN<Real, N>& pos) const = 0;

		virtual ~ITensorField3() {}
	};

	/**
	 * @brief Interface for rank-4 tensor fields in N-dimensional space.
	 * 
	 * Maps each position to a rank-4 tensor. Primary application is the
	 * Riemann curvature tensor field R^i_jkl(x) describing intrinsic
	 * curvature of a manifold.
	 * 
	 * @tparam N Dimension of the base space
	 */
	template<int N>
	class ITensorField4 : public IFunction<Tensor4<N>, const VectorN<Real, N>& >
	{
	protected:
		int _numContravar;
		int _numCovar;
	public:
		ITensorField4(int numContra, int numCo) : _numContravar(numContra), _numCovar(numCo) {}
		ITensorField4() : _numContravar(0), _numCovar(4) {}

		int getNumContravar() const { return _numContravar; }
		int getNumCovar() const { return _numCovar; }

		/**
		 * @brief Evaluate a single tensor component at a position.
		 * @param i First tensor index
		 * @param j Second tensor index
		 * @param k Third tensor index
		 * @param l Fourth tensor index
		 * @param pos Position in N-dimensional space
		 * @return The component value at pos
		 */
		virtual Real    Component(int i, int j, int k, int l, const VectorN<Real, N>& pos) const = 0;

		virtual ~ITensorField4() {}
	};

	/**
	 * @brief Interface for rank-5 tensor fields in N-dimensional space.
	 * 
	 * Maps each position to a rank-5 tensor for specialized applications
	 * such as covariant derivatives of the Riemann tensor or higher-order
	 * curvature invariants.
	 * 
	 * @tparam N Dimension of the base space
	 */
	template<int N>
	class ITensorField5 : public IFunction<Tensor5<N>, const VectorN<Real, N>& >
	{
	protected:
		int _numContravar;
		int _numCovar;
	public:
		ITensorField5(int numContra, int numCo) : _numContravar(numContra), _numCovar(numCo) {}
		ITensorField5() : _numContravar(0), _numCovar(5) {}

		int getNumContravar() const { return _numContravar; }
		int getNumCovar() const { return _numCovar; }

		/**
		 * @brief Evaluate a single tensor component at a position.
		 * @param i First tensor index
		 * @param j Second tensor index
		 * @param k Third tensor index
		 * @param l Fourth tensor index
		 * @param m Fifth tensor index
		 * @param pos Position in N-dimensional space
		 * @return The component value at pos
		 */
		virtual Real    Component(int i, int j, int k, int l, int m, const VectorN<Real, N>& pos) const = 0;
		virtual ~ITensorField5() {}
	};
}

///////////////////////////   mml/interfaces/IODESystemStepCalculator.h   ///////////////////////////

/**
 * @file IODESystemStepCalculator.h
 * @brief Interface for ODE single-step calculation algorithms.
 * 
 * Defines the contract for step calculators that advance an ODE solution
 * by one step of size h. This is the core computational unit used by
 * ODE solvers to implement various numerical methods.
 * 
 * Implementations include Euler, Runge-Kutta (RK4, RK45), and other
 * single-step methods. The interface separates step computation from
 * step-size control, allowing flexible composition.
 * 
 * @see IODESystemStepper for adaptive step-size control
 * @see IODESystem for the ODE system interface
 */





namespace MML
{
	/**
	 * @brief Interface for single-step ODE integration methods.
	 * 
	 * Computes one integration step from state x at time t to an
	 * approximation at time t+h, along with an error estimate.
	 * 
	 * The error estimate xerr is used by adaptive step-size controllers
	 * to adjust h for optimal accuracy/efficiency trade-off.
	 * 
	 * **Implementation Requirements:**
	 * - Must be stateless (all state passed as parameters)
	 * - Should compute error estimate for adaptive stepping
	 * - Thread-safe for parallel integration of independent systems
	 */
	class IODESystemStepCalculator
	{
	public:
		/**
		 * @brief Compute a single integration step.
		 * 
		 * Advances the ODE solution from (t, x_start) to approximately (t+h, xout)
		 * using the provided derivative dxdt = f(t, x_start).
		 * 
		 * @param odeSystem The ODE system being integrated
		 * @param t Current time
		 * @param x_start Current state vector
		 * @param dxdt Derivative at (t, x_start), pre-computed by caller
		 * @param h Step size
		 * @param[out] xout State vector at t+h (approximate solution)
		 * @param[out] xerr Error estimate for adaptive step control
		 * 
		 * @note The caller provides dxdt to avoid redundant derivative evaluations
		 *       when the same derivative is needed for multiple purposes.
		 */
		virtual void calcStep(const IODESystem& odeSystem, 
													const Real t, const Vector<Real>& x_start, const Vector<Real>& dxdt,
													const Real h, Vector<Real>& xout, Vector<Real>& xerr) const = 0;
	};
}

///////////////////////////   mml/interfaces/IODESystemStepper.h   ///////////////////////////

/**
 * @file IODESystemStepper.h
 * @brief Interface for ODE stepping with adaptive error control.
 * 
 * Defines the contract for ODE steppers that manage step-size adaptation
 * based on local error estimates. Unlike IODESystemStepCalculator which
 * performs a single computation, steppers maintain state for adaptive
 * control and may reject/retry steps.
 * 
 * The stepper combines:
 * - Step calculation (via an embedded step calculator or direct implementation)
 * - Error estimation and comparison to tolerances
 * - Step-size adjustment heuristics
 * 
 * @see IODESystemStepCalculator for stateless step computation
 * @see ODESolver for the high-level integration driver
 */





namespace MML
{
	/**
	 * @brief Interface for adaptive ODE steppers.
	 * 
	 * Performs integration steps with error control, potentially maintaining
	 * internal state for step-size adaptation, FSAL (First Same As Last)
	 * optimizations, or dense output.
	 * 
	 * Unlike the stateless IODESystemStepCalculator, a stepper may:
	 * - Cache intermediate results between steps
	 * - Track step-size history for optimal adaptation
	 * - Provide dense output between step endpoints
	 * 
	 * @note Non-const doStep() allows implementations to update internal state.
	 */
	class IODESystemStepper	{
	public:
		/**
		 * @brief Perform an adaptive integration step.
		 * 
		 * Advances from (t, x_start) to (t+h, xout) with error estimation.
		 * Implementations may adjust internal parameters based on the
		 * computed error for subsequent step-size recommendations.
		 * 
		 * @param odeSystem The ODE system being integrated
		 * @param t Current time
		 * @param x_start Current state vector
		 * @param dxdt Derivative at (t, x_start)
		 * @param h Step size (may be suggested size; actual may differ)
		 * @param[out] xout State vector at t+h
		 * @param[out] xerr Error estimate for this step
		 */
		virtual void doStep(const IODESystem& odeSystem, 
												const Real t, const Vector<Real>& x_start, const Vector<Real>& dxdt,
												const Real h, Vector<Real>& xout, Vector<Real>& xerr) = 0;
	};
}

///////////////////////////   mml/base/BaseUtils/SymbolUtils.h   ///////////////////////////

namespace MML
{
	namespace Utils
	{
		/// @brief Computes the 3D Levi-Civita symbol (permutation symbol).
		/// @details Returns +1 for even permutations of (1,2,3), -1 for odd permutations,
		///          and 0 if any indices are equal or out of range.
		/// @param i First index (1-3)
		/// @param j Second index (1-3)
		/// @param k Third index (1-3)
		/// @return +1, -1, or 0 depending on permutation parity
		static constexpr int LeviCivita(int i, int j, int k) noexcept
		{
			if (i == j || j == k || i == k)
				return 0;

			if (i == 1 && j == 2 && k == 3)
				return 1;
			if (i == 2 && j == 3 && k == 1)
				return 1;
			if (i == 3 && j == 1 && k == 2)
				return 1;
			if (i == 3 && j == 2 && k == 1)
				return -1;
			if (i == 2 && j == 1 && k == 3)
				return -1;
			if (i == 1 && j == 3 && k == 2)
				return -1;

			return 0;
		}

		/// @brief Computes the 4D Levi-Civita symbol (permutation symbol).
		/// @details Returns +1 for even permutations of (1,2,3,4), -1 for odd permutations,
		///          and 0 if any indices are repeated or out of range.
		/// @param i First index (1-4)
		/// @param j Second index (1-4)
		/// @param k Third index (1-4)
		/// @param l Fourth index (1-4)
		/// @return +1, -1, or 0 depending on permutation parity
		static constexpr int LeviCivita(int i, int j, int k, int l) noexcept
		{
			// Validate input: must be permutation of {1, 2, 3, 4}
			bool present[5] = { false, false, false, false, false }; // index 0 unused
			int indices[4] = { i, j, k, l };
			
			for (int idx = 0; idx < 4; idx++)
			{
				if (indices[idx] < 1 || indices[idx] > 4)
					return 0; // Invalid index
				if (present[indices[idx]])
					return 0; // Duplicate index
				present[indices[idx]] = true;
			}
			
			// All indices 1,2,3,4 present - compute sign from permutation
			int a[4] = { i, j, k, l };
			int ret = 1;

			for (int i = 0; i < 4; i++)
				for (int j = i + 1; j < 4; j++)
					if (a[i] > a[j])
					{
						int tmp = a[i];
						a[i] = a[j];
						a[j] = tmp;
						ret *= -1;
					}
			return ret;
		}

		/// @brief Kronecker delta function.
		/// @details Returns 1 if indices are equal, 0 otherwise.
		/// @param i First index
		/// @param j Second index
		/// @return 1 if i == j, 0 otherwise
		static constexpr int KroneckerDelta(int i, int j) noexcept
		{
			return (i == j) ? 1 : 0;
		}

	} // namespace Utils
} // namespace MML


///////////////////////////   mml/base/BaseUtils/AngleCoordUtils.h   ///////////////////////////


namespace MML
{
	namespace Utils
	{
		// ============================================================================
		// Angle Conversions
		// ============================================================================

		/// @brief Converts angle from degrees to radians.
		/// @param angleDeg Angle in degrees
		/// @return Angle in radians
		static constexpr Real DegToRad(Real angleDeg) noexcept { return angleDeg * Constants::PI / 180.0; }

		/// @brief Converts angle from radians to degrees.
		/// @param angleRad Angle in radians
		/// @return Angle in degrees
		static constexpr Real RadToDeg(Real angleRad) noexcept { return angleRad * 180.0 / Constants::PI; }

		/// @brief Converts decimal degrees to degrees, minutes, seconds.
		/// @param angle Angle in decimal degrees
		/// @param[out] deg Integer degrees
		/// @param[out] min Integer minutes
		/// @param[out] sec Seconds (fractional)
		static void AngleDegToExplicit(Real angle, Real& deg, Real& min, Real& sec)
		{
			deg = floor(angle);
			min = floor((angle - deg) * 60.0);
			sec = (angle - deg - min / 60.0) * 3600.0;
		}

		/// @brief Converts radians to degrees, minutes, seconds.
		/// @param angleRad Angle in radians
		/// @param[out] deg Integer degrees
		/// @param[out] min Integer minutes
		/// @param[out] sec Seconds (fractional)
		static void AngleRadToExplicit(Real angleRad, Real& deg, Real& min, Real& sec) 
		{ 
			AngleDegToExplicit(angleRad * 180.0 / Constants::PI, deg, min, sec); 
		}

		/// @brief Converts degrees, minutes, seconds to decimal degrees.
		/// @param deg Integer degrees
		/// @param min Integer minutes
		/// @param sec Seconds
		/// @return Angle in decimal degrees
		static constexpr Real ExplicitToAngleDeg(Real deg, Real min, Real sec) noexcept 
		{ 
			return deg + min / 60.0 + sec / 3600.0; 
		}

		/// @brief Converts degrees, minutes, seconds to radians.
		/// @param deg Integer degrees
		/// @param min Integer minutes
		/// @param sec Seconds
		/// @return Angle in radians
		static constexpr Real ExplicitToAngleRad(Real deg, Real min, Real sec) noexcept 
		{ 
			return ExplicitToAngleDeg(deg, min, sec) * Constants::PI / 180.0; 
		}

		/// @brief Normalizes angle to [0, 2π) range.
		/// @param rad Angle in radians
		/// @return Normalized angle in [0, 2π)
		static Real AngleTo2PiRange(Real rad)
		{
			while (rad < 0)
				rad += 2 * Constants::PI;
			while (rad >= 2 * Constants::PI)
				rad -= 2 * Constants::PI;
			return rad;
		}

		/// @brief Normalizes angle to [-π, π) range.
		/// @param rad Angle in radians
		/// @return Normalized angle in [-π, π)
		static Real AngleToPiPiRange(Real rad)
		{
			while (rad < -Constants::PI)
				rad += 2 * Constants::PI;
			while (rad >= Constants::PI)
				rad -= 2 * Constants::PI;
			return rad;
		}

		// ============================================================================
		// Coordinate Transformations
		// ============================================================================
		/// @details Basic coordinate transformation functions following Math/ISO conventions.
		/// These are the underlying formulas used by CoordTransf classes in Core layer.
		///
		/// 2D: Cartesian (x, y) <-> Polar (r, phi)
		///     phi = azimuthal angle from positive x-axis
		///
		/// 3D Spherical (r, theta, phi) - Math/ISO convention:
		///     r     = radial distance from origin
		///     theta = polar angle (inclination) from positive z-axis, θ ∈ [0, π]
		///     phi   = azimuthal angle in xy-plane from positive x-axis
		///
		/// 3D Cylindrical (r, phi, z):
		///     r   = distance from z-axis
		///     phi = azimuthal angle in xy-plane from positive x-axis
		///     z   = height along z-axis

		/// @brief Converts 2D Cartesian coordinates to polar coordinates.
		/// @param x X-coordinate
		/// @param y Y-coordinate
		/// @param[out] r Radial distance from origin
		/// @param[out] phi Azimuthal angle from positive x-axis (radians)
		static void CartesianToPolar(Real x, Real y, Real& r, Real& phi)
		{
			r   = std::sqrt(x * x + y * y);
			phi = std::atan2(y, x);
		}

		/// @brief Converts 2D polar coordinates to Cartesian coordinates.
		/// @param r Radial distance from origin
		/// @param phi Azimuthal angle from positive x-axis (radians)
		/// @param[out] x X-coordinate
		/// @param[out] y Y-coordinate
		static void PolarToCartesian(Real r, Real phi, Real& x, Real& y)
		{
			x = r * std::cos(phi);
			y = r * std::sin(phi);
		}

		/// @brief Converts 3D Cartesian coordinates to spherical coordinates (Math/ISO convention).
		/// @param x X-coordinate
		/// @param y Y-coordinate
		/// @param z Z-coordinate
		/// @param[out] r Radial distance from origin
		/// @param[out] theta Polar angle from positive z-axis (radians, [0, π])
		/// @param[out] phi Azimuthal angle in xy-plane from positive x-axis (radians)
		static void CartesianToSpherical(Real x, Real y, Real z, Real& r, Real& theta, Real& phi)
		{
			r = std::sqrt(x * x + y * y + z * z);
			if (r == 0.0) {
				theta = 0.0;
				phi   = 0.0;
			} else {
				theta = std::acos(z / r);
				phi   = std::atan2(y, x);
			}
		}

		/// @brief Converts 3D spherical coordinates to Cartesian coordinates (Math/ISO convention).
		/// @param r Radial distance from origin
		/// @param theta Polar angle from positive z-axis (radians, [0, π])
		/// @param phi Azimuthal angle in xy-plane from positive x-axis (radians)
		/// @param[out] x X-coordinate
		/// @param[out] y Y-coordinate
		/// @param[out] z Z-coordinate
		static void SphericalToCartesian(Real r, Real theta, Real phi, Real& x, Real& y, Real& z)
		{
			x = r * std::sin(theta) * std::cos(phi);
			y = r * std::sin(theta) * std::sin(phi);
			z = r * std::cos(theta);
		}

		/// @brief Converts 3D Cartesian coordinates to cylindrical coordinates.
		/// @param x X-coordinate
		/// @param y Y-coordinate
		/// @param z_in Z-coordinate (input)
		/// @param[out] r Radial distance from z-axis
		/// @param[out] phi Azimuthal angle in xy-plane from positive x-axis (radians)
		/// @param[out] z_out Z-coordinate (output, same as z_in)
		static void CartesianToCylindrical(Real x, Real y, Real z_in, Real& r, Real& phi, Real& z_out)
		{
			r     = std::sqrt(x * x + y * y);
			phi   = std::atan2(y, x);
			z_out = z_in;
		}

		/// @brief Converts 3D cylindrical coordinates to Cartesian coordinates.
		/// @param r Radial distance from z-axis
		/// @param phi Azimuthal angle in xy-plane from positive x-axis (radians)
		/// @param z_in Z-coordinate (input)
		/// @param[out] x X-coordinate
		/// @param[out] y Y-coordinate
		/// @param[out] z_out Z-coordinate (output, same as z_in)
		static void CylindricalToCartesian(Real r, Real phi, Real z_in, Real& x, Real& y, Real& z_out)
		{
			x     = r * std::cos(phi);
			y     = r * std::sin(phi);
			z_out = z_in;
		}

	} // namespace Utils
} // namespace MML


///////////////////////////   mml/base/BaseUtils/ComparisonUtils.h   ///////////////////////////



namespace MML
{
	namespace Utils
	{
		// ============================================================================
		// Complex Number Comparisons
		// ============================================================================

		/// @brief Tests if two complex numbers are equal within tolerance (per component).
		/// @param a First complex number
		/// @param b Second complex number
		/// @param eps Tolerance for real and imaginary parts separately
		/// @return True if both real and imaginary differences are within tolerance
		static bool AreEqual(const Complex& a, const Complex& b, double eps = Defaults::ComplexAreEqualTolerance)
		{
			if (std::abs(a.real() - b.real()) > eps || std::abs(a.imag() - b.imag()) > eps)
				return false;
			return true;
		}

		/// @brief Tests if two complex numbers are equal within tolerance (absolute value).
		/// @param a First complex number
		/// @param b Second complex number
		/// @param eps Tolerance for |a - b|
		/// @return True if |a - b| <= eps
		static bool AreEqualAbs(const Complex& a, const Complex& b, double eps = Defaults::ComplexAreEqualAbsTolerance)
		{
			if (Abs(a - b) > eps)
				return false;
			return true;
		}

		// ============================================================================
		// Real Vector Comparisons
		// ============================================================================

		/// @brief Tests if two real vectors are equal within tolerance.
		/// @param a First vector
		/// @param b Second vector
		/// @param eps Tolerance for element-wise comparison
		/// @return True if vectors are equal within tolerance
		static bool AreEqual(const Vector<Real> &a, const Vector<Real> &b, 
		                     Real eps = Defaults::VectorIsEqualTolerance)
		{
			return a.IsEqualTo(b, eps);
		}

		// ============================================================================
		// Complex Vector Comparisons
		// ============================================================================

		/// @brief Tests if two complex vectors are equal within tolerance (per component).
		/// @param a First complex vector
		/// @param b Second complex vector
		/// @param eps Tolerance for each complex element
		/// @return True if all elements are equal within tolerance
		static bool AreEqual(const Vector<Complex>& a, const Vector<Complex>& b, 
		                     Real eps = Defaults::ComplexAreEqualTolerance)
		{
			if (a.size() != b.size())
				return false;

			for (int i = 0; i < a.size(); i++)
				if( !AreEqual(a[i], b[i], eps) )
					return false;

			return true;
		}

		/// @brief Tests if two complex vectors are equal within tolerance (absolute value).
		/// @param a First complex vector
		/// @param b Second complex vector
		/// @param eps Tolerance for |a[i] - b[i]|
		/// @return True if all elements differ by at most eps in absolute value
		static bool AreEqualAbs(const Vector<Complex>& a, const Vector<Complex>& b, 
		                        Real eps = Defaults::ComplexAreEqualAbsTolerance)
		{
			if (a.size() != b.size())
				return false;

			for (int i = 0; i < a.size(); i++)
				if ( !AreEqualAbs(a[i], b[i], eps) )
					return false;

			return true;
		}

	} // namespace Utils
} // namespace MML


///////////////////////////   mml/base/BaseUtils/VectorOps.h   ///////////////////////////



namespace MML
{
	namespace Utils
	{
		// ============================================================================
		// Vector<Real> Operations
		// ============================================================================

		/// @brief Computes scalar (dot) product of two real vectors.
		/// @param a First vector
		/// @param b Second vector
		/// @return Sum of element-wise products
		/// @throws VectorDimensionError if vectors have different sizes
		static Real ScalarProduct(const Vector<Real>& a, const Vector<Real>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("ScalarProduct - must be same dim", a.size(), b.size());

			Real ret = 0;
			for (int i = 0; i < a.size(); i++)
				ret += a[i] * b[i];

			return ret;
		}

		/// @brief Computes scalar (dot) product of two complex vectors.
		/// @details Computes sum of a[i] * conj(b[i]) for proper inner product.
		/// @param a First complex vector
		/// @param b Second complex vector (conjugated in product)
		/// @return Complex inner product
		/// @throws VectorDimensionError if vectors have different sizes
		static Complex ScalarProduct(const Vector<Complex>& a, const Vector<Complex>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("ScalarProduct - must be same dim", a.size(), b.size());

			Complex ret = 0;
			for (int i = 0; i < a.size(); i++)
				ret += a[i] * std::conj(b[i]);

			return ret;
		}

		/// @brief Computes angle between two real vectors.
		/// @param a First vector
		/// @param b Second vector
		/// @return Angle in radians [0, π]
		/// @throws VectorDimensionError if vectors have different sizes
		static Real VectorsAngle(const Vector<Real>& a, const Vector<Real>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("Vector::AngleToVector - vectors must be equal size", a.size(), b.size());

			Real cosAngle = ScalarProduct(a, b) / (a.NormL2() * b.NormL2());
			cosAngle = std::clamp(cosAngle, Real(-1), Real(1));
			return std::acos(cosAngle);
		}

		/// @brief Computes projection of vector onto direction of another vector.
		/// @param orig Vector to project
		/// @param b Direction vector to project onto
		/// @return Component of orig parallel to b
		static Vector<Real> VectorProjectionParallelTo(const Vector<Real>& orig, const Vector<Real>& b)
		{
			return ScalarProduct(orig, b) / ScalarProduct(b, b) * b;
		}

		/// @brief Computes rejection of vector from direction of another vector.
		/// @param orig Vector to project
		/// @param b Direction vector to reject from
		/// @return Component of orig perpendicular to b
		static Vector<Real> VectorProjectionPerpendicularTo(const Vector<Real>& orig, const Vector<Real>& b)
		{
			return orig - VectorProjectionParallelTo(orig, b);
		}

		// ============================================================================
		// VectorN<Real/Complex, N> Operations
		// ============================================================================

		/// @brief Computes scalar (dot) product of two fixed-size real vectors.
		/// @tparam N Vector dimension
		/// @param a First vector
		/// @param b Second vector
		/// @return Sum of element-wise products
		template<int N>
		static Real ScalarProduct(const VectorN<Real, N> &a, const VectorN<Real, N> &b)
		{
			Real ret = 0;
			for (int i = 0; i < N; i++)
				ret += a[i] * b[i];
			return ret;
		}

		/// @brief Computes scalar (dot) product of two fixed-size complex vectors.
		/// @details Computes sum of a[i] * conj(b[i]) for proper inner product.
		/// @tparam N Vector dimension
		/// @param a First complex vector
		/// @param b Second complex vector (conjugated in product)
		/// @return Complex inner product
		template<int N> 
		static Complex ScalarProduct(const VectorN<Complex, N>& a, const VectorN<Complex, N>& b)
		{
			Complex ret = 0;
			for (int i = 0; i < N; i++)
				ret += a[i] * std::conj(b[i]);
			return ret;
		}

		/// @brief Computes angle between two fixed-size real vectors.
		/// @tparam N Vector dimension
		/// @param a First vector
		/// @param b Second vector
		/// @return Angle in radians [0, π]
		template<int N> 
		static Real VectorsAngle(const VectorN<Real, N> &a, const VectorN<Real, N> &b)
		{
			Real cosAngle = ScalarProduct(a, b) / (a.NormL2() * b.NormL2());
			cosAngle = std::clamp(cosAngle, Real(-1), Real(1));
			return std::acos(cosAngle);
		}

		// ============================================================================
		// Outer Product
		// ============================================================================

		/// @brief Computes outer product of two vectors.
		/// @details Result is matrix C where C[i][j] = a[i] * b[j].
		/// @tparam Type Element type
		/// @param a First vector (determines rows)
		/// @param b Second vector (determines columns)
		/// @return Matrix of size a.size() x b.size()
		template<class Type> 
		static Matrix<Type> OuterProduct(const Vector<Type>& a, const Vector<Type>& b)
		{
			Matrix<Type> ret(a.size(), b.size());

			for (int i = 0; i < a.size(); i++)
				for (int j = 0; j < b.size(); j++)
					ret[i][j] = a[i] * b[j];

			return ret;
		}

	} // namespace Utils
} // namespace MML


///////////////////////////   mml/base/BaseUtils/MatrixOps.h   ///////////////////////////



namespace MML
{
	namespace Utils
	{
		// ============================================================================
		// Creating Matrix from Vector
		// ============================================================================

		/// @brief Creates 1×n row matrix from vector.
		/// @tparam Type Element type
		/// @param b Source vector
		/// @return Matrix with single row containing vector elements
		template<class Type> 
		static Matrix<Type> RowMatrixFromVector(const Vector<Type>& b)
		{
			Matrix<Type> ret(1, (int)b.size());
			for (int i = 0; i < b.size(); i++)
				ret[0][i] = b[i];

			return ret;
		}

		/// @brief Creates n×1 column matrix from vector.
		/// @tparam Type Element type
		/// @param b Source vector
		/// @return Matrix with single column containing vector elements
		template<class Type> 
		static Matrix<Type> ColumnMatrixFromVector(const Vector<Type>& b)
		{
			Matrix<Type> ret((int)b.size(), 1);
			for (int i = 0; i < b.size(); i++)
				ret[i][0] = b[i];

			return ret;
		}

		/// @brief Creates n×n diagonal matrix from vector.
		/// @tparam Type Element type
		/// @param b Source vector (becomes diagonal elements)
		/// @return Square diagonal matrix with b[i] on diagonal
		template<class Type> 
		static Matrix<Type> DiagonalMatrixFromVector(const Vector<Type>& b)
		{
			Matrix<Type> ret((int)b.size(), (int)b.size());
			for (int i = 0; i < b.size(); i++)
				ret[i][i] = b[i];

			return ret;
		}

		/// @brief Creates matrix with vectors as rows.
		/// @tparam Type Element type
		/// @param b List of vectors (each becomes a row)
		/// @return Matrix with b.size() rows
		template<class Type> 
		static Matrix<Type> MatrixFromVectorsInRows(const std::vector<Vector<Type>>& b)
		{
			Matrix<Type> ret((int)b.size(), (int)b[0].size());
			for (int i = 0; i < b.size(); i++)
				for (int j = 0; j < b[i].size(); j++)
					ret[i][j] = b[i][j];
			return ret;
		}

		/// @brief Creates matrix with vectors as columns.
		/// @tparam Type Element type
		/// @param b List of vectors (each becomes a column)
		/// @return Matrix with b.size() columns
		template<class Type> 
		static Matrix<Type> MatrixFromVectorsInColumns(const std::vector<Vector<Type>>& b)
		{
			Matrix<Type> ret((int)b[0].size(), (int)b.size());
			for (int i = 0; i < b.size(); i++)
				for (int j = 0; j < b[i].size(); j++)
					ret[j][i] = b[i][j];
			return ret;
		}

		/// @brief Creates 1×N row matrix from fixed-size vector.
		/// @tparam Type Element type
		/// @tparam N Vector dimension
		/// @param b Source vector
		/// @return MatrixNM<1,N> row matrix
		template<class Type, int N> 
		MatrixNM<Type, 1, N> RowMatrixFromVector(const VectorN<Type, N>& b)
		{
			MatrixNM<Type, 1, N>  ret;
			for (int j = 0; j < N; j++)
				ret(0, j) = b[j];

			return ret;
		}

		/// @brief Creates N×1 column matrix from fixed-size vector.
		/// @tparam Type Element type
		/// @tparam N Vector dimension
		/// @param b Source vector
		/// @return MatrixNM<N,1> column matrix
		template<class Type, int N> 
		MatrixNM<Type, N, 1> ColumnMatrixFromVector(const VectorN<Type, N>& b)
		{
			MatrixNM<Type, N, 1>  ret;
			for (int i = 0; i < N; i++)
				ret(i, 0) = b[i];
			return ret;
		}

		/// @brief Creates N×N diagonal matrix from fixed-size vector.
		/// @tparam Type Element type
		/// @tparam N Vector dimension
		/// @param b Source vector (becomes diagonal elements)
		/// @return MatrixNM<N,N> diagonal matrix
		template<class Type, int N> 
		MatrixNM<Type, N, N> DiagonalMatrixFromVector(const VectorN<Type, N>& b)
		{
			MatrixNM<Type, N, N> ret;
			for (int i = 0; i < N; i++)
				ret[i][i] = b[i];
			return ret;
		}

		// ============================================================================
		// Matrix Algebraic Operations
		// ============================================================================

		/// @brief Computes matrix commutator [A, B] = AB - BA.
		/// @tparam Type Element type
		/// @param a First matrix
		/// @param b Second matrix
		/// @return Commutator matrix AB - BA
		template<class Type> 
		static Matrix<Type> Commutator(const Matrix<Type>& a, const Matrix<Type>& b)
		{
			return a * b - b * a;
		}

		/// @brief Computes matrix anti-commutator {A, B} = AB + BA.
		/// @tparam Type Element type
		/// @param a First matrix
		/// @param b Second matrix
		/// @return Anti-commutator matrix AB + BA
		template<class Type> 
		static Matrix<Type> AntiCommutator(const Matrix<Type>& a, const Matrix<Type>& b)
		{
			return a * b + b * a;
		}

		/// @brief Decomposes matrix into symmetric and antisymmetric parts.
		/// @details For any matrix A: A = (A + Aᵀ)/2 + (A - Aᵀ)/2 = Sym + Antisym
		/// @tparam Type Element type
		/// @param orig Original square matrix
		/// @param[out] outSym Symmetric part (A + Aᵀ)/2
		/// @param[out] outAntiSym Antisymmetric part (A - Aᵀ)/2
		/// @throws MatrixDimensionError if matrix is not square
		template<class Type> 
		static void MatrixDecomposeToSymAntisym(const Matrix<Type>& orig, 
		                                        Matrix<Type>& outSym, 
		                                        Matrix<Type>& outAntiSym)
		{
			if (orig.rows() != orig.cols())
				throw MatrixDimensionError("MatrixDecompose - matrix must be square", orig.rows(), orig.cols(), -1, -1);

			auto transp = orig.transpose();
			outSym = (orig + transp) * 0.5;
			outAntiSym = (orig - transp) * 0.5;
		}

		// ============================================================================
		// Matrix Functions (Power Series)
		// ============================================================================

		/// @brief Computes matrix exponential exp(A) via power series.
		/// @details exp(A) = I + A + A²/2! + A³/3! + ... (truncated at n terms)
		/// @tparam Type Element type
		/// @param a Square matrix
		/// @param n Number of terms in series expansion (default 10)
		/// @return Matrix exponential exp(A)
		template<class Type> 
		static Matrix<Type> Exp(const Matrix<Type>& a, int n = 10)
		{
			Matrix<Type> ret(a.rows(), a.cols());
			Matrix<Type> a_pow_n(a);

			double fact = 1.0;
			ret.MakeUnitMatrix();

			for (int i = 1; i <= n; i++)
			{
				fact *= (double)i;
				ret += a_pow_n / fact;

				a_pow_n = a_pow_n * a;
			}

			return ret;
		}

		/// @brief Computes matrix sine sin(A) via power series.
		/// @details sin(A) = A - A³/3! + A⁵/5! - ... (odd powers, alternating signs)
		/// @tparam Type Element type
		/// @param a Square matrix
		/// @param n Number of terms in series expansion (default 10)
		/// @return Matrix sine sin(A)
		template<class Type> 
		static Matrix<Type> Sin(const Matrix<Type>& a, int n = 10)
		{
			Matrix<Type> ret(a.rows(), a.cols());		// initialized to zero matrix!
			Matrix<Type> a_pow_n(a);
			
			double fact = 1.0;
			
			for (int i = 1; i <= n; i += 2)
			{
				ret += a_pow_n / fact;
				
				a_pow_n = (-1.0) * a_pow_n * a * a;
				fact *= (double)(i + 1) * (i + 2);
			}
			return ret;
		}

		/// @brief Computes matrix cosine cos(A) via power series.
		/// @details cos(A) = I - A²/2! + A⁴/4! - ... (even powers, alternating signs)
		/// @tparam Type Element type
		/// @param a Square matrix
		/// @param n Number of terms in series expansion (default 10)
		/// @return Matrix cosine cos(A)
		template<class Type> 
		static Matrix<Type> Cos(const Matrix<Type>& a, int n = 10)
		{
			Matrix<Type> ret(a.rows(), a.cols());
			Matrix<Type> a_pow_n(a.rows(), a.cols());

			double fact = 1.0;
			ret.MakeUnitMatrix();
			a_pow_n.MakeUnitMatrix();

			for (int i = 1; i <= n; i+=2)
			{
				a_pow_n = (-1.0) * a_pow_n * a * a;
				fact *= (double)(i) * (i + 1);

				ret += a_pow_n / fact;
			}
			return ret;
		}

		/// @brief Matrix hyperbolic sine: sinh(A) = (exp(A) - exp(-A)) / 2
		/// Power series: sinh(A) = A + A³/3! + A⁵/5! + ...
		/// @param a Square matrix
		/// @param n Number of terms in series expansion
		/// @return Matrix sinh(A)
		template<class Type> 
		static Matrix<Type> Sinh(const Matrix<Type>& a, int n = 10)
		{
			Matrix<Type> ret(a.rows(), a.cols());		// initialized to zero matrix
			Matrix<Type> a_pow_n(a);
			
			double fact = 1.0;
			
			// sinh(x) = x + x³/3! + x⁵/5! + ... (odd powers, all positive)
			for (int i = 1; i <= n; i += 2)
			{
				ret += a_pow_n / fact;
				
				a_pow_n = a_pow_n * a * a;  // Next odd power
				fact *= (double)(i + 1) * (i + 2);
			}
			return ret;
		}

		/// @brief Matrix hyperbolic cosine: cosh(A) = (exp(A) + exp(-A)) / 2
		/// Power series: cosh(A) = I + A²/2! + A⁴/4! + ...
		/// @param a Square matrix
		/// @param n Number of terms in series expansion
		/// @return Matrix cosh(A)
		template<class Type> 
		static Matrix<Type> Cosh(const Matrix<Type>& a, int n = 10)
		{
			Matrix<Type> ret(a.rows(), a.cols());
			Matrix<Type> a_pow_n(a.rows(), a.cols());

			double fact = 1.0;
			ret.MakeUnitMatrix();
			a_pow_n.MakeUnitMatrix();

			// cosh(x) = 1 + x²/2! + x⁴/4! + ... (even powers, all positive)
			for (int i = 2; i <= n; i += 2)
			{
				a_pow_n = a_pow_n * a * a;  // Next even power
				fact *= (double)(i - 1) * i;

				ret += a_pow_n / fact;
			}
			return ret;
		}

		// ============================================================================
		// Real Matrix Properties
		// ============================================================================

		/// @brief Tests if a real matrix is orthogonal (Q·Qᵀ = I).
		/// @param mat Square real matrix
		/// @param eps Tolerance for unit matrix comparison
		/// @return True if matrix is orthogonal within tolerance
		/// @throws MatrixDimensionError if matrix is not square
		static bool IsOrthogonal(const Matrix<Real>& mat, double eps = Defaults::IsMatrixOrthogonalTolerance)
		{
			if (mat.rows() != mat.cols())
				throw MatrixDimensionError("IsOrthogonal - matrix must be square", mat.rows(), mat.cols(), -1, -1);

			Matrix<Real> matProd = mat * mat.transpose();

			return matProd.isIdentity(eps);
		}

		// ============================================================================
		// Complex Matrix Operations
		// ============================================================================

		/// @brief Extracts real part of complex matrix.
		/// @param a Complex matrix
		/// @return Real matrix with a[i][j].real()
		static Matrix<Real> GetRealPart(const Matrix<Complex>& a)
		{
			Matrix<Real> ret(a.rows(), a.cols());

			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = a[i][j].real();
				}

			return ret;
		}

		/// @brief Extracts imaginary part of complex matrix.
		/// @param a Complex matrix
		/// @return Real matrix with a[i][j].imag()
		static Matrix<Real> GetImagPart(const Matrix<Complex>& a)
		{
			Matrix<Real> ret(a.rows(), a.cols());

			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = a[i][j].imag();
				}

			return ret;
		}

		/// @brief Computes conjugate transpose (Hermitian adjoint) of complex matrix.
		/// @details Result[j][i] = conj(mat[i][j])
		/// @param mat Complex matrix
		/// @return Conjugate transpose matrix
		static Matrix<Complex> GetConjugateTranspose(const Matrix<Complex>& mat)
		{
			Matrix<Complex> ret(mat.cols(), mat.rows());

			for (int i = 0; i < mat.rows(); i++)
				for (int j = 0; j < mat.cols(); j++)
					ret[j][i] = std::conj(mat[i][j]);

			return ret;
		}

		/// @brief Creates complex matrix from real matrix (zero imaginary parts).
		/// @param mat Real matrix
		/// @return Complex matrix with mat[i][j] + 0i
		static Matrix<Complex> CmplxMatFromRealMat(const Matrix<Real>& mat)
		{
			Matrix<Complex> mat_cmplx(mat.rows(), mat.cols());

			for (int i = 0; i < mat.rows(); i++)
				for (int j = 0; j < mat.cols(); j++)
					mat_cmplx[i][j] = Complex(mat(i, j), 0.0);

			return mat_cmplx;
		}

		/// @brief Tests if complex matrix has all real entries (zero imaginary parts).
		/// @param mat Complex matrix
		/// @return True if all imaginary parts are exactly zero
		static bool IsComplexMatReal(const Matrix<Complex>& mat)
		{
			for (int i = 0; i < mat.rows(); i++)
				for (int j = 0; j < mat.cols(); j++)
					if (mat[i][j].imag() != 0.0)
						return false;

			return true;
		}

		/// @brief Tests if complex matrix is Hermitian (A = A†).
		/// @details A Hermitian matrix equals its conjugate transpose: A[i][j] = conj(A[j][i])
		/// @param mat Square complex matrix
		/// @return True if matrix is Hermitian
		/// @throws MatrixDimensionError if matrix is not square
		static bool IsHermitian(const Matrix<Complex>& mat)
		{
			if (mat.rows() != mat.cols())
				throw MatrixDimensionError("IsHermitian - matrix must be square", mat.rows(), mat.cols(), -1, -1);

			for (int i = 0; i < mat.rows(); i++)
				for (int j = i + 1; j < mat.cols(); j++)
					if (mat[i][j] != std::conj(mat[j][i]))
						return false;
			return true;
		}

		/// @brief Tests if complex matrix is unitary (U·U† = I).
		/// @details A unitary matrix has its conjugate transpose as its inverse.
		/// @param mat Square complex matrix
		/// @return True if matrix is unitary
		/// @throws MatrixDimensionError if matrix is not square
		static bool IsUnitary(const Matrix<Complex>& mat)
		{
			// IsUnitary - complex square matrix U is unitary if its conjugate transpose U* is also its inverse
			if (mat.rows() != mat.cols())
				throw MatrixDimensionError("IsUnitary - matrix must be square", mat.rows(), mat.cols(), -1, -1);

			Matrix<Complex> matProd = mat * GetConjugateTranspose(mat);

			return matProd.isIdentity();
		}

	} // namespace Utils
} // namespace MML



///////////////////////////   mml/base/BaseUtils/MixedTypeOps.h   ///////////////////////////



namespace MML
{
	namespace Utils
	{
		// ============================================================================
		// Vector<Complex> - Vector<Real> Operations
		// ============================================================================

		/// @brief Adds complex and real vectors element-wise.
		/// @param a Complex vector
		/// @param b Real vector
		/// @return Complex vector with a[i] + b[i]
		/// @throws VectorDimensionError if vectors have different sizes
		static Vector<Complex> AddVec(const Vector<Complex>& a, const Vector<Real>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("AddVec(Complex, Real) - must be same dim", a.size(), b.size());

			Vector<Complex> ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret[i] = a[i] + b[i];
			return ret;
		}

		/// @brief Adds real and complex vectors element-wise.
		/// @param a Real vector
		/// @param b Complex vector
		/// @return Complex vector with a[i] + b[i]
		/// @throws VectorDimensionError if vectors have different sizes
		static Vector<Complex> AddVec(const Vector<Real>& a, const Vector<Complex>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("AddVec(Real, Complex) - must be same dim", a.size(), b.size());

			Vector<Complex> ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret[i] = a[i] + b[i];
			return ret;
		}

		/// @brief Subtracts real vector from complex vector element-wise.
		/// @param a Complex vector
		/// @param b Real vector
		/// @return Complex vector with a[i] - b[i]
		/// @throws VectorDimensionError if vectors have different sizes
		static Vector<Complex> SubVec(const Vector<Complex>& a, const Vector<Real>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("SubVec(Complex, Real) - must be same dim", a.size(), b.size());

			Vector<Complex> ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret[i] = a[i] - b[i];
			return ret;
		}

		/// @brief Subtracts complex vector from real vector element-wise.
		/// @param a Real vector
		/// @param b Complex vector
		/// @return Complex vector with a[i] - b[i]
		/// @throws VectorDimensionError if vectors have different sizes
		static Vector<Complex> SubVec(const Vector<Real>& a, const Vector<Complex>& b)
		{
			if (a.size() != b.size())
				throw VectorDimensionError("SubVec(Real, Complex) - must be same dim", a.size(), b.size());

			Vector<Complex> ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret[i] = a[i] - b[i];
			return ret;
		}

		/// @brief Multiplies complex scalar by real vector.
		/// @param a Complex scalar
		/// @param b Real vector
		/// @return Complex vector with a * b[i]
		static Vector<Complex> MulVec(const Complex& a, const Vector<Real>& b)
		{
			Vector<Complex> ret(b.size());;
			for (int i = 0; i < b.size(); i++)
				ret[i] = a * b[i];
			return ret;
		}

		/// @brief Multiplies real vector by complex scalar.
		/// @param a Real vector
		/// @param b Complex scalar
		/// @return Complex vector with b * a[i]
		static Vector<Complex> MulVec(const Vector<Real>& a, const Complex& b)
		{
			Vector<Complex> ret(a.size());;
			for (int i = 0; i < a.size(); i++)
				ret[i] = b * a[i];
			return ret;
		}

		// ============================================================================
		// Matrix<Complex> - Matrix<Real> Operations
		// ============================================================================

		/// @brief Adds complex and real matrices element-wise.
		/// @param a Complex matrix
		/// @param b Real matrix
		/// @return Complex matrix with a[i][j] + b[i][j]
		/// @throws MatrixDimensionError if matrices have different dimensions
		static Matrix<Complex> AddMat(const Matrix<Complex>& a, const Matrix<Real>& b)
		{
			if (a.rows() != b.rows() || a.cols() != b.cols())
				throw MatrixDimensionError("AddMat(Complex, Real) - must be same dim", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(a);
			for (int i = 0; i < b.rows(); i++)
				for (int j = 0; j < b.cols(); j++)
					ret[i][j] += b[i][j];
			return ret;
		}

		/// @brief Adds real and complex matrices element-wise.
		/// @param a Real matrix
		/// @param b Complex matrix
		/// @return Complex matrix with a[i][j] + b[i][j]
		/// @throws MatrixDimensionError if matrices have different dimensions
		static Matrix<Complex> AddMat(const Matrix<Real>& a, const Matrix<Complex>& b)
		{
			if (a.rows() != b.rows() || a.cols() != b.cols())
				throw MatrixDimensionError("AddMat(Real, Complex) - must be same dim", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(b);
			for (int i = 0; i < a.rows(); i++)
				for (int j = 0; j < a.cols(); j++)
					ret[i][j] += a[i][j];
			return ret;
		}

		/// @brief Subtracts real matrix from complex matrix element-wise.
		/// @param a Complex matrix
		/// @param b Real matrix
		/// @return Complex matrix with a[i][j] - b[i][j]
		/// @throws MatrixDimensionError if matrices have different dimensions
		static Matrix<Complex> SubMat(const Matrix<Complex>& a, const Matrix<Real>& b)
		{
			if (a.rows() != b.rows() || a.cols() != b.cols())
				throw MatrixDimensionError("SubMat(Complex, Real) - must be same dim", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(a);
			for (int i = 0; i < b.rows(); i++)
				for (int j = 0; j < b.cols(); j++)
					ret[i][j] -= b[i][j];
			return ret;
		}

		/// @brief Subtracts complex matrix from real matrix element-wise.
		/// @param a Real matrix
		/// @param b Complex matrix
		/// @return Complex matrix with a[i][j] - b[i][j]
		/// @throws MatrixDimensionError if matrices have different dimensions
		static Matrix<Complex> SubMat(const Matrix<Real>& a, const Matrix<Complex>& b)
		{
			if (a.rows() != b.rows() || a.cols() != b.cols())
				throw MatrixDimensionError("SubMat(Real, Complex) - must be same dim", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(b);
			for (int i = 0; i < a.rows(); i++)
				for (int j = 0; j < a.cols(); j++)
					ret[i][j] = a[i][j] - b[i][j];
			return ret;
		}

		/// @brief Multiplies complex scalar by real matrix.
		/// @param a Complex scalar
		/// @param b Real matrix
		/// @return Complex matrix with a * b[i][j]
		static Matrix<Complex> MulMat(const Complex& a, const Matrix<Real>& b)
		{
			Matrix<Complex> ret(b.rows(), b.cols());

			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = a * b[i][j];
				}

			return ret;
		}

		/// @brief Multiplies real matrix by complex scalar.
		/// @param a Real matrix
		/// @param b Complex scalar
		/// @return Complex matrix with b * a[i][j]
		static Matrix<Complex> MulMat(const Matrix<Real>& a, const Complex& b)
		{
			Matrix<Complex> ret(a.rows(), a.cols());

			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = b * a[i][j];
				}

			return ret;
		}
		
		/// @brief Multiplies complex matrix by real matrix.
		/// @param a Complex matrix (m×n)
		/// @param b Real matrix (n×p)
		/// @return Complex matrix (m×p)
		/// @throws MatrixDimensionError if inner dimensions don't match
		static Matrix<Complex> MulMat(const Matrix<Complex>& a, const Matrix<Real>& b)
		{
			if (a.cols() != b.rows())
				throw MatrixDimensionError("MulMat(Complex, Real) - a.colNum must be equal to b.rowNum", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(a.rows(), b.cols());
			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = 0.0;
					for (int k = 0; k < a.cols(); k++)
						ret[i][j] += a[i][k] * b[k][j];
				}

			return ret;
		}

		/// @brief Multiplies real matrix by complex matrix.
		/// @param a Real matrix (m×n)
		/// @param b Complex matrix (n×p)
		/// @return Complex matrix (m×p)
		/// @throws MatrixDimensionError if inner dimensions don't match
		static Matrix<Complex> MulMat(const Matrix<Real>& a, const Matrix<Complex>& b)
		{
			if (a.cols() != b.rows())
				throw MatrixDimensionError("MulMat(Real, Complex) - a.colNum must be equal to b.rowNum", a.rows(), a.cols(), b.rows(), b.cols());

			Matrix<Complex> ret(a.rows(), b.cols());
			for (int i = 0; i < ret.rows(); i++)
				for (int j = 0; j < ret.cols(); j++) {
					ret[i][j] = 0.0;
					for (int k = 0; k < a.cols(); k++)
						ret[i][j] += a[i][k] * b[k][j];
				}

			return ret;
		}

		// ============================================================================
		// Matrix-Vector Mixed Operations
		// ============================================================================

		/// @brief Multiplies real matrix by complex vector.
		/// @param a Real matrix (m×n)
		/// @param b Complex vector (size n)
		/// @return Complex vector (size m)
		/// @throws MatrixDimensionError if matrix columns don't match vector size
		static Vector<Complex> MulMatVec(const Matrix<Real>& a, const Vector<Complex>& b)
		{
			if (a.cols() != b.size())
				throw MatrixDimensionError("MulMatVec(Real, Complex) - a.colNum must be equal to vector size", a.rows(), a.cols(), (int)b.size(), -1);

			Vector<Complex> ret(a.rows());
			for (int i = 0; i < a.rows(); i++)
			{
				ret[i] = 0;
				for (int j = 0; j < a.cols(); j++)
					ret[i] += a[i][j] * b[j];
			}
			return ret;
		}

		/// @brief Multiplies complex matrix by real vector.
		/// @param a Complex matrix (m×n)
		/// @param b Real vector (size n)
		/// @return Complex vector (size m)
		/// @throws MatrixDimensionError if matrix columns don't match vector size
		static Vector<Complex> MulMatVec(const Matrix<Complex>& a, const Vector<Real>& b)
		{
			if (a.cols() != b.size())
				throw MatrixDimensionError("MulMatVec(Complex, Real) - a.colNum must be equal to vector size", a.rows(), a.cols(), (int)b.size(), -1);

			Vector<Complex> ret(a.rows());
			for (int i = 0; i < a.rows(); i++)
			{
				ret[i] = 0;
				for (int j = 0; j < a.cols(); j++)
					ret[i] += a[i][j] * b[j];
			}
			return ret;
		}

		/// @brief Multiplies complex row vector by real matrix.
		/// @param a Complex vector (size m)
		/// @param b Real matrix (m×n)
		/// @return Complex vector (size n)
		/// @throws MatrixDimensionError if vector size doesn't match matrix rows
		static Vector<Complex> MulVecMat(const Vector<Complex>& a, const Matrix<Real>& b)
		{
			if (a.size() != b.rows())
				throw MatrixDimensionError("MulVecMat(Complex, Real) - vector size must be equal to b.rowNum", (int)a.size(), -1, b.rows(), b.cols());

			Vector<Complex> ret(b.cols());
			for (int i = 0; i < b.cols(); i++)
			{
				ret[i] = 0;
				for (int j = 0; j < b.rows(); j++)
					ret[i] += a[j] * b[j][i];
			}
			return ret;
		}

		/// @brief Multiplies real row vector by complex matrix.
		/// @param a Real vector (size m)
		/// @param b Complex matrix (m×n)
		/// @return Complex vector (size n)
		/// @throws MatrixDimensionError if vector size doesn't match matrix rows
		static Vector<Complex> MulVecMat(const Vector<Real>& a, const Matrix<Complex>& b)
		{
			if (a.size() != b.rows())
				throw MatrixDimensionError("MulVecMat(Real, Complex) - vector size must be equal to b.rowNum", (int)a.size(), -1, b.rows(), b.cols());

			Vector<Complex> ret(b.cols());
			for (int i = 0; i < b.cols(); i++)
			{
				ret[i] = 0;
				for (int j = 0; j < b.rows(); j++)
					ret[i] += a[j] * b[j][i];
			}
			return ret;
		}

	} // namespace Utils
} // namespace MML


///////////////////////////   mml/base/Random.h   ///////////////////////////



namespace MML
{
	class Random
	{
	private:
		// Thread-local static RNG for performance and thread-safety
		// Creating RNG once per thread instead of on every call provides 100-1000x speedup
		inline static thread_local std::mt19937 gen{std::random_device{}()};

	public:
		// Seeds the thread-local RNG for reproducible results (affects calling thread only)
		static void SetSeed(unsigned int seed) { gen.seed(seed); }

		static Real UniformReal(Real min, Real max)
		{
			std::uniform_real_distribution<Real> dis(min, max);
			return dis(gen);
		}
		static int UniformInt(int min, int max)
		{
			std::uniform_int_distribution<int> dis(min, max);
			return dis(gen);
		}
		static Real UniformVecDirection2(Real& vx, Real& vy, Real abs)
		{
			// Generate a random angle in the range [0, 2*PI)
			Real angle = UniformReal(0, 2 * Constants::PI);
			vx = abs * std::cos(angle);
			vy = abs * std::sin(angle);
			return abs;
		}
		static Real UniformVecDirection3(Real& vx, Real& vy, Real& vz, Real abs)
		{
			// Generate a uniformly distributed random direction on the sphere with radius 'abs'
			// Correct method: sample u ~ Uniform(-1, 1) and set cos(phi) = u
			// This ensures uniform distribution over the sphere surface
			Real theta = UniformReal(0, 2 * Constants::PI); // azimuthal angle
			Real u = UniformReal(-1.0, 1.0);               // cos(polar angle)
			Real sin_phi = std::sqrt(1.0 - u * u);         // sin(phi) = sqrt(1 - cos²(phi))
			vx = abs * sin_phi * std::cos(theta);
			vy = abs * sin_phi * std::sin(theta);
			vz = abs * u;  // cos(phi) = u
			return abs;
		}
	};
}


///////////////////////////   mml/base/Vector/VectorTypes.h   ///////////////////////////



// Standard headers - include what we use

namespace MML
{
	/// @brief 2D Cartesian vector with X, Y components.
	class Vector2Cartesian : public VectorN<Real, 2>
	{
	public:
		/// @brief Default constructor (zero vector).
		Vector2Cartesian() {}
		/// @brief Constructs from X, Y components.
		/// @param x X component
		/// @param y Y component
		Vector2Cartesian(Real x, Real y)
		{
			_val[0] = x;
			_val[1] = y;
		}
		/// @brief Constructs from VectorN<Real,2>.
		/// @param b Vector to copy
		Vector2Cartesian(const VectorN<Real, 2>& b) : VectorN<Real, 2>{ b[0], b[1] } {}
		/// @brief Constructs vector from two points (b - a).
		/// @param a Start point
		/// @param b End point
		Vector2Cartesian(const Point2Cartesian& a, const Point2Cartesian& b)
		{
			_val[0] = b.X() - a.X();
			_val[1] = b.Y() - a.Y();
		}
		/// @brief Constructs from initializer list.
		/// @param list Initializer list of values
		Vector2Cartesian(std::initializer_list<Real> list) : VectorN<Real, 2>(list) {}

		/// @brief Returns X component (const).
		Real  X() const { return _val[0]; }
		/// @brief Returns X component (non-const).
		Real& X()				{ return _val[0]; }
		/// @brief Returns Y component (const).
		Real  Y() const { return _val[1]; }
		/// @brief Returns Y component (non-const).
		Real& Y()				{ return _val[1]; }
		
		/// @brief Unary minus (negation).
		Vector2Cartesian operator-() const
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = -_val[i];
			return ret;
		}
		
		/// @brief Vector addition.
		/// @param b Vector to add
		Vector2Cartesian operator+(const Vector2Cartesian& b) const
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = _val[i] + b[i];
			return ret;
		}
		/// @brief Vector subtraction.
		/// @param b Vector to subtract
		Vector2Cartesian operator-(const Vector2Cartesian& b) const
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = _val[i] - b[i];
			return ret;
		}

		/// @brief Scalar multiplication (vector * scalar).
		/// @param b Scalar multiplier
		Vector2Cartesian operator*(Real b) const
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = _val[i] * b;
			return ret;
		}
		/// @brief Scalar division (vector / scalar).
		/// @param b Scalar divisor
		Vector2Cartesian operator/(Real b) const
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = _val[i] / b;
			return ret;
		}
		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend Vector2Cartesian operator*(Real a, const Vector2Cartesian& b)
		{
			Vector2Cartesian ret;
			for (int i = 0; i < 2; i++)
				ret._val[i] = a * b[i];
			return ret;
		}

		/// @brief Exact equality comparison.
		/// @param b Vector to compare
		bool operator==(const Vector2Cartesian& b) const
		{
			return (X() == b.X()) && (Y() == b.Y());
		}
		/// @brief Inequality comparison.
		/// @param b Vector to compare
		bool operator!=(const Vector2Cartesian& b) const
		{
			return (X() != b.X()) || (Y() != b.Y());
		}
		/// @brief Checks equality within tolerance.
		/// @param b Vector to compare
		/// @param absEps Absolute tolerance
		bool IsEqualTo(const Vector2Cartesian& b, Real absEps = Defaults::Vec2CartIsEqualTolerance) const
		{
			return (std::abs(X() - b.X()) < absEps) && (std::abs(Y() - b.Y()) < absEps);
		}

		/// @brief Returns normalized vector (unit length).
		Vector2Cartesian Normalized() const
		{
			Vector2Cartesian ret;
			Real norm = NormL2();
			if (norm > 0.0)
			{
				for (int i = 0; i < 2; i++)
					ret._val[i] = _val[i] / norm;
			}
			else
			{
				ret._val[0] = 0.0;
				ret._val[1] = 0.0;
			}
			return ret;
		}
		/// @brief Returns unit vector in this direction.
		Vector2Cartesian GetAsUnitVector() const
		{
			VectorN<Real, 2> res = (*this) / NormL2();

			return Vector2Cartesian(res[0], res[1]);
		}
		/// @brief Returns unit vector at given position (for Cartesian, position doesn't matter).
		/// @param pos Position (unused in Cartesian coordinates)
		Vector2Cartesian GetAsUnitVectorAtPos(const Vector2Cartesian& pos) const
		{
			return Vector2Cartesian{ (*this) / NormL2() };
		}
		
		/// @brief Computes two perpendicular vectors.
		/// @param v1 First perpendicular vector (output)
		/// @param v2 Second perpendicular vector (output)
		void getPerpendicularVectors(Vector2Cartesian& v1, Vector2Cartesian& v2) const
		{
			v1 = Vector2Cartesian(-Y(), X());
			v2 = Vector2Cartesian(Y(), -X());
		}

		/// @brief Scalar product (dot product).
		/// @param b Vector to multiply
		Real operator*(const Vector2Cartesian& b) const
		{
			return X() * b.X() + Y() * b.Y();
		}

		/// @brief Scalar product (friend function).
		/// @param a First vector
		/// @param b Second vector
		friend Real ScalarProduct(const Vector2Cartesian& a, const Vector2Cartesian& b)
		{
			return a * b;
		}

		/// @brief Point + vector operation.
		friend Point2Cartesian operator+(const Point2Cartesian& a, const Vector2Cartesian& b) { return Point2Cartesian(a.X() + b[0], a.Y() + b[1]); }
		/// @brief Point - vector operation.
		friend Point2Cartesian operator-(const Point2Cartesian& a, const Vector2Cartesian& b) { return Point2Cartesian(a.X() - b[0], a.Y() - b[1]); }
	};

	/// @brief 2D Polar vector with R (radius), Phi (angle) components.
	class Vector2Polar : public VectorN<Real, 2>
	{
	public:
		/// @brief Returns R component (const).
		Real  R() const		{ return _val[0]; }
		/// @brief Returns R component (non-const).
		Real& R()					{ return _val[0]; }
		/// @brief Returns Phi component (const).
		Real  Phi() const { return _val[1]; }
		/// @brief Returns Phi component (non-const).
		Real& Phi()				{ return _val[1]; }

		/// @brief Default constructor (zero vector).
		Vector2Polar() {}
		/// @brief Constructs from R, Phi components.
		/// @param r Radius
		/// @param phi Angle
		Vector2Polar(Real r, Real phi)
		{
			_val[0] = r;
			_val[1] = phi;
		}
		/// @brief Constructs from VectorN<Real,2>.
		/// @param b Vector to copy
		Vector2Polar(const VectorN<Real, 2>& b) : VectorN<Real, 2>{ b[0], b[1] } {}

		/// @brief Unary minus (negation, adds p to angle).
		Vector2Polar operator-() const
		{
			// Negating a polar vector means keeping the radius and adding pi to the angle
			return Vector2Polar(R(), Phi() + Constants::PI);
		}
		
		/// @brief Vector addition (converts to Cartesian, adds, converts back).
		/// @param b Vector to add
		Vector2Polar operator+(const Vector2Polar& b) const
		{
			Real r1 = R();
			Real phi1 = Phi();
			Real r2 = b.R();
			Real phi2 = b.Phi();

			Real delta = phi2 - phi1;
			Real r	 = std::sqrt(r1 * r1 + r2 * r2 + 2 * r1 * r2 * std::cos(delta));
			Real phi = phi1 + std::atan2(r2 * std::sin(delta), r1 + r2 * std::cos(delta));

			return Vector2Polar(r, phi);
		}
		/// @brief Vector subtraction (converts to Cartesian, subtracts, converts back).
		/// @param b Vector to subtract
		Vector2Polar operator-(const Vector2Polar& b) const
		{
			Real r1 = R();
			Real phi1 = Phi();
			Real r2 = b.R();
			Real phi2 = b.Phi();

			Real delta = phi2 - phi1;
			Real r	 = std::sqrt(r1 * r1 + r2 * r2 - 2 * r1 * r2 * std::cos(delta));
			Real phi = phi1 + std::atan2(-r2 * std::sin(delta), r1 - r2 * std::cos(delta));

			return Vector2Polar(r, phi);
		}
		/// @brief Scalar multiplication (scales radius).
		/// @param b Scalar multiplier
		Vector2Polar operator*(Real b) const
		{
			return Vector2Polar(R() * b, Phi());
		}
		/// @brief Scalar division (divides radius).
		/// @param b Scalar divisor
		Vector2Polar operator/(Real b) const
		{
			return Vector2Polar(R() / b, Phi());
		}

		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend Vector2Polar operator*(Real a, const Vector2Polar& b)
		{
			return Vector2Polar(b.R() * a, b.Phi());
		}

		/// @brief Returns unit vector at given position.
		/// @param pos Position (unused)
		Vector2Polar GetAsUnitVectorAtPos(const Vector2Polar& /*pos*/) const
		{
			// Returns a unit vector in the direction of this vector (ignores pos)
			return Vector2Polar(1.0, Phi());
		}
	};

	/// @brief 3D Cartesian vector with X, Y, Z components.
	class Vector3Cartesian : public VectorN<Real, 3>
	{
	public:
		/// @brief Returns X component (const).
		Real  X() const { return _val[0]; }
		/// @brief Returns X component (non-const).
		Real& X()				{ return _val[0]; }
		/// @brief Returns Y component (const).
		Real  Y() const { return _val[1]; }
		/// @brief Returns Y component (non-const).
		Real& Y()				{ return _val[1]; }
		/// @brief Returns Z component (const).
		Real  Z() const { return _val[2]; }
		/// @brief Returns Z component (non-const).
		Real& Z()				{ return _val[2]; }

		/// @brief Default constructor (zero vector).
		Vector3Cartesian() : VectorN<Real, 3>{ 0.0, 0.0, 0.0 } {}
		/// @brief Constructs from VectorN<Real,3>.
		/// @param b Vector to copy
		Vector3Cartesian(const VectorN<Real, 3>& b) : VectorN<Real, 3>{ b } {}
		/// @brief Constructs from X, Y, Z components.
		/// @param x X component
		/// @param y Y component
		/// @param z Z component
		Vector3Cartesian(Real x, Real y, Real z) : VectorN<Real, 3>{ x, y, z } {}
		/// @brief Constructs from initializer list.
		/// @param list Initializer list of values
		Vector3Cartesian(std::initializer_list<Real> list) : VectorN<Real, 3>(list) { }
		/// @brief Constructs vector from two points (b - a).
		/// @param a Start point
		/// @param b End point
		Vector3Cartesian(const Point3Cartesian& a, const Point3Cartesian& b)
		{
			_val[0] = b.X() - a.X();
			_val[1] = b.Y() - a.Y();
			_val[2] = b.Z() - a.Z();
		}
		/// @brief Constructs from Point3Cartesian (converts point to position vector).
		/// @param a Point to convert
		Vector3Cartesian(const Point3Cartesian& a)
		{
			_val[0] = a.X();
			_val[1] = a.Y();
			_val[2] = a.Z();
		}

		/// @brief Converts vector to Point3Cartesian.
		Point3Cartesian getAsPoint()
		{
			return Point3Cartesian(_val[0], _val[1], _val[2]);
		}
		
		/// @brief Returns normalized vector (unit length).
		Vector3Cartesian Normalized() const
		{
			Vector3Cartesian ret;
			Real norm = NormL2();
			if (norm > 0.0)
			{
				for (int i = 0; i < 3; i++)
					ret._val[i] = _val[i] / norm;
			}
			else
			{
				ret._val[0] = 0.0;
				ret._val[1] = 0.0;
				ret._val[2] = 0.0;
			}
			return ret;
		}
		Vector3Cartesian GetAsUnitVector() const
		{
			if(NormL2() == 0.0)
			{
				return Vector3Cartesian{ REAL(0.0), REAL(0.0), REAL(0.0) };
			}
			return Vector3Cartesian{ (*this) / NormL2() };
		}
		/// @brief Returns unit vector at given position (for Cartesian, position doesn't matter).
		/// @param pos Position (unused)
		Vector3Cartesian GetAsUnitVectorAtPos(const Vector3Cartesian& pos) const
		{
			return GetAsUnitVector();
		}

		/// @brief Scalar product (dot product) via operator*.
		/// @param b Vector to multiply
		Real operator*(const Vector3Cartesian& b) const
		{
			return X()*b.X() + Y()*b.Y() + Z()*b.Z();
		}

		/// @brief Unary minus (negation).
		Vector3Cartesian operator-() const
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = -_val[i];
			return ret;
		}

		/// @brief Vector addition.
		/// @param b Vector to add
		Vector3Cartesian operator+(const Vector3Cartesian& b) const
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = _val[i] + b[i];
			return ret;
		}
		/// @brief Vector subtraction.
		/// @param b Vector to subtract
		Vector3Cartesian operator-(const Vector3Cartesian& b) const
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = _val[i] - b[i];
			return ret;
		}

		/// @brief Scalar multiplication (vector * scalar).
		/// @param b Scalar multiplier
		Vector3Cartesian operator*(Real b) const
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = _val[i] * b;
			return ret;
		}
		/// @brief Scalar division (vector / scalar).
		/// @param b Scalar divisor
		Vector3Cartesian operator/(Real b) const
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = _val[i] / b;
			return ret;
		}
		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend Vector3Cartesian operator*(Real a, const Vector3Cartesian& b)
		{
			Vector3Cartesian ret;
			for (int i = 0; i < 3; i++)
				ret._val[i] = a * b[i];
			return ret;
		}

		/// @brief Exact equality comparison.
		/// @param b Vector to compare
		bool operator==(const Vector3Cartesian& b) const
		{
			return (X() == b.X()) && (Y() == b.Y()) && (Z() == b.Z());
		}
		/// @brief Inequality comparison.
		/// @param b Vector to compare
		bool operator!=(const Vector3Cartesian& b) const
		{
			return (X() != b.X()) || (Y() != b.Y()) || (Z() != b.Z());
		}
		/// @brief Checks equality within tolerance.
		/// @param b Vector to compare
		/// @param absEps Absolute tolerance
		bool IsEqualTo(const Vector3Cartesian& b, Real absEps = Defaults::Vec3CartIsEqualTolerance) const
		{
			return (std::abs(X() - b.X()) < absEps) && (std::abs(Y() - b.Y()) < absEps) && (std::abs(Z() - b.Z()) < absEps);
		}

		/// @brief Point + vector operation.
		friend Point3Cartesian operator+(const Point3Cartesian& a, const Vector3Cartesian& b) { return Point3Cartesian(a.X() + b[0], a.Y() + b[1], a.Z() + b[2]); }
		/// @brief Point - vector operation.
		friend Point3Cartesian operator-(const Point3Cartesian& a, const Vector3Cartesian& b) { return Point3Cartesian(a.X() - b[0], a.Y() - b[1], a.Z() - b[2]); }

		/// @brief Checks if vectors are parallel.
		/// @param b Vector to compare
		/// @param eps Tolerance
		bool IsParallelTo(const Vector3Cartesian& b, Real eps = Defaults::Vec3CartIsParallelTolerance) const
		{
			Real norm1 = NormL2();
			Real norm2 = b.NormL2();

			return std::abs(X() / norm1 - b.X() / norm2) < eps &&
				std::abs(Y() / norm1 - b.Y() / norm2) < eps &&
				std::abs(Z() / norm1 - b.Z() / norm2) < eps;
		}
		/// @brief Checks if vectors are perpendicular.
		/// @param b Vector to compare
		/// @param eps Tolerance
		bool IsPerpendicularTo(const Vector3Cartesian& b, Real eps = Defaults::OrthogonalityTolerance) const
		{
			if (std::abs(this->ScalarProduct(b)) < eps)
				return true;
			else
				return false;
		}
		/// @brief Computes two vectors perpendicular to this vector.
		/// @param v1 First perpendicular vector (output)
		/// @param v2 Second perpendicular vector (output)
		/// @return true if successful, false if zero vector
		bool GetPerpendicularVectors(Vector3Cartesian& v1, Vector3Cartesian& v2) const
		{
			if (isZero())
				return false;
			
			// find a vector that is not parallel to this vector
			Vector3Cartesian not_parallel;
			if (std::abs(X()) <= std::abs(Y()) && std::abs(X()) <= std::abs(Z()))
				not_parallel = Vector3Cartesian(1.0, 0.0, 0.0);
			else if (std::abs(Y()) <= std::abs(X()) && std::abs(Y()) <= std::abs(Z()))
				not_parallel = Vector3Cartesian(0.0, 1.0, 0.0);
			else
				not_parallel = Vector3Cartesian(0.0, 0.0, 1.0);
			
			v1 = VectorProduct(*this, not_parallel).GetAsUnitVector();
			v2 = VectorProduct(*this, v1).GetAsUnitVector();
			
			return true;
		}

		/// @brief Computes angle between this vector and another.
		/// @param b Other vector
		/// @return Angle in radians [0, p]
		Real AngleToVector(const Vector3Cartesian& b)
		{
			Real normA = NormL2(), normB = b.NormL2();
			if (normA < std::numeric_limits<Real>::epsilon() ||
			    normB < std::numeric_limits<Real>::epsilon())
				throw DivisionByZeroError("AngleToVector: cannot compute angle with zero vector");
			Real cos_phi = this->ScalarProduct(b) / (normA * normB);
			// Clamp to [-1, 1] to prevent NaN from floating-point rounding errors
			cos_phi = std::max(Real{-1.0}, std::min(Real{1.0}, cos_phi));
			return std::acos(cos_phi);
		}

		/// @brief Scalar product (member method).
		/// @param b Vector to multiply
		Real ScalarProduct(const Vector3Cartesian& b) const
		{
			return (*this) * b;
		}

		/// @brief Scalar product (friend function).
		/// @param a First vector
		/// @param b Second vector
		friend Real ScalarProduct(const Vector3Cartesian& a, const Vector3Cartesian& b)
		{
			return a * b;
		}

		/// @brief Vector (cross) product.
		/// @param a First vector
		/// @param b Second vector
		friend Vector3Cartesian VectorProduct(const Vector3Cartesian& a, const Vector3Cartesian& b)
		{
			Vector3Cartesian ret;

			ret.X() = a.Y() * b.Z() - a.Z() * b.Y();
			ret.Y() = a.Z() * b.X() - a.X() * b.Z();
			ret.Z() = a.X() * b.Y() - a.Y() * b.X();

			return ret;
		}
	};

	/// @brief 3D Spherical vector with R (radius), Theta (polar angle), Phi (azimuthal angle) components.
	class Vector3Spherical : public VectorN<Real, 3>
	{
	public:
		/// @brief Returns R component (const).
		Real  R()     const { return _val[0]; }
		/// @brief Returns R component (non-const).
		Real& R()						{ return _val[0]; }
		/// @brief Returns Theta component (const).
		Real  Theta() const { return _val[1]; }
		/// @brief Returns Theta component (non-const).
		Real& Theta()				{ return _val[1]; }
		/// @brief Returns Phi component (const).
		Real  Phi()   const { return _val[2]; }
		/// @brief Returns Phi component (non-const).
		Real& Phi()					{ return _val[2]; }

		/// @brief Default constructor (zero vector).
		Vector3Spherical() : VectorN<Real, 3>{ 0.0, 0.0, 0.0 } {}
		/// @brief Constructs from VectorN<Real,3>.
		/// @param b Vector to copy
		Vector3Spherical(const VectorN<Real, 3>& b) : VectorN<Real, 3>{ b[0], b[1], b[2] } {}
		/// @brief Constructs from R, Theta, Phi components.
		/// @param r Radius
		/// @param theta Polar angle
		/// @param phi Azimuthal angle
		Vector3Spherical(Real r, Real theta, Real phi) : VectorN<Real, 3>{ r, theta, phi } {}
		/// @brief Constructs from initializer list.
		/// @param list Initializer list of values
		Vector3Spherical(std::initializer_list<Real> list) : VectorN<Real, 3>(list) { }

		/// @brief Unary minus (negation, flips direction in spherical coordinates).
		Vector3Spherical operator-() const
		{
			return Vector3Spherical(R(), Constants::PI - Theta(), Phi() + Constants::PI);
		}

		/// @brief Vector addition (converts to/from Cartesian).
		/// @param b Vector to add
		Vector3Spherical operator+(const Vector3Spherical& b) const
		{
			// Convert both to Cartesian
			Real x1, y1, z1, x2, y2, z2;
			Utils::SphericalToCartesian(R(), Theta(), Phi(), x1, y1, z1);
			Utils::SphericalToCartesian(b.R(), b.Theta(), b.Phi(), x2, y2, z2);
			
			// Add and convert back
			Real r, theta, phi;
			Utils::CartesianToSpherical(x1 + x2, y1 + y2, z1 + z2, r, theta, phi);
			return Vector3Spherical(r, theta, phi);
		}
		/// @brief Vector subtraction (converts to/from Cartesian).
		/// @param b Vector to subtract
		Vector3Spherical operator-(const Vector3Spherical& b) const
		{
			// Convert both to Cartesian
			Real x1, y1, z1, x2, y2, z2;
			Utils::SphericalToCartesian(R(), Theta(), Phi(), x1, y1, z1);
			Utils::SphericalToCartesian(b.R(), b.Theta(), b.Phi(), x2, y2, z2);
			
			// Subtract and convert back
			Real r, theta, phi;
			Utils::CartesianToSpherical(x1 - x2, y1 - y2, z1 - z2, r, theta, phi);
			return Vector3Spherical(r, theta, phi);
		}

		/// @brief Scalar multiplication (scales radius).
		/// @param b Scalar multiplier
		Vector3Spherical operator*(Real b) const
		{
			return Vector3Spherical(R() * b, Theta(), Phi());
		}
		/// @brief Scalar division (divides radius).
		/// @param b Scalar divisor
		Vector3Spherical operator/(Real b) const
		{
			if (b == 0.0)
				throw DivisionByZeroError("Division by zero in Vector3Spherical division.");
			return Vector3Spherical(R() / b, Theta(), Phi());
		}
		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend Vector3Spherical operator*(Real a, const Vector3Spherical& b)
		{
			return Vector3Spherical(b.R() * a, b.Theta(), b.Phi());
		}

		/// @brief Exact equality comparison.
		/// @param b Vector to compare
		bool operator==(const Vector3Spherical& b) const
		{
			return (R() == b.R()) && (Theta() == b.Theta()) && (Phi() == b.Phi());
		}
		/// @brief Inequality comparison.
		/// @param b Vector to compare
		bool operator!=(const Vector3Spherical& b) const
		{
			return (R() != b.R()) || (Theta() != b.Theta()) || (Phi() != b.Phi());
		}
		/// @brief Checks equality within tolerance with angle wrap-around awareness.
		/// @param b Vector to compare
		/// @param absEps Absolute tolerance
		/// @note For spherical vectors, theta ? [0, p] and phi ? [-p, p].
		///       Phi comparison uses AnglesAreEqual() to handle wrap-around at �p.
		bool IsEqualTo(const Vector3Spherical& b, Real absEps = Defaults::Vec3SphIsEqualTolerance) const
		{
			// R and theta are straightforward comparisons
			// Phi needs angle-aware comparison for wrap-around at �p
			return (std::abs(R() - b.R()) < absEps) && 
			       (std::abs(Theta() - b.Theta()) < absEps) && 
			       AnglesAreEqual(Phi(), b.Phi(), absEps);
		}
		
		/// @brief Returns unit vector at given position (global spherical result).
		/// @param pos Position in spherical coordinates
		Vector3Spherical GetAsUnitVectorAtPosGlobalSpher(const Vector3Spherical& pos) const
		{
			// Convert this vector to Cartesian (as a displacement from the origin)
			Real r = R();
			Real theta = Theta();
			Real phi = Phi();

			// Spherical to Cartesian (displacement from origin)
			Real x = r * std::sin(theta) * std::cos(phi);
			Real y = r * std::sin(theta) * std::sin(phi);
			Real z = r * std::cos(theta);

			// Now, express this vector in the local spherical basis at 'pos'
			// The local basis at 'pos' consists of:
			//   e_r     = [sin? cosf, sin? sinf, cos?]
			//   e_theta = [cos? cosf, cos? sinf, -sin?]
			//   e_phi   = [-sinf, cosf, 0]
			// at the position (pos.Theta(), pos.Phi())

			Real st = std::sin(pos.Theta());
			Real ct = std::cos(pos.Theta());
			Real sp = std::sin(pos.Phi());
			Real cp = std::cos(pos.Phi());

			// Local basis vectors at pos (expressed in Cartesian coordinates)
			Real e_r[3] = { st * cp, st * sp, ct };
			Real e_theta[3] = { ct * cp, ct * sp, -st };
			Real e_phi[3] = { -sp,   cp,    0 };

			// Project (x, y, z) onto the local basis at pos
			Real v_r = x * e_r[0] + y * e_r[1] + z * e_r[2];
			Real v_theta = x * e_theta[0] + y * e_theta[1] + z * e_theta[2];
			Real v_phi = x * e_phi[0] + y * e_phi[1] + z * e_phi[2];

			// Normalize
			Real norm = std::sqrt(v_r * v_r + v_theta * v_theta + v_phi * v_phi);
			if (norm == 0.0)
				return Vector3Spherical(0.0, 0.0, 0.0);

			// Clamp to [-1, 1] to prevent NaN from floating-point rounding
			Real cos_theta = std::max(Real{-1.0}, std::min(Real{1.0}, v_r / norm));
			return Vector3Spherical(1.0, std::acos(cos_theta), std::atan2(v_phi, v_theta));
		}
		/// @brief Returns unit vector at given position (local spherical basis result).
		/// @param pos Position in spherical coordinates
		Vector3Spherical GetAsUnitVectorAtPos(const Vector3Spherical& pos) const
		{
			// Step 1: Convert *this to Cartesian (as a displacement from the origin)
			Real r = R();
			Real theta = Theta();
			Real phi = Phi();

			Real x = r * std::sin(theta) * std::cos(phi);
			Real y = r * std::sin(theta) * std::sin(phi);
			Real z = r * std::cos(theta);

			// Step 2: Compute local spherical basis at pos
			Real st = std::sin(pos.Theta());
			Real ct = std::cos(pos.Theta());
			Real sp = std::sin(pos.Phi());
			Real cp = std::cos(pos.Phi());

			// Local basis vectors at pos
			Real e_r[3] = { st * cp, st * sp, ct };
			Real e_theta[3] = { ct * cp, ct * sp, -st };
			Real e_phi[3] = { -sp,   cp,    0 };

			// Step 3: Project (x, y, z) onto the local basis at pos
			Real v_r = x * e_r[0] + y * e_r[1] + z * e_r[2];
			Real v_theta = x * e_theta[0] + y * e_theta[1] + z * e_theta[2];
			Real v_phi = x * e_phi[0] + y * e_phi[1] + z * e_phi[2];

			// Step 4: Normalize
			Real norm = std::sqrt(v_r * v_r + v_theta * v_theta + v_phi * v_phi);
			if (norm == 0.0)
				return Vector3Spherical(0.0, 0.0, 0.0);

			return Vector3Spherical(v_r / norm, v_theta / norm, v_phi / norm);
		}

		/// @brief Prints vector with angles in degrees.
		/// @param stream Output stream
		/// @param width Field width
		/// @param precision Decimal precision
		std::ostream& PrintDeg(std::ostream& stream, int width, int precision) const
		{
			stream << "[ ";
			stream << std::fixed << std::setw(width) << std::setprecision(precision);
			stream << R();
			stream << ", " << Theta() * 180.0 / Constants::PI;
			stream << ", " << Phi() * 180.0 / Constants::PI << " ]" << std::endl;

			return stream;
		}
	};

	/// @brief 3D Cylindrical vector with R (radial), Phi (azimuthal), Z components.
	class Vector3Cylindrical : public VectorN<Real, 3>
	{
	public:
		/// @brief Returns R component (const).
		Real  R()   const { return _val[0]; }
		/// @brief Returns R component (non-const).
		Real& R()					{ return _val[0]; }
		/// @brief Returns Phi component (const).
		Real  Phi() const { return _val[1]; }
		/// @brief Returns Phi component (non-const).
		Real& Phi()				{ return _val[1]; }
		/// @brief Returns Z component (const).
		Real  Z()   const { return _val[2]; }
		/// @brief Returns Z component (non-const).
		Real& Z()					{ return _val[2]; }

		/// @brief Default constructor (zero vector).
		Vector3Cylindrical() : VectorN<Real, 3>{ 0.0, 0.0, 0.0 } {}
		/// @brief Constructs from VectorN<Real,3>.
		/// @param b Vector to copy
		Vector3Cylindrical(const VectorN<Real, 3>& b) : VectorN<Real, 3>{ b[0], b[1], b[2] } {}
		/// @brief Constructs from R, Phi, Z components.
		/// @param r Radial distance
		/// @param phi Azimuthal angle
		/// @param z Vertical coordinate
		Vector3Cylindrical(Real r, Real phi, Real z) : VectorN<Real, 3>{ r, phi, z } {}
		/// @brief Constructs from initializer list.
		/// @param list Initializer list of values
		Vector3Cylindrical(std::initializer_list<Real> list) : VectorN<Real, 3>(list) { }

		/// @brief Unary minus (negation, adjusts angle and flips Z).
		Vector3Cylindrical operator-() const
		{
			return Vector3Cylindrical(R(), Phi() + Constants::PI, Z());
		}

		/// @brief Vector addition (converts to/from Cartesian).
		/// @param b Vector to add
		Vector3Cylindrical operator+(const Vector3Cylindrical& b) const
		{
			// Convert both to Cartesian
			Real x1, y1, z1, x2, y2, z2;
			Utils::CylindricalToCartesian(R(), Phi(), Z(), x1, y1, z1);
			Utils::CylindricalToCartesian(b.R(), b.Phi(), b.Z(), x2, y2, z2);
			
			// Add and convert back
			Real r, phi, z;
			Utils::CartesianToCylindrical(x1 + x2, y1 + y2, z1 + z2, r, phi, z);
			return Vector3Cylindrical(r, phi, z);
		}
		/// @brief Vector subtraction (converts to/from Cartesian).
		/// @param b Vector to subtract
		Vector3Cylindrical operator-(const Vector3Cylindrical& b) const
		{
			// Convert both to Cartesian
			Real x1, y1, z1, x2, y2, z2;
			Utils::CylindricalToCartesian(R(), Phi(), Z(), x1, y1, z1);
			Utils::CylindricalToCartesian(b.R(), b.Phi(), b.Z(), x2, y2, z2);
			
			// Subtract and convert back
			Real r, phi, z;
			Utils::CartesianToCylindrical(x1 - x2, y1 - y2, z1 - z2, r, phi, z);
			return Vector3Cylindrical(r, phi, z);
		}

		/// @brief Scalar multiplication (scales R and Z).
		/// @param b Scalar multiplier
		Vector3Cylindrical operator*(Real b) const
		{
			return Vector3Cylindrical(R() * b, Phi(), Z() * b);
		}
		/// @brief Scalar division (divides R and Z).
		/// @param b Scalar divisor
		Vector3Cylindrical operator/(Real b) const
		{
			if (b == 0.0)
				throw DivisionByZeroError("Division by zero in Vector3Cylindrical division.");
			return Vector3Cylindrical(R() / b, Phi(), Z() / b);
		}
		/// @brief Scalar multiplication (scalar * vector).
		/// @param a Scalar multiplier
		/// @param b Vector
		friend Vector3Cylindrical operator*(Real a, const Vector3Cylindrical& b)
		{
			return Vector3Cylindrical(b.R() * a, b.Phi(), b.Z() * a);
		}

		/// @brief Returns unit vector at given position (local cylindrical basis result).
		/// @param pos Position in cylindrical coordinates
		Vector3Cylindrical GetAsUnitVectorAtPos(const Vector3Cylindrical& pos) const
		{
			// Step 1: Convert *this to Cartesian
			Real x = R() * std::cos(Phi());
			Real y = R() * std::sin(Phi());
			Real z = Z();

			// Step 2: Normalize in Cartesian
			Real norm = std::sqrt(x * x + y * y + z * z);
			if (norm == REAL(0.0))
				return Vector3Cylindrical(REAL(0.0), REAL(0.0), REAL(0.0));

			x /= norm;
			y /= norm;
			z /= norm;

			// Step 3: Compute local cylindrical basis at pos and project
			Real cp = std::cos(pos.Phi());
			Real sp = std::sin(pos.Phi());

			// ê_R   = (cos(φ_pos), sin(φ_pos), 0)
			// ê_Phi = (-sin(φ_pos), cos(φ_pos), 0)
			// ê_Z   = (0, 0, 1)
			Real v_R = x * cp + y * sp;
			Real v_Phi = -x * sp + y * cp;
			Real v_Z = z;

			return Vector3Cylindrical(v_R, v_Phi, v_Z);
		}
	};

	/// @brief 4D Minkowski spacetime vector with T (time), X, Y, Z components.
	class Vector4Minkowski : public VectorN<Real, 4>
	{
	public:
		/// @brief Returns T component (const).
		Real  T() const { return _val[0]; }
		/// @brief Returns T component (non-const).
		Real& T()				{ return _val[0]; }
		/// @brief Returns X component (const).
		Real  X() const { return _val[1]; }
		/// @brief Returns X component (non-const).
		Real& X()				{ return _val[1]; }
		/// @brief Returns Y component (const).
		Real  Y() const { return _val[2]; }
		/// @brief Returns Y component (non-const).
		Real& Y()				{ return _val[2]; }
		/// @brief Returns Z component (const).
		Real  Z() const { return _val[3]; }
		/// @brief Returns Z component (non-const).
		Real& Z()				{ return _val[3]; }

		/// @brief Default constructor (zero 4-vector).
		Vector4Minkowski() : VectorN<Real, 4>{ 0.0, 0.0, 0.0, 0.0 } {}
		/// @brief Constructs from initializer list.
		/// @param list Initializer list of values
		Vector4Minkowski(std::initializer_list<Real> list) : VectorN<Real, 4>(list) { }

		/// @brief Minkowski scalar product (T*T - X*X - Y*Y - Z*Z).
		/// @param a First 4-vector
		/// @param b Second 4-vector
		friend Real ScalarProduct(const Vector4Minkowski& a, const Vector4Minkowski& b)
		{
			return a.T() * b.T() - a.X() * b.X() - a.Y() * b.Y() - a.Z() * b.Z();
		}

		/// @brief Computes Minkowski norm (spacetime interval).
		Real Norm() const
		{
			if(T() == 0.0 && X() == 0.0 && Y() == 0.0 && Z() == 0.0)
				return 0.0;

			// Minkowski norm: sqrt(T^2 - X^2 - Y^2 - Z^2)
			if (isTimelike())
				return sqrt(T() * T() - X() * X() - Y() * Y() - Z() * Z());
			else if (isSpacelike())
				return -sqrt(X() * X() + Y() * Y() + Z() * Z() - T() * T());
			else 
				return 0.0; // Lightlike vectors have zero Minkowski norm
		}

		/// @brief Computes Minkowski distance to another 4-vector.
		/// @param b Other 4-vector
		Real Distance(const Vector4Minkowski& b) const
		{
			return sqrt((T() - b.T()) * (T() - b.T()) - (X() - b.X()) * (X() - b.X()) -
								(Y() - b.Y()) * (Y() - b.Y()) - (Z() - b.Z()) * (Z() - b.Z()));
		}
		
		/// @brief Checks if 4-vector is timelike (inside light cone).
		bool isTimelike() const
		{
			return (-T() * T() + X() * X() + Y() * Y() + Z() * Z()) < 0;
		}
		/// @brief Checks if 4-vector is spacelike (outside light cone).
		bool isSpacelike() const
		{
			return (-T() * T() + X() * X() + Y() * Y() + Z() * Z()) > 0;
		}
		/// @brief Checks if 4-vector is lightlike (on light cone).
		bool isLightlike() const
		{
			return (T() * T() - X() * X() - Y() * Y() - Z() * Z()) == 0;
		}
	};

	typedef Vector2Cartesian    Vec2Cart;
	typedef Vector2Polar				Vec2Pol;
	typedef Vector3Cartesian    Vec3Cart;
	typedef Vector3Spherical    Vec3Sph;
	typedef Vector3Cylindrical  Vec3Cyl;
	typedef Vector4Minkowski    Vec4Mink;
}

///////////////////////////   mml/base/Geometry/GeometrySpherical.h   ///////////////////////////

/// @file GeometrySpherical.h
/// @brief Spherical geometry calculations and coordinate conversions.
/// Provides utilities for working with spherical coordinates including:
/// - Coordinate conversions (Cartesian ↔ Spherical ↔ Lat/Long)
/// - Great circle distance calculations (geodesics)
/// - Geographic coordinate support (latitude/longitude)
/// @section coord_conventions Coordinate Conventions
/// **Spherical coordinates (r, θ, φ):**
/// - r: radial distance from origin
/// - θ (theta): polar angle from +Z axis [0, π]
/// - φ (phi): azimuthal angle in XY plane from +X axis [0, 2π]
/// **Geographic coordinates:**
/// - Latitude: -90° (South Pole) to +90° (North Pole)
/// - Longitude: -180° to +180° (East positive)
/// @section formulas Key Formulas
/// **Cartesian from Spherical:**
/// @f[
/// x = r \sin\theta \cos\phi, \quad
/// y = r \sin\theta \sin\phi, \quad
/// z = r \cos\theta
/// @f]
/// **Spherical Law of Cosines (angular distance):**
/// @f[
/// \cos c = \cos\theta_1 \cos\theta_2 + \sin\theta_1 \sin\theta_2 \cos(\phi_1 - \phi_2)
/// @f]
/// @see Pnt3Sph for spherical point representation
/// @see Pnt3Cart for Cartesian point representation



// Standard headers - include what we use






namespace MML
{
	/// @brief Static utility class for spherical geometry calculations.
/// Provides coordinate conversions and geodesic distance calculations
/// for points on a sphere. Supports both mathematical spherical coordinates
/// and geographic (latitude/longitude) coordinates.
/// @note All angle inputs/outputs are in radians unless explicitly noted.
/// @note Distance functions return angular distance; multiply by radius for arc length.

	class SphericalGeometryCalculator
	{
		public:
		/// @name Coordinate Conversions
		/// @{
		
		/// @brief Compute radial distance from Cartesian coordinates.
/// @param pnt Cartesian point
/// @return Distance from origin: √(x² + y² + z²)

		static Real RadiusFromCartesian(const Pnt3Cart& pnt)
		{
			return hypot(pnt.X(), hypot(pnt.Y(), pnt.Z()));
		}
		
		/// @brief Convert spherical coordinates to Cartesian.
/// @param pnt Spherical point (r, θ, φ)
/// @return Cartesian point (x, y, z)
/// Uses standard physics convention:
/// - θ (theta) = polar angle from +Z axis [0, π]
/// - φ (phi) = azimuthal angle in XY plane [0, 2π]

		static Pnt3Cart CartesianFromSpherical(const Pnt3Sph& pnt)
		{
			return Pnt3Cart(pnt.R() * sin(pnt.Theta()) * cos(pnt.Phi()),
											pnt.R() * sin(pnt.Theta()) * sin(pnt.Phi()),
											pnt.R() * cos(pnt.Theta()));
		}

		/// @brief Convert geographic coordinates to spherical (unit sphere).
/// @param latitudeDeg Latitude in degrees [-90 (South) to +90 (North)]
/// @param longitudeDeg Longitude in degrees [-180 to +180]
/// @return Spherical point on unit sphere (r=1)
/// Conversion: θ = 90° - latitude (so North Pole has θ=0)

		static Pnt3Sph SphericalFromLatLong(Real latitudeDeg, Real longitudeDeg)
		{
			Real latitudeRad = Utils::DegToRad(latitudeDeg);
			Real longitudeRad = Utils::DegToRad(longitudeDeg);
			// latitude 90° (North) -> theta = 0, latitude -90° (South) -> theta = PI
			Real theta = Constants::PI / 2.0 - latitudeRad;
			return Pnt3Sph(1.0, theta, longitudeRad);
		}
		/// @}

		/// @name Geodesic Distances
		/// @{
		
		/// @brief Compute great circle angular distance between two geographic points.
/// @param lat1Deg First point latitude (degrees)
/// @param long1Deg First point longitude (degrees)
/// @param lat2Deg Second point latitude (degrees)
/// @param long2Deg Second point longitude (degrees)
/// @return Angular distance in radians
/// Uses spherical law of cosines. The result is the central angle
/// subtended by the two points. Multiply by sphere radius to get arc length.
/// @note For Earth: multiply by 6371 km for approximate surface distance.

		static Real DistanceBetweenLatLong(Real lat1Deg, Real long1Deg, Real lat2Deg, Real long2Deg)
		{
			Pnt3Sph pnt1 = SphericalFromLatLong(lat1Deg, long1Deg);
			Pnt3Sph pnt2 = SphericalFromLatLong(lat2Deg, long2Deg);

			// Spherical law of cosines
			Real cosAngle = cos(pnt1.Theta()) * cos(pnt2.Theta()) +
											sin(pnt1.Theta()) * sin(pnt2.Theta()) *
											cos(pnt1.Phi() - pnt2.Phi());
			// Clamp to [-1, 1] for numerical stability
			cosAngle = std::max(Real(-1.0), std::min(Real(1.0), cosAngle));
			return acos(cosAngle);
		}
		
		/// @brief Compute great circle distance in physical units.
/// @param radius Sphere radius (in desired units, e.g., meters or km)
/// @param lat1Deg First point latitude (degrees)
/// @param long1Deg First point longitude (degrees)
/// @param lat2Deg Second point latitude (degrees)
/// @param long2Deg Second point longitude (degrees)
/// @return Arc length distance (same units as radius)
/// @note For Earth calculations, use radius ≈ 6371000 m or 6371 km.

		static Real DistanceBetweenLatLong(Real radius, Real lat1Deg, Real long1Deg, Real lat2Deg, Real long2Deg)
		{
      Real angleRad = DistanceBetweenLatLong(lat1Deg, long1Deg, lat2Deg, long2Deg);
      return radius * angleRad;
    }
		/// @}
	};
}


///////////////////////////   mml/base/Quaternions.h   ///////////////////////////


// Standard headers - include what we use

namespace MML
{
	///////////////////////////////////////////////////////////////////////////////
	// QUATERNION CONVENTIONS USED IN THIS FILE
	//
	//   Algebra:       Hamilton convention (ij = k, ji = -k)
	//                  NOT JPL/aerospace convention (ij = -k)
	//
	//   Storage order:  [w, x, y, z]  where w = scalar part, (x,y,z) = vector part
	//                  Identity quaternion = [1, 0, 0, 0]
	//
	//   Rotation:      Active (alibi) rotation via  v' = q * [0,v] * q⁻¹
	//                  A quaternion q = [cos(α/2), sin(α/2)·û] rotates by angle α
	//                  about axis û using the right-hand rule.
	//
	//   Angle units:   All angles in RADIANS (axis-angle, Euler angles, SLERP)
	//
	//   Euler angles:  Two conventions supported:
	//                    FromEulerZYX(yaw, pitch, roll)  → R = Rz·Ry·Rx
	//                    FromEulerXYZ(roll, pitch, yaw)  → R = Rx·Ry·Rz
	//                  Note: parameter ORDER matches the name, not the
	//                  multiplication order.
	//
	//   Rotation matrix: ToRotationMatrix() returns R such that R*v rotates
	//                  the vector (column-vector convention, active rotation).
	//
	//   SLERP:         Takes shortest path — negates q2 when dot(q1,q2) < 0.
	//
	// See also: CoordTransf.h, CoordTransfSpherical.h
	///////////////////////////////////////////////////////////////////////////////

	/// @brief Quaternion class for 3D rotations and spatial orientation
	/// @details Implements quaternions as q = w + xi + yj + zk with Hamilton multiplication.
	///          Storage order: [w, x, y, z] where w is scalar, (x,y,z) is vector part.
	///          Unit quaternions represent rotations via q*v*q^(-1) formula.
	///          Supports axis-angle, Euler angles, matrix conversions, and SLERP interpolation.
	class Quaternion
	{
	private:
		Real _data[4];  // [w, x, y, z] storage

	public:
		/// @brief Default constructor - creates identity quaternion [1, 0, 0, 0] (no rotation)
		Quaternion() : _data{1, 0, 0, 0} {}

		/// @brief Construct from components q = w + xi + yj + zk
		Quaternion(Real w, Real x, Real y, Real z) : _data{w, x, y, z} {}

		/// @brief Construct from scalar and vector parts q = w + v
		Quaternion(Real w, const Vec3Cart& vec) 
			: _data{w, vec[0], vec[1], vec[2]} {}

		/// @brief Construct pure imaginary quaternion from vector q = 0 + v
		explicit Quaternion(const Vec3Cart& vec)
			: _data{0, vec[0], vec[1], vec[2]} {}

		/// @brief Copy constructor
		Quaternion(const Quaternion& q) 
			: _data{q._data[0], q._data[1], q._data[2], q._data[3]} {}

		/// @brief Create identity quaternion (no rotation)
		static Quaternion Identity()
		{
			return Quaternion(1, 0, 0, 0);
		}

		/// @brief Create rotation quaternion from axis-angle
		/// @param axis Unit vector defining rotation axis
		/// @param angle Rotation angle in radians (right-hand rule)
		static Quaternion FromAxisAngle(const Vec3Cart& axis, Real angle)
		{
			Real halfAngle = angle / 2.0;
			Real sinHalf = std::sin(halfAngle);
			Real cosHalf = std::cos(halfAngle);
			
			return Quaternion(cosHalf, 
											 axis[0] * sinHalf,
											 axis[1] * sinHalf,
											 axis[2] * sinHalf);
		}

		/// @brief Create rotation quaternion from Euler angles (ZYX convention)
		/// @param yaw Rotation around Z-axis (radians)
		/// @param pitch Rotation around Y-axis (radians)
		/// @param roll Rotation around X-axis (radians)
		/// @details Applied as R = Rz(yaw) * Ry(pitch) * Rx(roll)
		static Quaternion FromEulerZYX(Real yaw, Real pitch, Real roll)
		{
			Real cy = std::cos(yaw * 0.5);
			Real sy = std::sin(yaw * 0.5);
			Real cp = std::cos(pitch * 0.5);
			Real sp = std::sin(pitch * 0.5);
			Real cr = std::cos(roll * 0.5);
			Real sr = std::sin(roll * 0.5);

			return Quaternion(
				cr * cp * cy + sr * sp * sy,
				sr * cp * cy - cr * sp * sy,
				cr * sp * cy + sr * cp * sy,
				cr * cp * sy - sr * sp * cy
			);
		}

		/// @brief Create rotation quaternion from Euler angles (XYZ convention)
		/// @param roll Rotation around X-axis (radians)
		/// @param pitch Rotation around Y-axis (radians)
		/// @param yaw Rotation around Z-axis (radians)
		/// @details Applied as R = Rx(roll) * Ry(pitch) * Rz(yaw)
		static Quaternion FromEulerXYZ(Real roll, Real pitch, Real yaw)
		{
			Real cr = std::cos(roll * 0.5);
			Real sr = std::sin(roll * 0.5);
			Real cp = std::cos(pitch * 0.5);
			Real sp = std::sin(pitch * 0.5);
			Real cy = std::cos(yaw * 0.5);
			Real sy = std::sin(yaw * 0.5);

			return Quaternion(
				cr * cp * cy - sr * sp * sy,
				sr * cp * cy + cr * sp * sy,
				cr * sp * cy - sr * cp * sy,
				cr * cp * sy + sr * sp * cy
			);
		}

		/// @brief Get scalar component w (const)
		Real w() const { return _data[0]; }
		/// @brief Get x component (const)
		Real x() const { return _data[1]; }
		/// @brief Get y component (const)
		Real y() const { return _data[2]; }
		/// @brief Get z component (const)
		Real z() const { return _data[3]; }

		/// @brief Get scalar component w (mutable)
		Real& w() { return _data[0]; }
		/// @brief Get x component (mutable)
		Real& x() { return _data[1]; }
		/// @brief Get y component (mutable)
		Real& y() { return _data[2]; }
		/// @brief Get z component (mutable)
		Real& z() { return _data[3]; }

		/// @brief Access by index [0]=w, [1]=x, [2]=y, [3]=z (const)
		Real operator[](int i) const { return _data[i]; }
		/// @brief Access by index [0]=w, [1]=x, [2]=y, [3]=z (mutable)
		Real& operator[](int i) { return _data[i]; }

		/// @brief Get scalar part
		Real Scalar() const { return _data[0]; }

		/// @brief Get vector part as Vec3Cart
		Vec3Cart Vector() const 
		{ 
			return Vec3Cart(_data[1], _data[2], _data[3]); 
		}

		/// @brief Quaternion addition
		Quaternion operator+(const Quaternion& q) const
		{
			return Quaternion(_data[0] + q._data[0],
											 _data[1] + q._data[1],
											 _data[2] + q._data[2],
											 _data[3] + q._data[3]);
		}

		// Subtraction
		Quaternion operator-(const Quaternion& q) const
		{
			return Quaternion(_data[0] - q._data[0],
											 _data[1] - q._data[1],
											 _data[2] - q._data[2],
											 _data[3] - q._data[3]);
		}

		// Negation
		Quaternion operator-() const
		{
			return Quaternion(-_data[0], -_data[1], -_data[2], -_data[3]);
		}

		// Scalar multiplication
		Quaternion operator*(Real scalar) const
		{
			return Quaternion(_data[0] * scalar,
											 _data[1] * scalar,
											 _data[2] * scalar,
											 _data[3] * scalar);
		}

		// Scalar division
		Quaternion operator/(Real scalar) const
		{
			Real inv = 1.0 / scalar;
			return (*this) * inv;
		}

		/// @brief Quaternion multiplication (Hamilton product)
		/// @note Non-commutative: p*q != q*p in general
		Quaternion operator*(const Quaternion& q) const
		{
			return Quaternion(
				_data[0] * q._data[0] - _data[1] * q._data[1] - _data[2] * q._data[2] - _data[3] * q._data[3],
				_data[0] * q._data[1] + _data[1] * q._data[0] + _data[2] * q._data[3] - _data[3] * q._data[2],
				_data[0] * q._data[2] - _data[1] * q._data[3] + _data[2] * q._data[0] + _data[3] * q._data[1],
				_data[0] * q._data[3] + _data[1] * q._data[2] - _data[2] * q._data[1] + _data[3] * q._data[0]
			);
		}

		/// @brief In-place addition
		Quaternion& operator+=(const Quaternion& q)
		{
			_data[0] += q._data[0];
			_data[1] += q._data[1];
			_data[2] += q._data[2];
			_data[3] += q._data[3];
			return *this;
		}

		/// @brief In-place subtraction
		Quaternion& operator-=(const Quaternion& q)
		{
			_data[0] -= q._data[0];
			_data[1] -= q._data[1];
			_data[2] -= q._data[2];
			_data[3] -= q._data[3];
			return *this;
		}

		/// @brief In-place scalar multiplication
		Quaternion& operator*=(Real scalar)
		{
			_data[0] *= scalar;
			_data[1] *= scalar;
			_data[2] *= scalar;
			_data[3] *= scalar;
			return *this;
		}

		/// @brief In-place quaternion multiplication
		Quaternion& operator*=(const Quaternion& q)
		{
			*this = (*this) * q;
			return *this;
		}

		/// @brief Conjugate q* = w - xi - yj - zk
		/// @note For unit quaternions: q* = q^(-1)
		Quaternion Conjugate() const
		{
			return Quaternion(_data[0], -_data[1], -_data[2], -_data[3]);
		}

		/// @brief Squared norm ||q||² = w² + x² + y² + z²
		Real NormSquared() const
		{
			return _data[0] * _data[0] + 
						 _data[1] * _data[1] + 
						 _data[2] * _data[2] + 
						 _data[3] * _data[3];
		}

		/// @brief Norm (magnitude) ||q|| = sqrt(w² + x² + y² + z²)
		Real Norm() const
		{
			return std::sqrt(NormSquared());
		}

		/// @brief Inverse q^(-1) = q* / ||q||²
		/// @note For unit quaternions: q^(-1) = q*
		Quaternion Inverse() const
		{
			Real normSq = NormSquared();
			if (normSq < PrecisionValues<Real>::QuaternionZeroThreshold)
				throw QuaternionError("Cannot invert zero quaternion");
			
			Real invNormSq = 1.0 / normSq;
			return Quaternion(_data[0] * invNormSq,
											 -_data[1] * invNormSq,
											 -_data[2] * invNormSq,
											 -_data[3] * invNormSq);
		}

		/// @brief Normalize quaternion to unit length
		void Normalize()
		{
			Real norm = Norm();
			if (norm < PrecisionValues<Real>::QuaternionZeroThreshold)
				throw QuaternionError("Cannot normalize zero quaternion");
			
			Real invNorm = 1.0 / norm;
			_data[0] *= invNorm;
			_data[1] *= invNorm;
			_data[2] *= invNorm;
			_data[3] *= invNorm;
		}

		/// @brief Return normalized copy
		Quaternion Normalized() const
		{
			Quaternion result(*this);
			result.Normalize();
			return result;
		}

		/// @brief Check if quaternion is unit (within tolerance)
		bool isUnit(Real tolerance = PrecisionValues<Real>::DefaultTolerance) const
		{
			return std::abs(NormSquared() - 1.0) < tolerance;
		}

		/// @brief Check if quaternion is identity
		bool isIdentity(Real tolerance = PrecisionValues<Real>::DefaultTolerance) const
		{
			return std::abs(_data[0] - 1.0) < tolerance &&
						 std::abs(_data[1]) < tolerance &&
						 std::abs(_data[2]) < tolerance &&
						 std::abs(_data[3]) < tolerance;
		}

		/// @brief Dot product q1 · q2 = w1*w2 + x1*x2 + y1*y2 + z1*z2
		Real Dot(const Quaternion& q) const
		{
			return _data[0] * q._data[0] + 
						 _data[1] * q._data[1] + 
						 _data[2] * q._data[2] + 
						 _data[3] * q._data[3];
		}

		/// @brief Rotate a 3D vector using this quaternion
		/// @param v The vector to rotate
		/// @return Rotated vector
		/// @note Assumes this is a unit rotation quaternion. Formula: v' = q * [0, v] * q^(-1)
		Vec3Cart Rotate(const Vec3Cart& v) const
		{
			// Optimized version avoiding quaternion construction
			// v' = v + 2w(u × v) + 2u × (u × v)
			// where q = [w, u]
			
			Vec3Cart u(_data[1], _data[2], _data[3]);
			Real w = _data[0];
			
			Vec3Cart uCrossV = VectorProduct(u, v);
			Vec3Cart uCrossUCrossV = VectorProduct(u, uCrossV);
			
			return v + uCrossV * (2.0 * w) + uCrossUCrossV * 2.0;
		}

		/// @brief Get rotation axis (for non-identity rotation quaternions)
		/// @return Unit vector along rotation axis
		Vec3Cart GetRotationAxis() const
		{
			if (isIdentity())
				return Vec3Cart(0, 0, 1);
			
			Vec3Cart axis(_data[1], _data[2], _data[3]);
			Real vecNorm = axis.NormL2();
			
			if (vecNorm < PrecisionValues<Real>::QuaternionZeroThreshold)
				return Vec3Cart(0, 0, 1);
			
			return axis / vecNorm;
		}

		/// @brief Get rotation angle in radians
		/// @return Rotation angle θ = 2*acos(w)
		Real GetRotationAngle() const
		{
			Real w = _data[0];
			
			// Clamp to [-1, 1] for numerical stability
			if (w > 1.0) w = 1.0;
			if (w < -1.0) w = -1.0;
			
			return 2.0 * std::acos(w);
		}

		/// @brief Get axis-angle representation
		/// @param axis Output rotation axis
		/// @param angle Output rotation angle in radians
		void ToAxisAngle(Vec3Cart& axis, Real& angle) const
		{
			angle = GetRotationAngle();
			axis = GetRotationAxis();
		}

		/// @brief Convert to Euler angles (ZYX convention)
		/// @return Vector [yaw, pitch, roll] in radians
		Vec3Cart ToEulerZYX() const
		{
			Real w = _data[0], x = _data[1], y = _data[2], z = _data[3];
			
			// Roll (x-axis rotation)
			Real sinr_cosp = 2.0 * (w * x + y * z);
			Real cosr_cosp = 1.0 - 2.0 * (x * x + y * y);
			Real roll = std::atan2(sinr_cosp, cosr_cosp);
			
			// Pitch (y-axis rotation)
			Real sinp = 2.0 * (w * y - z * x);
			Real pitch;
			if (std::abs(sinp) >= 1.0)
				pitch = std::copysign(Constants::PI / 2.0, sinp); // Gimbal lock
			else
				pitch = std::asin(sinp);
			
			// Yaw (z-axis rotation)
			Real siny_cosp = 2.0 * (w * z + x * y);
			Real cosy_cosp = 1.0 - 2.0 * (y * y + z * z);
			Real yaw = std::atan2(siny_cosp, cosy_cosp);
			
			return Vec3Cart(yaw, pitch, roll);
		}

		/// @brief Convert to 3×3 rotation matrix
		/// @return Orthogonal matrix R such that R*v rotates vector v
		MatrixNM<Real, 3, 3> ToRotationMatrix() const
		{
			Real w = _data[0], x = _data[1], y = _data[2], z = _data[3];
			
			MatrixNM<Real, 3, 3> mat;
			
			// First row
			mat[0][0] = 1.0 - 2.0 * (y*y + z*z);
			mat[0][1] = 2.0 * (x*y - w*z);
			mat[0][2] = 2.0 * (x*z + w*y);
			
			// Second row
			mat[1][0] = 2.0 * (x*y + w*z);
			mat[1][1] = 1.0 - 2.0 * (x*x + z*z);
			mat[1][2] = 2.0 * (y*z - w*x);
			
			// Third row
			mat[2][0] = 2.0 * (x*z - w*y);
			mat[2][1] = 2.0 * (y*z + w*x);
			mat[2][2] = 1.0 - 2.0 * (x*x + y*y);
			
			return mat;
		}

		/// @brief Create quaternion from 3×3 rotation matrix
		/// @param mat Orthogonal rotation matrix
		/// @return Quaternion representation
		/// @details Uses Shepperd's method for numerical stability
		static Quaternion FromRotationMatrix(const MatrixNM<Real, 3, 3>& mat)
		{
			Real trace = mat[0][0] + mat[1][1] + mat[2][2];
			
			if (trace > 0.0)
			{
				// w is the largest component
				Real s = std::sqrt(trace + 1.0) * 2.0;  // s = 4*w
				Real w = 0.25 * s;
				Real x = (mat[2][1] - mat[1][2]) / s;
				Real y = (mat[0][2] - mat[2][0]) / s;
				Real z = (mat[1][0] - mat[0][1]) / s;
				return Quaternion(w, x, y, z);
			}
			else if (mat[0][0] > mat[1][1] && mat[0][0] > mat[2][2])
			{
				// x is the largest component
				Real s = std::sqrt(1.0 + mat[0][0] - mat[1][1] - mat[2][2]) * 2.0;  // s = 4*x
				Real w = (mat[2][1] - mat[1][2]) / s;
				Real x = 0.25 * s;
				Real y = (mat[0][1] + mat[1][0]) / s;
				Real z = (mat[0][2] + mat[2][0]) / s;
				return Quaternion(w, x, y, z);
			}
			else if (mat[1][1] > mat[2][2])
			{
				// y is the largest component
				Real s = std::sqrt(1.0 + mat[1][1] - mat[0][0] - mat[2][2]) * 2.0;  // s = 4*y
				Real w = (mat[0][2] - mat[2][0]) / s;
				Real x = (mat[0][1] + mat[1][0]) / s;
				Real y = 0.25 * s;
				Real z = (mat[1][2] + mat[2][1]) / s;
				return Quaternion(w, x, y, z);
			}
			else
			{
				// z is the largest component
				Real s = std::sqrt(1.0 + mat[2][2] - mat[0][0] - mat[1][1]) * 2.0;  // s = 4*z
				Real w = (mat[1][0] - mat[0][1]) / s;
				Real x = (mat[0][2] + mat[2][0]) / s;
				Real y = (mat[1][2] + mat[2][1]) / s;
				Real z = 0.25 * s;
				return Quaternion(w, x, y, z);
			}
		}

		/// @brief Linear interpolation (faster but not constant angular velocity)
		/// @param q1 Start quaternion
		/// @param q2 End quaternion
		/// @param t Interpolation parameter [0,1]
		/// @return Interpolated quaternion (should be normalized for rotations)
		static Quaternion Lerp(const Quaternion& q1, const Quaternion& q2, Real t)
		{
			return q1 * (1.0 - t) + q2 * t;
		}

		/// @brief Spherical linear interpolation (constant angular velocity)
		/// @param q1 Start quaternion
		/// @param q2 End quaternion
		/// @param t Interpolation parameter [0,1]
		/// @return Interpolated quaternion along shortest arc on 4D unit sphere
		static Quaternion Slerp(const Quaternion& q1, const Quaternion& q2, Real t)
		{
			Quaternion q2_adjusted = q2;
			
			// Compute dot product
			Real dot = q1.Dot(q2);
			
			// If dot < 0, negate q2 to take shortest path
			if (dot < 0.0)
			{
				q2_adjusted = -q2_adjusted;
				dot = -dot;
			}
			
			// If quaternions are very close, use linear interpolation
			if (dot > 0.9995)
			{
				return Lerp(q1, q2_adjusted, t).Normalized();
			}
			
			// Perform slerp
			Real theta = std::acos(dot);
			Real sinTheta = std::sin(theta);

			// Guard against near-zero sinTheta for numerical stability
			if (std::abs(sinTheta) < Real{1e-6})
			{
				return Lerp(q1, q2_adjusted, t).Normalized();
			}
			
			Real w1 = std::sin((1.0 - t) * theta) / sinTheta;
			Real w2 = std::sin(t * theta) / sinTheta;
			
			return q1 * w1 + q2_adjusted * w2;
		}

		/// @brief Exact equality test
		bool operator==(const Quaternion& q) const
		{
			return _data[0] == q._data[0] &&
						 _data[1] == q._data[1] &&
						 _data[2] == q._data[2] &&
						 _data[3] == q._data[3];
		}

		/// @brief Inequality test
		bool operator!=(const Quaternion& q) const
		{
			return !(*this == q);
		}

		/// @brief Check approximate equality within tolerance
		bool isApprox(const Quaternion& q, Real tolerance = PrecisionValues<Real>::DefaultTolerance) const
		{
			return std::abs(_data[0] - q._data[0]) < tolerance &&
						 std::abs(_data[1] - q._data[1]) < tolerance &&
						 std::abs(_data[2] - q._data[2]) < tolerance &&
						 std::abs(_data[3] - q._data[3]) < tolerance;
		}

		/// @brief Stream output operator
		friend std::ostream& operator<<(std::ostream& os, const Quaternion& q)
		{
			os << "[" << q._data[0] << ", " 
				 << q._data[1] << "i, " 
				 << q._data[2] << "j, " 
				 << q._data[3] << "k]";
			return os;
		}

		/// @brief Print to output stream
		void Print(std::ostream& os = std::cout) const
		{
			os << *this;
		}
	};

	/// @brief Scalar * Quaternion operator
	inline Quaternion operator*(Real scalar, const Quaternion& q)
	{
		return q * scalar;
	}

} // namespace MML


///////////////////////////   mml/base/Polynom.h   ///////////////////////////




// Standard headers - include what we use

namespace MML
{
	/// @brief Polynomial class with arithmetic, evaluation, differentiation, and root finding.
	/// @tparam CoefT Coefficient type (Real, Complex, etc.)
	/// @tparam FieldT Field type for evaluation (defaults to CoefT)
	template <typename CoefT, typename FieldT = CoefT>
	class Polynom
	{
	protected:
		/// @brief Polynomial coefficients with _vecCoef[0] being the constant term
		std::vector<CoefT> _vecCoef;
	public:
		/// @brief Default constructor.
		Polynom() {}
		/// @brief Constructs polynomial of degree n with zero coefficients.
		/// @param n Degree of polynomial
		Polynom(int n) { _vecCoef.resize(n + 1); }
		/// @brief Constructs polynomial from coefficient vector.
		/// @param vecCoef Coefficients (vecCoef[0] = constant term)
		Polynom(const std::vector<CoefT>& vecCoef) : _vecCoef(vecCoef) {}
		/// @brief Constructs polynomial from initializer list.
		/// @param list Coefficients in ascending order
		Polynom(std::initializer_list<CoefT> list) : _vecCoef(list) {}
		/// @brief Copy constructor.
		Polynom(const Polynom& Copy) = default;

		/// @brief Constructs a constant polynomial from a single coefficient value.
		/// @param value Constant term value
		/// @note Uses explicit to avoid ambiguity with Polynom(int)
		explicit Polynom(const CoefT& value) : _vecCoef{value} {}

		/// @brief Move constructor.
		Polynom(Polynom&&) noexcept = default;
		/// @brief Move assignment.
		Polynom& operator=(Polynom&&) noexcept = default;

		/// @brief Returns the zero polynomial (all coefficients zero).
		static Polynom Zero() {
			return Polynom(std::initializer_list<CoefT>{CoefT(0)});
		}

		/// @brief Returns the monomial x^degree (coefficient 1 at degree, 0 elsewhere).
		/// @param degree Degree of monomial
		static Polynom Monomial(int degree) {
			std::vector<CoefT> coef(degree + 1, CoefT(0));
			if (degree >= 0) coef[degree] = CoefT(1);
			return Polynom(coef);
		}

		/// @brief Returns the constant polynomial.
		/// @param value Constant value
		static Polynom Constant(const CoefT& value) {
			return Polynom(std::initializer_list<CoefT>{value});
		}

		/// @brief Constructs interpolating polynomial from data points using Lagrange/Newton method.
		/// @param x X-coordinates of data points
		/// @param y Y-coordinates of data points
		/// @return Polynomial such that P(x[i]) = y[i]
    static Polynom FromValues(const std::vector<FieldT>& x, const std::vector<FieldT>& y)
    {
      int n = (int)x.size();
      if (n != (int)y.size())
        throw ArgumentError("FromValues: x and y arrays must have the same size");
      if (n == 0)
        throw ArgumentError("FromValues: arrays cannot be empty");

      // Check for duplicate x-values (causes division by zero in interpolation)
      for (int i = 0; i < n; i++)
        for (int j = i + 1; j < n; j++)
          if (x[i] == x[j])
            throw ArgumentError("FromValues: duplicate x-value at indices " + std::to_string(i) + " and " + std::to_string(j));

      std::vector<FieldT> cof(n, FieldT(0));
      std::vector<FieldT> s(n);
      
      // Initialize
      for (int i = 0; i < n; i++)
        s[i] = FieldT(0);
      
      s[n-1] = -x[0];
      
      // Build the polynomial basis
      for (int i = 1; i < n; i++) {
        for (int j = n-1-i; j < n-1; j++)
          s[j] -= x[i] * s[j+1];
        s[n-1] -= x[i];
      }
      
      // Compute coefficients using the basis
      for (int j = 0; j < n; j++) {
        FieldT phi = FieldT(n);
        for (int k = n-1; k > 0; k--)
          phi = FieldT(k) * s[k] + x[j] * phi;
      
        FieldT ff = y[j] / phi;
        FieldT b = FieldT(1);
        
        for (int k = n-1; k >= 0; k--) {
          cof[k] += b * ff;
          b = s[k] + x[j] * b;
        }
      }
      
      return Polynom(cof);
    }    

		/// @brief Returns the linear polynomial a*x + b.
		/// @param a Coefficient of x
		/// @param b Constant term
		static Polynom Linear(const CoefT& a, const CoefT& b) {
			return Polynom(std::initializer_list<CoefT>{b, a});
		}

		/// @brief Returns degree of polynomial (preferred API).
		int  degree() const noexcept { return (int)_vecCoef.size() - 1; }
		/// @brief Sets degree of polynomial (resizes coefficient vector).
		/// @param newDeg New degree
		void SetDegree(int newDeg) { _vecCoef.resize(newDeg + 1); }
		/// @brief Checks if polynomial is null (no coefficients).
		bool isNull() const noexcept { return _vecCoef.size() == 0; }
		/// @brief Removes trailing zero coefficients.
		void Reduce() { while (!_vecCoef.empty() && _vecCoef.back() == CoefT(0)) _vecCoef.pop_back(); }
		/// @brief Removes trailing coefficients smaller than eps in absolute value.
		/// @param eps Tolerance threshold for near-zero coefficients
		void Reduce(CoefT eps) { while (!_vecCoef.empty() && std::abs(_vecCoef.back()) < eps) _vecCoef.pop_back(); }
		
		/// @brief Returns leading coefficient.
		CoefT leadingTerm() const noexcept { return _vecCoef.empty() ? CoefT(0) : _vecCoef.back(); }
		/// @brief Returns constant term.
		CoefT constantTerm() const noexcept { return _vecCoef.empty() ? CoefT(0) : _vecCoef[0]; }

		/// @brief Coefficient access (const).
		/// @param i Coefficient index (0 = constant term)
		const CoefT& operator[] (int i) const noexcept { return _vecCoef[i]; }
		/// @brief Coefficient access (non-const).
		/// @param i Coefficient index (0 = constant term)
		CoefT& operator[] (int i) noexcept { return _vecCoef[i]; }

		///////////////////////////            Iterators              ///////////////////////////

		using iterator = typename std::vector<CoefT>::iterator;
		using const_iterator = typename std::vector<CoefT>::const_iterator;

		iterator begin() { return _vecCoef.begin(); }
		iterator end() { return _vecCoef.end(); }
		const_iterator begin() const { return _vecCoef.begin(); }
		const_iterator end() const { return _vecCoef.end(); }
		const_iterator cbegin() const { return _vecCoef.cbegin(); }
		const_iterator cend() const { return _vecCoef.cend(); }

		//////////////////   Additional convenience methods   /////////////////
		
		/// @brief Alias for operator() - evaluates polynomial at x.
		/// @param x Evaluation point
		FieldT eval(const FieldT& x) const { return operator()(x); }
		
		/// @brief Returns coefficient vector (const reference).
		const std::vector<CoefT>& coefficients() const { return _vecCoef; }
		
		/// @brief Returns coefficient at index i.
		/// @param i Coefficient index (0 = constant term)
		CoefT coeff(int i) const { return (i >= 0 && i < (int)_vecCoef.size()) ? _vecCoef[i] : CoefT(0); }
		
		/// @brief Returns string representation with default formatting.
		std::string to_string() const { return to_string(10, 6); }

		///////////////////////////            Operators              ///////////////////////////
		/// @brief Copy assignment.
		Polynom& operator=(const Polynom& Copy) { _vecCoef = Copy._vecCoef; return *this; }

		/// @brief Evaluates polynomial at given value using Horner's method.
		/// @param x Evaluation point
		/// @return P(x)
		FieldT operator() (const FieldT& x) const {
			if (_vecCoef.empty())
				return FieldT(0);
			int j = degree();
			FieldT p = _vecCoef[j] * FieldT(1);

			while (j > 0)
				p = p * x + _vecCoef[--j];
			return p;
		}

		/// @brief Checks exact equality with another polynomial (ignoring trailing zeros).
		/// @param b Polynomial to compare
		/// @note For tolerance-based comparison, use IsEqualTo()
		bool IsEqual(const Polynom& b) const
		{
			// Compare polynomials by effective degree (ignoring trailing zeros)
			int maxSize = (int)std::max(_vecCoef.size(), b._vecCoef.size());
			
			for (int i = 0; i < maxSize; i++)
			{
				CoefT a_coef = (i < (int)_vecCoef.size()) ? _vecCoef[i] : CoefT(0);
				CoefT b_coef = (i < (int)b._vecCoef.size()) ? b._vecCoef[i] : CoefT(0);
				
				if (a_coef != b_coef)
					return false;
			}
			return true;
		}

		/// @brief Checks tolerance-based equality with another polynomial.
		/// @param b Polynomial to compare
		/// @param eps Tolerance for coefficient comparison
		/// @return True if all coefficients are within eps of each other
		template<typename T = CoefT>
		typename std::enable_if<std::is_floating_point<T>::value, bool>::type
		IsEqualTo(const Polynom& b, T eps = Defaults::DefaultTolerance) const
		{
			int maxSize = (int)std::max(_vecCoef.size(), b._vecCoef.size());
			
			for (int i = 0; i < maxSize; i++)
			{
				T a_coef = (i < (int)_vecCoef.size()) ? _vecCoef[i] : T(0);
				T b_coef = (i < (int)b._vecCoef.size()) ? b._vecCoef[i] : T(0);
				
				if (std::abs(a_coef - b_coef) > eps)
					return false;
			}
			return true;
		}

		/// @brief Equality operator.
		bool operator==(const Polynom& b) const
		{
			return IsEqual(b);
		}

		/// @brief Inequality operator.
		bool operator!=(const Polynom& b) const
		{
			return !IsEqual(b);
		}

		/// @brief Unary negation operator.
		Polynom operator-() const
		{
			Polynom result;
			result._vecCoef.resize(_vecCoef.size());
			for (size_t i = 0; i < _vecCoef.size(); i++)
				result._vecCoef[i] = -_vecCoef[i];
			return result;
		}

		/// @brief Polynomial addition.
		/// @param b Polynomial to add
		Polynom operator+(const Polynom& b) const
		{
			Polynom result;
			int n = (int)std::max(_vecCoef.size(), b._vecCoef.size());
			result._vecCoef.resize(n);
			for (int i = 0; i < n; i++)
			{
				if (i < _vecCoef.size())
					result._vecCoef[i] += _vecCoef[i];
				if (i < b._vecCoef.size())
					result._vecCoef[i] += b._vecCoef[i];
			}
			return result;
		}

		/// @brief Polynomial subtraction.
		/// @param b Polynomial to subtract
		Polynom operator-(const Polynom& b) const
		{
			Polynom result;
			int n = (int)std::max(_vecCoef.size(), b._vecCoef.size());
			result._vecCoef.resize(n);
			for (int i = 0; i < n; i++)
			{
				if (i < _vecCoef.size())
					result._vecCoef[i] += _vecCoef[i];
				if (i < b._vecCoef.size())
					result._vecCoef[i] -= b._vecCoef[i];
			}
			return result;
		}

		/// @brief Polynomial multiplication.
		/// @param b Polynomial to multiply
		Polynom operator*(const Polynom& b) const
		{
			Polynom result;

			int n = (int)(_vecCoef.size() + b._vecCoef.size() - 1);
			result._vecCoef.resize(n);
			for (int i = 0; i < _vecCoef.size(); i++)
				for (int j = 0; j < b._vecCoef.size(); j++)
					result._vecCoef[i + j] += _vecCoef[i] * b._vecCoef[j];
			return result;
		}

		/// @brief Addition by scalar (adds to constant term).
		/// @param scalar Value to add
		Polynom operator+(const CoefT& scalar) const {
			Polynom result = *this;
			if (result._vecCoef.empty())
				result._vecCoef.resize(1, CoefT(0));
			result._vecCoef[0] += scalar;
			return result;
		}
		/// @brief Scalar + polynomial addition.
		friend Polynom operator+(const CoefT& scalar, const Polynom& poly) {
			return poly + scalar;
		}

		/// @brief Subtraction by scalar (subtracts from constant term).
		/// @param scalar Value to subtract
		Polynom operator-(const CoefT& scalar) const {
			Polynom result = *this;
			if (result._vecCoef.empty())
				result._vecCoef.resize(1, CoefT(0));
			result._vecCoef[0] -= scalar;
			return result;
		}
		/// @brief Scalar - polynomial subtraction.
		friend Polynom operator-(const CoefT& scalar, const Polynom& poly) {
			Polynom result = -poly;
			if (result._vecCoef.empty())
				result._vecCoef.resize(1, CoefT(0));
			result._vecCoef[0] += scalar;
			return result;
		}

		/// @brief Multiplication by scalar.
		/// @param scalar Multiplier
		Polynom operator*(const CoefT& scalar) const {
			Polynom result = *this;
			for (auto& coef : result._vecCoef)
				coef *= scalar;
			return result;
		}
		/// @brief Scalar * polynomial multiplication.
		friend Polynom operator*(const CoefT& scalar, const Polynom& poly) {
			return poly * scalar;
		}

		/// @brief Division by scalar.
		/// @param scalar Divisor
		Polynom operator/(const CoefT& scalar) const {
			Polynom result = *this;
			for (auto& coef : result._vecCoef)
				coef /= scalar;
			return result;
		}

		/// @brief Polynomial division with quotient and remainder.
		/// @param u Dividend polynomial
		/// @param v Divisor polynomial
		/// @param qout Quotient (output)
		/// @param rout Remainder (output)
		static void poldiv(const Polynom& u, const Polynom& v, Polynom& qout, Polynom& rout)
		{
			int k, j, n = u.degree(), nv = v.degree();

			// find real degree of v
			while (nv >= 0 && v._vecCoef[nv] == CoefT(0))
				nv--;

			if (nv < 0)
				throw DivisionByZeroError("poldiv: divide by zero polynomial");

			Polynom r = u;
			Polynom q(u.degree());
			for (k = n - nv; k >= 0; k--)
			{
				q[k] = r[nv + k] / v[nv];

				for (j = nv + k - 1; j >= k; j--)
					r[j] -= q[k] * v[j - k];
			}
			for (j = nv; j <= n; j++)
				r[j] = CoefT(0);


			int nq = q.degree();
			while (nq >= 0 && q[nq] == CoefT(0))
				nq--;

			// setting exact size for quotient
			qout.SetDegree(nq);
			for (j = 0; j <= nq; j++)
				qout[j] = q[j];

			// setting exact size for remainder
			rout.SetDegree(nv - 1);
			for (j = 0; j < nv; j++)
				rout[j] = r[j];
		}

		///////////////////////////           Operations              ///////////////////////////
		/// @brief Evaluates polynomial and its first n derivatives at point x.
		/// @param x Evaluation point
		/// @param pd Output vector: pd[0]=P(x), pd[1]=P'(x), ..., pd[n]=P^(n)(x)
		void Derive(const Real x, Vector<Real>& pd)
		{
			int  nnd, j, i;
			int  nc = degree();
			int  nd = pd.size() - 1;
			Real cnst = 1.0;

			pd[0] = (*this)[nc];
			for (j = 1; j < nd + 1; j++)
				pd[j] = 0.0;

			for (i = nc - 1; i >= 0; i--)
			{
				nnd = (nd < (nc - i) ? nd : nc - i);
				for (j = nnd; j > 0; j--)
					pd[j] = pd[j] * x + pd[j - 1];

				pd[0] = pd[0] * x + (*this)[i];
			}
			for (i = 2; i < nd + 1; i++) {
				cnst *= i;
				pd[i] *= cnst;
			}
		}

		/// @brief Returns the first derivative as a new polynomial (preferred API).
		Polynom derivative() const {
			Polynom result;
			int deg = degree();
			if (deg <= 0) {
				result._vecCoef.clear();
				return result;
			}
			result._vecCoef.resize(deg);
			for (int i = 1; i <= deg; ++i) {
				result._vecCoef[i - 1] = _vecCoef[i] * CoefT(i);
			}
			return result;
		}
		
		/// @brief Returns the indefinite integral (antiderivative) with constant = 0 (preferred API).
		Polynom integral() const {
			Polynom result;
			int deg = degree();
			result._vecCoef.resize(deg + 2, CoefT(0));
			for (int i = 0; i <= deg; ++i) {
				result._vecCoef[i + 1] = _vecCoef[i] / CoefT(i + 1);
			}
			return result;
		}
		
		///////////////////////////               I/O                 ///////////////////////////
		/// @brief Converts polynomial to string representation.
		/// @param width Field width
		/// @param precision Decimal precision
		std::string to_string(int width, int precision) const
		{
			std::stringstream str;

			Print(str, width, precision);

			return str.str();
		}

		/// @brief Prints polynomial to stream with default formatting.
		std::ostream& Print(std::ostream& stream) const
		{
			return Print(stream, 10, 6); // Default width and precision
		}

		/// @brief Prints polynomial to stream with custom formatting.
		/// @param stream Output stream
		/// @param width Field width
		/// @param precision Decimal precision
		std::ostream& Print(std::ostream& stream, int width, int precision) const
		{
			using std::abs;
			using std::to_string;

			std::ios_base::fmtflags f(stream.flags());
			stream << std::fixed << std::setw(width) << std::setprecision(precision);

			bool first = true;
			for (int i = (int)_vecCoef.size() - 1; i >= 0; --i)
			{
				// Skip zero coefficients
				bool is_zero = false;
				if constexpr (std::is_floating_point_v<CoefT>) {
					is_zero = (std::abs(_vecCoef[i]) < PrecisionValues<Real>::PolynomialCoeffZeroThreshold);
				}
				else if constexpr (std::is_same_v<CoefT, std::complex<double>> || std::is_same_v<CoefT, std::complex<float>>) {
					is_zero = (std::abs(_vecCoef[i]) < PrecisionValues<Real>::PolynomialCoeffZeroThreshold);
				}
				else {
					is_zero = (_vecCoef[i] == CoefT(0));
				}
				if (is_zero) continue;

				// Print sign and separator
				if (!first) {
					if constexpr (std::is_arithmetic_v<CoefT>) {
						stream << (_vecCoef[i] >= CoefT(0) ? " + " : " - ");
					}
					else {
						stream << " + "; // Always use '+' for non-ordered types
					}
				}
				else {
					if constexpr (std::is_arithmetic_v<CoefT>) {
						if (_vecCoef[i] < CoefT(0)) stream << "-";
					}
					first = false;
				}

				// Print coefficient (absolute value for arithmetic types, as-is for others)
				if constexpr (std::is_arithmetic_v<CoefT>) {
					CoefT abs_coef = _vecCoef[i] < CoefT(0) ? -_vecCoef[i] : _vecCoef[i];
					bool print_coef = (i == 0) || (abs_coef != CoefT(1));
					if (print_coef) stream << abs_coef;
				}
				else {
					stream << _vecCoef[i];
				}

				// Variable and exponent
				if (i > 0) {
					stream << "x";
					if (i > 1) stream << "^" << i;
				}
			}

			if (first) stream << CoefT(0);

			stream.flags(f);
			return stream;
		}

		/// @brief Stream output operator.
		friend std::ostream& operator<<(std::ostream& stream, const Polynom& poly)
		{
			return poly.Print(stream);
		}
	};

	/// @brief Real polynomial that implements IRealFunction interface.
	class PolynomRealFunc : public Polynom<Real>, public IRealFunction
	{
	public:
		/// @brief Default constructor.
		PolynomRealFunc() {}
		/// @brief Constructs polynomial of degree n.
		PolynomRealFunc(int n) { _vecCoef.resize(n + 1); }
		/// @brief Constructs from coefficient vector.
		PolynomRealFunc(const std::vector<Real>& vecCoef) : Polynom(vecCoef) {}
		/// @brief Constructs from initializer list.
		PolynomRealFunc(std::initializer_list<Real> list) : Polynom(list) {}
		/// @brief Constructs from existing polynomial.
		PolynomRealFunc(const Polynom& Copy) : Polynom(Copy) {}
		~PolynomRealFunc() {}

		/// @brief Evaluates polynomial at x (IRealFunction interface).
		Real operator()(Real x) const { return Polynom::operator()(x); }
	};

	typedef Polynom<Real>      PolynomReal;
	typedef Polynom<Complex>   PolynomComplex;
	
	typedef Polynom<Real, Complex>   PolynomComplexRealCoef;

	typedef Polynom<Real, MatrixNM<Real, 2, 2>>       Matrix2Polynom;
	typedef Polynom<Real, MatrixNM<Real, 3, 3>>       Matrix3Polynom;
	typedef Polynom<Real, MatrixNM<Real, 4, 4>>       Matrix4Polynom;
}


///////////////////////////   mml/base/ChebyshevPolynom.h   ///////////////////////////


namespace MML
{
	///////////////////////////////////////////////////////////////////////////////////////////
	///                         CHEBYSHEV POLYNOMIAL EVALUATION                             ///
	///////////////////////////////////////////////////////////////////////////////////////////

	/// @brief Evaluate Chebyshev polynomial of the first kind T_n(x)
	/// @details Uses the recurrence relation:
	///          - T_0(x) = 1
	///          - T_1(x) = x
	///          - T_{n+1}(x) = 2x · T_n(x) - T_{n-1}(x)
	///
	///          Key properties:
	///          - T_n(1) = 1 for all n
	///          - T_n(-1) = (-1)^n
	///          - T_n(cos θ) = cos(nθ)  (trigonometric definition)
	///          - |T_n(x)| ≤ 1 for x ∈ [-1, 1]
	/// @param n Polynomial degree (must be non-negative)
	/// @param x Evaluation point
	/// @return Value of T_n(x)
	/// @throws ArgumentError if n < 0
	inline Real ChebyshevT(int n, Real x)
	{
		if (n < 0)
			throw ArgumentError("ChebyshevT: n must be non-negative");
		
		if (n == 0) return 1.0;
		if (n == 1) return x;
		
		Real T_prev2 = 1.0;   // T_0
		Real T_prev1 = x;     // T_1
		Real T_curr = 0.0;
		
		for (int k = 2; k <= n; k++)
		{
			T_curr = 2.0 * x * T_prev1 - T_prev2;
			T_prev2 = T_prev1;
			T_prev1 = T_curr;
		}
		
		return T_curr;
	}

	/// @brief Evaluate Chebyshev polynomial of the second kind U_n(x)
	/// @details Uses the recurrence relation:
	///          - U_0(x) = 1
	///          - U_1(x) = 2x
	///          - U_{n+1}(x) = 2x · U_n(x) - U_{n-1}(x)
	///
	///          Key properties:
	///          - U_n(1) = n + 1
	///          - U_n(-1) = (-1)^n · (n + 1)
	///          - U_n(cos θ) = sin((n+1)θ) / sin θ
	///
	///          Relationship to T_n:
	///          - dT_n/dx = n · U_{n-1}(x)
	/// @param n Polynomial degree (must be non-negative)
	/// @param x Evaluation point
	/// @return Value of U_n(x)
	/// @throws ArgumentError if n < 0
	inline Real ChebyshevU(int n, Real x)
	{
		if (n < 0)
			throw ArgumentError("ChebyshevU: n must be non-negative");
		
		if (n == 0) return 1.0;
		if (n == 1) return 2.0 * x;
		
		Real U_prev2 = 1.0;       // U_0
		Real U_prev1 = 2.0 * x;   // U_1
		Real U_curr = 0.0;
		
		for (int k = 2; k <= n; k++)
		{
			U_curr = 2.0 * x * U_prev1 - U_prev2;
			U_prev2 = U_prev1;
			U_prev1 = U_curr;
		}
		
		return U_curr;
	}

}   // namespace MML


///////////////////////////   mml/base/Geometry/Geometry2DCore/Geometry2DLines.h   ///////////////////////////



namespace MML
{
	/// @brief Helper function for floating-point comparisons with tolerance
	/// @param a First value
	/// @param b Second value
	/// @param eps Tolerance (default: GEOMETRY_EPSILON)
	/// @return True if |a - b| < eps
	inline bool AreEqual(Real a, Real b, Real eps = Constants::GEOMETRY_EPSILON) {
		return std::abs(a - b) < eps;
	}

	// ============================================================================
	// 2D Line Intersection Types
	// ============================================================================

	/// @brief Classification of 2D line-line intersection
	enum class LineIntersectionType2D {
		Point,		///< Lines intersect at a single point
		Parallel,	///< Lines are parallel (no intersection)
		Coincident	///< Lines are the same (infinite intersections)
	};

	/// @brief Result of 2D line-line intersection
	struct LineIntersection2D {
		LineIntersectionType2D type = LineIntersectionType2D::Parallel;
		Point2Cartesian point;	///< Intersection point (valid only for Point type)
		Real t1 = 0.0;			///< Parameter on first line: point = p1 + t1 * d1
		Real t2 = 0.0;			///< Parameter on second line: point = p2 + t2 * d2

		/// @brief Check if lines intersect at a single point
		bool HasIntersection() const { return type == LineIntersectionType2D::Point; }
		/// @brief Check if intersection is a single point
		bool IsPoint() const { return type == LineIntersectionType2D::Point; }
		/// @brief Check if lines are parallel (no intersection)
		bool IsParallel() const { return type == LineIntersectionType2D::Parallel; }
		/// @brief Check if lines are coincident (infinite intersections)
		bool IsCoincident() const { return type == LineIntersectionType2D::Coincident; }
	};

	// ============================================================================
	// 2D Segment Intersection Types
	// ============================================================================

	/// @brief Classification of segment-segment intersection
	enum class SegmentIntersectionType {
		None,	   ///< No intersection
		Point,	   ///< Single point intersection
		Collinear, ///< Segments are collinear (may or may not overlap)
		Overlap	   ///< Collinear and overlapping
	};

	/// @brief Result of segment-segment intersection
	struct SegmentIntersection {
		SegmentIntersectionType type = SegmentIntersectionType::None;
		Point2Cartesian point;		  ///< Intersection point (for Point type)
		Point2Cartesian overlapStart; ///< Start of overlap (for Overlap type)
		Point2Cartesian overlapEnd;	  ///< End of overlap (for Overlap type)

		/// @brief Check if segments intersect (point or overlap)
		bool HasIntersection() const { 
			return type == SegmentIntersectionType::Point || type == SegmentIntersectionType::Overlap; 
		}
		/// @brief Check if intersection is a single point
		bool IsPointIntersection() const { return type == SegmentIntersectionType::Point; }
		/// @brief Check if segments overlap
		bool IsOverlap() const { return type == SegmentIntersectionType::Overlap; }
	};

	/// @brief 2D infinite line defined by a point and direction vector
	/// @details Represents an infinite line in 2D space using parametric form: P(t) = point + t * direction.
	///          The direction is automatically normalized to a unit vector.
	///          Provides methods for point distance, closest point, perpendicular lines, and line-line intersection.
	class Line2D
	{
	private:
		Point2Cartesian _point;
		Vector2Cartesian _direction;					// unit vector in line direction

	public:
		/// @brief Constructs a line from a point and direction vector
		/// @param pnt A point on the line
		/// @param dir Direction vector (will be normalized)
		Line2D(const Point2Cartesian& pnt, const Vector2Cartesian& dir)
		{
			_point = pnt;
			_direction = dir.GetAsUnitVector();
		}

		/// @brief Constructs a line through two points
		/// @param a First point on the line
		/// @param b Second point on the line
		Line2D(const Point2Cartesian& a, const Point2Cartesian& b)
		{
			Vector2Cartesian dir(a, b);
			_point = a;
			_direction = dir.GetAsUnitVector();
		}

		/// @brief Gets the start point (const version)
		Point2Cartesian   StartPoint() const { return _point; }
		/// @brief Gets the start point (mutable reference)
		Point2Cartesian&  StartPoint() { return _point; }

		/// @brief Gets the unit direction vector (const version)
		Vector2Cartesian  Direction() const { return _direction; }
		/// @brief Gets the unit direction vector (mutable reference)
		Vector2Cartesian& Direction() { return _direction; }

		/// @brief Gets point on line at parameter t
		/// @param t Parameter value (signed distance along direction)
		/// @return Point at StartPoint + t * Direction
		Point2Cartesian operator()(Real t) const
		{
			Vector2Cartesian dist = t * _direction;
			Point2Cartesian ret = _point + dist;
			return ret;
		}

		/// @brief Calculates perpendicular distance from point to line
		/// @param p The point
		/// @return Shortest distance from p to the line
		Real DistanceToPoint(const Point2Cartesian& p) const
		{
			Vector2Cartesian v(_point, p);
			// Distance = |v × direction| (2D cross product magnitude)
			Real cross = v.X() * _direction.Y() - v.Y() * _direction.X();
			return std::abs(cross);
		}

		/// @brief Finds the closest point on the line to a given point
		/// @param p The point
		/// @return Point on line closest to p
		Point2Cartesian ClosestPoint(const Point2Cartesian& p) const
		{
			Vector2Cartesian v(_point, p);
			// Project v onto direction
			Real t = v.X() * _direction.X() + v.Y() * _direction.Y();
			return (*this)(t);
		}

		/// @brief Creates a perpendicular line through a given point
		/// @param throughPoint The point through which the perpendicular passes
		/// @return Line perpendicular to this one, passing through throughPoint
		Line2D Perpendicular(const Point2Cartesian& throughPoint) const
		{
			// Perpendicular direction in 2D: rotate 90 degrees
			Vector2Cartesian perpDir(-_direction.Y(), _direction.X());
			return Line2D(throughPoint, perpDir);
		}

		/// @brief Checks if a point lies on the line
		/// @param p The point to test
		/// @param epsilon Tolerance for the test
		/// @return True if point is within epsilon of the line
		bool Contains(const Point2Cartesian& p, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return DistanceToPoint(p) < epsilon;
		}

		/// @brief Computes full intersection information with another line
		/// @param other The other line
		/// @return LineIntersection2D with type, point, and parameters
		/// @details Handles all cases: intersection point, parallel, coincident
		LineIntersection2D Intersection(const Line2D& other) const
		{
			LineIntersection2D result;

			Real cross = _direction.X() * other._direction.Y() - _direction.Y() * other._direction.X();
			Real dx = other._point.X() - _point.X();
			Real dy = other._point.Y() - _point.Y();

			if (std::abs(cross) < Constants::GEOMETRY_EPSILON) {
				// Lines are parallel - check if coincident
				Real crossP = dx * _direction.Y() - dy * _direction.X();
				if (std::abs(crossP) < Constants::GEOMETRY_EPSILON)
					result.type = LineIntersectionType2D::Coincident;
				else
					result.type = LineIntersectionType2D::Parallel;
				return result;
			}

			Real t = (dx * other._direction.Y() - dy * other._direction.X()) / cross;
			result.type = LineIntersectionType2D::Point;
			result.point = (*this)(t);
			result.t1 = t;
			result.t2 = (dx * _direction.Y() - dy * _direction.X()) / cross;
			return result;
		}

		/// @brief Tests for intersection with another line (convenience method)
		/// @param other The other line
		/// @param intersection Optional output parameter for intersection point
		/// @return True if lines intersect at a single point, false if parallel/coincident
		bool Intersects(const Line2D& other, Point2Cartesian* intersection = nullptr) const
		{
			auto result = Intersection(other);
			if (intersection && result.HasIntersection())
				*intersection = result.point;
			return result.HasIntersection();
		}
	};

	/// @brief 2D line segment defined by two endpoints
	/// @details Represents a finite line segment in 2D space between two points.
	///          Provides methods for point-on-segment access, distance calculations,
	///          closest point computation, and segment-segment intersection tests.
	class SegmentLine2D
	{
	private:
		Point2Cartesian _point1;
		Point2Cartesian _point2;

	public:
		/// @brief Constructs a segment from two endpoints
		/// @param pnt1 Start point
		/// @param pnt2 End point
		SegmentLine2D(const Point2Cartesian& pnt1, const Point2Cartesian& pnt2) : _point1(pnt1), _point2(pnt2)
		{ }

		/// @brief Constructs a segment from a start point, direction, and length
		/// @param pnt1 Start point
		/// @param direction Direction vector (not necessarily unit)
		/// @param t Length parameter (endpoint = pnt1 + direction * t)
		SegmentLine2D(const Point2Cartesian& pnt1, const Vector2Cartesian& direction, Real t) : _point1(pnt1)
		{
			_point2 = pnt1 + direction * t;
		}

		/// @brief Gets the start point (const version)
		Point2Cartesian  StartPoint() const { return _point1; }
		/// @brief Gets the start point (mutable reference)
		Point2Cartesian& StartPoint() { return _point1; }

		/// @brief Gets the end point (const version)
		Point2Cartesian  EndPoint()  const { return _point2; }
		/// @brief Gets the end point (mutable reference)
		Point2Cartesian& EndPoint() { return _point2; }

		/// @brief Gets a point on the segment at parameter t ∈ [0,1]
		/// @param t Parameter value (0 = start, 1 = end)
		/// @return Point on segment at the specified parameter
		/// @throws GeometryError if t is outside [0,1]
		Point2Cartesian PointOnSegment(Real t) const
		{
			if (t < 0.0 || t > 1.0)
				throw GeometryError("SegmentLine2D::PointOnSegment t must be in [0,1]");

			Vector2Cartesian dist = t * Direction();
			Point2Cartesian ret = _point1 + dist;
			return ret;
		}

		/// @brief Gets the length of the segment
		Real                Length()    const { return _point1.Dist(_point2); }
		/// @brief Gets the direction vector from start to end (not normalized)
		Vector2Cartesian    Direction() const { return Vector2Cartesian(_point1, _point2); }
		
		/// @brief Gets the midpoint of the segment
		Point2Cartesian Midpoint() const
		{
			return Point2Cartesian((_point1.X() + _point2.X()) / 2.0,
			                      (_point1.Y() + _point2.Y()) / 2.0);
		}

		/// @brief Calculates the distance from a point to the segment
		/// @param p The point
		/// @return Shortest distance from p to any point on the segment
		Real DistanceToPoint(const Point2Cartesian& p) const
		{
			Vector2Cartesian v(_point1, _point2);
			Vector2Cartesian w(_point1, p);
			
			Real lenSq = v.NormL2() * v.NormL2();
			if (lenSq < Constants::GEOMETRY_EPSILON)
				return _point1.Dist(p); // Degenerate segment
			
			// Project w onto v
			Real t = (w.X() * v.X() + w.Y() * v.Y()) / lenSq;
			t = std::clamp(t, REAL(0.0), REAL(1.0)); // Clamp to segment
			
			Point2Cartesian projection = _point1 + v * t;
			return p.Dist(projection);
		}

		/// @brief Finds the closest point on the segment to a given point
		/// @param p The point
		/// @return Point on segment closest to p
		Point2Cartesian ClosestPoint(const Point2Cartesian& p) const
		{
			Vector2Cartesian v(_point1, _point2);
			Vector2Cartesian w(_point1, p);
			
			Real lenSq = v.NormL2() * v.NormL2();
			if (lenSq < Constants::GEOMETRY_EPSILON)
				return _point1; // Degenerate segment
			
			Real t = (w.X() * v.X() + w.Y() * v.Y()) / lenSq;
			t = std::clamp(t, REAL(0.0), REAL(1.0));
			
			return _point1 + v * t;
		}

	private:
		/// @brief Cross product of vectors OA and OB (internal helper)
		static Real Cross(const Point2Cartesian& O, const Point2Cartesian& A, const Point2Cartesian& B) {
			return (A.X() - O.X()) * (B.Y() - O.Y()) - (A.Y() - O.Y()) * (B.X() - O.X());
		}

		/// @brief Check if point q lies on segment pr (assuming collinearity)
		static bool OnSegment(const Point2Cartesian& p, const Point2Cartesian& q, const Point2Cartesian& r) {
			return q.X() <= std::max(p.X(), r.X()) + Constants::GEOMETRY_EPSILON && 
			       q.X() >= std::min(p.X(), r.X()) - Constants::GEOMETRY_EPSILON &&
			       q.Y() <= std::max(p.Y(), r.Y()) + Constants::GEOMETRY_EPSILON && 
			       q.Y() >= std::min(p.Y(), r.Y()) - Constants::GEOMETRY_EPSILON;
		}

	public:
		/// @brief Computes full intersection information with another segment
		/// @param other The other segment
		/// @return SegmentIntersection with type, point, or overlap endpoints
		/// @details Handles all cases: crossing, endpoint touching, collinear, overlapping
		SegmentIntersection Intersection(const SegmentLine2D& other) const
		{
			SegmentIntersection result;
			constexpr Real EPSILON = Constants::GEOMETRY_EPSILON;

			const Point2Cartesian& p1 = _point1;
			const Point2Cartesian& q1 = _point2;
			const Point2Cartesian& p2 = other._point1;
			const Point2Cartesian& q2 = other._point2;

			Real d1 = Cross(p2, q2, p1);
			Real d2 = Cross(p2, q2, q1);
			Real d3 = Cross(p1, q1, p2);
			Real d4 = Cross(p1, q1, q2);

			// General case: segments cross
			if (((d1 > EPSILON && d2 < -EPSILON) || (d1 < -EPSILON && d2 > EPSILON)) &&
				((d3 > EPSILON && d4 < -EPSILON) || (d3 < -EPSILON && d4 > EPSILON))) {
				Real dx1 = q1.X() - p1.X();
				Real dy1 = q1.Y() - p1.Y();
				Real dx2 = q2.X() - p2.X();
				Real dy2 = q2.Y() - p2.Y();
				Real dx12 = p2.X() - p1.X();
				Real dy12 = p2.Y() - p1.Y();

				Real denom = dx1 * dy2 - dy1 * dx2;
				Real t = (dx12 * dy2 - dy12 * dx2) / denom;

				result.type = SegmentIntersectionType::Point;
				result.point = Point2Cartesian(p1.X() + t * dx1, p1.Y() + t * dy1);
				return result;
			}

			// Check for collinearity
			bool collinear = (std::abs(d1) <= EPSILON && std::abs(d2) <= EPSILON);

			if (collinear) {
				bool p2_on_seg1 = OnSegment(p1, p2, q1);
				bool q2_on_seg1 = OnSegment(p1, q2, q1);
				bool p1_on_seg2 = OnSegment(p2, p1, q2);
				bool q1_on_seg2 = OnSegment(p2, q1, q2);

				if (p2_on_seg1 || q2_on_seg1 || p1_on_seg2 || q1_on_seg2) {
					std::vector<Point2Cartesian> candidates;
					if (p2_on_seg1) candidates.push_back(p2);
					if (q2_on_seg1) candidates.push_back(q2);
					if (p1_on_seg2) candidates.push_back(p1);
					if (q1_on_seg2) candidates.push_back(q1);

					if (candidates.size() >= 2) {
						std::sort(candidates.begin(), candidates.end(), 
							[&p1, &q1, EPSILON](const Point2Cartesian& a, const Point2Cartesian& b) {
								Real ta = (std::abs(q1.X() - p1.X()) > EPSILON) 
									? (a.X() - p1.X()) / (q1.X() - p1.X())
									: (a.Y() - p1.Y()) / (q1.Y() - p1.Y());
								Real tb = (std::abs(q1.X() - p1.X()) > EPSILON) 
									? (b.X() - p1.X()) / (q1.X() - p1.X())
									: (b.Y() - p1.Y()) / (q1.Y() - p1.Y());
								return ta < tb;
							});

						result.overlapStart = candidates.front();
						result.overlapEnd = candidates.back();

						if (result.overlapStart.Dist(result.overlapEnd) < EPSILON) {
							result.type = SegmentIntersectionType::Point;
							result.point = result.overlapStart;
						} else {
							result.type = SegmentIntersectionType::Overlap;
						}
						return result;
					}
				}
				result.type = SegmentIntersectionType::Collinear;
				return result;
			}

			// Check for endpoint touches
			if (std::abs(d1) <= EPSILON && OnSegment(p2, p1, q2)) {
				result.type = SegmentIntersectionType::Point;
				result.point = p1;
				return result;
			}
			if (std::abs(d2) <= EPSILON && OnSegment(p2, q1, q2)) {
				result.type = SegmentIntersectionType::Point;
				result.point = q1;
				return result;
			}
			if (std::abs(d3) <= EPSILON && OnSegment(p1, p2, q1)) {
				result.type = SegmentIntersectionType::Point;
				result.point = p2;
				return result;
			}
			if (std::abs(d4) <= EPSILON && OnSegment(p1, q2, q1)) {
				result.type = SegmentIntersectionType::Point;
				result.point = q2;
				return result;
			}

			return result; // No intersection
		}

		/// @brief Tests for intersection with another segment (convenience method)
		/// @param other The other segment
		/// @param intersection Optional output parameter for intersection point
		/// @return True if segments intersect (point or overlap)
		bool Intersects(const SegmentLine2D& other, Point2Cartesian* intersection = nullptr) const
		{
			auto result = Intersection(other);
			if (intersection && result.IsPointIntersection())
				*intersection = result.point;
			return result.HasIntersection();
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry2DCore/Geometry2DTriangle.h   ///////////////////////////



namespace MML
{
	/// @brief 2D triangle defined by three vertices
	/// @details Professional 2D triangle class with cached side lengths for efficiency.
	///          Provides comprehensive geometric computations including area (signed and unsigned),
	///          perimeter, centroid, circumcenter, incenter, circumradius, inradius, angles,
	///          point containment tests, and triangle classification (right, isosceles, equilateral).
	class Triangle2D
	{
	private:
		Point2Cartesian _pnt1, _pnt2, _pnt3;
		mutable Real _a, _b, _c; // Cached side lengths
		mutable bool _sidesComputed;

		/// @brief Computes and caches side lengths on demand
		void ComputeSides() const
		{
			if (!_sidesComputed) {
				_a = _pnt1.Dist(_pnt2);
				_b = _pnt2.Dist(_pnt3);
				_c = _pnt3.Dist(_pnt1);
				_sidesComputed = true;
			}
		}

	public:
		/// @brief Constructs a triangle from three vertices
		/// @param pnt1 First vertex
		/// @param pnt2 Second vertex
		/// @param pnt3 Third vertex
		Triangle2D(const Point2Cartesian& pnt1, const Point2Cartesian& pnt2, const Point2Cartesian& pnt3) 
			: _pnt1(pnt1), _pnt2(pnt2), _pnt3(pnt3), _a(0), _b(0), _c(0), _sidesComputed(false)
		{ }

		/// @brief Gets first vertex (const version)
		Point2Cartesian  Pnt1() const { return _pnt1; }
		/// @brief Gets first vertex (mutable reference, invalidates cache)
		Point2Cartesian& Pnt1() { _sidesComputed = false; return _pnt1; }
		/// @brief Gets second vertex (const version)
		Point2Cartesian  Pnt2() const { return _pnt2; }
		/// @brief Gets second vertex (mutable reference, invalidates cache)
		Point2Cartesian& Pnt2() { _sidesComputed = false; return _pnt2; }
		/// @brief Gets third vertex (const version)
		Point2Cartesian  Pnt3() const { return _pnt3; }
		/// @brief Gets third vertex (mutable reference, invalidates cache)
		Point2Cartesian& Pnt3() { _sidesComputed = false; return _pnt3; }

		/// @brief Gets length of side a (P1 to P2)
		Real A() const { ComputeSides(); return _a; }
		/// @brief Gets length of side b (P2 to P3)
		Real B() const { ComputeSides(); return _b; }
		/// @brief Gets length of side c (P3 to P1)
		Real C() const { ComputeSides(); return _c; }

		/// @brief Calculates the perimeter
		Real Perimeter() const { return A() + B() + C(); }

		/// @brief Calculates the area using Heron's formula
		Real Area() const
		{
			Real a = A(), b = B(), c = C();
			Real s = (a + b + c) / 2.0;
			return std::sqrt(s * (s - a) * (s - b) * (s - c));
		}

		/// @brief Calculates the signed area (positive = CCW, negative = CW)
		Real SignedArea() const
		{
			Real area = (_pnt2.X() - _pnt1.X()) * (_pnt3.Y() - _pnt1.Y()) -
			           (_pnt3.X() - _pnt1.X()) * (_pnt2.Y() - _pnt1.Y());
			return area / 2.0;
		}

		/// @brief Calculates the centroid (geometric center)
		/// @return Point at (P1 + P2 + P3) / 3
		Point2Cartesian Centroid() const
		{
			return Point2Cartesian((_pnt1.X() + _pnt2.X() + _pnt3.X()) / 3.0,
			                      (_pnt1.Y() + _pnt2.Y() + _pnt3.Y()) / 3.0);
		}

		/// @brief Calculates the circumcenter (center of circumscribed circle)
		/// @throws GeometryError if triangle is degenerate
		Point2Cartesian Circumcenter() const
		{
			Real D = 2.0 * (_pnt1.X() * (_pnt2.Y() - _pnt3.Y()) +
			               _pnt2.X() * (_pnt3.Y() - _pnt1.Y()) +
			               _pnt3.X() * (_pnt1.Y() - _pnt2.Y()));
			
			if (std::abs(D) < Constants::GEOMETRY_EPSILON)
				throw GeometryError("Triangle2D::Circumcenter - degenerate triangle");
			
			Real p1Sq = _pnt1.X() * _pnt1.X() + _pnt1.Y() * _pnt1.Y();
			Real p2Sq = _pnt2.X() * _pnt2.X() + _pnt2.Y() * _pnt2.Y();
			Real p3Sq = _pnt3.X() * _pnt3.X() + _pnt3.Y() * _pnt3.Y();
			
			Real ux = (p1Sq * (_pnt2.Y() - _pnt3.Y()) +
			          p2Sq * (_pnt3.Y() - _pnt1.Y()) +
			          p3Sq * (_pnt1.Y() - _pnt2.Y())) / D;
			
			Real uy = (p1Sq * (_pnt3.X() - _pnt2.X()) +
			          p2Sq * (_pnt1.X() - _pnt3.X()) +
			          p3Sq * (_pnt2.X() - _pnt1.X())) / D;
			
			return Point2Cartesian(ux, uy);
		}

		/// @brief Calculates the circumradius (radius of circumscribed circle)
		/// @throws GeometryError if triangle is degenerate
		Real CircumRadius() const
		{
			Real a = A(), b = B(), c = C();
			Real area = Area();
			
			if (area < Constants::GEOMETRY_EPSILON)
				throw GeometryError("Triangle2D::CircumRadius - degenerate triangle");
			
			return (a * b * c) / (4.0 * area);
		}

		/// @brief Calculates the incenter (center of inscribed circle)
		/// @throws GeometryError if triangle is degenerate
		Point2Cartesian Incenter() const
		{
			Real a = A(), b = B(), c = C();
			Real perimeter = a + b + c;
			
			if (perimeter < Constants::GEOMETRY_EPSILON)
				throw GeometryError("Triangle2D::Incenter - degenerate triangle");
			
			Real x = (a * _pnt3.X() + b * _pnt1.X() + c * _pnt2.X()) / perimeter;
			Real y = (a * _pnt3.Y() + b * _pnt1.Y() + c * _pnt2.Y()) / perimeter;
			
			return Point2Cartesian(x, y);
		}

		/// @brief Calculates the inradius (radius of inscribed circle)
		/// @throws GeometryError if triangle is degenerate
		Real InRadius() const
		{
			Real area = Area();
			Real s = Perimeter() / 2.0;
			
			if (s < Constants::GEOMETRY_EPSILON)
				throw GeometryError("Triangle2D::InRadius - degenerate triangle");
			
			return area / s;
		}

		/// @brief Calculates angle A at vertex 3 (opposite to side a) in radians
		Real AngleA() const
		{
			Real a = A(), b = B(), c = C();
			// Law of cosines: a² = b² + c² - 2bc·cos(A)
			Real cosA = (b * b + c * c - a * a) / (2.0 * b * c);
			return std::acos(std::clamp(cosA, REAL(-1.0), REAL(1.0)));
		}

		/// @brief Calculates angle B at vertex 1 (opposite to side b) in radians
		Real AngleB() const
		{
			Real a = A(), b = B(), c = C();
			Real cosB = (a * a + c * c - b * b) / (2.0 * a * c);
			return std::acos(std::clamp(cosB, REAL(-1.0), REAL(1.0)));
		}

		/// @brief Calculates angle C at vertex 2 (opposite to side c) in radians
		Real AngleC() const
		{
			Real a = A(), b = B(), c = C();
			Real cosC = (a * a + b * b - c * c) / (2.0 * a * b);
			return std::acos(std::clamp(cosC, REAL(-1.0), REAL(1.0)));
		}

		/// @brief Tests if a point is inside the triangle using barycentric coordinates
		/// @param p The point to test
		/// @param epsilon Tolerance for boundary cases
		/// @return True if point is inside or on the boundary
		bool Contains(const Point2Cartesian& p, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			// Compute barycentric coordinates
			Real denom = (_pnt2.Y() - _pnt3.Y()) * (_pnt1.X() - _pnt3.X()) +
			            (_pnt3.X() - _pnt2.X()) * (_pnt1.Y() - _pnt3.Y());
			
			if (std::abs(denom) < epsilon)
				return false; // Degenerate triangle
			
			Real a = ((_pnt2.Y() - _pnt3.Y()) * (p.X() - _pnt3.X()) +
			         (_pnt3.X() - _pnt2.X()) * (p.Y() - _pnt3.Y())) / denom;
			
			Real b = ((_pnt3.Y() - _pnt1.Y()) * (p.X() - _pnt3.X()) +
			         (_pnt1.X() - _pnt3.X()) * (p.Y() - _pnt3.Y())) / denom;
			
			Real c = 1.0 - a - b;
			
			// Point is inside if all barycentric coordinates are non-negative
			return (a >= -epsilon) && (b >= -epsilon) && (c >= -epsilon);
		}

		/// @brief Tests if the triangle is a right triangle
		/// @param epsilon Tolerance for the test
		bool IsRight(Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			Real a = A(), b = B(), c = C();
			Real aSq = a * a, bSq = b * b, cSq = c * c;
			
			return AreEqual(aSq + bSq, cSq, epsilon) ||
			       AreEqual(aSq + cSq, bSq, epsilon) ||
			       AreEqual(bSq + cSq, aSq, epsilon);
		}

		/// @brief Tests if the triangle is isosceles (at least two equal sides)
		/// @param epsilon Tolerance for the test
		bool IsIsosceles(Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			Real a = A(), b = B(), c = C();
			return AreEqual(a, b, epsilon) || AreEqual(a, c, epsilon) || AreEqual(b, c, epsilon);
		}

		/// @brief Tests if the triangle is equilateral (all sides equal)
		/// @param epsilon Tolerance for the test
		bool IsEquilateral(Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			Real a = A(), b = B(), c = C();
			return AreEqual(a, b, epsilon) && AreEqual(a, c, epsilon);
		}

		/// @brief Tests if vertices are ordered counter-clockwise
		bool IsCounterClockwise() const
		{
			return SignedArea() > 0.0;
		}

		/// @brief Tests if vertices are ordered clockwise
		bool IsClockwise() const
		{
			return SignedArea() < 0.0;
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry2DCore/Geometry2DPolygon.h   ///////////////////////////



namespace MML
{
	/// @brief 2D polygon defined by an ordered sequence of vertices
	/// @details Professional computational geometry polygon class supporting
	///          simple and convex polygons. Provides comprehensive operations
	///          including area (shoelace formula), centroid, bounding box,
	///          point containment (ray casting and winding number), convexity test,
	///          simplicity test, and basic triangularization.
	class Polygon2D
	{
	private:
		std::vector<Point2Cartesian> _vertices;

		/// @brief Helper for segment intersection test (proper intersection only)
		static bool SegmentsIntersect(const Point2Cartesian& p1, const Point2Cartesian& p2,
		                              const Point2Cartesian& p3, const Point2Cartesian& p4)
		{
			auto sign = [](Real val) { return (val > 0) - (val < 0); };
			
			// Compute cross products for orientation tests
			Real d1 = (p3.X() - p1.X()) * (p2.Y() - p1.Y()) - (p3.Y() - p1.Y()) * (p2.X() - p1.X());
			Real d2 = (p4.X() - p1.X()) * (p2.Y() - p1.Y()) - (p4.Y() - p1.Y()) * (p2.X() - p1.X());
			Real d3 = (p1.X() - p3.X()) * (p4.Y() - p3.Y()) - (p1.Y() - p3.Y()) * (p4.X() - p3.X());
			Real d4 = (p2.X() - p3.X()) * (p4.Y() - p3.Y()) - (p2.Y() - p3.Y()) * (p4.X() - p3.X());
			
			// Check if segments straddle each other
			if (sign(d1) * sign(d2) < 0 && sign(d3) * sign(d4) < 0)
				return true;
			
			return false;
		}

	public:
		/// @brief Default constructor - creates empty polygon
		Polygon2D() {}
		
		/// @brief Constructs polygon from vector of vertices
		/// @param vertices The vertices in order
		Polygon2D(const std::vector<Point2Cartesian>& vertices) : _vertices(vertices) {}
		
		/// @brief Constructs polygon from initializer list
		/// @param list The vertices in order
		Polygon2D(std::initializer_list<Point2Cartesian> list) : _vertices(list) {}

		/// @brief Gets the number of vertices
		int NumVertices() const { return static_cast<int>(_vertices.size()); }
		
		/// @brief Gets const reference to vertices vector
		const std::vector<Point2Cartesian>& Vertices() const { return _vertices; }
		/// @brief Gets mutable reference to vertices vector
		std::vector<Point2Cartesian>& Vertices() { return _vertices; }
		
		/// @brief Index operator for vertex access (const)
		const Point2Cartesian& operator[](int i) const { return _vertices[i]; }
		/// @brief Index operator for vertex access (mutable)
		Point2Cartesian& operator[](int i) { return _vertices[i]; }
		
		/// @brief Gets vertex by index with bounds checking
		/// @throws VectorAccessBoundsError if index out of range
		const Point2Cartesian& Vertex(int i) const { 
			if (i < 0 || i >= NumVertices())
				throw VectorAccessBoundsError("Polygon2D::Vertex - index out of range", i, NumVertices());
			return _vertices[i]; 
		}
		
		/// @brief Adds a vertex to the polygon
		void AddVertex(const Point2Cartesian& p) { _vertices.push_back(p); }
		
		/// @brief Removes all vertices
		void Clear() { _vertices.clear(); }

		/// @brief Gets edge as a segment
		/// @param i Edge index (0 to NumVertices-1)
		/// @throws VectorAccessBoundsError if index out of range
		SegmentLine2D Edge(int i) const {
			if (i < 0 || i >= NumVertices())
				throw VectorAccessBoundsError("Polygon2D::Edge - index out of range", i, NumVertices());
			return SegmentLine2D(_vertices[i], _vertices[(i + 1) % NumVertices()]);
		}

		/// @brief Calculates the perimeter
		Real Perimeter() const {
			if (NumVertices() < 2) return 0.0;
			
			Real perimeter = 0.0;
			int n = NumVertices();
			for (int i = 0; i < n; i++) {
				perimeter += _vertices[i].Dist(_vertices[(i + 1) % n]);
			}
			return perimeter;
		}

		/// @brief Calculates the signed area using shoelace formula
		/// @return Positive for CCW, negative for CW orientation
		Real SignedArea() const {
			if (NumVertices() < 3) return 0.0;
			
			Real area = 0.0;
			int n = NumVertices();
			for (int i = 0; i < n; i++) {
				area += _vertices[i].X() * _vertices[(i + 1) % n].Y();
				area -= _vertices[i].Y() * _vertices[(i + 1) % n].X();
			}
			return area / 2.0;
		}

		/// @brief Calculates the unsigned area
		Real Area() const {
			return std::abs(SignedArea());
		}

		/// @brief Calculates the centroid (geometric center)
		/// @throws GeometryError if polygon is empty or degenerate
		Point2Cartesian Centroid() const {
			if (NumVertices() == 0)
				throw GeometryError("Polygon2D::Centroid - empty polygon");
			
			if (NumVertices() == 1)
				return _vertices[0];
			
			if (NumVertices() == 2)
				return Point2Cartesian((_vertices[0].X() + _vertices[1].X()) / 2.0,
				                      (_vertices[0].Y() + _vertices[1].Y()) / 2.0);
			
			// For polygons with 3+ vertices, use area-weighted formula
			Real cx = 0.0, cy = 0.0;
			Real signedArea = 0.0;
			int n = NumVertices();
			
			for (int i = 0; i < n; i++) {
				int j = (i + 1) % n;
				Real cross = _vertices[i].X() * _vertices[j].Y() - _vertices[j].X() * _vertices[i].Y();
				signedArea += cross;
				cx += (_vertices[i].X() + _vertices[j].X()) * cross;
				cy += (_vertices[i].Y() + _vertices[j].Y()) * cross;
			}
			
			signedArea /= 2.0;
			if (std::abs(signedArea) < Constants::GEOMETRY_EPSILON)
				throw GeometryError("Polygon2D::Centroid - degenerate polygon (zero area)");
			
			cx /= (6.0 * signedArea);
			cy /= (6.0 * signedArea);
			
			return Point2Cartesian(cx, cy);
		}

		/// @brief Axis-aligned bounding box structure
		struct BoundingBox {
			Real minX, maxX, minY, maxY;
			
			/// @brief Gets the width of the bounding box
			Real Width() const { return maxX - minX; }
			/// @brief Gets the height of the bounding box
			Real Height() const { return maxY - minY; }
			/// @brief Gets the center of the bounding box
			Point2Cartesian Center() const { return Point2Cartesian((minX + maxX) / 2.0, (minY + maxY) / 2.0); }
		};
		
		/// @brief Computes the axis-aligned bounding box
		/// @throws GeometryError if polygon is empty
		BoundingBox GetBoundingBox() const {
			if (NumVertices() == 0)
				throw GeometryError("Polygon2D::GetBoundingBox - empty polygon");
			
			BoundingBox box;
			box.minX = box.maxX = _vertices[0].X();
			box.minY = box.maxY = _vertices[0].Y();
			
			for (int i = 1; i < NumVertices(); i++) {
				box.minX = std::min(box.minX, _vertices[i].X());
				box.maxX = std::max(box.maxX, _vertices[i].X());
				box.minY = std::min(box.minY, _vertices[i].Y());
				box.maxY = std::max(box.maxY, _vertices[i].Y());
			}
			
			return box;
		}

		/// @brief Tests if vertices are ordered counter-clockwise
		bool IsCounterClockwise() const {
			return SignedArea() > 0.0;
		}
		
		/// @brief Tests if vertices are ordered clockwise
		bool IsClockwise() const {
			return SignedArea() < 0.0;
		}

		/// @brief Reverses the vertex order
		void Reverse() {
			std::reverse(_vertices.begin(), _vertices.end());
		}

		/// @brief Tests if the polygon is simple (no self-intersections)
		bool IsSimple() const {
			int n = NumVertices();
			if (n < 3) return false;
			
			// Check all non-adjacent edge pairs for intersections
			for (int i = 0; i < n; i++) {
				Point2Cartesian p1 = _vertices[i];
				Point2Cartesian p2 = _vertices[(i + 1) % n];
				
				// Check against non-adjacent edges
				for (int j = i + 2; j < n; j++) {
					// Skip if edges are adjacent (share a vertex)
					if (j == (i + n - 1) % n) continue;
					
					Point2Cartesian p3 = _vertices[j];
					Point2Cartesian p4 = _vertices[(j + 1) % n];
					
					if (SegmentsIntersect(p1, p2, p3, p4))
						return false;
				}
			}
			
			return true;
		}

		/// @brief Tests if the polygon is convex
		bool IsConvex() const {
			int n = NumVertices();
			if (n < 3) return false;
			
			bool hasPositive = false;
			bool hasNegative = false;
			
			for (int i = 0; i < n; i++) {
				Point2Cartesian p0 = _vertices[i];
				Point2Cartesian p1 = _vertices[(i + 1) % n];
				Point2Cartesian p2 = _vertices[(i + 2) % n];
				
				// Compute cross product of edges (p0->p1) and (p1->p2)
				Vector2Cartesian v1(p0, p1);
				Vector2Cartesian v2(p1, p2);
				Real cross = v1.X() * v2.Y() - v1.Y() * v2.X();
				
				if (cross > Constants::GEOMETRY_EPSILON) hasPositive = true;
				if (cross < -Constants::GEOMETRY_EPSILON) hasNegative = true;
				
				// If we have both signs, polygon is not convex
				if (hasPositive && hasNegative)
					return false;
			}
			
			return true;
		}

		/// @brief Tests if a point is inside the polygon using ray-casting
		/// @details Works for simple polygons (both convex and non-convex)
		/// @param point The point to test
		/// @return True if point is inside the polygon
		bool Contains(const Point2Cartesian& point) const {
			int n = NumVertices();
			if (n < 3) return false;
			
			// Ray casting: count intersections of horizontal ray from point to the right
			int intersections = 0;
			
			for (int i = 0; i < n; i++) {
				Point2Cartesian p1 = _vertices[i];
				Point2Cartesian p2 = _vertices[(i + 1) % n];
				
				// Check if ray intersects edge
				if ((p1.Y() > point.Y()) != (p2.Y() > point.Y())) {
					// Compute x-coordinate of intersection
					Real xIntersect = p1.X() + (point.Y() - p1.Y()) * (p2.X() - p1.X()) / (p2.Y() - p1.Y());
					
					if (point.X() < xIntersect)
						intersections++;
				}
			}
			
			// Odd number of intersections = inside
			return (intersections % 2) == 1;
		}

		/// @brief Computes the winding number for a point
		/// @details More robust than ray-casting for complex polygons
		/// @param point The point to test
		/// @return Winding number (non-zero means inside)
		int WindingNumber(const Point2Cartesian& point) const {
			int n = NumVertices();
			if (n < 3) return 0;
			
			int wn = 0; // winding number counter
			
			for (int i = 0; i < n; i++) {
				Point2Cartesian p1 = _vertices[i];
				Point2Cartesian p2 = _vertices[(i + 1) % n];
				
				if (p1.Y() <= point.Y()) {
					if (p2.Y() > point.Y()) {
						// Upward crossing
						Real cross = (p2.X() - p1.X()) * (point.Y() - p1.Y()) - (point.X() - p1.X()) * (p2.Y() - p1.Y());
						if (cross > 0) {
							wn++; // Point is left of edge
						}
					}
				} else {
					if (p2.Y() <= point.Y()) {
						// Downward crossing
						Real cross = (p2.X() - p1.X()) * (point.Y() - p1.Y()) - (point.X() - p1.X()) * (p2.Y() - p1.Y());
						if (cross < 0) {
							wn--; // Point is right of edge
						}
					}
				}
			}
			
			return wn;
		}

		/// @brief Decomposes polygon into triangles
		/// @details Uses fan triangulation (works correctly for convex polygons)
		/// @return Vector of triangles covering the polygon
		std::vector<Triangle2D> Triangularization() const {
			std::vector<Triangle2D> triangles;
			int n = NumVertices();
			
			if (n < 3) return triangles;
			if (n == 3) {
				triangles.push_back(Triangle2D(_vertices[0], _vertices[1], _vertices[2]));
				return triangles;
			}
			
			// Simple fan triangulation from first vertex (works for convex polygons)
			// For non-convex, this is a placeholder - full ear clipping would be more complex
			for (int i = 1; i < n - 1; i++) {
				triangles.push_back(Triangle2D(_vertices[0], _vertices[i], _vertices[i + 1]));
			}
			
			return triangles;
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry2DCore/Geometry2DCircleBox.h   ///////////////////////////



namespace MML
{
	/// @brief Circle positioned in 2D space with center and radius
	/// @details Provides comprehensive circle operations including point containment,
	///          closest point, tangent vectors, arc/sector calculations, and
	///          intersection tests with other circles and lines.
	class Circle2D
	{
	private:
		Point2Cartesian _center;
		Real _radius;

	public:
		/// @brief Default constructor - unit circle at origin
		Circle2D() : _center(0, 0), _radius(1) {}
		/// @brief Constructs a circle from center point and radius
		/// @param center Center point
		/// @param radius Radius (must be non-negative)
		/// @throws GeometryError if radius is negative
		Circle2D(const Point2Cartesian& center, Real radius) : _center(center), _radius(radius)
		{
			if (radius < 0)
				throw GeometryError("Circle2D - radius must be non-negative");
		}
		/// @brief Constructs a circle from center coordinates and radius
		/// @param centerX Center x-coordinate
		/// @param centerY Center y-coordinate
		/// @param radius Radius (must be non-negative)
		/// @throws GeometryError if radius is negative
		Circle2D(Real centerX, Real centerY, Real radius) : _center(centerX, centerY), _radius(radius)
		{
			if (radius < 0)
				throw GeometryError("Circle2D - radius must be non-negative");
		}

		/// @brief Creates a circle from two diameter endpoints
		static Circle2D FromDiameter(const Point2Cartesian& p1, const Point2Cartesian& p2)
		{
			Point2Cartesian center((p1.X() + p2.X()) / 2, (p1.Y() + p2.Y()) / 2);
			Real radius = p1.Dist(p2) / 2;
			return Circle2D(center, radius);
		}

		/// @brief Creates the circumcircle of three points
		static Circle2D FromThreePoints(const Point2Cartesian& p1, const Point2Cartesian& p2, const Point2Cartesian& p3)
		{
			// Circumcircle of triangle
			Triangle2D tri(p1, p2, p3);
			return Circle2D(tri.Circumcenter(), tri.CircumRadius());
		}

		/// @brief Creates a unit circle centered at origin
		static Circle2D UnitCircle() { return Circle2D(Point2Cartesian(0, 0), 1); }

		/// @brief Gets the center (const version)
		Point2Cartesian  Center() const { return _center; }
		/// @brief Gets the center (mutable reference)
		Point2Cartesian& Center() { return _center; }
		/// @brief Gets the radius (const version)
		Real  Radius() const { return _radius; }
		/// @brief Gets the radius (mutable reference)
		Real& Radius() { return _radius; }
		/// @brief Gets the diameter
		Real  Diameter() const { return 2 * _radius; }

		/// @brief Calculates the area
		Real Area() const { return Constants::PI * _radius * _radius; }
		/// @brief Calculates the circumference
		Real Circumference() const { return 2 * Constants::PI * _radius; }
		/// @brief Alias for Circumference()
		Real Perimeter() const { return Circumference(); }

		/// @brief Gets the point on the circle at angle theta
		/// @param theta Angle from positive x-axis (in radians)
		Point2Cartesian PointAt(Real theta) const
		{
			return Point2Cartesian(_center.X() + _radius * std::cos(theta),
			                       _center.Y() + _radius * std::sin(theta));
		}

		/// @brief Calculates arc length for given central angle
		/// @param theta Central angle in radians
		Real ArcLength(Real theta) const { return _radius * std::abs(theta); }

		/// @brief Calculates sector area for given central angle
		/// @param theta Central angle in radians
		Real SectorArea(Real theta) const { return 0.5 * _radius * _radius * std::abs(theta); }

		/// @brief Calculates chord length for given central angle
		/// @param theta Central angle in radians
		Real ChordLength(Real theta) const { return 2 * _radius * std::sin(std::abs(theta) / 2); }

		/// @brief Gets distance from center to a point
		Real DistanceFromCenter(const Point2Cartesian& p) const { return _center.Dist(p); }

		/// @brief Gets signed distance from circle boundary to point
		/// @return Negative if inside, positive if outside
		Real SignedDistance(const Point2Cartesian& p) const { return DistanceFromCenter(p) - _radius; }
		/// @brief Gets absolute distance from circle boundary to point
		Real DistanceToPoint(const Point2Cartesian& p) const { return std::abs(SignedDistance(p)); }

		/// @brief Tests if a point is inside or on the circle
		/// @param p The point to test
		/// @param epsilon Tolerance for boundary cases
		bool Contains(const Point2Cartesian& p, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return DistanceFromCenter(p) <= _radius + epsilon;
		}

		/// @brief Tests if a point is on the circle boundary
		/// @param p The point to test
		/// @param epsilon Tolerance for the test
		bool IsOnBoundary(const Point2Cartesian& p, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return std::abs(DistanceFromCenter(p) - _radius) < epsilon;
		}

		/// @brief Finds the closest point on the circle to a given point
		/// @param p The point
		/// @return Point on circle closest to p
		Point2Cartesian ClosestPoint(const Point2Cartesian& p) const
		{
			Real dist = DistanceFromCenter(p);
			if (dist < Constants::GEOMETRY_EPSILON)
			{
				// Point at center - return arbitrary point on circle
				return PointAt(0);
			}
			// Scale vector from center to point to radius length
			Real scale = _radius / dist;
			return Point2Cartesian(_center.X() + scale * (p.X() - _center.X()),
			                       _center.Y() + scale * (p.Y() - _center.Y()));
		}

		/// @brief Gets the tangent vector at angle theta
		/// @param theta Angle in radians
		/// @return Unit tangent vector (perpendicular to radius)
		Vector2Cartesian TangentAt(Real theta) const
		{
			return Vector2Cartesian(-std::sin(theta), std::cos(theta));
		}

		/// @brief Tests for intersection with another circle
		bool Intersects(const Circle2D& other) const
		{
			Real d = _center.Dist(other._center);
			return d <= _radius + other._radius && d >= std::abs(_radius - other._radius);
		}

		/// @brief Tests for intersection with a line
		bool Intersects(const Line2D& line) const
		{
			return line.DistanceToPoint(_center) <= _radius;
		}

		/// @brief Gets the axis-aligned bounding box
		Polygon2D::BoundingBox GetBoundingBox() const
		{
			Polygon2D::BoundingBox box;
			box.minX = _center.X() - _radius;
			box.maxX = _center.X() + _radius;
			box.minY = _center.Y() - _radius;
			box.maxY = _center.Y() + _radius;
			return box;
		}

		/// @brief Creates a translated copy of the circle
		/// @param v Translation vector
		Circle2D Translated(const Vector2Cartesian& v) const
		{
			return Circle2D(_center + v, _radius);
		}

		/// @brief Creates a scaled copy of the circle (from center)
		/// @param factor Scale factor (must be positive)
		/// @throws GeometryError if factor is not positive
		Circle2D Scaled(Real factor) const
		{
			if (factor <= 0)
				throw GeometryError("Circle2D::Scaled - factor must be positive");
			return Circle2D(_center, _radius * factor);
		}
	};

	/// @brief 2D axis-aligned bounding box (AABB)
	/// @details Represents a rectangular region aligned with the coordinate axes.
	///          Provides comprehensive operations including point/box containment,
	///          distance calculations, intersection/union, and transformation methods.
	class Box2D
	{
	private:
		Point2Cartesian _min;  // Bottom-left corner
		Point2Cartesian _max;  // Top-right corner

	public:
		/// @brief Default constructor - unit box from (0,0) to (1,1)
		Box2D() : _min(0, 0), _max(1, 1) {}
		
		/// @brief Constructs a box from corner points
		/// @param min Bottom-left corner
		/// @param max Top-right corner
		Box2D(const Point2Cartesian& min, const Point2Cartesian& max) : _min(min), _max(max)
		{
			Normalize();
		}
		
		/// @brief Constructs a box from coordinates
		/// @param minX Minimum x-coordinate
		/// @param minY Minimum y-coordinate
		/// @param maxX Maximum x-coordinate
		/// @param maxY Maximum y-coordinate
		Box2D(Real minX, Real minY, Real maxX, Real maxY) : _min(minX, minY), _max(maxX, maxY)
		{
			Normalize();
		}

		/// @brief Creates a box from center and dimensions
		static Box2D FromCenterAndSize(const Point2Cartesian& center, Real width, Real height)
		{
			Real halfW = width / 2;
			Real halfH = height / 2;
			return Box2D(center.X() - halfW, center.Y() - halfH,
			            center.X() + halfW, center.Y() + halfH);
		}

		/// @brief Creates a box from center and half-extents
		static Box2D FromCenterAndHalfExtents(const Point2Cartesian& center, Real halfWidth, Real halfHeight)
		{
			return Box2D(center.X() - halfWidth, center.Y() - halfHeight,
			            center.X() + halfWidth, center.Y() + halfHeight);
		}

		/// @brief Creates a bounding box for a set of points
		/// @throws GeometryError if points vector is empty
		static Box2D FromPoints(const std::vector<Point2Cartesian>& points)
		{
			if (points.empty())
				throw GeometryError("Box2D::FromPoints - empty point set");
			
			Real minX = points[0].X(), maxX = points[0].X();
			Real minY = points[0].Y(), maxY = points[0].Y();
			
			for (size_t i = 1; i < points.size(); ++i)
			{
				minX = std::min(minX, points[i].X());
				maxX = std::max(maxX, points[i].X());
				minY = std::min(minY, points[i].Y());
				maxY = std::max(maxY, points[i].Y());
			}
			
			return Box2D(minX, minY, maxX, maxY);
		}

		/// @brief Creates a unit box from (0,0) to (1,1)
		static Box2D UnitBox() { return Box2D(0, 0, 1, 1); }

		/// @brief Ensures min <= max for all coordinates
		void Normalize()
		{
			if (_min.X() > _max.X()) std::swap(_min.X(), _max.X());
			if (_min.Y() > _max.Y()) std::swap(_min.Y(), _max.Y());
		}

		/// @brief Gets the minimum corner (const version)
		Point2Cartesian  Min() const { return _min; }
		/// @brief Gets the minimum corner (mutable reference)
		Point2Cartesian& Min() { return _min; }
		/// @brief Gets the maximum corner (const version)
		Point2Cartesian  Max() const { return _max; }
		/// @brief Gets the maximum corner (mutable reference)
		Point2Cartesian& Max() { return _max; }

		/// @brief Gets the minimum x-coordinate
		Real MinX() const { return _min.X(); }
		/// @brief Gets the minimum y-coordinate
		Real MinY() const { return _min.Y(); }
		/// @brief Gets the maximum x-coordinate
		Real MaxX() const { return _max.X(); }
		/// @brief Gets the maximum y-coordinate
		Real MaxY() const { return _max.Y(); }

		/// @brief Gets the width
		Real Width() const { return _max.X() - _min.X(); }
		/// @brief Gets the height
		Real Height() const { return _max.Y() - _min.Y(); }
		/// @brief Gets the size as a vector
		Vector2Cartesian Size() const { return Vector2Cartesian(Width(), Height()); }
		/// @brief Gets the half-extents
		Vector2Cartesian HalfExtents() const { return Vector2Cartesian(Width() / 2, Height() / 2); }
		/// @brief Gets the diagonal length
		Real Diagonal() const { return std::sqrt(Width() * Width() + Height() * Height()); }
		/// @brief Gets the aspect ratio (width/height)
		Real AspectRatio() const { return Width() / Height(); }

		/// @brief Calculates the area
		Real Area() const { return Width() * Height(); }
		/// @brief Calculates the perimeter
		Real Perimeter() const { return 2 * (Width() + Height()); }

		/// @brief Gets the center point
		Point2Cartesian Center() const
		{
			return Point2Cartesian((_min.X() + _max.X()) / 2, (_min.Y() + _max.Y()) / 2);
		}

		/// @brief Gets the bottom-left corner
		Point2Cartesian BottomLeft() const { return _min; }
		/// @brief Gets the bottom-right corner
		Point2Cartesian BottomRight() const { return Point2Cartesian(_max.X(), _min.Y()); }
		/// @brief Gets the top-left corner
		Point2Cartesian TopLeft() const { return Point2Cartesian(_min.X(), _max.Y()); }
		/// @brief Gets the top-right corner
		Point2Cartesian TopRight() const { return _max; }

		/// @brief Gets all four corners as a vector
		std::vector<Point2Cartesian> Corners() const
		{
			return { BottomLeft(), BottomRight(), TopRight(), TopLeft() };
		}

		/// @brief Converts to a polygon
		Polygon2D ToPolygon() const
		{
			return Polygon2D({ BottomLeft(), BottomRight(), TopRight(), TopLeft() });
		}

		/// @brief Tests if a point is inside the box
		/// @param p The point to test
		/// @param epsilon Tolerance for boundary cases
		bool Contains(const Point2Cartesian& p, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return p.X() >= _min.X() - epsilon && p.X() <= _max.X() + epsilon &&
			       p.Y() >= _min.Y() - epsilon && p.Y() <= _max.Y() + epsilon;
		}

		/// @brief Tests if another box is fully contained within this box
		/// @param other The box to test
		/// @param epsilon Tolerance for boundary cases
		bool Contains(const Box2D& other, Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return other._min.X() >= _min.X() - epsilon && other._max.X() <= _max.X() + epsilon &&
			       other._min.Y() >= _min.Y() - epsilon && other._max.Y() <= _max.Y() + epsilon;
		}

		/// @brief Calculates distance from point to box
		/// @param p The point
		/// @return Distance (0 if inside)
		Real DistanceToPoint(const Point2Cartesian& p) const
		{
			Real dx = std::max({ _min.X() - p.X(), REAL(0.0), p.X() - _max.X() });
			Real dy = std::max({ _min.Y() - p.Y(), REAL(0.0), p.Y() - _max.Y() });
			return std::sqrt(dx * dx + dy * dy);
		}

		/// @brief Finds the closest point on the box boundary to a given point
		/// @param p The point
		/// @return Point on box closest to p
		Point2Cartesian ClosestPoint(const Point2Cartesian& p) const
		{
			return Point2Cartesian(std::clamp(p.X(), _min.X(), _max.X()),
			                       std::clamp(p.Y(), _min.Y(), _max.Y()));
		}

		/// @brief Tests for intersection with another box
		bool Intersects(const Box2D& other) const
		{
			return _min.X() <= other._max.X() && _max.X() >= other._min.X() &&
			       _min.Y() <= other._max.Y() && _max.Y() >= other._min.Y();
		}

		/// @brief Computes the intersection of two boxes
		/// @return Intersection box, or empty box (0,0,0,0) if no intersection
		Box2D Intersection(const Box2D& other) const
		{
			Real minX = std::max(_min.X(), other._min.X());
			Real minY = std::max(_min.Y(), other._min.Y());
			Real maxX = std::min(_max.X(), other._max.X());
			Real maxY = std::min(_max.Y(), other._max.Y());
			
			if (minX > maxX || minY > maxY)
				return Box2D(0, 0, 0, 0);  // Empty box
			
			return Box2D(minX, minY, maxX, maxY);
		}

		/// @brief Computes the union of two boxes
		/// @return Smallest box containing both boxes
		Box2D Union(const Box2D& other) const
		{
			return Box2D(std::min(_min.X(), other._min.X()),
			            std::min(_min.Y(), other._min.Y()),
			            std::max(_max.X(), other._max.X()),
			            std::max(_max.Y(), other._max.Y()));
		}

		/// @brief Expands the box to include a point
		/// @param p The point to include
		void ExpandToInclude(const Point2Cartesian& p)
		{
			_min.X() = std::min(_min.X(), p.X());
			_min.Y() = std::min(_min.Y(), p.Y());
			_max.X() = std::max(_max.X(), p.X());
			_max.Y() = std::max(_max.Y(), p.Y());
		}

		/// @brief Creates a box expanded by a uniform margin
		/// @param margin Expansion amount in all directions
		Box2D Expanded(Real margin) const
		{
			return Box2D(_min.X() - margin, _min.Y() - margin,
			            _max.X() + margin, _max.Y() + margin);
		}

		/// @brief Tests if the box is degenerate (zero area)
		/// @param epsilon Tolerance for the test
		bool IsDegenerate(Real epsilon = Constants::GEOMETRY_EPSILON) const
		{
			return Width() < epsilon || Height() < epsilon;
		}

		/// @brief Creates a translated copy of the box
		/// @param v Translation vector
		Box2D Translated(const Vector2Cartesian& v) const
		{
			return Box2D(_min + v, _max + v);
		}

		/// @brief Creates a scaled copy of the box (from center)
		/// @param factor Scale factor
		Box2D Scaled(Real factor) const
		{
			Point2Cartesian c = Center();
			Vector2Cartesian half = HalfExtents();
			return Box2D::FromCenterAndHalfExtents(c, half.X() * factor, half.Y() * factor);
		}

		/// @brief Tests for intersection with a circle
		bool Intersects(const Circle2D& circle) const
		{
			Point2Cartesian closest = ClosestPoint(circle.Center());
			return circle.Center().Dist(closest) <= circle.Radius();
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DCore/Geometry3DLines.h   ///////////////////////////


namespace MML
{

	// ============================================================================
	// 3D Line Intersection Types
	// ============================================================================

	/// @brief Classification of 3D line-line intersection
	enum class LineIntersectionType3D {
		Point,		///< Lines intersect at a single point
		Parallel,	///< Lines are parallel (no intersection)
		Coincident,	///< Lines are the same (infinite intersections)
		Skew		///< Lines are skew (not parallel but don't intersect)
	};

	/// @brief Result of 3D line-line intersection
	struct LineIntersection3D {
		LineIntersectionType3D type = LineIntersectionType3D::Parallel;
		Point3Cartesian point1;	///< Closest point on first line (also intersection point if intersecting)
		Point3Cartesian point2;	///< Closest point on second line
		Real t1 = 0.0;			///< Parameter on first line
		Real t2 = 0.0;			///< Parameter on second line
		Real distance = 0.0;	///< Distance between closest points (0 if intersecting)

		/// @brief Check if lines intersect at a single point
		bool HasIntersection() const { return type == LineIntersectionType3D::Point; }
		/// @brief Check if intersection is a single point
		bool IsIntersecting() const { return type == LineIntersectionType3D::Point; }
		/// @brief Check if lines are skew (closest approach but no intersection)
		bool AreSkew() const { return type == LineIntersectionType3D::Skew; }
		/// @brief Check if lines are skew
		bool IsSkew() const { return type == LineIntersectionType3D::Skew; }
		/// @brief Check if lines are parallel
		bool IsParallel() const { return type == LineIntersectionType3D::Parallel; }
		/// @brief Check if lines are coincident
		bool IsCoincident() const { return type == LineIntersectionType3D::Coincident; }
		
		/// @brief Get intersection point (alias for point1, valid when IsIntersecting)
		const Point3Cartesian& Point() const { return point1; }
	};

	// ============================================================================
	// 3D Line Primitives
	// ============================================================================

	/// @brief Infinite line in 3D space
	/// @details Represented by a point on the line and a unit direction vector.
	///          Provides operations for point distance, line-line distance,
	///          intersection detection, and perpendicular line construction.
	class Line3D
	{
	private:
		Pnt3Cart  _point;
		Vec3Cart _direction;

	public:
		/// @brief Default constructor
		Line3D() {}
		
		/// @brief Constructs a line from point and direction
		/// @param pnt A point on the line
		/// @param dir Direction vector (will be normalized)
		/// @throws GeometryError if direction is null vector
		Line3D(const Pnt3Cart& pnt, const Vec3Cart dir)
		{
			// check for null vector as direction
			if (dir.X() == 0.0 && dir.Y() == 0.0 && dir.Z() == 0.0)
				throw GeometryError("Line3D ctor - null vector as direction");

			_point = pnt;
			_direction = dir.GetAsUnitVector();
		}
		
		/// @brief Constructs a line through two points
		/// @param a First point
		/// @param b Second point
		/// @throws GeometryError if points are identical
		Line3D(const Pnt3Cart& a, const Pnt3Cart& b)
		{
			// check for same points
			if (a == b)
				throw GeometryError("Line3D ctor - same points");

			Vec3Cart dir(a, b);
			_point = a;
			_direction = dir.GetAsUnitVector();
		}

		/// @brief Gets the reference point on the line (const)
		Pnt3Cart   StartPoint() const { return _point; }
		/// @brief Gets the reference point on the line (mutable)
		Pnt3Cart& StartPoint() { return _point; }

		/// @brief Gets the unit direction vector (const)
		Vec3Cart  Direction() const { return _direction; }
		/// @brief Gets the unit direction vector (mutable)
		Vec3Cart& Direction() { return _direction; }

		/// @brief Gets a point on the line at parameter t
		/// @param t Parameter value (point = startPoint + t * direction)
		Pnt3Cart operator()(Real t) const { return _point + t * _direction; }

		/// @brief Tests if two lines are equal (same geometric line, not just parallel)
		/// @param b The other line
		/// @param eps Tolerance for comparison
		/// @details Two lines are equal if they share the same points (each start point lies
		///          on the other line) AND their directions are either equal or anti-parallel
		///          (opposite directions represent the same geometric line).
		bool AreEqual(const Line3D& b, Real eps = Defaults::Line3DAreEqualTolerance) const
		{
			if (!IsPointOnLine(b.StartPoint()) || !b.IsPointOnLine(StartPoint()))
				return false;
			
			// Check if directions are equal OR anti-parallel (same line, opposite direction)
			Vec3Cart negDir = -b.Direction();
			return Direction().IsEqualTo(b.Direction(), eps) || Direction().IsEqualTo(negDir, eps);
		}
		
		/// @brief Equality operator
		bool operator==(const Line3D& b) const
		{
			return AreEqual(b, Defaults::Line3DAreEqualTolerance);
		}

		/// @brief Tests if this line is perpendicular to another line
		bool IsPerpendicular(const Line3D& b, Real eps = Defaults::Line3DIsPerpendicularTolerance) const
		{
			return ScalarProduct(Direction(), b.Direction()) < eps;
		}
		
		/// @brief Tests if this line is parallel to another line
		/// @details Two lines are parallel if their directions are either equal or anti-parallel
		bool IsParallel(const Line3D& b, Real eps = Defaults::Line3DIsParallelTolerance) const
		{
			Vec3Cart negDir = -b.Direction();
			return Direction().IsEqualTo(b.Direction(), eps) || Direction().IsEqualTo(negDir, eps);
		}

		/// @brief Tests if a point lies on this line
		/// @param pnt The point to test
		/// @param eps Tolerance for the test
		bool IsPointOnLine(const Pnt3Cart& pnt, Real eps = Defaults::Line3DIsPointOnLineTolerance) const
		{
			if (pnt == StartPoint())
				return true;	// point is start point of line

			// check if point is on line by checking if the vector from start point to point is parallel OR anti-parallel to direction vector
			// A line extends infinitely in both directions, so we use cross product which is zero for both parallel and anti-parallel vectors
			Vec3Cart vecFromStartToPnt(_point, pnt);
			Vec3Cart crossProd = VectorProduct(vecFromStartToPnt, _direction);
			return crossProd.NormL2() < eps;
		}

		/// @brief Calculates the distance from a point to this line
		/// @param pnt The point
		/// @return Perpendicular distance from point to line
		Real Dist(const Pnt3Cart& pnt) const
		{
			// Bronshtein 3.394
			const Real a = pnt.X();
			const Real b = pnt.Y();
			const Real c = pnt.Z();

			const Real x1 = StartPoint().X();
			const Real y1 = StartPoint().Y();
			const Real z1 = StartPoint().Z();

			const Real l = Direction().X();
			const Real m = Direction().Y();
			const Real n = Direction().Z();

			Real numer = POW2((a - x1) * m - (b - y1) * l) + POW2((b - y1) * n - (c - z1) * m) + POW2((c - z1) * l - (a - x1) * n);
			Real denom = l * l + m * m + n * n;

			return sqrt(numer / denom);
		}
	
		/// @brief Finds the nearest point on this line to a given point
		/// @param pnt The external point
		/// @return Point on line closest to pnt
		Pnt3Cart NearestPointOnLine(const Pnt3Cart& pnt) const
		{
			// https://math.stackexchange.com/questions/1521128/given-a-line-and-a-point-in-3d-how-to-find-the-closest-point-on-the-line         
			Vec3Cart line_dir = this->Direction();
			Vec3Cart rad_vec_AP(StartPoint(), pnt);

			Real t = rad_vec_AP * line_dir / POW2(line_dir.NormL2());

			return StartPoint() + t * line_dir;
		}

		/// @brief Calculates the distance between two lines
		/// @param line The other line
		/// @return Shortest distance between the lines (0 if they intersect)
		Real Dist(const Line3D& line) const
		{
			// https://math.stackexchange.com/questions/2213165/distance-between-two-lines-in-3d-space
			// https://en.wikipedia.org/wiki/Skew_lines#Nearest_points
			Pnt3Cart  p1 = StartPoint();
			Vec3Cart d1 = Direction();
			Pnt3Cart  p2 = line.StartPoint();
			Vec3Cart d2 = line.Direction();

			Vec3Cart n = VectorProduct(d1, d2);

			if (n.isZero())
			{
				// parallel lines
				return Vec3Cart(p1, p2) * d1 / d2.NormL2();
			}
			else
			{
				// skew lines
				return Abs(n * Vec3Cart(p1, p2)) / n.NormL2();
			}
		}
		
		/// @brief Calculates distance between two lines with nearest points
		/// @param line The other line
		/// @param out_dist Output: shortest distance between lines
		/// @param out_line1_pnt Output: nearest point on this line
		/// @param out_line2_pnt Output: nearest point on other line
		/// @return false if lines are parallel (nearest points undefined)
		bool Dist(const Line3D& line, Real& out_dist, Pnt3Cart& out_line1_pnt, Pnt3Cart& out_line2_pnt) const
		{
			// https://math.stackexchange.com/questions/2213165/distance-between-two-lines-in-3d-space
			// https://en.wikipedia.org/wiki/Skew_lines#Nearest_points
			Pnt3Cart  p1 = StartPoint();
			Vec3Cart d1 = Direction();
			Pnt3Cart  p2 = line.StartPoint();
			Vec3Cart d2 = line.Direction();
			out_dist = 0.0;

			Vec3Cart n = VectorProduct(d1, d2);

			if (n.isZero())				// check for parallel lines
			{
				out_dist = Vec3Cart(p1, p2) * d1 / d2.NormL2();
				return false;
			}
			else
			{
				// skew lines
				out_dist = Abs(n * Vec3Cart(p1, p2)) / n.NormL2();

				Real t1 = (VectorProduct(d2, n) * Vec3Cart(p1, p2)) / POW2(n.NormL2());
				Real t2 = (VectorProduct(d1, n) * Vec3Cart(p1, p2)) / POW2(n.NormL2());

				out_line1_pnt = p1 + t1 * d1;
				out_line2_pnt = p2 + t2 * d2;
			}

			return true;
		}
		
		/// @brief Computes full intersection information with another line
		/// @param line The other line
		/// @return LineIntersection3D with type, closest points, parameters, and distance
		/// @details Handles all cases: intersection, parallel, coincident, skew
		LineIntersection3D Intersection(const Line3D& line) const
		{
			LineIntersection3D result;
			result.distance = 0;

			Pnt3Cart  p1 = StartPoint();
			Vec3Cart d1 = Direction();
			Pnt3Cart  p2 = line.StartPoint();
			Vec3Cart d2 = line.Direction();

			Vec3Cart cross = VectorProduct(d1, d2);
			Real crossMagSq = cross.NormL2() * cross.NormL2();
			Vec3Cart w(p1.X() - p2.X(), p1.Y() - p2.Y(), p1.Z() - p2.Z());

			if (crossMagSq < Constants::GEOMETRY_EPSILON * Constants::GEOMETRY_EPSILON) {
				// Lines are parallel - check if coincident
				Vec3Cart crossW = VectorProduct(d1, w);
				if (crossW.NormL2() < Constants::GEOMETRY_EPSILON)
					result.type = LineIntersectionType3D::Coincident;
				else
					result.type = LineIntersectionType3D::Parallel;
				return result;
			}

			Real a = ScalarProduct(d1, d1);
			Real b = ScalarProduct(d1, d2);
			Real c = ScalarProduct(d2, d2);
			Real d = ScalarProduct(d1, w);
			Real e = ScalarProduct(d2, w);
			Real denom = a * c - b * b;

			Real t1 = (b * e - c * d) / denom;
			Real t2 = (a * e - b * d) / denom;

			result.point1 = Pnt3Cart(p1.X() + t1 * d1.X(), p1.Y() + t1 * d1.Y(), p1.Z() + t1 * d1.Z());
			result.point2 = Pnt3Cart(p2.X() + t2 * d2.X(), p2.Y() + t2 * d2.Y(), p2.Z() + t2 * d2.Z());
			result.t1 = t1;
			result.t2 = t2;
			result.distance = result.point1.Dist(result.point2);

			if (result.distance < Defaults::Line3DIntersectionTolerance) {
				result.type = LineIntersectionType3D::Point;
			} else {
				result.type = LineIntersectionType3D::Skew;
			}
			return result;
		}

		/// @brief Finds the intersection point of two lines (convenience method)
		/// @param line The other line
		/// @param out_inter_pnt Output: intersection point if exists
		/// @return true if lines intersect, false if parallel or skew
		bool Intersects(const Line3D& line, Pnt3Cart& out_inter_pnt) const
		{
			auto result = Intersection(line);
			if (result.HasIntersection()) {
				out_inter_pnt = result.point1;
				return true;
			}
			if (result.IsCoincident()) {
				out_inter_pnt = StartPoint();
				return true;
			}
			return false;
		}

		/// @brief Creates a perpendicular line through a given point
		/// @param pnt The point (must not be on this line)
		/// @return Line perpendicular to this line, passing through pnt
		/// @throws GeometryError if point is on the line
		Line3D PerpendicularLineThroughPoint(const Pnt3Cart& pnt) const
		{
			if (IsPointOnLine(pnt))
				throw GeometryError("Line3D::PerpendicularLineThroughPoint - point is on the line");

			return Line3D(pnt, Vec3Cart(pnt, NearestPointOnLine(pnt)).GetAsUnitVector());
		}
	};

	/// @brief Line segment in 3D space
	/// @details Represents a finite line segment defined by two endpoints.
	///          Provides length, direction, and point-to-segment distance calculations.
	class SegmentLine3D
	{
	private:
		Pnt3Cart _point1;
		Pnt3Cart _point2;

	public:
		/// @brief Constructs a segment from two points
		/// @param pnt1 Start point
		/// @param pnt2 End point
		SegmentLine3D(Pnt3Cart pnt1, Pnt3Cart pnt2) : _point1(pnt1), _point2(pnt2)
		{
		}
		
		/// @brief Constructs a segment from point, direction, and length
		/// @param pnt1 Start point
		/// @param direction Direction vector
		/// @param t Length along direction
		SegmentLine3D(Pnt3Cart pnt1, Vec3Cart direction, Real t)
		{
			_point1 = pnt1;
			_point2 = pnt1 + t * direction;
		}

		/// @brief Gets the start point (const)
		Pnt3Cart   StartPoint() const { return _point1; }
		/// @brief Gets the start point (mutable)
		Pnt3Cart& StartPoint() { return _point1; }

		/// @brief Gets the end point (const)
		Pnt3Cart   EndPoint() const { return _point2; }
		/// @brief Gets the end point (mutable)
		Pnt3Cart& EndPoint() { return _point2; }

		/// @brief Gets a point on the segment at parameter t
		/// @param t Parameter in [0, 1]
		/// @throws GeometryError if t is outside [0, 1]
		Pnt3Cart		operator()(Real t) const
		{
			if (t < 0.0 || t > 1.0)
				throw GeometryError("SegmentLine3D::PointOnSegment - t not in [0,1]");

			return _point1 + t * Direction();
		}

		/// @brief Gets the length of the segment
		Real              Length()    const { return _point1.Dist(_point2); }
		/// @brief Gets the direction vector from start to end
		Vec3Cart  Direction() const { return Vec3Cart(_point1, _point2); }

		/// @brief Calculates the distance from a point to this segment
		/// @param pnt The point
		/// @return Shortest distance from point to segment
		Real Dist(const Pnt3Cart& pnt) const
		{
			Vec3Cart segDir = Direction();
			Real segLength = Length();
			
			if (segLength == 0.0)
				return _point1.Dist(pnt);  // degenerate segment
			
			// Project point onto line containing segment
			Vec3Cart vecToPnt(_point1, pnt);
			Real t = (vecToPnt * segDir) / (segLength * segLength);
			
			// Clamp t to [0, 1] to stay on segment
			if (t < 0.0)
				return _point1.Dist(pnt);  // closest to start point
			else if (t > 1.0)
				return _point2.Dist(pnt);  // closest to end point
			else
			{
				// Closest point is on the segment
				Pnt3Cart closestPoint = _point1 + t * segDir;
				return closestPoint.Dist(pnt);
			}
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DCore/Geometry3DPlane.h   ///////////////////////////


namespace MML
{

	/// @brief Plane in 3D space
	/// @details Represented in general form Ax + By + Cz + D = 0 where (A,B,C) is the unit normal.
	///          Provides multiple construction methods, point/line/plane operations,
	///          distance calculations, and intersection computations.
	class Plane3D
	{
	private:
		Real _A, _B, _C, _D;

	public:
		/// @brief Constructs a plane from a point and normal vector
		/// @param a A point on the plane
		/// @param normal The plane normal (will be normalized)
		/// @throws GeometryError if normal is null vector
		Plane3D(const Pnt3Cart& a, const Vec3Cart& normal)
		{
			if (normal.isZero())
				throw GeometryError("Plane3D ctor - normal is null vector");

			Vec3Cart unitNormal = normal.GetAsUnitVector();

			_A = unitNormal.X();
			_B = unitNormal.Y();
			_C = unitNormal.Z();
			_D = -(a.X() * unitNormal.X() + a.Y() * unitNormal.Y() + a.Z() * unitNormal.Z());
		}
		
		/// @brief Constructs a plane from three points
		/// @param a First point
		/// @param b Second point
		/// @param c Third point
		Plane3D(const Pnt3Cart& a, const Pnt3Cart& b, const Pnt3Cart& c)
			: Plane3D(a, VectorProduct(Vec3Cart(a, b), Vec3Cart(a, c)))
		{
		}
		
		/// @brief Constructs a plane in Hesse normal form
		/// @param alpha Direction cosine angle for x
		/// @param beta Direction cosine angle for y
		/// @param gamma Direction cosine angle for z
		/// @param d Distance from origin
		Plane3D(Real alpha, Real beta, Real gamma, Real d)
		{
			_A = cos(alpha);
			_B = cos(beta);
			_C = cos(gamma);
			_D = -d;
		}
		
		/// @brief Constructs a plane from intercepts on coordinate axes
		/// @param seg_x X-axis intercept
		/// @param seg_y Y-axis intercept
		/// @param seg_z Z-axis intercept
		/// @throws GeometryError if any intercept is zero
		Plane3D(Real seg_x, Real seg_y, Real seg_z)
		{
			if (seg_x == 0 || seg_y == 0 || seg_z == 0)
				throw GeometryError("Plane3D ctor - zero segment");

			_A = 1 / seg_x;
			_B = 1 / seg_y;
			_C = 1 / seg_z;
			_D = -1;
		}

		/// @brief Gets the XY plane (z = 0)
		static Plane3D GetXYPlane() { return Plane3D(Pnt3Cart(0, 0, 0), Vec3Cart(0, 0, 1)); }
		/// @brief Gets the XZ plane (y = 0)
		static Plane3D GetXZPlane() { return Plane3D(Pnt3Cart(0, 0, 0), Vec3Cart(0, 1, 0)); }
		/// @brief Gets the YZ plane (x = 0)
		static Plane3D GetYZPlane() { return Plane3D(Pnt3Cart(0, 0, 0), Vec3Cart(1, 0, 0)); }

		/// @brief Gets coefficient A (const)
		Real  A() const { return _A; }
		/// @brief Gets coefficient A (mutable)
		Real& A() { return _A; }
		/// @brief Gets coefficient B (const)
		Real  B() const { return _B; }
		/// @brief Gets coefficient B (mutable)
		Real& B() { return _B; }
		/// @brief Gets coefficient C (const)
		Real  C() const { return _C; }
		/// @brief Gets coefficient C (mutable)
		Real& C() { return _C; }
		/// @brief Gets coefficient D (const)
		Real  D() const { return _D; }
		/// @brief Gets coefficient D (mutable)
		Real& D() { return _D; }

		/// @brief Gets the unit normal vector
		Vec3Cart	Normal() const { return Vec3Cart(_A, _B, _C); }
		
		/// @brief Gets an arbitrary point on the plane
		Pnt3Cart	GetPointOnPlane() const {
			if (_A != 0.0)
				return Pnt3Cart(-_D / _A, 0, 0);
			else  if (_B != 0.0)
				return Pnt3Cart(0, -_D / _B, 0);
			else
				return Pnt3Cart(0, 0, -_D / _C);
		}

		/// @brief Gets the intercepts on coordinate axes
		/// @param outseg_x Output: X-axis intercept (PosInf if parallel)
		/// @param outseg_y Output: Y-axis intercept (PosInf if parallel)
		/// @param outseg_z Output: Z-axis intercept (PosInf if parallel)
		void GetCoordAxisSegments(Real& outseg_x, Real& outseg_y, Real& outseg_z) const
		{
			if (_A != 0.0)
				outseg_x = -_D / _A;
			else
				outseg_x = Constants::PosInf;

			if (_B != 0.0)
				outseg_y = -_D / _B;
			else
				outseg_y = Constants::PosInf;

			if (_C != 0.0)
				outseg_z = -_D / _C;
			else
				outseg_z = Constants::PosInf;
		}

		/// @brief Tests if a point lies on this plane
		/// @param pnt The point to test
		/// @param defEps Tolerance for the test
		bool IsPointOnPlane(const Pnt3Cart& pnt, Real defEps = Defaults::Plane3DIsPointOnPlaneTolerance) const
		{
			return std::abs(_A * pnt.X() + _B * pnt.Y() + _C * pnt.Z() + _D) < defEps;
		}
		
		/// @brief Calculates the distance from a point to this plane
		Real DistToPoint(const Pnt3Cart& pnt) const
		{
			Real a = _A * pnt.X() + _B * pnt.Y() + _C * pnt.Z() + _D;
			Real b = sqrt(_A * _A + _B * _B + _C * _C);

			return std::abs(a / b);
		}

		/// @brief Projects a point onto this plane
		/// @param pnt The point to project
		/// @return The projected point on the plane
		/// @throws GeometryError if plane normal is zero
		Pnt3Cart ProjectionToPlane(const Pnt3Cart& pnt) const
		{
			// Plane: n·x + D = 0
			// Projection: p_proj = pnt - n * (n·pnt + D) / |n|^2
			Vec3Cart n = Normal();
			
			Real n_norm2 = n.NormL2() * n.NormL2();
			if (n_norm2 == 0.0)
				throw GeometryError("ProjectionToPlane: plane normal is zero vector");

			Real dist = (n * pnt + D()) / n_norm2;
			
			return pnt - n * dist;
		}

		/// @brief Tests if a line lies entirely on this plane
		bool IsLineOnPlane(const Line3D& line) const
		{
			// get two points
			const Pnt3Cart pnt1 = line.StartPoint();
			const Pnt3Cart pnt2 = line(1.0);

			if (IsPointOnPlane(pnt1) && IsPointOnPlane(pnt2))
				return true;
			else
				return false;
		}
		
		/// @brief Calculates the angle between a line and this plane
		/// @return Angle in radians
		Real AngleToLine(const Line3D& line) const
		{
			// angle between line and normal to plane
			return Constants::PI / 2.0 - line.Direction().AngleToVector(this->Normal());
		}
		
		/// @brief Finds the intersection point of a line with this plane
		/// @param line The line
		/// @param out_inter_pnt Output: intersection point if exists
		/// @return false if line is parallel to plane
		bool IntersectionWithLine(const Line3D& line, Pnt3Cart& out_inter_pnt, Real eps = Defaults::Line3DIsParallelTolerance) const
		{
			Vec3Cart line_dir = line.Direction();
			Vec3Cart plane_normal = Normal();

			// Check if the line is parallel to the plane
			Real dot = ScalarProduct(line_dir, plane_normal);
			if (std::abs(dot) < eps) {
				return false;
			}

			// Calculate the distance between the point on the line and the plane
			double t = -(plane_normal * line.StartPoint() + D()) / dot;
			Pnt3Cart inter_pnt = line.StartPoint() + line_dir * t;
			out_inter_pnt = inter_pnt;
			
			return true;
		}

		/// @brief Tests if this plane is parallel to another plane
		bool IsParallelToPlane(const Plane3D& plane) const
		{
			Vec3Cart norm1(_A, _B, _C);
			Vec3Cart norm2(plane._A, plane._B, plane._C);

			return norm1.IsParallelTo(norm2);
		}
		
		/// @brief Tests if this plane is perpendicular to another plane
		bool IsPerpendicularToPlane(const Plane3D& plane) const
		{
			Vec3Cart norm1(_A, _B, _C);
			Vec3Cart norm2(plane._A, plane._B, plane._C);

			return norm1.IsPerpendicularTo(norm2);
		}
		
		/// @brief Calculates the angle between two planes
		/// @return Angle in radians
		Real AngleToPlane(const Plane3D& plane) const
		{
			// angle between normals of two planes
			return this->Normal().AngleToVector(plane.Normal());
		}
		
		/// @brief Calculates the distance between two planes
		/// @return Distance (0 if planes intersect)
		Real DistToPlane(const Plane3D& plane) const
		{
			if (IsParallelToPlane(plane))
			{
				// distance between two parallel planes is the distance between any point on one plane and the other plane
				return DistToPoint(plane.GetPointOnPlane());
			}
			else
				return 0.0;
		}

		/// @brief Finds the intersection line of two planes
		/// @param plane The other plane
		/// @param out_inter_line Output: intersection line if exists
		/// @return false if planes are parallel
		bool IntersectionWithPlane(const Plane3D& plane, Line3D& out_inter_line) const
		{
			Vec3Cart n1 = Normal();
			Vec3Cart n2 = plane.Normal();
			Vec3Cart dir = VectorProduct(n1, n2);

			if (dir.NormL2() < Defaults::Vec3CartIsParallelTolerance) {
				// Planes are parallel
				return false;
			}

			// Solve for a point on the intersection line:
			// x = ( (d2 n1 - d1 n2) x (n1 x n2) ) / |n1 x n2|^2
			double d1 = -D();
			double d2 = -plane.D();

			Vec3Cart n1xn2 = dir;
			Vec3Cart p = VectorProduct((d2 * n1 - d1 * n2), n1xn2) / POW2(n1xn2.NormL2());

			out_inter_line = Line3D(Pnt3Cart(p.X(), p.Y(), p.Z()), dir.GetAsUnitVector());
			return true;
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DCore/Geometry3DSurfaces.h   ///////////////////////////


namespace MML
{

	/// @brief Triangle in 3D space
	/// @details Represents a triangle defined by three vertices in 3D space.
	///          Provides side lengths, area calculation, triangle classification,
	///          centroid, and point containment testing using barycentric coordinates.
	class Triangle3D
	{
	protected:
		Pnt3Cart _pnt1, _pnt2, _pnt3;
	public:
		/// @brief Default constructor
		Triangle3D() {}
		
		/// @brief Constructs a triangle from three vertices
		Triangle3D(Pnt3Cart pnt1, Pnt3Cart pnt2, Pnt3Cart pnt3)
			: _pnt1(pnt1), _pnt2(pnt2), _pnt3(pnt3)
		{
		}

		/// @brief Gets side length A (from pnt1 to pnt2)
		Real A() const { return _pnt1.Dist(_pnt2); }
		/// @brief Gets side length B (from pnt2 to pnt3)
		Real B() const { return _pnt2.Dist(_pnt3); }
		/// @brief Gets side length C (from pnt3 to pnt1)
		Real C() const { return _pnt3.Dist(_pnt1); }

		/// @brief Gets vertex 1 (const)
		Pnt3Cart	Pnt1() const { return _pnt1; }
		/// @brief Gets vertex 1 (mutable)
		Pnt3Cart& Pnt1()			 { return _pnt1; }
		/// @brief Gets vertex 2 (const)
		Pnt3Cart	Pnt2() const { return _pnt2; }
		/// @brief Gets vertex 2 (mutable)
		Pnt3Cart& Pnt2()			 { return _pnt2; }
		/// @brief Gets vertex 3 (const)
		Pnt3Cart	Pnt3() const { return _pnt3; }
		/// @brief Gets vertex 3 (mutable)
		Pnt3Cart& Pnt3()			 { return _pnt3; }

		/// @brief Calculates the area using Heron's formula
		Real Area() const
		{
			Real s = (A() + B() + C()) / 2.0;
			return sqrt(s * (s - A()) * (s - B()) * (s - C()));
		}

		/// @brief Tests if this is a right triangle
		bool IsRight(Real eps = Defaults::Triangle3DIsRightTolerance) const
		{
			// Check if a^2 + b^2 = c^2 (Pythagorean theorem) with tolerance
			Real a = A(), b = B(), c = C();
			return (std::abs(a*a + b*b - c*c) < eps) || 
						(std::abs(a*a + c*c - b*b) < eps) || 
						(std::abs(b*b + c*c - a*a) < eps);
		}
		
		/// @brief Tests if this is an isosceles triangle (two equal sides)
		bool IsIsosceles(Real eps = Defaults::Triangle3DIsIsoscelesTolerance) const
		{
			Real a = A(), b = B(), c = C();
			return (std::abs(a - b) < eps) || (std::abs(a - c) < eps) || (std::abs(b - c) < eps);
		}
		
		/// @brief Tests if this is an equilateral triangle (all sides equal)
		bool IsEquilateral(Real eps = Defaults::Triangle3DIsEquilateralTolerance) const
		{
			Real a = A(), b = B(), c = C();
			return (std::abs(a - b) < eps) && (std::abs(a - c) < eps);
		}

		/// @brief Gets the centroid (center of mass)
		Pnt3Cart Centroid() const
		{
			return (_pnt1 + _pnt2 + _pnt3) / 3.0;
		}

		/// @brief Gets the plane containing this triangle
		Plane3D getDefinedPlane() const
		{
			return Plane3D(_pnt1, _pnt2, _pnt3);
		}

		/// @brief Tests if a point is inside the triangle
		/// @param pnt The point to test
		/// @param eps Tolerance for boundary cases
		/// @details Uses barycentric coordinates for containment testing
		bool IsPointInside(const Pnt3Cart& pnt, Real eps = Defaults::Triangle3DIsPointInsideTolerance) const
		{
			// check if point is inside triangle using barycentric coordinates
			Vec3Cart v0 = Vec3Cart(_pnt1, _pnt2);
			Vec3Cart v1 = Vec3Cart(_pnt1, _pnt3);
			Vec3Cart v2 = Vec3Cart(_pnt1, pnt);
			
			Real d00 = ScalarProduct(v0, v0);
			Real d01 = ScalarProduct(v0, v1);
			Real d11 = ScalarProduct(v1, v1);
			Real d20 = ScalarProduct(v2, v0);
			Real d21 = ScalarProduct(v2, v1);
			Real denom = d00 * d11 - d01 * d01;
			
			if (denom == 0.0)
				return false; // degenerate triangle
			
			Real v = (d11 * d20 - d01 * d21) / denom;
			
			if (v < 0.0 || v > 1.0)
				return false;
			
			Real w = (d00 * d21 - d01 * d20) / denom;
			
			if (w < 0.0 || w > 1.0)
				return false;
			
			return (v + w <= 1.0 + eps); // allow for small numerical errors
		}
	};

	/// @brief Triangular parametric surface in 3D
	/// @details Extends Triangle3D to implement IParametricSurface interface.
	///          Establishes a local coordinate system for parametric mapping.
	///          The longest side is used as the base for the local x-axis.
	class TriangleSurface3D : public Triangle3D, IParametricSurface<3>
	{
	public:
		Real _minX, _maxX, _minY, _maxY;
		Pnt3Cart _origin;
		Pnt3Cart _center;
		Vec3Cart _localX, _localY;
		Vec3Cart _normal;
		Real _pnt3XCoord;

		/// @brief Constructs a triangular surface from three vertices
		/// @details Automatically reorders vertices so the longest side becomes the base.
		/// @param pnt1 First vertex
		/// @param pnt2 Second vertex
		/// @param pnt3 Third vertex
		TriangleSurface3D(Pnt3Cart pnt1, Pnt3Cart pnt2, Pnt3Cart pnt3)
		{
			// CHECK THAT 1-2 side is THE LONGEST ONE!!!
			Real a = pnt1.Dist(pnt2);
			Real b = pnt2.Dist(pnt3);
			Real c = pnt3.Dist(pnt1);

			if (a >= b && a >= c)
			{
				; // nice, we are all good
			}
			else if (b >= a && b >= c)
			{
				// rotate points one place, so that 'b' side (pnt2-pnt3) is at the beginning
				Pnt3Cart tmp = pnt1;
				pnt1 = pnt2;
				pnt2 = pnt3;
				pnt3 = tmp;
			}
			else
			{
				// rotate points two places (c is longest, so pnt3-pnt1 becomes new pnt1-pnt2)
				Pnt3Cart tmp = pnt1;
				pnt1 = pnt3;
				pnt3 = pnt2;
				pnt2 = tmp;
			}

			_pnt1 = pnt1;		// initializing points in base Triangle3D class
			_pnt2 = pnt2;
			_pnt3 = pnt3;

			// calculate min and max
			// calculate center
			_center = (pnt1 + pnt2 + pnt3) / 3.0;

			// calculate local coordinate system
			// we will take x-axis to be from pnt1 to pnt2
			_localX = Vec3Cart(pnt1, pnt2).GetAsUnitVector();

			// we will calculate y-axis as following
			// calculate perpendicular vector to x-axis, that goes through pnt3
			Line3D	 lineX(pnt1, pnt2);
			Pnt3Cart pntOnLine = lineX.NearestPointOnLine(pnt3);

			_localY = Vec3Cart(pntOnLine, pnt3).GetAsUnitVector();

			_minX = 0.0;
			_maxX = pnt1.Dist(pnt2);
			_minY = 0.0;
			_maxY = pntOnLine.Dist(pnt3);
			_pnt3XCoord = pntOnLine.Dist(pnt1);

			_normal = VectorProduct(_localX, _localY).GetAsUnitVector();

			_origin = pnt1;
		}

		/// @brief Gets minimum u parameter
		virtual Real getMinU() const { return _minX; }
		/// @brief Gets maximum u parameter
		virtual Real getMaxU() const { return _maxX; }
		/// @brief Gets minimum w parameter for given u
		virtual Real getMinW(Real u) const { return _minY; }
		/// @brief Gets maximum w parameter for given u (varies with u due to triangle shape)
		virtual Real getMaxW(Real u) const
		{
			// this depends on value of u (which is localX)
			if (u < _pnt3XCoord)
				return _minY + (u / _pnt3XCoord) * (_maxY - _minY);
			else
				return _minY + ((_maxX - u) / (_maxX - _pnt3XCoord)) * (_maxY - _minY);
		}

		/// @brief Evaluates the surface at parameters (u, w)
		/// @param u First parameter (along local x-axis)
		/// @param w Second parameter (along local y-axis)
		/// @return 3D point on the surface
		VectorN<Real, 3> operator()(Real u, Real w) const
		{
			Pnt3Cart ret = _origin + u * _localX + w * _localY;
			return VectorN<Real, 3>({ ret.X(), ret.Y(), ret.Z() });
		}
	};

	/// @brief Rectangular parametric surface in 3D
	/// @details Represents a planar rectangular region in 3D space.
	///          Implements IParametricSurfaceRect interface for integration and analysis.
	///          All four corners must be coplanar.
	class RectSurface3D : public IParametricSurfaceRect<3>
	{
	public:
		// all constructors are expected to set properly these values
		Pnt3Cart _pnt1, _pnt2, _pnt3, _pnt4;
		Real _minX, _maxX, _minY, _maxY;
		Pnt3Cart _center;
		Vec3Cart _localX, _localY;

		/// @brief Default constructor
		RectSurface3D() {}
		
		/// @brief Constructs a rectangular surface from four coplanar corners
		/// @param pnt1 First corner
		/// @param pnt2 Second corner (along x-direction from pnt1)
		/// @param pnt3 Third corner (diagonal from pnt1)
		/// @param pnt4 Fourth corner (along y-direction from pnt1)
		/// @throws GeometryError if points are not coplanar
		RectSurface3D(Pnt3Cart pnt1, Pnt3Cart pnt2, Pnt3Cart pnt3, Pnt3Cart pnt4)
			: _pnt1(pnt1), _pnt2(pnt2), _pnt3(pnt3), _pnt4(pnt4)
		{
			// Validate coplanarity: all 4 points must lie in the same plane
			Plane3D plane(pnt1, pnt2, pnt3);
			if (!plane.IsPointOnPlane(pnt4))
				throw GeometryError("RectSurface3D ctor - points are not coplanar");

			// podesiti min i max
			Real lenX = _pnt1.Dist(_pnt2);
			Real lenY = _pnt1.Dist(_pnt4);
			_minX = -lenX / 2;
			_maxX = lenX / 2;
			_minY = -lenY / 2;
			_maxY = lenY / 2;

			// calculate center
			_center = (_pnt1 + _pnt2 + _pnt3 + _pnt4) / 4.0;

			// calculate local coordinate system
			_localX = Vec3Cart(_pnt1, _pnt2).GetAsUnitVector();
			_localY = Vec3Cart(_pnt1, _pnt4).GetAsUnitVector();
		}

		/// @brief Gets minimum u parameter
		virtual Real getMinU() const { return _minX; }
		/// @brief Gets maximum u parameter
		virtual Real getMaxU() const { return _maxX; }
		/// @brief Gets minimum w parameter
		virtual Real getMinW() const { return _minY; }
		/// @brief Gets maximum w parameter
		virtual Real getMaxW() const { return _maxY; }

		/// @brief Gets the surface normal vector
		Vec3Cart getNormal() const {
			return VectorProduct(Vec3Cart(_pnt1, _pnt2), Vec3Cart(_pnt1, _pnt4)).GetAsUnitVector();
		}
		
		/// @brief Gets the center point
		Pnt3Cart getCenter() const { return _center; }

		/// @brief Gets the area of the rectangle
		Real getArea() const {
			return VectorProduct(Vec3Cart(_pnt1, _pnt2), Vec3Cart(_pnt1, _pnt4)).NormL2();
		}
		
		/// @brief Evaluates the surface at parameters (u, w)
		/// @param u First parameter (along local x-axis)
		/// @param w Second parameter (along local y-axis)
		/// @return 3D point on the surface
		VectorN<Real, 3> operator()(Real u, Real w) const {
			Pnt3Cart ret = _center + u * _localX + w * _localY;
			return VectorN<Real, 3>({ ret.X(), ret.Y(), ret.Z() });
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DBodiesCore/Geometry3DBounding.h   ///////////////////////////

/// @file Geometry3DBounding.h
/// @brief 3D bounding volume classes for spatial queries.
/// - BoundingSphere3D: Rotation-invariant bounding sphere
/// - Box3D: Axis-Aligned Bounding Box (AABB)
/// @see Geometry3DBodies.h for the aggregate header




namespace MML {
	// Forward declaration
	class Box3D;

	/// @brief Bounding sphere for fast spatial queries and collision detection.
	/// A bounding sphere is defined by a center point and radius. While less tight-fitting
	/// than an AABB, sphere-sphere intersection tests are extremely fast (single distance
	/// comparison), making them ideal for broad-phase collision detection.
	/// @note Bounding spheres are rotation-invariant, unlike AABBs.

	class BoundingSphere3D {
	private:
		Pnt3Cart _center; ///< Center point of the sphere
		Real _radius;	  ///< Radius (must be non-negative)

	public:
		/// @name Constructors
		/// @{

		/// /** @brief Default constructor: unit sphere at origin. */

		BoundingSphere3D()
			: _center(0, 0, 0)
			, _radius(0) {}

		/// @brief Construct from center and radius.
		/// @param center Center point
		/// @param radius Sphere radius (must be ≥ 0)
		/// @throws ArgumentError if radius is negative

		BoundingSphere3D(const Pnt3Cart& center, Real radius)
			: _center(center)
			, _radius(radius) {
			if (radius < 0.0)
				throw ArgumentError("BoundingSphere3D: radius must be non-negative");
		}
		/// @}

		/// @name Accessors
		/// @{
		Pnt3Cart Center() const { return _center; }
		Real Radius() const { return _radius; }
		/// @}

		/// /** @brief Calculate sphere volume: V = 4/3 π r³ */

		Real Volume() const { return (4.0 / 3.0) * Constants::PI * _radius * _radius * _radius; }

		/// @brief Test if a point lies inside or on the sphere.
		/// @param pnt Point to test
		/// @return true if distance from center ≤ radius

		bool Contains(const Pnt3Cart& pnt) const { return _center.Dist(pnt) <= _radius; }

		/// @brief Test intersection with another bounding sphere.
		/// @param other The other sphere
		/// @return true if spheres overlap or touch

		bool Intersects(const BoundingSphere3D& other) const {
			Real centerDist = _center.Dist(other._center);
			return centerDist <= (_radius + other._radius);
		}

		/// @brief Expand sphere to include a point.
		/// @param pnt Point to include
		/// @note Only increases radius; center remains fixed.

		void ExpandToInclude(const Pnt3Cart& pnt) {
			Real dist = _center.Dist(pnt);
			if (dist > _radius)
				_radius = dist;
		}

		std::string ToString() const {
			std::ostringstream oss;
			oss << "BoundingSphere3D[Center=(" << _center.X() << "," << _center.Y() << "," << _center.Z() << ")"
				<< ", Radius=" << _radius << "]";
			return oss.str();
		}
	};

	/// @brief Axis-Aligned Bounding Box (AABB) for 3D spatial queries.
	/// An AABB is defined by its minimum and maximum corner points, with edges
	/// parallel to the coordinate axes. AABBs provide:
	/// - Fast intersection tests (separating axis theorem)
	/// - Tight bounds for axis-aligned geometry
	/// - Efficient spatial partitioning (octrees, BVH)
	/// ## Factory Methods
	/// - FromCenterAndSize() - From center point and dimensions
	/// - FromCenterAndHalfExtents() - From center and half-sizes
	/// - FromPoints() - Minimal box containing point set
	/// - UnitBox(), CenteredUnitCube() - Standard unit boxes
	/// @note Coordinates are automatically normalized (min ≤ max) on construction.

	class Box3D {
	private:
		Pnt3Cart _min; ///< Minimum corner (smallest x, y, z)
		Pnt3Cart _max; ///< Maximum corner (largest x, y, z)

	public:
		/// @name Constructors
		/// @{

		/// /** @brief Default constructor: unit cube [0,1]³. */

		Box3D()
			: _min(0, 0, 0)
			, _max(1, 1, 1) {}

		/// @brief Construct from min/max corner points.
		/// @param min Minimum corner point
		/// @param max Maximum corner point
		/// @note Automatically normalizes if min > max in any dimension.

		Box3D(const Pnt3Cart& min, const Pnt3Cart& max)
			: _min(min)
			, _max(max) {
			Normalize();
		}

		/// @brief Construct from explicit coordinates.
		/// @param minX,minY,minZ Minimum corner coordinates
		/// @param maxX,maxY,maxZ Maximum corner coordinates

		Box3D(Real minX, Real minY, Real minZ, Real maxX, Real maxY, Real maxZ)
			: _min(minX, minY, minZ)
			, _max(maxX, maxY, maxZ) {
			Normalize();
		}
		/// @}

		/// @name Factory Methods
		/// @{

		/// @brief Create box from center point and full dimensions.
		/// @param center Center point of the box
		/// @param width Size in X direction
		/// @param height Size in Y direction
		/// @param depth Size in Z direction

		static Box3D FromCenterAndSize(const Pnt3Cart& center, Real width, Real height, Real depth) {
			Real halfW = width / 2;
			Real halfH = height / 2;
			Real halfD = depth / 2;
			return Box3D(center.X() - halfW, center.Y() - halfH, center.Z() - halfD, center.X() + halfW, center.Y() + halfH,
						 center.Z() + halfD);
		}

		/// /** @brief Create box from center and half-extents (scalars). */

		static Box3D FromCenterAndHalfExtents(const Pnt3Cart& center, Real halfWidth, Real halfHeight, Real halfDepth) {
			return Box3D(center.X() - halfWidth, center.Y() - halfHeight, center.Z() - halfDepth, center.X() + halfWidth,
						 center.Y() + halfHeight, center.Z() + halfDepth);
		}

		/// /** @brief Create box from center and half-extents vector. */

		static Box3D FromCenterAndHalfExtents(const Pnt3Cart& center, const Vec3Cart& halfExtents) {
			return Box3D(center.X() - halfExtents.X(), center.Y() - halfExtents.Y(), center.Z() - halfExtents.Z(),
						 center.X() + halfExtents.X(), center.Y() + halfExtents.Y(), center.Z() + halfExtents.Z());
		}

		/// @brief Create minimal AABB containing a set of points.
		/// @param points Vector of points to bound
		/// @throws GeometryError if points is empty

		static Box3D FromPoints(const std::vector<Pnt3Cart>& points) {
			if (points.empty())
				throw GeometryError("Box3D::FromPoints - empty point set");

			Real minX = points[0].X(), maxX = points[0].X();
			Real minY = points[0].Y(), maxY = points[0].Y();
			Real minZ = points[0].Z(), maxZ = points[0].Z();

			for (size_t i = 1; i < points.size(); ++i) {
				minX = std::min(minX, points[i].X());
				maxX = std::max(maxX, points[i].X());
				minY = std::min(minY, points[i].Y());
				maxY = std::max(maxY, points[i].Y());
				minZ = std::min(minZ, points[i].Z());
				maxZ = std::max(maxZ, points[i].Z());
			}

			return Box3D(minX, minY, minZ, maxX, maxY, maxZ);
		}

		/// /** @brief Unit box [0,1]³. */

		static Box3D UnitBox() { return Box3D(0, 0, 0, 1, 1, 1); }

		/// /** @brief Unit cube [0,1]³ (alias for UnitBox). */

		static Box3D UnitCube() { return Box3D(0, 0, 0, 1, 1, 1); }

		/// /** @brief Centered unit cube [-0.5, 0.5]³. */

		static Box3D CenteredUnitCube() { return Box3D(-0.5, -0.5, -0.5, 0.5, 0.5, 0.5); }
		/// @}

		/// /** @brief Ensure min ≤ max in all dimensions (swaps if needed). */

		void Normalize() {
			if (_min.X() > _max.X())
				std::swap(_min.X(), _max.X());
			if (_min.Y() > _max.Y())
				std::swap(_min.Y(), _max.Y());
			if (_min.Z() > _max.Z())
				std::swap(_min.Z(), _max.Z());
		}

		/// @name Accessors
		/// @{
		Pnt3Cart Min() const { return _min; }
		Pnt3Cart& Min() { return _min; }
		Pnt3Cart Max() const { return _max; }
		Pnt3Cart& Max() { return _max; }

		Real MinX() const { return _min.X(); }
		Real MinY() const { return _min.Y(); }
		Real MinZ() const { return _min.Z(); }
		Real MaxX() const { return _max.X(); }
		Real MaxY() const { return _max.Y(); }
		Real MaxZ() const { return _max.Z(); }
		/// @}

		/// @name Dimensions
		/// @{
		Real Width() const { return _max.X() - _min.X(); }	///< Size in X direction
		Real Height() const { return _max.Y() - _min.Y(); } ///< Size in Y direction
		Real Depth() const { return _max.Z() - _min.Z(); }	///< Size in Z direction
		Vec3Cart Size() const { return Vec3Cart(Width(), Height(), Depth()); }
		Vec3Cart HalfExtents() const { return Vec3Cart(Width() / 2, Height() / 2, Depth() / 2); }
		Real Diagonal() const { return std::sqrt(Width() * Width() + Height() * Height() + Depth() * Depth()); }
		/// @}

		/// @name Geometric Properties
		/// @{

		/// /** @brief Calculate box volume: V = W × H × D */

		Real Volume() const { return Width() * Height() * Depth(); }
		/// /** @brief Calculate surface area: A = 2(WH + HD + DW) */

		Real SurfaceArea() const { return 2 * (Width() * Height() + Height() * Depth() + Depth() * Width()); }

		/// /** @brief Get the center point of the box. */

		Pnt3Cart Center() const { return Pnt3Cart((_min.X() + _max.X()) / 2, (_min.Y() + _max.Y()) / 2, (_min.Z() + _max.Z()) / 2); }
		/// @}

		/// @name Corner Access
		/// @{
		/// /** @brief Get corner at (minX, minY, minZ). */

		Pnt3Cart Corner000() const { return _min; }
		Pnt3Cart Corner100() const { return Pnt3Cart(_max.X(), _min.Y(), _min.Z()); }
		Pnt3Cart Corner010() const { return Pnt3Cart(_min.X(), _max.Y(), _min.Z()); }
		Pnt3Cart Corner110() const { return Pnt3Cart(_max.X(), _max.Y(), _min.Z()); }
		Pnt3Cart Corner001() const { return Pnt3Cart(_min.X(), _min.Y(), _max.Z()); }
		Pnt3Cart Corner101() const { return Pnt3Cart(_max.X(), _min.Y(), _max.Z()); }
		Pnt3Cart Corner011() const { return Pnt3Cart(_min.X(), _max.Y(), _max.Z()); }
		/// /** @brief Get corner at (maxX, maxY, maxZ). */

		Pnt3Cart Corner111() const { return _max; }

		/// /** @brief Get all 8 corners as a vector. */

		std::vector<Pnt3Cart> Corners() const {
			return {Corner000(), Corner100(), Corner010(), Corner110(), Corner001(), Corner101(), Corner011(), Corner111()};
		}
		/// @}

		/// @name Spatial Queries
		/// @{

		/// @brief Test if a point is inside or on the box boundary.
		/// @param p Point to test
		/// @param epsilon Tolerance for boundary tests

		bool Contains(const Pnt3Cart& p, Real epsilon = Constants::GEOMETRY_EPSILON) const {
			return p.X() >= _min.X() - epsilon && p.X() <= _max.X() + epsilon && p.Y() >= _min.Y() - epsilon &&
				   p.Y() <= _max.Y() + epsilon && p.Z() >= _min.Z() - epsilon && p.Z() <= _max.Z() + epsilon;
		}

		/// @brief Test if another box is fully contained within this box.
		/// @param other Box to test
		/// @param epsilon Tolerance for boundary tests

		bool Contains(const Box3D& other, Real epsilon = Constants::GEOMETRY_EPSILON) const {
			return other._min.X() >= _min.X() - epsilon && other._max.X() <= _max.X() + epsilon && other._min.Y() >= _min.Y() - epsilon &&
				   other._max.Y() <= _max.Y() + epsilon && other._min.Z() >= _min.Z() - epsilon && other._max.Z() <= _max.Z() + epsilon;
		}

		/// @brief Calculate distance from a point to the box surface.
		/// @param p Point to measure from
		/// @return 0 if inside, positive distance otherwise

		Real DistanceToPoint(const Pnt3Cart& p) const {
			Real dx = std::max({_min.X() - p.X(), REAL(0.0), p.X() - _max.X()});
			Real dy = std::max({_min.Y() - p.Y(), REAL(0.0), p.Y() - _max.Y()});
			Real dz = std::max({_min.Z() - p.Z(), REAL(0.0), p.Z() - _max.Z()});
			return std::sqrt(dx * dx + dy * dy + dz * dz);
		}

		/// @brief Find the closest point on the box to a given point.
		/// @param p External point
		/// @return Closest point on or inside the box

		Pnt3Cart ClosestPoint(const Pnt3Cart& p) const {
			return Pnt3Cart(std::clamp(p.X(), _min.X(), _max.X()), std::clamp(p.Y(), _min.Y(), _max.Y()),
							std::clamp(p.Z(), _min.Z(), _max.Z()));
		}

		/// @brief Test if two boxes overlap.
		/// @param other Box to test against
		/// @return true if boxes intersect (including touching)

		bool Intersects(const Box3D& other) const {
			return _min.X() <= other._max.X() && _max.X() >= other._min.X() && _min.Y() <= other._max.Y() && _max.Y() >= other._min.Y() &&
				   _min.Z() <= other._max.Z() && _max.Z() >= other._min.Z();
		}
		/// @}

		/// @name Set Operations
		/// @{

		/// @brief Compute intersection of two boxes.
		/// @param other Box to intersect with
		/// @return Intersection box, or empty box (0,0,0,0,0,0) if disjoint

		Box3D Intersection(const Box3D& other) const {
			Real minX = std::max(_min.X(), other._min.X());
			Real minY = std::max(_min.Y(), other._min.Y());
			Real minZ = std::max(_min.Z(), other._min.Z());
			Real maxX = std::min(_max.X(), other._max.X());
			Real maxY = std::min(_max.Y(), other._max.Y());
			Real maxZ = std::min(_max.Z(), other._max.Z());

			if (minX > maxX || minY > maxY || minZ > maxZ)
				return Box3D(0, 0, 0, 0, 0, 0); // Empty box

			return Box3D(minX, minY, minZ, maxX, maxY, maxZ);
		}

		/// @brief Compute union (smallest enclosing box) of two boxes.
		/// @param other Box to merge with
		/// @return Minimal AABB containing both boxes

		Box3D Union(const Box3D& other) const {
			return Box3D(std::min(_min.X(), other._min.X()), std::min(_min.Y(), other._min.Y()), std::min(_min.Z(), other._min.Z()),
						 std::max(_max.X(), other._max.X()), std::max(_max.Y(), other._max.Y()), std::max(_max.Z(), other._max.Z()));
		}

		/// @brief Expand box in-place to include a point.
		/// @param p Point to include

		void ExpandToInclude(const Pnt3Cart& p) {
			_min.X() = std::min(_min.X(), p.X());
			_min.Y() = std::min(_min.Y(), p.Y());
			_min.Z() = std::min(_min.Z(), p.Z());
			_max.X() = std::max(_max.X(), p.X());
			_max.Y() = std::max(_max.Y(), p.Y());
			_max.Z() = std::max(_max.Z(), p.Z());
		}

		/// @brief Create expanded copy with uniform margin.
		/// @param margin Distance to expand in all directions

		Box3D Expanded(Real margin) const {
			return Box3D(_min.X() - margin, _min.Y() - margin, _min.Z() - margin, _max.X() + margin, _max.Y() + margin, _max.Z() + margin);
		}
		/// @}

		/// @name Transformations & Utilities
		/// @{

		/// @brief Check if box is degenerate (zero volume in any dimension).
		/// @param epsilon Tolerance for near-zero dimension

		bool IsDegenerate(Real epsilon = Constants::GEOMETRY_EPSILON) const {
			return Width() < epsilon || Height() < epsilon || Depth() < epsilon;
		}

		/// @brief Create translated copy.
		/// @param v Translation vector

		Box3D Translated(const Vec3Cart& v) const { return Box3D(_min + v, _max + v); }

		/// @brief Create scaled copy (about center).
		/// @param factor Scale factor

		Box3D Scaled(Real factor) const {
			Pnt3Cart c = Center();
			Vec3Cart half = HalfExtents();
			return Box3D::FromCenterAndHalfExtents(c, half.X() * factor, half.Y() * factor, half.Z() * factor);
		}
		/// @}

		std::string ToString() const {
			std::ostringstream oss;
			oss << "Box3D[Min=(" << _min.X() << "," << _min.Y() << "," << _min.Z() << ")"
				<< ", Max=(" << _max.X() << "," << _max.Y() << "," << _max.Z() << ")"
				<< ", Size=(" << Width() << "×" << Height() << "×" << Depth() << ")]";
			return oss.str();
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DBodiesCore/Geometry3DBodyBase.h   ///////////////////////////

/// @file Geometry3DBodyBase.h
/// @brief Base interfaces and abstract classes for 3D solid bodies.
/// - IBody: Abstract interface for all solid bodies
/// - ISolidBodyWithBoundary: Bodies defined by boundary functions
/// - BodyWithTriangleSurfaces: Base for triangulated mesh bodies
/// - BodyWithRectSurfaces: Base for quad mesh bodies
/// - ComposedSolidSurfaces3D: Composite solid from multiple bodies
/// @see Geometry3DBodies.h for the aggregate header




namespace MML {

	/// @brief Abstract interface for 3D solid bodies.
	/// Defines the contract for all solid body representations in MML.
	/// Implementations provide geometric properties (volume, surface area),
	/// spatial queries (containment), and bounding volumes.

	class IBody {
	public:
		/// @name Geometric Properties
		/// @{
		virtual Real Volume() const = 0;		///< Total enclosed volume
		virtual Real SurfaceArea() const = 0;	///< Total surface area
		virtual Pnt3Cart GetCenter() const = 0; ///< Geometric centroid
		/// @}

		/// @name Bounding Volumes
		/// @{
		virtual Box3D GetBoundingBox() const = 0;				///< Axis-aligned bounding box
		virtual BoundingSphere3D GetBoundingSphere() const = 0; ///< Bounding sphere
		/// @}

		/// @name Spatial Queries
		/// @{

		/// @brief Test if a point lies inside the body.
		/// @param pnt Point to test
		/// @return true if point is strictly inside

		virtual bool IsInside(const Pnt3Cart& pnt) const = 0;
		/// @}

		virtual std::string ToString() const = 0;

		virtual ~IBody() = default;
	};

	/// @brief Solid body defined by boundary functions for numerical integration.
	/// This class represents a 3D solid defined by functional boundaries:
	/// - x ∈ [x1, x2]
	/// - y ∈ [y1(x), y2(x)]
	/// - z ∈ [z1(x,y), z2(x,y)]
	/// This representation is ideal for:
	/// - Volume integration (mass, center of mass)
	/// - Moment of inertia calculations
	/// - Bodies with variable density
	/// @note Volume/SurfaceArea require numerical integration via
	/// ContinuousMassMomentOfInertiaTensorCalculator.
	/// @see SolidBodyWithBoundary for variable density implementation
	/// @see SolidBodyWithBoundaryConstDensity for constant density

	class ISolidBodyWithBoundary : public IBody {
	public:
		Real _x1, _x2; ///< X-axis bounds

		Real (*_y1)(Real); ///< Lower Y bound as function of x
		Real (*_y2)(Real); ///< Upper Y bound as function of x

		Real (*_z1)(Real, Real); ///< Lower Z bound as function of (x, y)
		Real (*_z2)(Real, Real); ///< Upper Z bound as function of (x, y)

	public:
		/// @brief Construct body from boundary functions.
		/// @param x1,x2 X-axis bounds
		/// @param y1,y2 Y bounds as functions of x
		/// @param z1,z2 Z bounds as functions of (x, y)

		ISolidBodyWithBoundary(Real x1, Real x2, Real (*y1)(Real), Real (*y2)(Real), Real (*z1)(Real, Real), Real (*z2)(Real, Real))
			: _x1(x1)
			, _x2(x2)
			, _y1(y1)
			, _y2(y2)
			, _z1(z1)
			, _z2(z2) {}

		/// @brief Get density at a point inside the body.
		/// @param x Position vector (3D)
		/// @return Density at that position

		virtual Real getDensity(const VectorN<Real, 3>& x) const = 0;

		virtual bool IsInside(const Pnt3Cart& pnt) const override {
			const Real x = pnt.X();
			const Real y = pnt.Y();
			const Real z = pnt.Z();

			if (_x1 < x && x < _x2) {
				// check y bounds
				if (_y1(x) < y && y < _y2(x)) {
					// check z bounds
					if (_z1(x, y) < z && z < _z2(x, y)) {
						return true; // point is inside the solid body
					}
				}
			}
			return false;
		}

		// IBody interface - provide default implementations
		// These are primarily used for physics calculations, not geometric queries
		virtual Real Volume() const override {
			// Volume would require integration - not implemented for general case
			throw NotImplementedError("Volume() requires integration - use ContinuousMassMomentOfInertiaTensorCalculator for mass properties");
		}

		virtual Real SurfaceArea() const override {
			// Surface area would require integration - not implemented for general case
			throw NotImplementedError("SurfaceArea() requires integration - not implemented for general ISolidBodyWithBoundary");
		}

		virtual Pnt3Cart GetCenter() const override {
			// Return geometric center of the bounding box as approximation
			Real cx = (_x1 + _x2) / 2.0;
			Real cy = (_y1(cx) + _y2(cx)) / 2.0;
			Real cz = (_z1(cx, cy) + _z2(cx, cy)) / 2.0;
			return Pnt3Cart(cx, cy, cz);
		}

		virtual Box3D GetBoundingBox() const override {
			// For general case, we need to find min/max across the entire domain
			// This is an approximation - assumes boundaries are monotonic
			Real minY = std::min(_y1(_x1), _y1(_x2));
			Real maxY = std::max(_y2(_x1), _y2(_x2));

			Real midX = (_x1 + _x2) / 2.0;
			Real midY = (_y1(midX) + _y2(midX)) / 2.0;
			Real minZ = std::min(_z1(_x1, midY), std::min(_z1(_x2, midY), _z1(midX, minY)));
			Real maxZ = std::max(_z2(_x1, midY), std::max(_z2(_x2, midY), _z2(midX, maxY)));

			return Box3D(Pnt3Cart(_x1, minY, minZ), Pnt3Cart(_x2, maxY, maxZ));
		}

		virtual BoundingSphere3D GetBoundingSphere() const override {
			Pnt3Cart center = GetCenter();
			Box3D box = GetBoundingBox();

			// Use half the diagonal of bounding box as radius
			Real dx = box.Max().X() - box.Min().X();
			Real dy = box.Max().Y() - box.Min().Y();
			Real dz = box.Max().Z() - box.Min().Z();
			Real radius = 0.5 * std::sqrt(dx * dx + dy * dy + dz * dz);

			return BoundingSphere3D(center, radius);
		}

		virtual std::string ToString() const override {
			std::ostringstream oss;
			oss << "ISolidBodyWithBoundary[x∈[" << _x1 << "," << _x2 << "]]";
			return oss.str();
		}
	};

	/// @brief Solid body with variable density distribution.
	/// Extension of ISolidBodyWithBoundary where density varies spatially
	/// according to a user-provided function.

	class SolidBodyWithBoundary : public ISolidBodyWithBoundary {
		Real (*_density)(const VectorN<Real, 3>& x); ///< Density function
	public:
		/// @brief Construct with boundary functions and density function.

		SolidBodyWithBoundary(Real x1, Real x2, Real (*y1)(Real), Real (*y2)(Real), Real (*z1)(Real, Real), Real (*z2)(Real, Real),
							  Real (*density)(const VectorN<Real, 3>& x))
			: ISolidBodyWithBoundary(x1, x2, y1, y2, z1, z2)
			, _density(density) {}

		virtual Real getDensity(const VectorN<Real, 3>& x) const { return _density(x); }
	};

	/// @brief Solid body with uniform constant density.
	/// Simplified ISolidBodyWithBoundary for homogeneous materials.

	class SolidBodyWithBoundaryConstDensity : public ISolidBodyWithBoundary {
		Real _density; ///< Constant density value
	public:
		SolidBodyWithBoundaryConstDensity(Real x1, Real x2, Real (*y1)(Real), Real (*y2)(Real), Real (*z1)(Real, Real),
										  Real (*z2)(Real, Real), Real density)
			: ISolidBodyWithBoundary(x1, x2, y1, y2, z1, z2)
			, _density(density) {}

		virtual Real getDensity(const VectorN<Real, 3>& x) const { return _density; }
	};

	/// @brief Solid body defined by triangular surface mesh.
	/// Base class for bodies represented as a collection of Triangle3D faces.
	/// Used for mesh-based geometric representations that support:
	/// - Surface rendering
	/// - Surface integration
	/// - Ray casting (with appropriate algorithms)
	/// @note IBody methods throw by default; override in derived classes.

	class BodyWithTriangleSurfaces : public IBody {
	protected:
		std::vector<Triangle3D> _surfaces; ///< Triangle faces
	public:
		/// /** @brief Get the number of triangular faces. */

		int GetSurfaceCount() const { return _surfaces.size(); }

		/// @brief Access a triangle face by index.
		/// @param index Face index (0 to GetSurfaceCount()-1)
		/// @throws IndexError if index invalid

		const Triangle3D& GetSurface(int index) const {
			if (index < 0 || index >= GetSurfaceCount())
				throw IndexError("BodyWithTriangleSurfaces::GetSurface - index out of range");
			return _surfaces[index];
		}

		// IBody interface - to be implemented by derived classes
		Real Volume() const override { throw NotImplementedError("Volume() not implemented"); }
		Real SurfaceArea() const override { throw NotImplementedError("SurfaceArea() not implemented"); }
		Pnt3Cart GetCenter() const override { throw NotImplementedError("GetCenter() not implemented"); }
		Box3D GetBoundingBox() const override { throw NotImplementedError("GetBoundingBox() not implemented"); }
		BoundingSphere3D GetBoundingSphere() const override { throw NotImplementedError("GetBoundingSphere() not implemented"); }
		bool IsInside(const Pnt3Cart& pnt) const override { throw NotImplementedError("IsInside() not implemented"); }
		std::string ToString() const override { throw NotImplementedError("ToString() not implemented"); }
	};

	/// @brief Solid body defined by rectangular (quad) surface mesh.
	/// Base class for bodies represented as RectSurface3D faces.
	/// Commonly used for:
	/// - Box-shaped objects
	/// - Parametric surfaces (torus, etc.)
	/// - CAD-style representations
	/// @note IBody methods throw by default; override in derived classes.

	class BodyWithRectSurfaces : public IBody {
	protected:
		std::vector<RectSurface3D> _surfaces; ///< Rectangular faces

	public:
		int GetSurfaceCount() const { return static_cast<int>(_surfaces.size()); }
		const RectSurface3D& GetSurface(int index) const {
			if (index < 0 || index >= GetSurfaceCount())
				throw IndexError("BodyWithRectSurfaces::GetSurface - index out of range");
			return _surfaces[index];
		}

		// IBody interface - to be implemented by derived classes
		Real Volume() const override { throw NotImplementedError("Volume() not implemented"); }
		Real SurfaceArea() const override { throw NotImplementedError("SurfaceArea() not implemented"); }
		Pnt3Cart GetCenter() const override { throw NotImplementedError("GetCenter() not implemented"); }
		Box3D GetBoundingBox() const override { throw NotImplementedError("GetBoundingBox() not implemented"); }
		BoundingSphere3D GetBoundingSphere() const override { throw NotImplementedError("GetBoundingSphere() not implemented"); }
		bool IsInside(const Pnt3Cart& pnt) const override { throw NotImplementedError("IsInside() not implemented"); }
		std::string ToString() const override { throw NotImplementedError("ToString() not implemented"); }

		// TODO: isClosed() - cast rays from center of mass in all directions
		// and check if they hit at least one surface
	};

	/// @brief Composite solid made of multiple IBody components.
	/// Represents a solid that is the union of other solids.
	/// Point containment returns true if point is inside ANY component.
	/// @note For tight/watertight validation, compute flux through all surfaces.

	class ComposedSolidSurfaces3D {
	private:
		std::vector<IBody*> _solids; ///< Component bodies (not owned)

	public:
		ComposedSolidSurfaces3D() = default;
		ComposedSolidSurfaces3D(const std::vector<IBody*>& solids)
			: _solids(solids) {}

		void AddSolid(IBody* solid) { _solids.push_back(solid); }
		size_t GetSolidCount() const { return _solids.size(); }
		IBody* GetSolid(size_t index) { return _solids[index]; }
		const IBody* GetSolid(size_t index) const { return _solids[index]; }

		/// /** @brief Test if point is inside any component solid. */

		bool IsInside(const Pnt3Cart& pnt) const {
			for (const auto* solid : _solids) {
				if (solid && solid->IsInside(pnt))
					return true;
			}
			return false;
		}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DBodiesCore/Geometry3DCubes.h   ///////////////////////////

/// @file Geometry3DCubes.h
/// @brief Cube solid body representations.
/// - Cube3D: Axis-aligned cube with 6 rectangular (quad) faces
/// - CubeWithTriangles3D: Axis-aligned cube with 12 triangular faces
/// @see Geometry3DBodies.h for the aggregate header




namespace MML {

	/// @brief Axis-aligned cube with rectangular (quad) surface mesh.
	/// Represents a cube with 6 rectangular faces (RectSurface3D).
	/// The cube is axis-aligned with faces parallel to coordinate planes.
	/// @note Vertex ordering produces outward-facing normals.
	/// @see CubeWithTriangles3D for triangulated version
	/// @see Box3D for AABB representation

	class Cube3D : public BodyWithRectSurfaces {
		Real _a;		  ///< Side length
		Pnt3Cart _center; ///< Center point
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct cube centered at origin.
		/// @param a Side length

		Cube3D(Real a)
			: _a(a)
			, _center(0, 0, 0) {
			Pnt3Cart pnt1(a / 2, -a / 2, -a / 2);
			Pnt3Cart pnt2(a / 2, a / 2, -a / 2);
			Pnt3Cart pnt3(-a / 2, a / 2, -a / 2);
			Pnt3Cart pnt4(-a / 2, -a / 2, -a / 2);
			Pnt3Cart pnt5(a / 2, -a / 2, a / 2);
			Pnt3Cart pnt6(a / 2, a / 2, a / 2);
			Pnt3Cart pnt7(-a / 2, a / 2, a / 2);
			Pnt3Cart pnt8(-a / 2, -a / 2, a / 2);

			// Add all 6 faces
			_surfaces.push_back(RectSurface3D(pnt1, pnt4, pnt3, pnt2)); // lower side in xy plane
			_surfaces.push_back(RectSurface3D(pnt5, pnt6, pnt7, pnt8)); // upper side in xy plane
			_surfaces.push_back(RectSurface3D(pnt1, pnt2, pnt6, pnt5)); // front side in yz plane
			_surfaces.push_back(RectSurface3D(pnt4, pnt8, pnt7, pnt3)); // back side in yz plane
			_surfaces.push_back(RectSurface3D(pnt1, pnt5, pnt8, pnt4)); // left side in xz plane
			_surfaces.push_back(RectSurface3D(pnt2, pnt3, pnt7, pnt6)); // right side in xz plane
		}

		/// @brief Construct cube centered at specified point.
		/// @param a Side length
		/// @param center Center point of the cube

		Cube3D(Real a, const Pnt3Cart& center)
			: _a(a)
			, _center(center) {
			// Create 8 corner vertices centered at the given point
			Pnt3Cart pnt1(center.X() + a / 2, center.Y() - a / 2, center.Z() - a / 2);
			Pnt3Cart pnt2(center.X() + a / 2, center.Y() + a / 2, center.Z() - a / 2);
			Pnt3Cart pnt3(center.X() - a / 2, center.Y() + a / 2, center.Z() - a / 2);
			Pnt3Cart pnt4(center.X() - a / 2, center.Y() - a / 2, center.Z() - a / 2);
			Pnt3Cart pnt5(center.X() + a / 2, center.Y() - a / 2, center.Z() + a / 2);
			Pnt3Cart pnt6(center.X() + a / 2, center.Y() + a / 2, center.Z() + a / 2);
			Pnt3Cart pnt7(center.X() - a / 2, center.Y() + a / 2, center.Z() + a / 2);
			Pnt3Cart pnt8(center.X() - a / 2, center.Y() - a / 2, center.Z() + a / 2);

			// Add all 6 faces
			_surfaces.push_back(RectSurface3D(pnt1, pnt4, pnt3, pnt2)); // lower side in xy plane
			_surfaces.push_back(RectSurface3D(pnt5, pnt6, pnt7, pnt8)); // upper side in xy plane
			_surfaces.push_back(RectSurface3D(pnt1, pnt2, pnt6, pnt5)); // front side in yz plane
			_surfaces.push_back(RectSurface3D(pnt4, pnt8, pnt7, pnt3)); // back side in yz plane
			_surfaces.push_back(RectSurface3D(pnt1, pnt5, pnt8, pnt4)); // left side in xz plane
			_surfaces.push_back(RectSurface3D(pnt2, pnt3, pnt7, pnt6)); // right side in xz plane
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			Real half_a = _a / 2.0;
			return (pnt.X() >= _center.X() - half_a && pnt.X() <= _center.X() + half_a && pnt.Y() >= _center.Y() - half_a &&
					pnt.Y() <= _center.Y() + half_a && pnt.Z() >= _center.Z() - half_a && pnt.Z() <= _center.Z() + half_a);
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = a³ */

		Real Volume() const override { return _a * _a * _a; }

		/// /** @brief Surface area = 6a² */

		Real SurfaceArea() const override { return 6.0 * _a * _a; }

		Pnt3Cart GetCenter() const override { return _center; }

		Box3D GetBoundingBox() const override {
			Real half_a = _a / 2.0;
			Pnt3Cart min(_center.X() - half_a, _center.Y() - half_a, _center.Z() - half_a);
			Pnt3Cart max(_center.X() + half_a, _center.Y() + half_a, _center.Z() + half_a);
			return Box3D(min, max);
		}

		/// /** @brief Bounding sphere radius = (a√3)/2 (half space diagonal) */

		BoundingSphere3D GetBoundingSphere() const override {
			Real radius = _a * std::sqrt(3.0) / 2.0;
			return BoundingSphere3D(_center, radius);
		}

		std::string ToString() const override {
			std::ostringstream oss;
			oss << "Cube3D{Center=(" << _center.X() << ", " << _center.Y() << ", " << _center.Z() << "), Side=" << _a
				<< ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << "}";
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		/// /** @brief Get side length. */

		Real GetSide() const { return _a; }
		/// @}
	};

	/// @brief Axis-aligned cube with triangular surface mesh.
	/// Represents a cube with 12 triangular faces (2 per quad face).
	/// Triangle winding is CCW for outward-facing normals.
	/// @see Cube3D for quad-face version

	class CubeWithTriangles3D : public BodyWithTriangleSurfaces {
		Real _a;		  ///< Side length
		Pnt3Cart _center; ///< Center point
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct cube centered at origin.
		/// @param a Side length

		CubeWithTriangles3D(Real a)
			: _a(a)
			, _center(0, 0, 0) {
			Real h = a / 2.0;
			// 8 vertices of the cube
			Pnt3Cart p1(h, -h, -h);
			Pnt3Cart p2(h, h, -h);
			Pnt3Cart p3(-h, h, -h);
			Pnt3Cart p4(-h, -h, -h);
			Pnt3Cart p5(h, -h, h);
			Pnt3Cart p6(h, h, h);
			Pnt3Cart p7(-h, h, h);
			Pnt3Cart p8(-h, -h, h);

			// Each face: two triangles (CCW order for outward normals)
			// Bottom face (z = -h)
			_surfaces.emplace_back(p1, p4, p3);
			_surfaces.emplace_back(p1, p3, p2);

			// Top face (z = +h)
			_surfaces.emplace_back(p5, p6, p7);
			_surfaces.emplace_back(p5, p7, p8);

			// Front face (y = +h)
			_surfaces.emplace_back(p2, p3, p7);
			_surfaces.emplace_back(p2, p7, p6);

			// Back face (y = -h)
			_surfaces.emplace_back(p1, p5, p8);
			_surfaces.emplace_back(p1, p8, p4);

			// Left face (x = -h)
			_surfaces.emplace_back(p4, p8, p7);
			_surfaces.emplace_back(p4, p7, p3);

			// Right face (x = +h)
			_surfaces.emplace_back(p1, p2, p6);
			_surfaces.emplace_back(p1, p6, p5);
		}

		/// @brief Construct cube centered at specified point.
		/// @param a Side length
		/// @param center Center point of the cube

		CubeWithTriangles3D(Real a, const Pnt3Cart& center)
			: _a(a)
			, _center(center) {
			Real h = a / 2.0;
			// 8 vertices centered at _center
			Pnt3Cart p1(center.X() + h, center.Y() - h, center.Z() - h);
			Pnt3Cart p2(center.X() + h, center.Y() + h, center.Z() - h);
			Pnt3Cart p3(center.X() - h, center.Y() + h, center.Z() - h);
			Pnt3Cart p4(center.X() - h, center.Y() - h, center.Z() - h);
			Pnt3Cart p5(center.X() + h, center.Y() - h, center.Z() + h);
			Pnt3Cart p6(center.X() + h, center.Y() + h, center.Z() + h);
			Pnt3Cart p7(center.X() - h, center.Y() + h, center.Z() + h);
			Pnt3Cart p8(center.X() - h, center.Y() - h, center.Z() + h);

			// Each face: two triangles (CCW order for outward normals)
			// Bottom face (z = -h)
			_surfaces.emplace_back(p1, p4, p3);
			_surfaces.emplace_back(p1, p3, p2);

			// Top face (z = +h)
			_surfaces.emplace_back(p5, p6, p7);
			_surfaces.emplace_back(p5, p7, p8);

			// Front face (y = +h)
			_surfaces.emplace_back(p2, p3, p7);
			_surfaces.emplace_back(p2, p7, p6);

			// Back face (y = -h)
			_surfaces.emplace_back(p1, p5, p8);
			_surfaces.emplace_back(p1, p8, p4);

			// Left face (x = -h)
			_surfaces.emplace_back(p4, p8, p7);
			_surfaces.emplace_back(p4, p7, p3);

			// Right face (x = +h)
			_surfaces.emplace_back(p1, p2, p6);
			_surfaces.emplace_back(p1, p6, p5);
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			Real h = _a / 2.0;
			return (pnt.X() >= _center.X() - h && pnt.X() <= _center.X() + h && pnt.Y() >= _center.Y() - h && pnt.Y() <= _center.Y() + h &&
					pnt.Z() >= _center.Z() - h && pnt.Z() <= _center.Z() + h);
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = a³ */

		Real Volume() const override { return _a * _a * _a; }

		/// /** @brief Surface area = 6a² */

		Real SurfaceArea() const override { return 6.0 * _a * _a; }

		Pnt3Cart GetCenter() const override { return _center; }

		Box3D GetBoundingBox() const override {
			Real h = _a / 2.0;
			Pnt3Cart min(_center.X() - h, _center.Y() - h, _center.Z() - h);
			Pnt3Cart max(_center.X() + h, _center.Y() + h, _center.Z() + h);
			return Box3D(min, max);
		}

		/// /** @brief Bounding sphere radius = (a/2)√3 (corner distance) */

		BoundingSphere3D GetBoundingSphere() const override {
			Real radius = (_a / 2.0) * std::sqrt(3.0);
			return BoundingSphere3D(_center, radius);
		}

		std::string ToString() const override {
			std::ostringstream oss;
			oss << "CubeWithTriangles3D: Center=(" << _center.X() << ", " << _center.Y() << ", " << _center.Z() << ")"
				<< ", Side=" << _a << ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << ", Triangles=" << _surfaces.size();
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		/// /** @brief Get side length. */

		Real GetSide() const { return _a; }
		/// @}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DBodiesCore/Geometry3DTorusCylinder.h   ///////////////////////////

/// @file Geometry3DTorusCylinder.h
/// @brief Torus and Cylinder solid body representations.
/// - Torus3D: Donut shape with rectangular surface mesh
/// - Cylinder3D: Cylinder with triangular surface mesh
/// @see Geometry3DBodies.h for the aggregate header




namespace MML {

	/// @brief Torus (donut shape) with rectangular surface mesh.
	/// Parametric surface: (R + r·cos(v))·cos(u), (R + r·cos(v))·sin(u), r·sin(v)
	/// where R is major radius and r is minor (tube) radius.
	/// @note Formulas:
	/// - Volume = 2π²Rr²
	/// - Surface Area = 4π²Rr

	class Torus3D : public BodyWithRectSurfaces {
		Real _R;		  ///< Major radius (center to tube center)
		Real _r;		  ///< Minor radius (tube radius)
		Pnt3Cart _center; ///< Center of the torus
		int _numU;		  ///< Divisions around major circle
		int _numV;		  ///< Divisions around tube
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct torus centered at origin.
		/// @param R Major radius
		/// @param r Minor radius (tube)
		/// @param numU Divisions around major circle (default 20)
		/// @param numV Divisions around tube (default 12)

		Torus3D(Real R, Real r, int numU = 20, int numV = 12)
			: _R(R)
			, _r(r)
			, _center(0, 0, 0)
			, _numU(numU)
			, _numV(numV) {
			constructSurfaces();
		}

		/// @brief Construct torus centered at specified point.
		/// @param R Major radius
		/// @param r Minor radius (tube)
		/// @param center Center point
		/// @param numU Divisions around major circle (default 20)
		/// @param numV Divisions around tube (default 12)

		Torus3D(Real R, Real r, const Pnt3Cart& center, int numU = 20, int numV = 12)
			: _R(R)
			, _r(r)
			, _center(center)
			, _numU(numU)
			, _numV(numV) {
			constructSurfaces();
		}
		/// @}

		/// @name Surface Generation
		/// @{

		/// /** @brief Generate rectangular patches for the torus surface. */

		void constructSurfaces() {
			_surfaces.clear();
			Real du = 2.0 * Constants::PI / _numU;
			Real dv = 2.0 * Constants::PI / _numV;

			for (int i = 0; i < _numU; ++i) {
				for (int j = 0; j < _numV; ++j) {
					Real u1 = i * du;
					Real u2 = (i + 1) * du;
					Real v1 = j * dv;
					Real v2 = (j + 1) * dv;

					// Four corners of this patch
					Pnt3Cart p1 = torusPoint(u1, v1);
					Pnt3Cart p2 = torusPoint(u2, v1);
					Pnt3Cart p3 = torusPoint(u2, v2);
					Pnt3Cart p4 = torusPoint(u1, v2);

					_surfaces.push_back(RectSurface3D(p1, p2, p3, p4));
				}
			}
		}

		/// @brief Compute point on torus surface.
		/// @param u Angle around major circle [0, 2π]
		/// @param v Angle around tube [0, 2π]

		Pnt3Cart torusPoint(Real u, Real v) const {
			Real x = (_R + _r * std::cos(v)) * std::cos(u);
			Real y = (_R + _r * std::cos(v)) * std::sin(u);
			Real z = _r * std::sin(v);
			return Pnt3Cart(_center.X() + x, _center.Y() + y, _center.Z() + z);
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			// Translate to torus-centered coordinates
			Real x = pnt.X() - _center.X();
			Real y = pnt.Y() - _center.Y();
			Real z = pnt.Z() - _center.Z();

			// Distance from point to Z-axis
			Real d = std::sqrt(x * x + y * y);

			// Distance from point to the tube center circle
			Real dist = std::sqrt((d - _R) * (d - _R) + z * z);

			return dist <= _r;
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = 2π²Rr² */

		Real Volume() const override { return 2.0 * Constants::PI * Constants::PI * _R * _r * _r; }

		/// /** @brief Surface area = 4π²Rr */

		Real SurfaceArea() const override { return 4.0 * Constants::PI * Constants::PI * _R * _r; }

		Pnt3Cart GetCenter() const override { return _center; }

		Box3D GetBoundingBox() const override {
			Real outerRadius = _R + _r;
			Pnt3Cart min(_center.X() - outerRadius, _center.Y() - outerRadius, _center.Z() - _r);
			Pnt3Cart max(_center.X() + outerRadius, _center.Y() + outerRadius, _center.Z() + _r);
			return Box3D(min, max);
		}

		/// /** @brief Bounding sphere radius = R + r (outer radius) */

		BoundingSphere3D GetBoundingSphere() const override {
			Real radius = _R + _r;
			return BoundingSphere3D(_center, radius);
		}

		std::string ToString() const override {
			std::ostringstream oss;
			oss << "Torus3D{Center=(" << _center.X() << ", " << _center.Y() << ", " << _center.Z() << "), MajorRadius=" << _R
				<< ", MinorRadius=" << _r << ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << "}";
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		Real GetMajorRadius() const { return _R; }
		Real GetMinorRadius() const { return _r; }
		int GetNumU() const { return _numU; }
		int GetNumV() const { return _numV; }
		/// @}
	};

	/// @brief Cylinder with triangular surface mesh.
	/// Cylinder aligned with Z-axis, with circular caps at top and bottom.
	/// Surface includes:
	/// - Bottom cap (triangular fan)
	/// - Top cap (triangular fan)
	/// - Lateral surface (rectangular strips as triangle pairs)
	/// @note Formulas:
	/// - Volume = πR²H
	/// - Surface Area = 2πR² + 2πRH

	class Cylinder3D : public BodyWithTriangleSurfaces {
		Real _R;		  ///< Radius
		Real _H;		  ///< Height
		Pnt3Cart _center; ///< Bottom center
		int _numSegments; ///< Divisions around circumference
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct cylinder centered at origin (bottom at z = -H/2).
		/// @param R Radius
		/// @param H Height
		/// @param numSegments Circumferential divisions (default 20)

		Cylinder3D(Real R, Real H, int numSegments = 20)
			: _R(R)
			, _H(H)
			, _center(0, 0, -H / 2)
			, _numSegments(numSegments) {
			constructSurfaces();
		}

		/// @brief Construct cylinder with specified bottom center.
		/// @param R Radius
		/// @param H Height
		/// @param center Bottom center point
		/// @param numSegments Circumferential divisions (default 20)

		Cylinder3D(Real R, Real H, const Pnt3Cart& center, int numSegments = 20)
			: _R(R)
			, _H(H)
			, _center(center)
			, _numSegments(numSegments) {
			constructSurfaces();
		}
		/// @}

		/// @name Surface Generation
		/// @{

		/// /** @brief Generate triangles for caps and lateral surface. */

		void constructSurfaces() {
			_surfaces.clear();
			Real angleStep = 2.0 * Constants::PI / _numSegments;

			Pnt3Cart bottomCenter(_center.X(), _center.Y(), _center.Z());
			Pnt3Cart topCenter(_center.X(), _center.Y(), _center.Z() + _H);

			for (int i = 0; i < _numSegments; ++i) {
				Real angle1 = i * angleStep;
				Real angle2 = (i + 1) * angleStep;

				// Points on bottom circle
				Pnt3Cart b1(_center.X() + _R * std::cos(angle1), _center.Y() + _R * std::sin(angle1), _center.Z());
				Pnt3Cart b2(_center.X() + _R * std::cos(angle2), _center.Y() + _R * std::sin(angle2), _center.Z());

				// Points on top circle
				Pnt3Cart t1(_center.X() + _R * std::cos(angle1), _center.Y() + _R * std::sin(angle1), _center.Z() + _H);
				Pnt3Cart t2(_center.X() + _R * std::cos(angle2), _center.Y() + _R * std::sin(angle2), _center.Z() + _H);

				// Bottom cap (CCW when viewed from above)
				_surfaces.emplace_back(bottomCenter, b2, b1);

				// Top cap (CCW when viewed from below)
				_surfaces.emplace_back(topCenter, t1, t2);

				// Lateral surface (two triangles per segment)
				_surfaces.emplace_back(b1, b2, t2);
				_surfaces.emplace_back(b1, t2, t1);
			}
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			Real x = pnt.X() - _center.X();
			Real y = pnt.Y() - _center.Y();
			Real z = pnt.Z() - _center.Z();

			// Height check
			if (z < 0.0 || z > _H)
				return false;

			// Circular cross-section check
			Real distSq = x * x + y * y;
			return distSq <= _R * _R;
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = πR²H */

		Real Volume() const override { return Constants::PI * _R * _R * _H; }

		/// /** @brief Surface area = 2πR² + 2πRH */

		Real SurfaceArea() const override { return 2.0 * Constants::PI * _R * _R + 2.0 * Constants::PI * _R * _H; }

		/// /** @brief Return geometric center (middle of cylinder). */

		Pnt3Cart GetCenter() const override { return Pnt3Cart(_center.X(), _center.Y(), _center.Z() + _H / 2.0); }

		Box3D GetBoundingBox() const override {
			Pnt3Cart min(_center.X() - _R, _center.Y() - _R, _center.Z());
			Pnt3Cart max(_center.X() + _R, _center.Y() + _R, _center.Z() + _H);
			return Box3D(min, max);
		}

		/// /** @brief Bounding sphere radius = √(R² + (H/2)²) */

		BoundingSphere3D GetBoundingSphere() const override {
			Pnt3Cart geomCenter = GetCenter();
			Real halfH = _H / 2.0;
			Real radius = std::sqrt(_R * _R + halfH * halfH);
			return BoundingSphere3D(geomCenter, radius);
		}

		std::string ToString() const override {
			std::ostringstream oss;
			Pnt3Cart geomCenter = GetCenter();
			oss << "Cylinder3D{Center=(" << geomCenter.X() << ", " << geomCenter.Y() << ", " << geomCenter.Z() << "), Radius=" << _R
				<< ", Height=" << _H << ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << "}";
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		Real GetRadius() const { return _R; }
		Real GetHeight() const { return _H; }
		Pnt3Cart GetBaseCenter() const { return _center; }
		int GetNumSegments() const { return _numSegments; }
		/// @}
	};

} // namespace MML


///////////////////////////   mml/base/Geometry/Geometry3DBodiesCore/Geometry3DSpherePyramid.h   ///////////////////////////

/// @file Geometry3DSpherePyramid.h
/// @brief Sphere and Pyramid solid body representations.
/// - Sphere3D: UV-sphere with triangular surface mesh
/// - Pyramid3D: Square-based pyramid with triangular faces
/// - PyramidEquilateral3D: Equilateral pyramid (all edges equal)
/// @see Geometry3DBodies.h for the aggregate header




namespace MML {

	/// @brief Sphere with triangular surface mesh.
	/// UV-sphere parameterization with latitude/longitude divisions.
	/// Special handling at poles to avoid degenerate triangles.
	/// @note Formulas:
	/// - Volume = (4/3)πR³
	/// - Surface Area = 4πR²

	class Sphere3D : public BodyWithTriangleSurfaces {
		Real _R;		   ///< Radius
		Pnt3Cart _center;  ///< Center point
		int _numLatitude;  ///< Latitude divisions (θ: 0 to π)
		int _numLongitude; ///< Longitude divisions (φ: 0 to 2π)
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct sphere centered at origin.
		/// @param R Radius
		/// @param numLatitude Latitude divisions (default 16)
		/// @param numLongitude Longitude divisions (default 20)

		Sphere3D(Real R, int numLatitude = 16, int numLongitude = 20)
			: _R(R)
			, _center(0, 0, 0)
			, _numLatitude(numLatitude)
			, _numLongitude(numLongitude) {
			constructSurfaces();
		}

		/// @brief Construct sphere centered at specified point.
		/// @param R Radius
		/// @param center Center point
		/// @param numLatitude Latitude divisions (default 16)
		/// @param numLongitude Longitude divisions (default 20)

		Sphere3D(Real R, const Pnt3Cart& center, int numLatitude = 16, int numLongitude = 20)
			: _R(R)
			, _center(center)
			, _numLatitude(numLatitude)
			, _numLongitude(numLongitude) {
			constructSurfaces();
		}
		/// @}

		/// @name Surface Generation
		/// @{

		/// /** @brief Generate triangles for the sphere surface. */

		void constructSurfaces() {
			_surfaces.clear();
			Real dTheta = Constants::PI / _numLatitude;
			Real dPhi = 2.0 * Constants::PI / _numLongitude;

			for (int i = 0; i < _numLatitude; ++i) {
				Real theta1 = i * dTheta;
				Real theta2 = (i + 1) * dTheta;

				for (int j = 0; j < _numLongitude; ++j) {
					Real phi1 = j * dPhi;
					Real phi2 = (j + 1) * dPhi;

					Pnt3Cart p1 = spherePoint(theta1, phi1);
					Pnt3Cart p2 = spherePoint(theta1, phi2);
					Pnt3Cart p3 = spherePoint(theta2, phi2);
					Pnt3Cart p4 = spherePoint(theta2, phi1);

					// Special pole handling (avoid degenerate triangles)
					if (i == 0) {
						// Top pole: single triangle
						_surfaces.emplace_back(p1, p4, p3);
					} else if (i == _numLatitude - 1) {
						// Bottom pole: single triangle
						_surfaces.emplace_back(p1, p2, p3);
					} else {
						// Regular patch: two triangles
						_surfaces.emplace_back(p1, p2, p3);
						_surfaces.emplace_back(p1, p3, p4);
					}
				}
			}
		}

		/// @brief Compute point on sphere surface.
		/// @param theta Latitude angle [0, π] (0 = north pole)
		/// @param phi Longitude angle [0, 2π]

		Pnt3Cart spherePoint(Real theta, Real phi) const {
			Real x = _R * std::sin(theta) * std::cos(phi);
			Real y = _R * std::sin(theta) * std::sin(phi);
			Real z = _R * std::cos(theta);
			return Pnt3Cart(_center.X() + x, _center.Y() + y, _center.Z() + z);
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			Real dx = pnt.X() - _center.X();
			Real dy = pnt.Y() - _center.Y();
			Real dz = pnt.Z() - _center.Z();
			Real distSq = dx * dx + dy * dy + dz * dz;
			return distSq <= _R * _R;
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = (4/3)πR³ */

		Real Volume() const override { return (4.0 / 3.0) * Constants::PI * _R * _R * _R; }

		/// /** @brief Surface area = 4πR² */

		Real SurfaceArea() const override { return 4.0 * Constants::PI * _R * _R; }

		Pnt3Cart GetCenter() const override { return _center; }

		Box3D GetBoundingBox() const override {
			Pnt3Cart min(_center.X() - _R, _center.Y() - _R, _center.Z() - _R);
			Pnt3Cart max(_center.X() + _R, _center.Y() + _R, _center.Z() + _R);
			return Box3D(min, max);
		}

		/// /** @brief Bounding sphere = the sphere itself. */

		BoundingSphere3D GetBoundingSphere() const override { return BoundingSphere3D(_center, _R); }

		std::string ToString() const override {
			std::ostringstream oss;
			oss << "Sphere3D{Center=(" << _center.X() << ", " << _center.Y() << ", " << _center.Z() << "), Radius=" << _R
				<< ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << "}";
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		Real GetRadius() const { return _R; }
		int GetNumLatitude() const { return _numLatitude; }
		int GetNumLongitude() const { return _numLongitude; }
		/// @}
	};

	/// @brief Square-based pyramid with triangular surface mesh.
	/// Pyramid with square base in XY plane and apex at (0, 0, h).
	/// Base is centered at origin (or specified center), extending ±a/2 in X and Y.
	/// @note Formulas:
	/// - Volume = (1/3)a²h
	/// - Surface Area = a² + 2as (s = slant height = √(h² + (a/2)²))

	class Pyramid3D : public BodyWithTriangleSurfaces {
		Real _a;		  ///< Base side length
		Real _h;		  ///< Pyramid height
		Vec3Cart _center; ///< Base center
	public:
		/// @name Constructors
		/// @{

		/// @brief Construct pyramid with base centered at origin.
		/// @param a Base side length
		/// @param h Height (apex at z = h)

		Pyramid3D(Real a, Real h)
			: _a(a)
			, _h(h)
			, _center(0, 0, 0) {
			Pnt3Cart pnt1(a / 2, -a / 2, -a / 2);
			Pnt3Cart pnt2(a / 2, a / 2, -a / 2);
			Pnt3Cart pnt3(-a / 2, a / 2, -a / 2);
			Pnt3Cart pnt4(-a / 2, -a / 2, -a / 2);
			Pnt3Cart pnt5(0, 0, h); // apex

			_surfaces.push_back(TriangleSurface3D(pnt1, pnt4, pnt3)); // base triangle 1
			_surfaces.push_back(TriangleSurface3D(pnt1, pnt3, pnt2)); // base triangle 2
			_surfaces.push_back(TriangleSurface3D(pnt5, pnt1, pnt2)); // front face
			_surfaces.push_back(TriangleSurface3D(pnt5, pnt2, pnt3)); // right face
			_surfaces.push_back(TriangleSurface3D(pnt5, pnt3, pnt4)); // back face
			_surfaces.push_back(TriangleSurface3D(pnt5, pnt4, pnt1)); // left face
		}

		/// @brief Construct pyramid with base centered at specified point.
		/// @param a Base side length
		/// @param h Height
		/// @param center Base center point

		Pyramid3D(Real a, Real h, const Vec3Cart& center)
			: Pyramid3D(a, h) {
			_center = center;
		}
		/// @}

		/// @name Containment Test
		/// @{

		bool IsInside(const Pnt3Cart& pnt) const override {
			// Translate relative to center
			Real x = pnt.X() - _center.X();
			Real y = pnt.Y() - _center.Y();
			Real z = pnt.Z() - _center.Z();

			// Height bounds
			if (z < 0.0 || z > _h)
				return false;

			// Cross-section shrinks linearly from base to apex
			Real half_side = (_a / 2.0) * (1.0 - z / _h);

			return (std::abs(x) <= half_side && std::abs(y) <= half_side);
		}
		/// @}

		/// @name IBody Interface
		/// @{

		/// /** @brief Volume = (1/3)a²h */

		Real Volume() const override { return (_a * _a * _h) / 3.0; }

		/// /** @brief Surface area = a² + 2as where s = √(h² + (a/2)²) */

		Real SurfaceArea() const override {
			Real slant_height = std::sqrt(_h * _h + (_a / 2.0) * (_a / 2.0));
			return _a * _a + 2.0 * _a * slant_height;
		}

		/// /** @brief Centroid at 1/4 height from base. */

		Pnt3Cart GetCenter() const override { return Pnt3Cart(_center.X(), _center.Y(), _center.Z() + _h / 4.0); }

		Box3D GetBoundingBox() const override {
			Real half_a = _a / 2.0;
			Pnt3Cart min(_center.X() - half_a, _center.Y() - half_a, _center.Z());
			Pnt3Cart max(_center.X() + half_a, _center.Y() + half_a, _center.Z() + _h);
			return Box3D(min, max);
		}

		BoundingSphere3D GetBoundingSphere() const override {
			Pnt3Cart geomCenter = GetCenter();
			Real half_a = _a / 2.0;

			// Distance from centroid to base corner
			Real distToBaseCorner = std::sqrt(half_a * half_a + half_a * half_a + (_h / 4.0) * (_h / 4.0));

			// Distance from centroid to apex (dz = 3h/4)
			Real distToApex = (3.0 * _h) / 4.0;

			Real radius = std::max(distToBaseCorner, distToApex);
			return BoundingSphere3D(geomCenter, radius);
		}

		std::string ToString() const override {
			std::ostringstream oss;
			Pnt3Cart geomCenter = GetCenter();
			oss << "Pyramid3D{Center=(" << geomCenter.X() << ", " << geomCenter.Y() << ", " << geomCenter.Z() << "), BaseSize=" << _a
				<< ", Height=" << _h << ", Volume=" << Volume() << ", SurfaceArea=" << SurfaceArea() << "}";
			return oss.str();
		}
		/// @}

		/// @name Accessors
		/// @{

		Real GetBaseSize() const { return _a; }
		Real GetHeight() const { return _h; }
		Vec3Cart GetBaseCenter() const { return _center; }
		/// @}
	};

	/// @brief Equilateral pyramid (height = a/√3).
	/// Special case of Pyramid3D with all edges equal length.

	class PyramidEquilateral3D : public Pyramid3D {
	public:
		/// @brief Construct equilateral pyramid centered at origin.
		/// @param a Base side length (height = a/√3)

		PyramidEquilateral3D(Real a)
			: Pyramid3D(a, a / sqrt(3)) {}

		/// @brief Construct equilateral pyramid centered at specified point.
		/// @param a Base side length
		/// @param center Base center point

		PyramidEquilateral3D(Real a, const Vec3Cart& center)
			: Pyramid3D(a, a / sqrt(3), center) {}

		std::string ToString() const override {
			std::ostringstream oss;
			Vec3Cart baseCenter = GetBaseCenter();
			oss << "PyramidEquilateral3D (Equilateral triangular base): Center=(" << baseCenter.X() << ", " << baseCenter.Y() << ", "
				<< baseCenter.Z() << ")"
				<< ", BaseSize=" << GetBaseSize() << ", Height=" << GetHeight() << ", Volume=" << Volume()
				<< ", SurfaceArea=" << SurfaceArea();
			return oss.str();
		}
	};

} // namespace MML


