namespace MML
{
	///////////////////////////////////////////////////////////////////////////
	///                    IterativeSolverConfig                            ///
	///////////////////////////////////////////////////////////////////////////
	/**
	 * @brief Configuration for iterative linear equation solvers
	 * 
	 * Standardized config object following API Standardization Phase 5 pattern.
	 */
	struct IterativeSolverConfig
	{
		Real tolerance = 1e-10;       ///< Convergence tolerance
		int max_iterations = 1000;    ///< Maximum iterations
		Real omega = 1.0;             ///< Relaxation parameter (for SOR, 0 < omega < 2)
		bool verbose = false;         ///< Enable verbose output

		/// Default constructor
		IterativeSolverConfig() = default;

		/// Constructor with tolerance and max iterations
		IterativeSolverConfig(Real tol, int max_iter = 1000)
			: tolerance(tol)
			, max_iterations(max_iter) {}

		/// Factory: High precision configuration
		static IterativeSolverConfig HighPrecision() {
			IterativeSolverConfig cfg;
			cfg.tolerance = 1e-14;
			cfg.max_iterations = 10000;
			return cfg;
		}

		/// Factory: Fast configuration (lower precision, fewer iterations)
		static IterativeSolverConfig Fast() {
			IterativeSolverConfig cfg;
			cfg.tolerance = 1e-6;
			cfg.max_iterations = 200;
			return cfg;
		}

		/// Factory: SOR configuration with optimal omega
		static IterativeSolverConfig SOR(Real omega_val) {
			IterativeSolverConfig cfg;
			cfg.omega = omega_val;
			return cfg;
		}
	};

	///////////////////////////////////////////////////////////////////////////
	///                    IterativeSolverResult                            ///
	///////////////////////////////////////////////////////////////////////////
	/**
	 * @brief Result structure for iterative linear equation solvers
	 * 
	 * Contains solution vector along with convergence information.
	 * Enhanced with diagnostic fields for API Standardization Phase 5.
	 */
	struct IterativeSolverResult
	{
		Vector<Real> solution;      ///< Solution vector x
		int          iterations;    ///< Number of iterations performed
		Real         residual;      ///< Final residual norm ||Ax - b||
		bool         converged;     ///< True if converged within tolerance
		
		// Enhanced diagnostic fields (API Standardization Phase 5)
		std::string algorithm_name;  ///< Name of the algorithm used
		AlgorithmStatus status = AlgorithmStatus::Success;  ///< Algorithm termination status
		std::string error_message;   ///< Error message if failed
		double elapsed_time_ms = 0;  ///< Execution time in milliseconds
		Real initial_residual = 0;   ///< Initial residual norm (before iterations)
		Real omega_used = 0;         ///< Relaxation parameter used (for SOR)
		
		IterativeSolverResult() : iterations(0), residual(0.0), converged(false) {}
		IterativeSolverResult(const Vector<Real>& sol, int iter, Real res, bool conv)
			: solution(sol), iterations(iter), residual(res), converged(conv) {}
	};

	/**
	 * @brief Jacobi iterative method for solving linear systems Ax = b
	 * 
	 * The Jacobi method is a classical iterative technique that updates each component
	 * of the solution using only values from the previous iteration:
	 * 
	 *   x_i^(k+1) = (1/a_ii) * (b_i - Σ_{j≠i} a_ij * x_j^(k))
	 * 
	 * @par Convergence Properties:
	 * - Guaranteed to converge for strictly diagonally dominant matrices
	 * - Converges for symmetric positive definite matrices
	 * - Each iteration can be parallelized (all updates independent)
	 * - Generally slower than Gauss-Seidel but more parallelizable
	 * 
	 * @par Convergence Rate:
	 * The spectral radius ρ(D⁻¹(L+U)) determines convergence rate.
	 * For tridiagonal Poisson: ρ ≈ 1 - π²/(2n²), very slow for large n.
	 * 
	 * @see GaussSeidelSolver, SORSolver
	 */
	class JacobiSolver
	{
	public:
		/**
		 * @brief Solve Ax = b using Jacobi iteration
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @param tol Convergence tolerance for relative residual ||Ax-b||/||b||
		 * @param maxIter Maximum number of iterations
		 * @return IterativeSolverResult containing solution and convergence info
		 * 
		 * @throws MatrixDimensionError if dimensions don't match
		 * @throws SingularMatrixError if any diagonal element is zero
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    const Vector<Real>& x0 = Vector<Real>(),
		                                    Real tol = 1e-10,
		                                    int maxIter = 1000)
		{
			int n = A.rows();
			
			// Dimension checks
			if (A.cols() != n)
				throw MatrixDimensionError("JacobiSolver::Solve - matrix must be square", n, A.cols(), -1, -1);
			if (b.size() != n)
				throw MatrixDimensionError("JacobiSolver::Solve - vector b dimension mismatch", n, n, b.size(), -1);
			
			// Check for near-zero diagonal elements (tolerance-based)
			Real maxDiag = Real{0};
			for (int i = 0; i < n; i++) { Real mag = std::abs(A(i, i)); if (mag > maxDiag) maxDiag = mag; }
			Real diagTol = maxDiag * std::numeric_limits<Real>::epsilon();
			if (diagTol < std::numeric_limits<Real>::epsilon()) diagTol = std::numeric_limits<Real>::epsilon();
			for (int i = 0; i < n; i++)
			{
				if (std::abs(A(i, i)) < diagTol)
					throw SingularMatrixError("JacobiSolver::Solve - near-zero diagonal element at row " + std::to_string(i));
			}
			
			// Initialize solution vector
			Vector<Real> x(n);
			if (x0.size() == n)
				x = x0;
			else
				for (int i = 0; i < n; i++) x[i] = 0.0;
			
			Vector<Real> x_new(n);
			Real b_norm = b.NormL2();
			if (b_norm == 0.0) b_norm = 1.0;  // Avoid division by zero
			
			int iter = 0;
			Real residual = 0.0;
			bool converged = false;
			
			for (iter = 1; iter <= maxIter; iter++)
			{
				// Jacobi iteration: x_new[i] = (b[i] - sum_{j!=i} A[i][j]*x[j]) / A[i][i]
				for (int i = 0; i < n; i++)
				{
					Real sigma = 0.0;
					for (int j = 0; j < n; j++)
					{
						if (j != i)
							sigma += A(i, j) * x[j];
					}
					x_new[i] = (b[i] - sigma) / A(i, i);
				}
				
				// Compute residual ||Ax_new - b||
				Vector<Real> r = A * x_new - b;
				residual = r.NormL2() / b_norm;
				
				// Check convergence
				if (residual < tol)
				{
					converged = true;
					x = x_new;
					break;
				}
				
				// Update for next iteration
				x = x_new;
			}
			
			return IterativeSolverResult(x, iter, residual, converged);
		}
		
		/**
		 * @brief Simple solve returning only solution vector
		 * @throws std::runtime_error if solver doesn't converge
		 */
		static Vector<Real> SolveSimple(const Matrix<Real>& A, 
		                                 const Vector<Real>& b,
		                                 Real tol = 1e-10,
		                                 int maxIter = 1000)
		{
			auto result = Solve(A, b, Vector<Real>(), tol, maxIter);
			if (!result.converged)
				throw ConvergenceError("JacobiSolver::SolveSimple - failed to converge after " + 
				                       std::to_string(result.iterations) + " iterations",
				                       result.iterations, result.residual);
			return result.solution;
		}

		/**
		 * @brief Solve Ax = b using Jacobi iteration with config object
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param config Solver configuration
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @return IterativeSolverResult with enhanced diagnostics
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    const IterativeSolverConfig& config,
		                                    const Vector<Real>& x0 = Vector<Real>())
		{
			AlgorithmTimer timer;
			IterativeSolverResult result = Solve(A, b, x0, config.tolerance, config.max_iterations);
			
			result.algorithm_name = "Jacobi";
			result.elapsed_time_ms = timer.elapsed_ms();
			if (!result.converged) {
				result.status = AlgorithmStatus::MaxIterationsExceeded;
				result.error_message = "Jacobi method did not converge within " + 
				                       std::to_string(config.max_iterations) + " iterations";
			}
			return result;
		}
	};

	/**
	 * @brief Gauss-Seidel iterative method for solving linear systems Ax = b
	 * 
	 * The Gauss-Seidel method improves on Jacobi by using updated values
	 * immediately as they are computed:
	 * 
	 *   x_i^(k+1) = (1/a_ii) * (b_i - Σ_{j<i} a_ij * x_j^(k+1) - Σ_{j>i} a_ij * x_j^(k))
	 * 
	 * @par Convergence Properties:
	 * - Guaranteed to converge for strictly diagonally dominant matrices
	 * - Guaranteed to converge for symmetric positive definite matrices
	 * - Generally converges faster than Jacobi (about 2x for many problems)
	 * - Cannot be easily parallelized (sequential dependencies)
	 * 
	 * @par Convergence Rate:
	 * The spectral radius ρ((D+L)⁻¹U) determines convergence rate.
	 * For tridiagonal Poisson: ρ_GS ≈ ρ_J², roughly twice as fast as Jacobi.
	 * 
	 * @see JacobiSolver, SORSolver
	 */
	class GaussSeidelSolver
	{
	public:
		/**
		 * @brief Solve Ax = b using Gauss-Seidel iteration
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @param tol Convergence tolerance for relative residual ||Ax-b||/||b||
		 * @param maxIter Maximum number of iterations
		 * @return IterativeSolverResult containing solution and convergence info
		 * 
		 * @throws MatrixDimensionError if dimensions don't match
		 * @throws SingularMatrixError if any diagonal element is zero
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    const Vector<Real>& x0 = Vector<Real>(),
		                                    Real tol = 1e-10,
		                                    int maxIter = 1000)
		{
			int n = A.rows();
			
			// Dimension checks
			if (A.cols() != n)
				throw MatrixDimensionError("GaussSeidelSolver::Solve - matrix must be square", n, A.cols(), -1, -1);
			if (b.size() != n)
				throw MatrixDimensionError("GaussSeidelSolver::Solve - vector b dimension mismatch", n, n, b.size(), -1);
			
			// Check for near-zero diagonal elements (tolerance-based)
			Real maxDiag = Real{0};
			for (int i = 0; i < n; i++) { Real mag = std::abs(A(i, i)); if (mag > maxDiag) maxDiag = mag; }
			Real diagTol = maxDiag * std::numeric_limits<Real>::epsilon();
			if (diagTol < std::numeric_limits<Real>::epsilon()) diagTol = std::numeric_limits<Real>::epsilon();
			for (int i = 0; i < n; i++)
			{
				if (std::abs(A(i, i)) < diagTol)
					throw SingularMatrixError("GaussSeidelSolver::Solve - near-zero diagonal element at row " + std::to_string(i));
			}
			
			// Initialize solution vector
			Vector<Real> x(n);
			if (x0.size() == n)
				x = x0;
			else
				for (int i = 0; i < n; i++) x[i] = 0.0;
			
			Real b_norm = b.NormL2();
			if (b_norm == 0.0) b_norm = 1.0;
			
			int iter = 0;
			Real residual = 0.0;
			bool converged = false;
			
			for (iter = 1; iter <= maxIter; iter++)
			{
				// Gauss-Seidel iteration: use updated values immediately
				for (int i = 0; i < n; i++)
				{
					Real sigma = 0.0;
					// Use new values for j < i (already computed this iteration)
					for (int j = 0; j < i; j++)
						sigma += A(i, j) * x[j];
					// Use old values for j > i
					for (int j = i + 1; j < n; j++)
						sigma += A(i, j) * x[j];
					
					x[i] = (b[i] - sigma) / A(i, i);
				}
				
				// Compute residual ||Ax - b||
				Vector<Real> r = A * x - b;
				residual = r.NormL2() / b_norm;
				
				// Check convergence
				if (residual < tol)
				{
					converged = true;
					break;
				}
			}
			
			return IterativeSolverResult(x, iter, residual, converged);
		}
		
		/**
		 * @brief Simple solve returning only solution vector
		 * @throws std::runtime_error if solver doesn't converge
		 */
		static Vector<Real> SolveSimple(const Matrix<Real>& A, 
		                                 const Vector<Real>& b,
		                                 Real tol = 1e-10,
		                                 int maxIter = 1000)
		{
			auto result = Solve(A, b, Vector<Real>(), tol, maxIter);
			if (!result.converged)
				throw ConvergenceError("GaussSeidelSolver::SolveSimple - failed to converge after " + 
				                       std::to_string(result.iterations) + " iterations",
				                       result.iterations, result.residual);
			return result.solution;
		}

		/**
		 * @brief Solve Ax = b using Gauss-Seidel with config object
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param config Solver configuration
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @return IterativeSolverResult with enhanced diagnostics
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    const IterativeSolverConfig& config,
		                                    const Vector<Real>& x0 = Vector<Real>())
		{
			AlgorithmTimer timer;
			IterativeSolverResult result = Solve(A, b, x0, config.tolerance, config.max_iterations);
			
			result.algorithm_name = "GaussSeidel";
			result.elapsed_time_ms = timer.elapsed_ms();
			if (!result.converged) {
				result.status = AlgorithmStatus::MaxIterationsExceeded;
				result.error_message = "Gauss-Seidel method did not converge within " + 
				                       std::to_string(config.max_iterations) + " iterations";
			}
			return result;
		}
	};

	/**
	 * @brief Successive Over-Relaxation (SOR) method for solving linear systems Ax = b
	 * 
	 * SOR is a generalization of Gauss-Seidel that introduces a relaxation parameter ω:
	 * 
	 *   x_i^(k+1) = (1-ω)*x_i^(k) + (ω/a_ii) * (b_i - Σ_{j<i} a_ij * x_j^(k+1) - Σ_{j>i} a_ij * x_j^(k))
	 * 
	 * or equivalently:
	 *   x_i^(k+1) = x_i^(k) + ω * (x_i^GS - x_i^(k))
	 * 
	 * where x_i^GS is the Gauss-Seidel update.
	 * 
	 * @par Relaxation Parameter ω:
	 * - ω = 1: Reduces to Gauss-Seidel
	 * - 0 < ω < 1: Under-relaxation (can help convergence for some problems)
	 * - 1 < ω < 2: Over-relaxation (can significantly accelerate convergence)
	 * - ω ≥ 2 or ω ≤ 0: Method diverges
	 * 
	 * @par Optimal ω Selection:
	 * For tridiagonal systems from Poisson equation:
	 *   ω_opt = 2 / (1 + sin(π/n)) ≈ 2 - 2π/n
	 * 
	 * This can reduce iterations from O(n²) to O(n).
	 * 
	 * @par Convergence Properties:
	 * - Converges for 0 < ω < 2 if A is symmetric positive definite
	 * - With optimal ω, convergence can be dramatically faster than Gauss-Seidel
	 * 
	 * @see JacobiSolver, GaussSeidelSolver
	 */
	class SORSolver
	{
	public:
		/**
		 * @brief Solve Ax = b using Successive Over-Relaxation
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param omega Relaxation parameter (0 < ω < 2 for convergence)
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @param tol Convergence tolerance for relative residual ||Ax-b||/||b||
		 * @param maxIter Maximum number of iterations
		 * @return IterativeSolverResult containing solution and convergence info
		 * 
		 * @throws MatrixDimensionError if dimensions don't match
		 * @throws SingularMatrixError if any diagonal element is zero
		 * @throws std::invalid_argument if omega not in (0, 2)
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    Real omega,
		                                    const Vector<Real>& x0 = Vector<Real>(),
		                                    Real tol = 1e-10,
		                                    int maxIter = 1000)
		{
			// Validate omega
			if (omega <= 0.0 || omega >= 2.0)
				throw NumericalMethodError("SORSolver::Solve - omega must be in (0, 2), got " + std::to_string(omega));
			
			int n = A.rows();
			
			// Dimension checks
			if (A.cols() != n)
				throw MatrixDimensionError("SORSolver::Solve - matrix must be square", n, A.cols(), -1, -1);
			if (b.size() != n)
				throw MatrixDimensionError("SORSolver::Solve - vector b dimension mismatch", n, n, b.size(), -1);
			
			// Check for near-zero diagonal elements (tolerance-based)
			Real maxDiag = Real{0};
			for (int i = 0; i < n; i++) { Real mag = std::abs(A(i, i)); if (mag > maxDiag) maxDiag = mag; }
			Real diagTol = maxDiag * std::numeric_limits<Real>::epsilon();
			if (diagTol < std::numeric_limits<Real>::epsilon()) diagTol = std::numeric_limits<Real>::epsilon();
			for (int i = 0; i < n; i++)
			{
				if (std::abs(A(i, i)) < diagTol)
					throw SingularMatrixError("SORSolver::Solve - near-zero diagonal element at row " + std::to_string(i));
			}
			
			// Initialize solution vector
			Vector<Real> x(n);
			if (x0.size() == n)
				x = x0;
			else
				for (int i = 0; i < n; i++) x[i] = 0.0;
			
			Real b_norm = b.NormL2();
			if (b_norm == 0.0) b_norm = 1.0;
			
			int iter = 0;
			Real residual = 0.0;
			bool converged = false;
			
			for (iter = 1; iter <= maxIter; iter++)
			{
				// SOR iteration
				for (int i = 0; i < n; i++)
				{
					Real sigma = 0.0;
					// Use new values for j < i
					for (int j = 0; j < i; j++)
						sigma += A(i, j) * x[j];
					// Use old values for j > i
					for (int j = i + 1; j < n; j++)
						sigma += A(i, j) * x[j];
					
					// Gauss-Seidel update
					Real x_gs = (b[i] - sigma) / A(i, i);
					
					// SOR: weighted average of old value and Gauss-Seidel update
					x[i] = (1.0 - omega) * x[i] + omega * x_gs;
				}
				
				// Compute residual ||Ax - b||
				Vector<Real> r = A * x - b;
				residual = r.NormL2() / b_norm;
				
				// Check convergence
				if (residual < tol)
				{
					converged = true;
					break;
				}
			}
			
			return IterativeSolverResult(x, iter, residual, converged);
		}
		
		/**
		 * @brief Solve with automatic omega selection for tridiagonal systems
		 * 
		 * Uses the optimal ω formula: ω = 2 / (1 + sin(π/n))
		 * This is optimal for tridiagonal systems from discretized Poisson equation.
		 * For other systems, may not be optimal but often gives good results.
		 */
		static IterativeSolverResult SolveOptimal(const Matrix<Real>& A, 
		                                           const Vector<Real>& b,
		                                           const Vector<Real>& x0 = Vector<Real>(),
		                                           Real tol = 1e-10,
		                                           int maxIter = 1000)
		{
			int n = A.rows();
			Real omega = 2.0 / (1.0 + std::sin(Constants::PI / n));
			return Solve(A, b, omega, x0, tol, maxIter);
		}
		
		/**
		 * @brief Simple solve returning only solution vector
		 * @throws std::runtime_error if solver doesn't converge
		 */
		static Vector<Real> SolveSimple(const Matrix<Real>& A, 
		                                 const Vector<Real>& b,
		                                 Real omega,
		                                 Real tol = 1e-10,
		                                 int maxIter = 1000)
		{
			auto result = Solve(A, b, omega, Vector<Real>(), tol, maxIter);
			if (!result.converged)
				throw ConvergenceError("SORSolver::SolveSimple - failed to converge after " + 
				                       std::to_string(result.iterations) + " iterations",
				                       result.iterations, result.residual);
			return result.solution;
		}
		
		/**
		 * @brief Estimate optimal omega empirically by trying several values
		 * 
		 * Performs a small number of iterations with different omega values
		 * and returns the one that gives the smallest residual.
		 * 
		 * @param A Coefficient matrix
		 * @param b Right-hand side vector
		 * @param numSamples Number of omega values to try (default 10)
		 * @param testIter Number of iterations for each test (default 50)
		 * @return Estimated optimal omega value
		 */
		static Real EstimateOptimalOmega(const Matrix<Real>& A,
		                                  const Vector<Real>& b,
		                                  int numSamples = 10,
		                                  int testIter = 50)
		{
			Real bestOmega = 1.0;
			Real bestResidual = std::numeric_limits<Real>::max();
			
			// Try omega values from 1.0 to 1.95
			for (int i = 0; i <= numSamples; i++)
			{
				Real omega = 1.0 + 0.95 * i / numSamples;
				auto result = Solve(A, b, omega, Vector<Real>(), PrecisionValues<Real>::EigenSolverZeroThreshold, testIter);
				if (result.residual < bestResidual)
				{
					bestResidual = result.residual;
					bestOmega = omega;
				}
			}
			
			return bestOmega;
		}

		/**
		 * @brief Solve Ax = b using SOR with config object
		 * 
		 * @param A Coefficient matrix (must be square, non-zero diagonal)
		 * @param b Right-hand side vector
		 * @param config Solver configuration (omega from config.omega)
		 * @param x0 Initial guess (if empty, uses zero vector)
		 * @return IterativeSolverResult with enhanced diagnostics
		 */
		static IterativeSolverResult Solve(const Matrix<Real>& A, 
		                                    const Vector<Real>& b,
		                                    const IterativeSolverConfig& config,
		                                    const Vector<Real>& x0 = Vector<Real>())
		{
			AlgorithmTimer timer;
			IterativeSolverResult result = Solve(A, b, config.omega, x0, config.tolerance, config.max_iterations);
			
			result.algorithm_name = "SOR";
			result.elapsed_time_ms = timer.elapsed_ms();
			result.omega_used = config.omega;
			if (!result.converged) {
				result.status = AlgorithmStatus::MaxIterationsExceeded;
				result.error_message = "SOR method (omega=" + std::to_string(config.omega) + 
				                       ") did not converge within " + 
				                       std::to_string(config.max_iterations) + " iterations";
			}
			return result;
		}
	};

} // namespace MML


///////////////////////////   mml/core/MatrixUtils.h   ///////////////////////////





namespace MML
{
	namespace Utils
	{
		// =========================================================================
		// MATRIX PROPERTY CHECKS (Simple O(n²) operations)
		// =========================================================================

		/**
		 * @brief Check if matrix H is upper Hessenberg within tolerance.
		 * 
		 * Upper Hessenberg: H(i,j) = 0 for all i > j + 1
		 * (all elements below the first subdiagonal are zero)
		 * 
		 * @param H Matrix to check
		 * @param tol Tolerance for zero comparison
		 * @return true if H is upper Hessenberg
		 */
		template<class Type>
		bool IsUpperHessenberg(const Matrix<Type>& H, Type tol = 1e-10)
		{
			int n = H.rows();
			for (int i = 2; i < n; i++)
				for (int j = 0; j < i - 1; j++)
					if (std::abs(H(i, j)) > tol)
						return false;
			return true;
		}

		/**
		 * @brief Check if matrix is upper triangular within tolerance.
		 * 
		 * @param A Matrix to check
		 * @param tol Tolerance for zero comparison
		 * @return true if A is upper triangular
		 */
		template<class Type>
		bool IsUpperTriangular(const Matrix<Type>& A, Type tol = 1e-10)
		{
			int n = A.rows();
			for (int i = 1; i < n; i++)
				for (int j = 0; j < i; j++)
					if (std::abs(A(i, j)) > tol)
						return false;
			return true;
		}

		/**
		 * @brief Check if matrix is lower triangular within tolerance.
		 * 
		 * @param A Matrix to check
		 * @param tol Tolerance for zero comparison
		 * @return true if A is lower triangular
		 */
		template<class Type>
		bool IsLowerTriangular(const Matrix<Type>& A, Type tol = 1e-10)
		{
			int n = A.rows();
			for (int i = 0; i < n; i++)
				for (int j = i + 1; j < n; j++)
					if (std::abs(A(i, j)) > tol)
						return false;
			return true;
		}

		/**
		 * @brief Check if matrix is diagonal within tolerance.
		 * 
		 * @param A Matrix to check
		 * @param tol Tolerance for zero comparison
		 * @return true if A is diagonal
		 */
		template<class Type>
		bool IsDiagonal(const Matrix<Type>& A, Type tol = 1e-10)
		{
			int n = A.rows();
			for (int i = 0; i < n; i++)
				for (int j = 0; j < n; j++)
					if (i != j && std::abs(A(i, j)) > tol)
						return false;
			return true;
		}

		/**
		 * @brief Check if matrix is symmetric within tolerance: A[i][j] ≈ A[j][i]
		 * 
		 * @param A Matrix to check
		 * @param tol Tolerance for comparison
		 * @return true if A is symmetric
		 */
		template<class Type>
		bool IsSymmetric(const Matrix<Type>& A, Type tol = 1e-10)
		{
			int n = A.rows();
			if (A.cols() != n) return false;  // Must be square
			
			for (int i = 0; i < n; i++)
				for (int j = i + 1; j < n; j++)
					if (std::abs(A(i, j) - A(j, i)) > tol)
						return false;
			return true;
		}

		/**
		 * @brief Check if matrix is skew-symmetric: A[i][j] ≈ -A[j][i]
		 * 
		 * @param A Matrix to check
		 * @param tol Tolerance for comparison
		 * @return true if A is skew-symmetric
		 */
		template<class Type>
		bool IsSkewSymmetric(const Matrix<Type>& A, Type tol = 1e-10)
		{
			int n = A.rows();
			if (A.cols() != n) return false;  // Must be square
			
			for (int i = 0; i < n; i++)
			{
				// Diagonal must be zero for skew-symmetric
				if (std::abs(A(i, i)) > tol)
					return false;
				for (int j = i + 1; j < n; j++)
					if (std::abs(A(i, j) + A(j, i)) > tol)
						return false;
			}
			return true;
		}

		// =========================================================================
		// MATRIX SCALAR QUANTITIES (Simple O(n²) operations)
		// =========================================================================

		/**
		 * @brief Compute trace (sum of diagonal elements)
		 * 
		 * @param A Input matrix
		 * @return Sum of diagonal elements
		 */
		template<class Type>
		Type Trace(const Matrix<Type>& A)
		{
			Type sum = 0;
			int n = std::min(A.rows(), A.cols());
			for (int i = 0; i < n; i++)
				sum += A(i, i);
			return sum;
		}

		/**
		 * @brief Compute Frobenius norm: ||A||_F = sqrt(sum of all a_ij²)
		 * 
		 * @param A Input matrix
		 * @return Frobenius norm
		 */
		template<class Type>
		Real FrobeniusNorm(const Matrix<Type>& A)
		{
			Real sum = 0.0;
			for (int i = 0; i < A.rows(); i++)
				for (int j = 0; j < A.cols(); j++)
					sum += std::abs(A(i, j)) * std::abs(A(i, j));
			return std::sqrt(sum);
		}

		/**
		 * @brief Compute infinity norm (maximum absolute row sum): ||A||_∞
		 * 
		 * @param A Input matrix
		 * @return Infinity norm
		 */
		template<class Type>
		Real InfinityNorm(const Matrix<Type>& A)
		{
			Real maxRowSum = 0.0;
			for (int i = 0; i < A.rows(); i++)
			{
				Real rowSum = 0.0;
				for (int j = 0; j < A.cols(); j++)
					rowSum += std::abs(A(i, j));
				maxRowSum = std::max(maxRowSum, rowSum);
			}
			return maxRowSum;
		}

		/**
		 * @brief Compute 1-norm (maximum absolute column sum): ||A||_1
		 * 
		 * @param A Input matrix
		 * @return 1-norm
		 */
		template<class Type>
		Real OneNorm(const Matrix<Type>& A)
		{
			Real maxColSum = 0.0;
			for (int j = 0; j < A.cols(); j++)
			{
				Real colSum = 0.0;
				for (int i = 0; i < A.rows(); i++)
					colSum += std::abs(A(i, j));
				maxColSum = std::max(maxColSum, colSum);
			}
			return maxColSum;
		}

		/**
		 * @brief Compute maximum absolute difference between two matrices
		 * 
		 * @param A First matrix
		 * @param B Second matrix
		 * @return Maximum |A(i,j) - B(i,j)|
		 */
		template<class Type>
		Real MaxAbsDiff(const Matrix<Type>& A, const Matrix<Type>& B)
		{
			Real maxDiff = 0.0;
			int rows = std::min(A.rows(), B.rows());
			int cols = std::min(A.cols(), B.cols());
			for (int i = 0; i < rows; i++)
				for (int j = 0; j < cols; j++)
					maxDiff = std::max(maxDiff, static_cast<Real>(std::abs(A(i, j) - B(i, j))));
			return maxDiff;
		}

		// =========================================================================
		// MATRIX TRANSFORMATIONS (Simple operations)
		// =========================================================================

		/**
		 * @brief Compute Q^T * A * Q (similarity transformation)
		 * 
		 * @param Q Transformation matrix
		 * @param A Matrix to transform
		 * @return Q^T * A * Q
		 */
		template<class Type>
		Matrix<Type> SimilarityTransform(const Matrix<Type>& Q, const Matrix<Type>& A)
		{
			int n = A.rows();
			Matrix<Type> temp(n, n);
			Matrix<Type> result(n, n);
			
			// temp = A * Q
			for (int i = 0; i < n; i++)
				for (int j = 0; j < n; j++)
				{
					temp(i, j) = 0;
					for (int k = 0; k < n; k++)
						temp(i, j) += A(i, k) * Q(k, j);
				}
			
			// result = Q^T * temp
			for (int i = 0; i < n; i++)
				for (int j = 0; j < n; j++)
				{
					result(i, j) = 0;
					for (int k = 0; k < n; k++)
						result(i, j) += Q(k, i) * temp(k, j);
				}
			
			return result;
		}

		// =========================================================================
		// SPECIAL MATRIX PROPERTIES (No solver dependencies)
		// =========================================================================

		/**
		 * @brief Check if matrix is nilpotent (A^n = 0 for some n)
		 */
		template<class Type>
		bool IsNilpotent(const Matrix<Type>& A)
		{
			int N = A.rows();
			if (N != A.cols())
				throw MatrixDimensionError("IsNilpotent - must be square matrix", N, A.cols(), -1, -1);
			
			Matrix<Type> M = A;
			for (int k = 1; k < N; k++)
			{
				M = A * M;
				if (M.isZero())
					return true;
			}
			return false;
		}

		/**
		 * @brief Check if matrix is unipotent ((A-I)^n = 0 for some n)
		 */
		template<class Type>
		bool IsUnipotent(const Matrix<Type>& A)
		{
			int N = A.rows();
			if (N != A.cols())
				throw MatrixDimensionError("IsUnipotent - must be square matrix", N, A.cols(), -1, -1);

			Matrix<Type> B = A - Matrix<Type>::Identity(N);
			Matrix<Type> M = B;
			for (int k = 1; k < N; k++)
			{
				if (M.isZero())
					return true;
				M = B * M;
			}
			return M.isZero();
		}

		/**
		 * @brief Faddeev-Leverrier algorithm for characteristic polynomial, determinant and inverse matrix
		 * 
		 * Computes the characteristic polynomial coefficients, determinant, and inverse of a square matrix.
		 * The inverse is only valid if the matrix is invertible (det != 0).
		 * 
		 * Characteristic polynomial: det(λI - A) = λ^n + c_{n-1}λ^{n-1} + ... + c_1λ + c_0
		 * where c_0 = (-1)^n * det(A)
		 */
		inline void FaddeevAlg(const Matrix<Real>& A, PolynomRealFunc& outCharPoly, Real& outDet, Matrix<Real>& outInv)
		{
			int N = A.rows();

			auto identMat = Matrix<Real>::Identity(N);
			Matrix<Real> nullMat(N, N);

			// Faddeev-Leverrier recurrence:
			// B_0 = I
			// c_{n-k} = -1/k * Tr(A * B_{k-1})  for k=1,...,n
			// B_k = A*B_{k-1} + c_{n-k}*I       for k=1,...,n
			// 
			// At the end: A^(-1) = -B_{n-1} / c_0 (when A is invertible)
			
			Vector<Matrix<Real>> B(N + 1, nullMat);
			outCharPoly.SetDegree(N);
			
			B[0] = identMat;
			outCharPoly[N] = 1.0;  // Leading coefficient is always 1
			
			for (int k = 1; k <= N; k++)
			{
				outCharPoly[N - k] = -1.0 / k * Trace(A * B[k - 1]);
				B[k] = A * B[k - 1] + outCharPoly[N - k] * identMat;
			}

			outDet = std::pow(-1.0, N) * outCharPoly[0];
			// A^(-1) = -B_{n-1} / c_0
			outInv = -B[N - 1] / outCharPoly[0];
		}

		// =========================================================================
		// RANK CALCULATION (Gaussian elimination - no external solver)
		// =========================================================================

		/**
		 * @brief Calculate the rank of a matrix using Gaussian elimination
		 * 
		 * Note: For numerical stability with ill-conditioned matrices,
		 * consider using MatrixAlg::Rank() which uses SVD.
		 */
		template<class Type>
		int RankGaussian(const Matrix<Type>& A, Real EPS = Defaults::RankAlgEPS)
		{
			int rows = A.rows();
			int cols = A.cols();
			Matrix<Type> mat = A;			// Make a copy to preserve the original

			int rank = 0;
			std::vector<bool> row_selected(rows, false);

			for (int col = 0; col < cols; ++col)
			{
				// Partial pivoting: find row with largest absolute value in this column
				int pivot_row = -1;
				Real best = 0;
				for (int row = 0; row < rows; ++row)
				{
					Real val = std::abs(mat(row, col));
					if (!row_selected[row] && val > EPS && val > best)
					{
						best = val;
						pivot_row = row;
					}
				}
				if (pivot_row == -1)
					continue;

				++rank;
				row_selected[pivot_row] = true;

				// Eliminate below
				for (int row = 0; row < rows; ++row)
				{
					if (row != pivot_row)
					{
						Type factor = mat(row, col) / mat(pivot_row, col);
						for (int k = col; k < cols; ++k)
							mat(row, k) -= factor * mat(pivot_row, k);
					}
				}
			}
			return rank;
		}

		// =========================================================================
		// DETERMINANT (uses LU decomposition)
		// =========================================================================

		/**
		 * @brief Calculate the determinant of a matrix using LU decomposition
		 * 
		 * Uses LU decomposition for efficient O(n³) computation.
		 * For singular matrices, returns 0 instead of throwing.
		 * 
		 * @param A Input matrix (must be square)
		 * @return Determinant value
		 */
		template<class Type>
		Type Det(const Matrix<Type>& A)
		{
			try
			{
				LUSolver<Type> lu(A);
				return lu.det();
			}
			catch(const SingularMatrixError&)
			{
				return Type(0);
			}
		}

		/**
		 * @brief Calculate the determinant of a fixed-size MatrixNM
		 * 
		 * Uses closed-form expressions for dimensions 1, 2, and 3 for maximum
		 * efficiency. For larger dimensions, converts to dynamic Matrix and uses
		 * LU decomposition.
		 * 
		 * @tparam Type Element type
		 * @tparam N    Matrix dimension (N×N)
		 * @param A     Input square MatrixNM
		 * @return      Determinant value
		 */
		template<class Type, int N>
		Type Det(const MatrixNM<Type, N, N>& A)
		{
			if constexpr (N == 1)
			{
				return A(0, 0);
			}
			else if constexpr (N == 2)
			{
				// |a b| = ad - bc
				// |c d|
				return A(0, 0) * A(1, 1) - A(0, 1) * A(1, 0);
			}
			else if constexpr (N == 3)
			{
				// Sarrus' rule (cofactor expansion along first row)
				return A(0, 0) * (A(1, 1) * A(2, 2) - A(1, 2) * A(2, 1))
				     - A(0, 1) * (A(1, 0) * A(2, 2) - A(1, 2) * A(2, 0))
				     + A(0, 2) * (A(1, 0) * A(2, 1) - A(1, 1) * A(2, 0));
			}
			else
			{
				// Convert to dynamic Matrix and use LU-based Det
				Matrix<Type> M(N, N);
				for (int i = 0; i < N; i++)
					for (int j = 0; j < N; j++)
						M(i, j) = A(i, j);
				return Det(M);
			}
		}

		// =========================================================================
		// SVD-BASED LINEAR ALGEBRA UTILITIES
		// =========================================================================

		/**
		 * @struct SVDResult
		 * @brief Result of SVD decomposition with linear algebra utilities
		 */
		struct SVDResult
		{
			Vector<Real> singularValues;  ///< Singular values in descending order
			Matrix<Real> U;               ///< Left singular vectors (m x n)
			Matrix<Real> V;               ///< Right singular vectors (n x n)
			int rank;                     ///< Numerical rank
			Real conditionNumber;         ///< Condition number (σ_max / σ_min)
			
			SVDResult() : rank(0), conditionNumber(0.0) {}
		};

		/**
		 * Compute SVD decomposition and derive linear algebra quantities.
		 * 
		 * Computes A = U * diag(σ) * V^T where:
		 * - U: m×n matrix of left singular vectors
		 * - σ: singular values in descending order
		 * - V: n×n matrix of right singular vectors
		 * 
		 * @param A Input matrix (m x n)
		 * @param tol Tolerance for rank determination
		 * @return SVDResult with singular values, U, V, rank, and condition number
		 */
		inline SVDResult ComputeSVD(const Matrix<Real>& A, Real tol = -1.0)
		{
			SVDecompositionSolver<Real> svd(A);
			SVDResult result;
			
			result.singularValues = svd.getW();
			result.U = svd.getU();
			result.V = svd.getV();
			result.rank = svd.Rank(tol);
			
			// Condition number = σ_max / σ_min
			int n = result.singularValues.size();
			if (n > 0 && result.singularValues[n-1] > 0)
				result.conditionNumber = result.singularValues[0] / result.singularValues[n-1];
			else
				result.conditionNumber = std::numeric_limits<Real>::infinity();
			
			return result;
		}

		/**
		 * Compute singular values of a matrix.
		 * 
		 * @param A Input matrix
		 * @return Vector of singular values in descending order
		 */
		inline Vector<Real> SingularValues(const Matrix<Real>& A)
		{
			SVDecompositionSolver<Real> svd(A);
			return svd.getW();
		}

		/**
		 * Compute numerical rank of a matrix using SVD.
		 * 
		 * The rank is the number of singular values above the threshold.
		 * This is more numerically stable than Gaussian elimination for
		 * ill-conditioned matrices.
		 * 
		 * @param A Input matrix
		 * @param tol Threshold for zero singular values (-1 for automatic)
		 * @return Numerical rank
		 */
		inline int RankSVD(const Matrix<Real>& A, Real tol = -1.0)
		{
			SVDecompositionSolver<Real> svd(A);
			return svd.Rank(tol);
		}

		/**
		 * Compute nullity (dimension of null space) of a matrix.
		 * 
		 * Nullity = n - rank, where n is the number of columns.
		 * 
		 * @param A Input matrix
		 * @param tol Threshold for zero singular values
		 * @return Nullity (dimension of kernel)
		 */
		inline int Nullity(const Matrix<Real>& A, Real tol = -1.0)
		{
			SVDecompositionSolver<Real> svd(A);
			return svd.Nullity(tol);
		}

		/**
		 * Compute condition number of a matrix.
		 * 
		 * The condition number κ(A) = σ_max / σ_min measures how sensitive
		 * the solution of Ax = b is to perturbations in A and b.
		 * 
		 * - κ ≈ 1: Well-conditioned
		 * - κ >> 1: Ill-conditioned
		 * - κ = ∞: Singular matrix
		 * 
		 * Rule of thumb: You lose log10(κ) decimal digits of precision
		 * when solving linear systems.
		 * 
		 * @param A Input matrix
		 * @return Condition number (infinity if singular)
		 */
		inline Real ConditionNumber(const Matrix<Real>& A)
		{
			SVDecompositionSolver<Real> svd(A);
			Vector<Real> w = svd.getW();
			int n = w.size();
			
			if (n == 0 || w[n-1] <= 0.0)
				return std::numeric_limits<Real>::infinity();
			
			return w[0] / w[n-1];
		}

		/**
		 * Compute orthonormal basis for the null space (kernel) of A.
		 * 
		 * The null space is {x : Ax = 0}. The columns of the returned matrix
		 * form an orthonormal basis for this space.
		 * 
		 * @param A Input matrix (m x n)
		 * @param tol Threshold for zero singular values
		 * @return Matrix whose columns are orthonormal basis of null(A)
		 *         Returns empty matrix (n x 0) if null space is trivial
		 */
		inline Matrix<Real> NullSpace(const Matrix<Real>& A, Real tol = -1.0)
		{
			SVDecompositionSolver<Real> svd(A);
			return svd.Nullspace(tol);
		}

		/**
		 * Alias for NullSpace - kernel is the same as null space
		 */
		inline Matrix<Real> Kernel(const Matrix<Real>& A, Real tol = -1.0)
		{
			return NullSpace(A, tol);
		}

		/**
		 * Compute orthonormal basis for the column space (range) of A.
		 * 
		 * The column space is {Ax : x ∈ R^n} = span of columns of A.
		 * The columns of the returned matrix form an orthonormal basis.
		 * 
		 * @param A Input matrix (m x n)
		 * @param tol Threshold for zero singular values
		 * @return Matrix whose columns are orthonormal basis of col(A)
		 */
		inline Matrix<Real> ColumnSpace(const Matrix<Real>& A, Real tol = -1.0)
		{
			SVDecompositionSolver<Real> svd(A);
			return svd.Range(tol);
		}

		/**
		 * Alias for ColumnSpace - range is the same as column space
		 */
		inline Matrix<Real> Range(const Matrix<Real>& A, Real tol = -1.0)
		{
			return ColumnSpace(A, tol);
		}

		/**
		 * Compute the row space of A.
		 * 
		 * The row space is the column space of A^T.
		 * 
		 * @param A Input matrix
		 * @param tol Threshold for zero singular values
		 * @return Matrix whose columns are orthonormal basis of row(A)
		 */
		inline Matrix<Real> RowSpace(const Matrix<Real>& A, Real tol = -1.0)
		{
			// Row space of A = Column space of A^T
			return ColumnSpace(A.transpose(), tol);
		}

		/**
		 * Compute the left null space of A.
		 * 
		 * The left null space is {y : y^T A = 0} = null(A^T).
		 * 
		 * @param A Input matrix
		 * @param tol Threshold for zero singular values
		 * @return Matrix whose columns are orthonormal basis of null(A^T)
		 */
		inline Matrix<Real> LeftNullSpace(const Matrix<Real>& A, Real tol = -1.0)
		{
			// Left null space = Null space of A^T
			return NullSpace(A.transpose(), tol);
		}

		/**
		 * @struct FundamentalSubspaces
		 * @brief The four fundamental subspaces of a matrix
		 * 
		 * For an m×n matrix A:
		 * - Column space: dim = r (rank)
		 * - Row space: dim = r
		 * - Null space: dim = n - r
		 * - Left null space: dim = m - r
		 * 
		 * Key relationships:
		 * - Column space ⊥ Left null space (in R^m)
		 * - Row space ⊥ Null space (in R^n)
		 */
		struct FundamentalSubspaces
		{
			Matrix<Real> columnSpace;    ///< Orthonormal basis for col(A)
			Matrix<Real> rowSpace;       ///< Orthonormal basis for row(A)
			Matrix<Real> nullSpace;      ///< Orthonormal basis for null(A)
			Matrix<Real> leftNullSpace;  ///< Orthonormal basis for null(A^T)
			int rank;                    ///< Rank of the matrix
		};

		/**
		 * Compute all four fundamental subspaces of a matrix.
		 * 
		 * @param A Input matrix (m x n)
		 * @param tol Threshold for zero singular values
		 * @return FundamentalSubspaces containing bases for all four spaces
		 */
		inline FundamentalSubspaces ComputeFundamentalSubspaces(const Matrix<Real>& A, Real tol = -1.0)
		{
			FundamentalSubspaces result;
			
			SVDecompositionSolver<Real> svd(A);
			result.columnSpace = svd.Range(tol);
			result.nullSpace = svd.Nullspace(tol);
			result.rank = svd.Rank(tol);
			
			// For row space and left null space, use SVD of A^T
			SVDecompositionSolver<Real> svdT(A.transpose());
			result.rowSpace = svdT.Range(tol);
			result.leftNullSpace = svdT.Nullspace(tol);
			
			return result;
		}

		/**
		 * Compute the pseudoinverse (Moore-Penrose inverse) of a matrix.
		 * 
		 * For A = U * diag(σ) * V^T, the pseudoinverse is:
		 * A⁺ = V * diag(1/σ) * U^T
		 * 
		 * Properties:
		 * - A * A⁺ * A = A
		 * - A⁺ * A * A⁺ = A⁺
		 * - For full-rank square A: A⁺ = A⁻¹
		 * - x = A⁺ * b is the least-squares solution to Ax = b
		 * 
		 * @param A Input matrix (m x n)
		 * @param tol Threshold for zero singular values
		 * @return Pseudoinverse A⁺ (n x m)
		 */
		inline Matrix<Real> PseudoInverse(const Matrix<Real>& A, Real tol = -1.0)
		{
			int m = A.rows();
			int n = A.cols();
			
			SVDecompositionSolver<Real> svd(A);
			Vector<Real> w = svd.getW();
			Matrix<Real> U = svd.getU();
			Matrix<Real> V = svd.getV();
			
			// Compute threshold
			Real eps = std::numeric_limits<Real>::epsilon();
			Real threshold = (tol >= 0.0) ? tol : 0.5 * std::sqrt(m + n + 1.0) * w[0] * eps;
			
			// Compute A⁺ = V * diag(1/σ) * U^T
			Matrix<Real> result(n, m);
			for (int i = 0; i < n; i++)
			{
				for (int j = 0; j < m; j++)
				{
					Real sum = 0.0;
					for (int k = 0; k < n; k++)
					{
						if (w[k] > threshold)
							sum += V(i, k) * U(j, k) / w[k];
					}
					result(i, j) = sum;
				}
			}
			
			return result;
		}
	}
} // namespace MML





///////////////////////////   mml/core/NumericValidation.h   ///////////////////////////



namespace MML {

	///////////////////////////////////////////////////////////////////////////
	///                    NUMERIC VALIDATION HELPERS                       ///
	///////////////////////////////////////////////////////////////////////////
	//
	// These helpers provide consistent input validation across all numerical
	// algorithms. They check for non-finite values (NaN, Inf) and throw
	// NumericInputError with descriptive messages.
	//
	// Usage:
	//   ValidateFinite(x, "initial guess");
	//   ValidateBounds(a, b, "bisection");
	//   ValidateTolerance(tol, "Newton iteration");
	//   ValidateFunctionValue(f(x), "f(x)");
	//
	///////////////////////////////////////////////////////////////////////////

	/// @brief Check if a value is finite (not NaN or Inf)
	/// @param x Value to check
	/// @return true if x is finite, false if NaN or Inf
	inline bool IsFinite(Real x) noexcept {
		return std::isfinite(x);
	}

	/// @brief Check if a value is finite (for generic types)
	/// @tparam T Numeric type
	/// @param x Value to check
	/// @return true if x is finite, false if NaN or Inf
	template<typename T>
	inline bool IsFiniteValue(T x) noexcept {
		return std::isfinite(static_cast<double>(x));
	}

	/// @brief Validate that a value is finite, throw if not
	/// @param x Value to check
	/// @param name Name of the parameter for error message
	/// @throws NumericInputError if x is NaN or Inf
	inline void ValidateFinite(Real x, const char* name) {
		if (!std::isfinite(x)) {
			throw NumericInputError(std::string(name) + " must be finite (got " + 
				(std::isnan(x) ? "NaN" : "Inf") + ")");
		}
	}

	/// @brief Validate that a value is finite, throw if not (string version)
	/// @param x Value to check
	/// @param name Name of the parameter for error message
	/// @throws NumericInputError if x is NaN or Inf
	inline void ValidateFinite(Real x, const std::string& name) {
		ValidateFinite(x, name.c_str());
	}

	/// @brief Validate bounds for 1D algorithms (root finding, optimization, integration)
	/// @param a Lower bound
	/// @param b Upper bound
	/// @param context Name of the algorithm context for error message
	/// @throws NumericInputError if either bound is NaN or Inf
	inline void ValidateBounds(Real a, Real b, const char* context = "algorithm") {
		if (!std::isfinite(a)) {
			throw NumericInputError(std::string(context) + ": lower bound 'a' must be finite (got " +
				(std::isnan(a) ? "NaN" : "Inf") + ")");
		}
		if (!std::isfinite(b)) {
			throw NumericInputError(std::string(context) + ": upper bound 'b' must be finite (got " +
				(std::isnan(b) ? "NaN" : "Inf") + ")");
		}
	}

	/// @brief Validate bounds (string version)
	inline void ValidateBounds(Real a, Real b, const std::string& context) {
		ValidateBounds(a, b, context.c_str());
	}

	/// @brief Validate tolerance parameter
	/// @param tol Tolerance value
	/// @param context Name of the algorithm context for error message
	/// @throws NumericInputError if tolerance is not positive and finite
	inline void ValidateTolerance(Real tol, const char* context = "algorithm") {
		if (!std::isfinite(tol) || tol <= 0) {
			throw NumericInputError(std::string(context) + ": tolerance must be positive and finite (got " +
				std::to_string(tol) + ")");
		}
	}

	/// @brief Validate tolerance (string version)
	inline void ValidateTolerance(Real tol, const std::string& context) {
		ValidateTolerance(tol, context.c_str());
	}

	/// @brief Validate a function value returned during iteration
	/// @param fval Function value to check
	/// @param context Description of where this was evaluated
	/// @throws NumericInputError if function returned NaN or Inf
	inline void ValidateFunctionValue(Real fval, const char* context = "function evaluation") {
		if (!std::isfinite(fval)) {
			throw NumericInputError(std::string(context) + " returned non-finite value (" +
				(std::isnan(fval) ? "NaN" : "Inf") + ")");
		}
	}

	/// @brief Validate function value (string version)
	inline void ValidateFunctionValue(Real fval, const std::string& context) {
		ValidateFunctionValue(fval, context.c_str());
	}

	/// @brief Check if a function value is finite (non-throwing version)
	/// @param fval Function value to check
	/// @return true if fval is finite, false if NaN or Inf
	inline bool IsFunctionValueValid(Real fval) noexcept {
		return std::isfinite(fval);
	}

	/// @brief Validate maximum iterations parameter
	/// @param maxIter Maximum iterations value
	/// @param context Name of the algorithm context for error message
	/// @throws NumericInputError if maxIter is not positive
	inline void ValidateMaxIterations(int maxIter, const char* context = "algorithm") {
		if (maxIter <= 0) {
			throw NumericInputError(std::string(context) + ": max_iterations must be positive (got " +
				std::to_string(maxIter) + ")");
		}
	}

	/// @brief Validate step size for numerical differentiation/integration
	/// @param h Step size
	/// @param context Name of the algorithm context for error message
	/// @throws NumericInputError if h is not positive and finite
	inline void ValidateStepSize(Real h, const char* context = "algorithm") {
		if (!std::isfinite(h) || h <= 0) {
			throw NumericInputError(std::string(context) + ": step size must be positive and finite (got " +
				std::to_string(h) + ")");
		}
	}

} // namespace MML


///////////////////////////   mml/core/RichardsonExtrapolation.h   ///////////////////////////



namespace MML
{
	/// @brief Result of Richardson extrapolation
	struct RichardsonResult
	{
		Real value;           ///< Extrapolated value
		Real error_estimate;  ///< Estimated error from tableau differences
		int  iterations;      ///< Number of refinement steps used
		bool converged;       ///< True if converged within tolerance

		RichardsonResult(Real v = 0.0, Real e = 0.0, int it = 0, bool conv = false)
			: value(v), error_estimate(e), iterations(it), converged(conv) {}
	};

	namespace Richardson
	{
		/*************************************************************************/
		/*****         NEVILLE'S ALGORITHM (Polynomial Extrapolation)        *****/
		/*****         Used by Romberg integration - extrapolates to h=0     *****/
		/*************************************************************************/

		/// @brief Extrapolate sequence of values to limit using Neville's algorithm.
		/// @details Given values y[i] computed at "positions" x[i] (typically h² values),
		///          extrapolates to x=0 using polynomial interpolation.
		/// @param y Vector of computed values (at least 2 elements)
		/// @param x Vector of positions/step sizes (same size as y), must approach 0
		/// @return RichardsonResult with extrapolated value and error estimate
		static RichardsonResult NevilleExtrapolate(const std::vector<Real>& y, 
		                                            const std::vector<Real>& x)
		{
			int n = static_cast<int>(y.size());
			if (n < 2 || x.size() != y.size())
				return RichardsonResult(y.empty() ? 0.0 : y[0], 0.0, 0, false);

			std::vector<Real> c(n), d(n);
			
			// Find index of x closest to 0
			int ns = 0;
			Real dif = std::abs(x[0]);
			for (int i = 0; i < n; i++)
			{
				Real dift = std::abs(x[i]);
				if (dift < dif)
				{
					ns = i;
					dif = dift;
				}
				c[i] = y[i];
				d[i] = y[i];
			}

			// Initial best guess
			Real result = y[ns];
			Real error = 0.0;
			ns--;

			// Build Neville tableau
			for (int m = 1; m < n; m++)
			{
				for (int i = 0; i < n - m; i++)
				{
					Real ho = x[i];
					Real hp = x[i + m];
					Real w = c[i + 1] - d[i];
					Real den = ho - hp;

					if (den == 0.0)
						return RichardsonResult(result, std::abs(error), m, false);

					den = w / den;
					d[i] = hp * den;
					c[i] = ho * den;
				}

				// Choose correction from c or d based on position
				if (2 * (ns + 1) < (n - m))
					error = c[ns + 1];
				else
					error = d[ns--];

				result += error;
			}

			return RichardsonResult(result, std::abs(error), n, true);
		}

		/*************************************************************************/
		/*****         RICHARDSON TABLEAU (Ridders' Method Style)            *****/
		/*****         Used by dfridr - geometric step reduction              *****/
		/*************************************************************************/

		/// @brief Richardson extrapolation with geometric step reduction (dfridr-style).
		/// @details Builds a tableau of estimates computed at h, h/con, h/con², ...
		///          and extrapolates to h→0. Automatically finds optimal estimate.
		/// @tparam Evaluator Callable that computes estimate at given step size: Real(Real h)
		/// @param eval Function object: eval(h) returns approximation computed with step h
		/// @param h0 Initial step size
		/// @param con Step reduction factor (typically 1.4)
		/// @param max_iter Maximum tableau size (typically 10)
		/// @param safe Safety factor for convergence check (typically 2.0)
		/// @return RichardsonResult with best estimate and error
		template<typename Evaluator>
		static RichardsonResult Extrapolate(Evaluator eval, Real h0, 
		                                    Real con = 1.4, int max_iter = 10, Real safe = 2.0)
		{
			const Real con2 = con * con;
			const Real big = std::numeric_limits<Real>::max();

			if (h0 == 0.0)
				return RichardsonResult(0.0, big, 0, false);

			// Allocate tableau (triangular, but use full matrix for clarity)
			std::vector<std::vector<Real>> a(max_iter, std::vector<Real>(max_iter));

			Real hh = h0;
			a[0][0] = eval(hh);
			Real err = big;
			Real ans = a[0][0];

			int final_iter = 1;
			for (int i = 1; i < max_iter; i++)
			{
				hh /= con;
				a[0][i] = eval(hh);

				// Richardson extrapolation: eliminate error terms
				Real fac = con2;
				for (int j = 1; j <= i; j++)
				{
					// A_j(h) = (con^(2j) * A_{j-1}(h/con) - A_{j-1}(h)) / (con^(2j) - 1)
					a[j][i] = (a[j - 1][i] * fac - a[j - 1][i - 1]) / (fac - 1.0);
					fac *= con2;

					// Error estimate: max difference from previous column
					Real errt = std::max(std::abs(a[j][i] - a[j - 1][i]), 
					                     std::abs(a[j][i] - a[j - 1][i - 1]));

					// Track best answer (lowest error)
					if (errt <= err)
					{
						err = errt;
						ans = a[j][i];
					}
				}

				final_iter = i + 1;

				// Convergence check: error growing means we've passed optimal h
				if (std::abs(a[i][i] - a[i - 1][i - 1]) >= safe * err)
					break;
			}

			return RichardsonResult(ans, err, final_iter, err < big);
		}

		/*************************************************************************/
		/*****         SIMPLE RICHARDSON (Known Error Order)                 *****/
		/*****         When error order p is known: A_true ≈ A(h) + c*h^p    *****/
		/*************************************************************************/

		/// @brief Simple Richardson extrapolation for known error order.
		/// @details Given A(h) and A(h/r) where error is O(h^p), computes improved estimate.
		///          Formula: A_improved = (r^p * A(h/r) - A(h)) / (r^p - 1)
		/// @param a_h Value computed at step h
		/// @param a_h_over_r Value computed at step h/r
		/// @param r Step ratio (typically 2)
		/// @param p Error order (e.g., 2 for trapezoidal rule)
		/// @return Improved estimate
		static Real SimpleExtrapolate(Real a_h, Real a_h_over_r, Real r, int p)
		{
			Real rp = std::pow(r, p);
			return (rp * a_h_over_r - a_h) / (rp - 1.0);
		}

		/// @brief Estimate error from simple Richardson extrapolation.
		/// @param a_h Value at step h
		/// @param a_h_over_r Value at step h/r
		/// @param r Step ratio
		/// @param p Error order
		/// @return Estimated error in a_h_over_r
		static Real SimpleErrorEstimate(Real a_h, Real a_h_over_r, Real r, int p)
		{
			Real rp = std::pow(r, p);
			return std::abs(a_h_over_r - a_h) / (rp - 1.0);
		}

	} // namespace Richardson

} // namespace MML


///////////////////////////   mml/core/SingularityHandling.h   ///////////////////////////



namespace MML
{
	///////////////////////////////////////////////////////////////////////////////////////////
	///                         SINGULARITY HANDLING POLICY                                ///
	///////////////////////////////////////////////////////////////////////////////////////////
	
	/// @brief Policy for handling mathematical singularities in coordinate operations
	///
	/// Defines behavior when an operation encounters a coordinate singularity
	/// (division by zero, undefined limits, etc.)
	enum class SingularityPolicy
	{
		/// Throw a DomainError exception with detailed message
		/// Use when: Caller must handle singular cases explicitly
		Throw,
		
		/// Return NaN (std::numeric_limits<Real>::quiet_NaN())
		/// Use when: Propagating undefined values for later detection
		ReturnNaN,
		
		/// Return signed infinity (+/-inf based on sign of numerator)
		/// Use when: Mathematically correct limit behavior is needed
		ReturnInf,
		
		/// Clamp denominator to a small epsilon, preserving sign
		/// Use when: Approximate but finite values are acceptable near singularities
		Clamp,
		
		/// Return zero (useful for some physical contexts)
		/// Use when: Zero is a sensible default (e.g., field strength at origin)
		ReturnZero
	};

	/// @brief Convert singularity policy to string for diagnostics
	inline const char* SingularityPolicyToString(SingularityPolicy policy) {
		switch (policy) {
			case SingularityPolicy::Throw:      return "Throw";
			case SingularityPolicy::ReturnNaN:  return "ReturnNaN";
			case SingularityPolicy::ReturnInf:  return "ReturnInf";
			case SingularityPolicy::Clamp:      return "Clamp";
			case SingularityPolicy::ReturnZero: return "ReturnZero";
			default:                            return "Unknown";
		}
	}

	///////////////////////////////////////////////////////////////////////////////////////////
	///                         SINGULARITY DETECTION AND SAFE OPERATIONS                  ///
	///////////////////////////////////////////////////////////////////////////////////////////
	
	namespace Singularity
	{
		/// @brief Default tolerance for singularity detection
		/// 
		/// Points within this distance of a singular coordinate are considered singular.
		/// Chosen to be above machine epsilon but small enough for most practical uses.
		static constexpr Real DEFAULT_SINGULARITY_TOL = 1e-12;

		/// @brief Default policy when none is specified
		static constexpr SingularityPolicy DEFAULT_POLICY = SingularityPolicy::Throw;

		///////////////////////////////////////////////////////////////////////////////////
		//                           SINGULARITY DETECTION                               //
		///////////////////////////////////////////////////////////////////////////////////

		/// @brief Check if a value is effectively zero (potential singularity)
		/// @param value Value to check
		/// @param tol Tolerance for near-zero detection
		/// @return true if |value| < tol
		inline bool IsNearZero(Real value, Real tol = DEFAULT_SINGULARITY_TOL) {
			return std::abs(value) < tol;
		}

		/// @brief Check if spherical radius r is at origin singularity
		/// @param r Radial coordinate
		/// @param tol Tolerance
		/// @return true if r < tol
		inline bool IsAtSphericalOrigin(Real r, Real tol = DEFAULT_SINGULARITY_TOL) {
			return r < tol;
		}

		/// @brief Check if spherical theta is at a pole (θ=0 or θ=π)
		/// 
		/// The poles are singular because sin(θ)=0, causing division by zero
		/// in φ-components of operators.
		/// 
		/// @param theta Polar angle in radians [0, π]
		/// @param tol Tolerance
		/// @return true if sin(theta) < tol
		inline bool IsAtSphericalPole(Real theta, Real tol = DEFAULT_SINGULARITY_TOL) {
			return std::abs(std::sin(theta)) < tol;
		}

		/// @brief Check if cylindrical radius is at z-axis singularity
		/// @param r Radial distance from z-axis
		/// @param tol Tolerance
		/// @return true if r < tol
		inline bool IsAtCylindricalAxis(Real r, Real tol = DEFAULT_SINGULARITY_TOL) {
			return r < tol;
		}

		/// @brief Combined check: is spherical position (r,θ,φ) at ANY singularity?
		/// @param r Radial coordinate
		/// @param theta Polar angle
		/// @param tol Tolerance
		/// @return true if at origin OR at pole
		inline bool IsAtSphericalSingularity(Real r, Real theta, 
		                                     Real tol = DEFAULT_SINGULARITY_TOL) {
			return IsAtSphericalOrigin(r, tol) || IsAtSphericalPole(theta, tol);
		}

		/// @brief Get descriptive string for spherical singularity type
		/// @return "origin" if r≈0, "pole" if θ≈0 or π, "none" otherwise
		inline const char* DescribeSphericalSingularity(Real r, Real theta,
		                                                Real tol = DEFAULT_SINGULARITY_TOL) {
			if (IsAtSphericalOrigin(r, tol)) return "origin (r=0)";
			if (IsAtSphericalPole(theta, tol)) return "pole (sin(θ)=0)";
			return "none";
		}

		///////////////////////////////////////////////////////////////////////////////////
		//                           SAFE ARITHMETIC OPERATIONS                          //
		///////////////////////////////////////////////////////////////////////////////////

		/// @brief Safe division with singularity policy
		///
		/// Performs a/b with configurable behavior when b is near zero.
		///
		/// @param numerator Numerator value
		/// @param denominator Denominator value (checked for near-zero)
		/// @param policy What to do if denominator is singular
		/// @param context Optional context string for error messages
		/// @param tol Tolerance for near-zero detection
		/// @return Result of division or policy-determined value
		/// @throws DomainError if policy is Throw and denominator is singular
		inline Real SafeDivide(Real numerator, Real denominator, 
		                       SingularityPolicy policy = DEFAULT_POLICY,
		                       const char* context = nullptr,
		                       Real tol = DEFAULT_SINGULARITY_TOL)
		{
			if (!IsNearZero(denominator, tol)) {
				return numerator / denominator;
			}

			// Denominator is near zero - apply policy
			switch (policy)
			{
				case SingularityPolicy::Throw: {
					std::string msg = "Division by near-zero denominator";
					if (context) {
						msg += " in ";
						msg += context;
					}
					msg += " (denominator = " + std::to_string(denominator) + ")";
					throw DomainError(msg);
				}

				case SingularityPolicy::ReturnNaN:
					return std::numeric_limits<Real>::quiet_NaN();

				case SingularityPolicy::ReturnInf:
					if (numerator >= 0)
						return std::numeric_limits<Real>::infinity();
					else
						return -std::numeric_limits<Real>::infinity();

				case SingularityPolicy::Clamp: {
					// Clamp denominator to tol with same sign
					Real clampedDenom = (denominator >= 0) ? tol : -tol;
					return numerator / clampedDenom;
				}

				case SingularityPolicy::ReturnZero:
					return Real(0);

				default:
					return std::numeric_limits<Real>::quiet_NaN();
			}
		}

		/// @brief Safe 1/r operation common in spherical/cylindrical coordinates
		/// @param r Radial coordinate
		/// @param policy Singularity handling policy
		/// @param context Optional context for error messages
		/// @param tol Near-zero tolerance
		/// @return 1/r or policy-determined value
		inline Real SafeInverseR(Real r, 
		                         SingularityPolicy policy = DEFAULT_POLICY,
		                         const char* context = "1/r",
		                         Real tol = DEFAULT_SINGULARITY_TOL) {
			return SafeDivide(Real(1), r, policy, context, tol);
		}

		/// @brief Safe 1/r² operation
		/// @param r Radial coordinate  
		/// @param policy Singularity handling policy
		/// @param context Optional context for error messages
		/// @param tol Near-zero tolerance
		/// @return 1/r² or policy-determined value
		inline Real SafeInverseR2(Real r, 
		                          SingularityPolicy policy = DEFAULT_POLICY,
		                          const char* context = "1/r²",
		                          Real tol = DEFAULT_SINGULARITY_TOL) {
			return SafeDivide(Real(1), r * r, policy, context, tol);
		}

		/// @brief Safe 1/(r*sin(θ)) for spherical azimuthal component
		/// @param r Radial coordinate
		/// @param theta Polar angle
		/// @param policy Singularity handling policy
		/// @param context Optional context for error messages
		/// @param tol Near-zero tolerance
		/// @return 1/(r*sin(θ)) or policy-determined value
		inline Real SafeInverseRSinTheta(Real r, Real theta,
		                                 SingularityPolicy policy = DEFAULT_POLICY,
		                                 const char* context = "1/(r·sinθ)",
		                                 Real tol = DEFAULT_SINGULARITY_TOL) {
			return SafeDivide(Real(1), r * std::sin(theta), policy, context, tol);
		}

		/// @brief Safe 1/(r²*sin²(θ)) for spherical Laplacian azimuthal term
		/// @param r Radial coordinate
		/// @param theta Polar angle
		/// @param policy Singularity handling policy
		/// @param context Optional context for error messages
		/// @param tol Near-zero tolerance
		/// @return 1/(r²·sin²θ) or policy-determined value
		inline Real SafeInverseR2Sin2Theta(Real r, Real theta,
		                                   SingularityPolicy policy = DEFAULT_POLICY,
		                                   const char* context = "1/(r²·sin²θ)",
		                                   Real tol = DEFAULT_SINGULARITY_TOL) {
			Real sinTheta = std::sin(theta);
			return SafeDivide(Real(1), r * r * sinTheta * sinTheta, policy, context, tol);
		}

		/// @brief Safe cot(θ)/r² for spherical Laplacian polar term
		/// @param r Radial coordinate
		/// @param theta Polar angle
		/// @param policy Singularity handling policy
		/// @param context Optional context for error messages
		/// @param tol Near-zero tolerance
		/// @return cot(θ)/r² or policy-determined value
		inline Real SafeCotThetaOverR2(Real r, Real theta,
		                               SingularityPolicy policy = DEFAULT_POLICY,
		                               const char* context = "cotθ/r²",
		                               Real tol = DEFAULT_SINGULARITY_TOL) {
			Real sinTheta = std::sin(theta);
			Real cosTheta = std::cos(theta);
			return SafeDivide(cosTheta, r * r * sinTheta, policy, context, tol);
		}

	} // namespace Singularity

} // namespace MML


///////////////////////////   mml/core/Derivation/DerivationBase.h   ///////////////////////////



namespace MML
{
	namespace Derivation
	{
		/// @brief Optimal step size for 1st order derivative (forward/backward difference)
		/// @note h = 2√ε minimizes roundoff + truncation error for O(h) methods
		static inline const Real NDer1_h = 2 * std::sqrt(Constants::Eps);
		/// @brief Optimal step size for 2nd order derivative (central difference)
		/// @note h = (3ε)^(1/3) for O(h²) methods, balances O(ε/h) roundoff with O(h²) truncation
		static inline const Real NDer2_h = std::pow(3 * Constants::Eps, 1.0 / 3.0);
		/// @brief Optimal step size for 4th order derivative (5-point stencil)
		/// @note h = (11.25ε)^(1/5) ≈ 0.0012 for double precision
		static inline const Real NDer4_h = std::pow(11.25 * Constants::Eps, 1.0 / 5.0);     // 0.0012009323661373839 for double!
		/// @brief Optimal step size for 6th order derivative (7-point stencil)
		/// @note h = (ε/168)^(1/7) for O(h⁶) methods
		static inline const Real NDer6_h = std::pow(Constants::Eps / 168.0, 1.0 / 7.0);
		/// @brief Optimal step size for 8th order derivative (9-point stencil)
		/// @note h = (551.25ε)^(1/9) for O(h⁸) methods
		static inline const Real NDer8_h = std::pow(551.25 * Constants::Eps, 1.0 / 9.0);

		/// @brief Scale step size relative to |x| to avoid cancellation at large x
		/// @details For |x| > 1 scales h proportionally; for |x| <= 1 returns h unchanged
		static inline Real ScaleStep(Real h, Real x) {
			return h * std::max(Real(1), std::abs(x));
		}
	}
}


